template<class T>
class MyTemplatedClass {
private:
    T* data;
    int capacity;
    int currentSize;

    void resize() {
        capacity = (capacity == 0) ? 1 : capacity * 2;
        T* newData = new T[capacity];
        for (int i = 0; i < currentSize; ++i) {
            newData[i] = data[i];
        }
        delete[] data;
        data = newData;
    }

public:
    MyTemplatedClass() : data(nullptr), capacity(0), currentSize(0) {}

    explicit MyTemplatedClass(int initialSize) : capacity(initialSize), currentSize(initialSize) {
        data = new T[capacity];
        for (int i = 0; i < currentSize; ++i) {
            data[i] = T(); // Initialize with default value of T
        }
    }

    ~MyTemplatedClass() {
        delete[] data;
    }

    void push_back(T element) {
        if (currentSize == capacity) {
            resize();
        }
        data[currentSize++] = element;
    }

    T get(int index) {
        if (index < 0 || index >= currentSize) {
            throw std::out_of_range("Index out of range");
        }
        return data[index];
    }

    int size() const {
        return currentSize;
    }
};

// Test cases
