class HexProcessor {
public:
    std::vector<int> data1;
    std::vector<int> data2;

    HexProcessor() {}

    static HexProcessor processInput(const std::string& input) {
        HexProcessor processor;
        std::vector<std::string> hexStrings;

        if (input.size() == 42 && input.substr(0, 2) == "0x") {
            hexStrings.push_back(input.substr(2));
        } else {
            std::ifstream file(input);
            if (file.is_open()) {
                std::string line;
                while (std::getline(file, line)) {
                    if (line.size() == 42 && line.substr(0, 2) == "0x") {
                        hexStrings.push_back(line.substr(2));
                    }
                }
            } else {
                throw std::runtime_error("Failed to open file: " + input);
            }
        }

        for (const auto& hexStr : hexStrings) {
            for (size_t i = 0; i < hexStr.size(); i += 2) {
                int highNibble = hexValueNoException(hexStr[i]);
                int lowNibble = (i + 1) < hexStr.size() ? hexValueNoException(hexStr[i + 1]) : 0;
                processor.data1.push_back((highNibble << 4) | lowNibble);
                processor.data2.push_back((highNibble << 4) | lowNibble);
            }
        }

        return processor;
    }

private:
    static int hexValueNoException(char c) {
        const std::string hex = "0123456789abcdef";
        size_t index = hex.find(std::tolower(c));
        return index != std::string::npos ? static_cast<int>(index) : 0;
    }
};

