#include <algorithm>
#include <numeric>
using namespace std;

int gcd(int a, int b) {
    return b == 0 ? a : gcd(b, a % b);
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);
    cout.precision(10);

    int tt; cin >> tt;
    while(tt--) {
        int n; cin >> n;
        vector<int> a(n);
        for(int& i : a) cin >> i;
        sort(a.begin(), a.end());
        int common_gcd = a[0];
        for(int i = 1; i < n; ++i) {
            common_gcd = gcd(common_gcd, a[i]);
        }
        if(common_gcd > 1) {
            cout << 1 << endl;
        } else {
            // Since the GCD of all numbers is 1, we need to find the minimum number of groups
            // with GCD greater than 1. This can be done by grouping numbers with the same prime factors.
            vector<int> prime_factors(1000001, 0);
            for(int i = 2; i <= 1000000; ++i) {
                if(prime_factors[i] == 0) { // i is a prime number
                    for(int j = i; j <= 1000000; j += i) {
                        prime_factors[j] = i;
                    }
                }
            }
            vector<int> group_count(1000001, 0);
            for(int num : a) {
                int largest_prime = prime_factors[num];
                group_count[largest_prime]++;
            }
            cout << *max_element(group_count.begin(), group_count.end()) << endl;
        }
    }

    return 0;
}
