#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

/**
 * Helper function to recursively generate permutations.
 * @param nums The current permutation being processed.
 * @param ans The vector to store all unique permutations.
 * @param idx The current index being considered for swapping.
 */
void solve(vector<int> nums, vector<vector<int>>& ans, int idx) {
    if (idx == nums.size()) {
        ans.push_back(nums);
        return;
    }
    for (int i = idx; i < nums.size(); i++) {
        if (i != idx && nums[i] == nums[idx])
            continue;
        swap(nums[i], nums[idx]);
        solve(nums, ans, idx + 1);
    }
}

/**
 * Generates all unique permutations of a given vector of numbers.
 * @param nums The vector of numbers to permute.
 * @return A vector of vectors, where each inner vector is a unique permutation.
 */
vector<vector<int>> permute(vector<int> nums) {
    vector<vector<int>> ans;
    sort(nums.begin(), nums.end());
    solve(nums, ans, 0);
    return ans;
}

int main() {
    // Test case: Permutations of {1, 2, 2}
    vector<vector<int>> res = permute({1, 2, 2});
    for (const auto& permutation : res) {
        for (int num : permutation) {
            cout << num << " ";
        }
        cout << endl;
    }
    return 0;
}
