#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <climits>

using namespace std;

const int INF = INT_MAX;
const int Max = 20 + 5;

struct Team {
    string name;
    int id;
};

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int numberOfFriends, numberOfRoads;
    int caseNumber = 1;

    while (cin >> numberOfFriends >> numberOfRoads) {
        if (numberOfFriends == 0 && numberOfRoads == 0) break;

        vector<Team> friends(numberOfFriends);
        vector<vector<int>> distance(numberOfFriends, vector<int>(numberOfFriends, INF));

        for (int i = 0; i < numberOfFriends; ++i) {
            cin >> friends[i].name;
            friends[i].id = i;
            distance[i][i] = 0;
        }

        for (int i = 0; i < numberOfRoads; ++i) {
            int first, second, cost;
            cin >> first >> second >> cost;
            --first; --second;
            distance[first][second] = distance[second][first] = cost;
        }

        for (int k = 0; k < numberOfFriends; ++k) {
            for (int i = 0; i < numberOfFriends; ++i) {
                for (int j = 0; j < numberOfFriends; ++j) {
                    if (distance[i][k] != INF && distance[k][j] != INF) {
                        distance[i][j] = min(distance[i][j], distance[i][k] + distance[k][j]);
                    }
                }
            }
        }

        int target = -1;
        int minSum = INF;

        for (int i = 0; i < numberOfFriends; ++i) {
            int sum = 0;
            for (int j = 0; j < numberOfFriends; ++j) {
                sum += distance[i][j];
            }
            if (sum < minSum) {
                minSum = sum;
                target = i;
            } else if (sum == minSum && friends[i].name < friends[target].name) {
                target = i;
            }
        }

        cout << "Case #" << caseNumber++ << " : " << friends[target].name << "\n";
    }

    return 0;
}
