#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;
using ll = long long;

/**
 * Finds the minimum height difference between the tallest and shortest hills
 * out of a selection of K hills from a total of N hills.
 * 
 * @param N The total number of hills.
 * @param K The number of hills to select for building towers.
 * @param heights A vector containing the heights of the N hills.
 * @return The minimum height difference between the tallest and shortest selected hills.
 */
ll findMinHeightDifference(int N, int K, const vector<ll>& heights) {
    vector<ll> sortedHeights = heights;
    sort(sortedHeights.begin(), sortedHeights.end());
    ll ans = LLONG_MAX;
    for (int i = 0; i <= N - K; i++) {
        ans = min(sortedHeights[i + K - 1] - sortedHeights[i], ans);
    }
    return ans;
}

int main() {
    int N, K;
    cin >> N >> K;
    vector<ll> h(N);
    for (int i = 0; i < N; i++)
        cin >> h[i];

    ll result = findMinHeightDifference(N, K, h);
    cout << result << endl;
    return 0;
}
