            if constexpr (has_atnd_v<T>)
                return true;
            else if constexpr (has_square_bracket_v<T>)
                return true;
            else if constexpr (nested_array_dim_v<T> == 1)
                return true;
            else return false;
        }();
    };

    template <typename T>
    inline constexpr bool is_array1d_v = is_array1d<T>::value;
}

// Test cases
