    static_assert(nmtools::meta::is_array1d_v<std::vector<int>>, "std::vector should be 1d array-like");
    static_assert(!nmtools::meta::is_array1d_v<std::list<int>>, "std::list should not be 1d array-like");
    static_assert(!nmtools::meta::is_array1d_v<int>, "int should not be 1d array-like");

