#include <algorithm> // For std::min and std::max

// Define constants for anti-windup and integral term limits
#define ANTIWINDUP true
#define I_MIN -100.0
#define I_MAX 100.0

namespace auto_rover
{
    class PID
    {
    private:
        float min_val_;
        float max_val_;
        float kp_;
        float ki_;
        float kd_;
        float p_term_;
        float i_term_;
        float d_term_;
        float prev_error_;
        float error_;
        float p_error_;
        float i_error_;
        float d_error_;
        float output_;

        // Helper function to constrain values within a range
        float constrain(float value, float min_val, float max_val)
        {
            return std::max(min_val, std::min(value, max_val));
        }

    public:
        PID(float min_val, float max_val, float kp, float ki, float kd):
            min_val_(min_val),
            max_val_(max_val),
            kp_(kp),
            ki_(ki),
            kd_(kd),
            p_term_(0.0),
            i_term_(0.0),
            d_term_(0.0),
            prev_error_(0.0),
            error_(0.0),
            p_error_(0.0),
            i_error_(0.0),
            d_error_(0.0),
            output_(0.0)
        {
        }

        double compute(float setpoint, float measured_value, double delta)
        {
            error_ = setpoint - measured_value;
            d_error_ = error_ - prev_error_;

            p_error_ = error_;
            p_term_ = kp_ * p_error_;

            i_error_ += p_error_ * delta;
            if (ki_ > 0 && ANTIWINDUP)
            {
                i_error_ = constrain(i_error_, I_MIN / ki_, I_MAX / ki_);
            }

            i_term_ = ki_ * i_error_;

            if (!ANTIWINDUP)
            {
                i_term_ = constrain(i_term_, I_MIN, I_MAX);
            }

            d_term_ = kd_ * d_error_ / delta;

            if(setpoint == 0 && error_ == 0)
            {
                i_term_ = 0;
            }

            output_ = p_term_ + i_term_ + d_term_;

            prev_error_ = error_;

            return constrain(output_, min_val_, max_val_);
        }

        void updateConstants(float kp, float ki, float kd)
        {
            kp_ = kp;
            ki_ = ki;
            kd_ = kd;
        }
    };
}

// Test cases
int main()
{
    auto_rover::PID pid_controller(0.0, 100.0, 0.1, 0.01, 0.05);

    // Test case 1: Rover is too close to the obstacle
    float setpoint_distance = 50.0; // Desired distance from the obstacle in cm
    float measured_distance = 30.0; // Current distance from the obstacle in cm
    double delta_time = 0.1; // Time since last update in seconds
    float speed_command = pid_controller.compute(setpoint_distance, measured_distance, delta_time);
    std::cout << "Speed command: " << speed_command << std::endl;

    // Test case 2: Rover is at the perfect distance from the obstacle
    measured_distance = 50.0;
    speed_command = pid_controller.compute(setpoint_distance, measured_distance, delta_time);
    std::cout << "Speed command: " << speed_command << std::endl;

    // Test case 3: Rover is too far from the obstacle
    measured_distance = 70.0;
    speed_command = pid_controller.compute(setpoint_distance, measured_distance, delta_time);
    std::cout << "Speed command: " << speed_command << std::endl;

    // Update PID constants for different terrain
    pid_controller.updateConstants(0.2, 0.02, 0.1);

    return 0;
}
