instruction:
Given a root node of an N-ary tree, write a function to find the maximum depth of the tree. An N-ary tree is a tree in which each node has no more than N children. The maximum depth is the number of nodes along the longest path from the root node down to the farthest leaf node.

A tree node is defined as follows:

```cpp
class Node {
public:
    int val;
    vector<Node*> children;

    Node() {}

    Node(int _val) {
        val = _val;
    }

    Node(int _val, vector<Node*> _children) {
        val = _val;
        children = _children;
    }
};
```

Implement the `Solution` class with the following method:

```cpp
class Solution {
public:
    int maxDepth(Node* node);
};
```

The `maxDepth` function should return an integer representing the maximum depth of the given N-ary tree.

output:
```cpp
#include <iostream>
#include <vector>
#include <deque>
using namespace std;

// Definition for a Node.
class Node {
public:
    int val;
    vector<Node*> children;

    Node() {}

    Node(int _val) {
        val = _val;
    }

    Node(int _val, vector<Node*> _children) {
        val = _val;
        children = _children;
    }
};

class Solution {
public:
    int maxDepth(Node* node) {
        if (!node)
            return 0;
        int res = 0;
        deque<Node*> dq;

        dq.push_back(node);
        while (!dq.empty()) {
            ++res;
            int len = (int) dq.size();
            while (len--) {
                Node* p = dq.front();
                dq.pop_front();
                for (Node* n : p->children) {
                    if (n)
                        dq.push_back(n);
                }
            }
        }
        return res;
    }
};

// Test cases
int main() {
    // Test case 1
    Node* root1 = new Node(1, {new Node(2), new Node(3, {new Node(6), new Node(7, {new Node(11, {new Node(14)})})}), new Node(4, {new Node(8, {new Node(12)})}), new Node(5, {new Node(9, {new Node(13)}), new Node(10)})});
    Solution solution;
    cout << "Test case 1 - Expected Max Depth: 5, Actual Max Depth: " << solution.maxDepth(root1) << endl;

    // Test case 2
    Node* root2 = new Node(1, {new Node(2), new Node(3), new Node(4), new Node(5)});
    cout << "Test case 2 - Expected Max Depth: 2, Actual Max Depth: " << solution.maxDepth(root2) << endl;

    // Test case 3
    Node* root3 = new Node(1);
    cout << "Test case 3 - Expected Max Depth: 1, Actual Max Depth: " << solution.maxDepth(root3) << endl;

    // Test case 4
    Node* root4 = nullptr;
