class Solution {
public:
    /**
     * Finds the maximum sum of a contiguous subarray within an array of integers.
     * 
     * @param arr The array of integers.
     * @param n The size of the array.
     * @return The maximum subarray sum.
     */
    int maxSubarraySum(int arr[], int n) {
        int maximum = arr[0], sum = 0;
        for (int i = 0; i < n; i++) {
            sum += arr[i];
            if (sum < 0)
                sum = 0;
            maximum = max(sum, maximum);
        }
        return maximum;
    }
};

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        int arr[n];
        for (int i = 0; i < n; i++)
            cin >> arr[i];

        Solution ob;
        cout << ob.maxSubarraySum(arr, n) << endl;
    }
    return 0;
}
