// Constants
const int TEMP_SENSOR_VOLT_DEGRE = 10; // Assuming 10mV per degree
const int REFRESH_TIME = 1000; // Refresh time in milliseconds

// Global variables
int button_speed = 1;
int button_times = 0;
int button_value = 100; // Initial target temperature
int button_value_max = 2000; // Maximum target temperature

void setup() {
  Serial.begin(9600);
  init_pins();
  lcd_init();
  control_init();
}

void loop() {
  int analog_read = analogRead(Temp_Read);
  int temperature = analog_read / TEMP_SENSOR_VOLT_DEGRE * 5 / 1024;

  // Display the current temperature on the LCD
  lcd_display_temperature(temperature);

  loop_button();
  control_loop(temperature, button_value);

  delay(REFRESH_TIME);
}

void loop_button() {
  if (digitalRead(BUTTON_OK)) {
    control_ok();
  }
  if (digitalRead(BUTTON_RESET)) {
    control_reset();
    button_value = 100; // Reset to default target temperature
  }

  bool button_pressed = false;
  if (digitalRead(BUTTON_UP) == LOW) {
    button_value += button_speed;
    button_times++;
    button_pressed = true;
    button_value = min(button_value, button_value_max);
    control_setup(button_value);
  }
  if (digitalRead(BUTTON_DOWN) == LOW) {
    button_value -= button_speed;
    button_times++;
    button_pressed = true;
    button_value = max(button_value, 1);
    control_setup(button_value);
  }

  if (button_pressed) {
    if (button_times > 9) {
      button_speed = button_speed * 5;
      button_times = 0;
    }

    if (button_speed > 100) {
      button_speed = 100;
    }
  } else {
    button_speed = 1;
    button_times = 0;
  }
}

