#include <cmath>

#ifndef MAT4_HPP
#define MAT4_HPP

class mat4 {
public:
    mat4() {
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 4; ++j) {
                value[i][j] = (i == j) ? 1.0f : 0.0f;
            }
        }
    }

    mat4(float diag) {
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 4; ++j) {
                value[i][j] = (i == j) ? diag : 0.0f;
            }
        }
    }

    mat4(const mat4 &src) {
        memcpy(value, src.value, sizeof(value));
    }

    mat4& operator=(const mat4 &rhs) {
        if (this != &rhs) {
            memcpy(value, rhs.value, sizeof(value));
        }
        return *this;
    }

    mat4& translate(float x, float y, float z) {
        mat4 translation(1.0f);
        translation.value[0][3] = x;
        translation.value[1][3] = y;
        translation.value[2][3] = z;
        *this = *this * translation;
        return *this;
    }

    mat4& rotate(float angle, float x, float y, float z) {
        float rad = angle * M_PI / 180.0f;
        float c = cos(rad);
        float s = sin(rad);
        float omc = 1.0f - c;

        mat4 rotation(1.0f);
        rotation.value[0][0] = x * x * omc + c;
        rotation.value[0][1] = x * y * omc - z * s;
        rotation.value[0][2] = x * z * omc + y * s;

        rotation.value[1][0] = y * x * omc + z * s;
        rotation.value[1][1] = y * y * omc + c;
        rotation.value[1][2] = y * z * omc - x * s;

        rotation.value[2][0] = z * x * omc - y * s;
        rotation.value[2][1] = z * y * omc + x * s;
        rotation.value[2][2] = z * z * omc + c;

        *this = *this * rotation;
        return *this;
    }

    mat4& perspective(float fov, float aspect, float near, float far) {
        float tanHalfFOV = tan(fov / 2.0f * M_PI / 180.0f);
        mat4 projection(0.0f);
        projection.value[0][0] = 1.0f / (aspect * tanHalfFOV);
        projection.value[1][1] = 1.0f / tanHalfFOV;
        projection.value[2][2] = -(far + near) / (far - near);
        projection.value[2][3] = -(2.0f * far * near) / (far - near);
        projection.value[3][2] = -1.0f;
        *this = *this * projection;
        return *this;
    }

    void print_mat() const {
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 4; ++j) {
                std::cout << std::setw(10) << value[i][j] << " ";
            }
            std::cout << std::endl;
        }
    }

    float& getValue(int row, int col) {
        return value[row][col];
    }

private:
    float value[4][4];

    mat4 operator*(const mat4 &rhs) const {
        mat4 result;
        for (int i = 0; i < 4; ++i) {
            for (int j = 0; j < 4; ++j) {
                result.value[i][j] = 0.0f;
                for (int k = 0; k < 4; ++k) {
                    result.value[i][j] += value[i][k] * rhs.value[k][j];
                }
            }
        }
        return result;
    }
};

#endif // MAT4_HPP

// Test cases
int main() {
    mat4 matrix;
    matrix.print_mat(); // Should print the identity matrix

    matrix.translate(1.0f, 2.0f, 3.0f);
    matrix.print_mat(); // Should print the translation matrix

    matrix.rotate(90.0f, 0.0f, 0.0f, 1.0f);
    matrix.print_mat(); // Should print the rotation matrix

    matrix.perspective(45.0f, 1.0f, 0.1f, 100.0f);
    matrix.print_mat(); // Should print the perspective projection matrix

    return 0;
}
