class TextureManager {
public:
    TextureManager() {}
    ~TextureManager() {
        clearTextures();
    }

    GLuint loadTexture(const std::string& identifier, const std::string& path) {
        std::string fullPath = "../res/textures/" + path;
        GLuint textureID;
        glGenTextures(1, &textureID);
        int width, height;
        unsigned char* image = SOIL_load_image(fullPath.c_str(), &width, &height, 0, SOIL_LOAD_RGB);
        if (!image) {
            std::cerr << "Texture load failed for path: " << fullPath << std::endl;
            return 0;
        }
        glBindTexture(GL_TEXTURE_2D, textureID);
        glTexImage2D(GL_TEXTURE_2D, 0, GL_SRGB, width, height, 0, GL_RGB, GL_UNSIGNED_BYTE, image);
        glGenerateMipmap(GL_TEXTURE_2D);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_REPEAT);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_REPEAT);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR_MIPMAP_LINEAR);
        glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
        glBindTexture(GL_TEXTURE_2D, 0);
        SOIL_free_image_data(image);

        textures[identifier] = textureID;
        return textureID;
    }

    GLuint getTexture(const std::string& identifier) const {
        auto it = textures.find(identifier);
        if (it != textures.end()) {
            return it->second;
        }
        return 0;
    }

    void clearTextures() {
        for (auto& pair : textures) {
            glDeleteTextures(1, &pair.second);
        }
        textures.clear();
    }

private:
    std::map<std::string, GLuint> textures;
};

