using namespace std;

class Solution {
public:
    int maxScore(vector<int>& cardPoints, int k) {
        int l = 0, r = cardPoints.size() - k;
        int sum = 0;
        for (int i = r; i < cardPoints.size(); i++) {
            sum += cardPoints[i];
        }
        int maxsum = sum;
        while (r < cardPoints.size()) {
            sum += (cardPoints[l++] - cardPoints[r++]);
            maxsum = max(maxsum, sum);
        }
        return maxsum;
    }
};

int main() {
    Solution solution;
    vector<int> cardPoints1 = {1, 2, 3, 4, 5, 6, 1};
    int k1 = 3;
    cout << "Test Case 1 - Expected Output: 12" << endl;
    cout << "Actual Output: " << solution.maxScore(cardPoints1, k1) << endl;

