        "1. What is the capital of France?: ",
        "2. Who wrote 'To Kill a Mockingbird'?: ",
        "3. Which element has the chemical symbol 'O'?: ",
        "4. In which year did the Titanic sink?: "
    };

    string options[][4] = {
        {"A. Paris", "B. London", "C. Rome", "D. Berlin"},
        {"A. Ernest Hemingway", "B. Harper Lee", "C. J.K. Rowling", "D. Mark Twain"},
        {"A. Hydrogen", "B. Helium", "C. Oxygen", "D. Carbon"},
        {"A. 1912", "B. 1920", "C. 1905", "D. 1898"}
    };

    char answerKey[] = {'A', 'B', 'C', 'A'};

    int size = sizeof(questions) / sizeof(questions[0]);
    char guess;
    int score = 0;

    for (int i = 0; i < size; ++i) {
        cout << "******************************\n";
        cout << questions[i] << '\n';
        cout << "******************************\n";

        for (int j = 0; j < sizeof(options[i]) / sizeof(options[i][0]); ++j) {
            cout << options[i][j] << '\n';
        }

        do {
            cout << "Enter your answer (A, B, C, D): ";
            cin >> guess;
            guess = toupper(guess);
            if (guess < 'A' || guess > 'D' || !isalpha(guess)) {
                cout << "Invalid input. Please enter a valid option.\n";
            }
        } while (guess < 'A' || guess > 'D' || !isalpha(guess));

        if (guess == answerKey[i]) {
            cout << "CORRECT!\n";
            score++;
        } else {
            cout << "WRONG!\n";
            cout << "Answer: " << answerKey[i] << "\n";
        }
    }

    cout << "******************************\n";
    cout << "             RESULTS:          \n";
    cout << "******************************\n";
    cout << "CORRECT GUESSES: " << score << "\n";
    cout << "# of QUESTIONS: " << size << "\n";
