#include <cmath>
using namespace std;

/**
 * Calculates the minimum number of steps required to cover all the points
 * on a 2D grid in the order given by the arrays X and Y.
 * 
 * @param X A vector of integers representing the x-coordinates of the points.
 * @param Y A vector of integers representing the y-coordinates of the points.
 * @return The minimum number of steps required to cover all the points.
 */
int minStepsToCoverPoints(vector<int> &X, vector<int> &Y) {
    int totalSteps = 0;
    for (int i = 0; i < X.size() - 1; ++i) {
        totalSteps += max(abs(X[i] - X[i + 1]), abs(Y[i] - Y[i + 1]));
    }
    return totalSteps;
}

int main() {
    // Test cases
    vector<int> X1{0, 1, 1};
    vector<int> Y1{0, 1, 2};
    cout << "Test Case 1: " << minStepsToCoverPoints(X1, Y1) << endl; // Output: 2

    vector<int> X2{0, 2, 6};
    vector<int> Y2{0, 2, 10};
