        layout->addWidget(disconnectButton);
        layout->addWidget(messageEdit);
        layout->addWidget(sendButton);
        layout->addWidget(chatDisplay);

        setCentralWidget(centralWidget);
    }

    void connectSignals() {
        connect(connectButton, &QPushButton::clicked, this, &ChatClient::onConnectClicked);
        connect(disconnectButton, &QPushButton::clicked, this, &ChatClient::onDisconnectClicked);
        connect(sendButton, &QPushButton::clicked, this, &ChatClient::onSendClicked);
        connect(socket, &QTcpSocket::connected, this, &ChatClient::onConnected);
        connect(socket, &QTcpSocket::disconnected, this, &ChatClient::onDisconnected);
        connect(socket, &QTcpSocket::readyRead, this, &ChatClient::onReadyRead);
        connect(socket, QOverload<QAbstractSocket::SocketError>::of(&QTcpSocket::error), this, &ChatClient::onError);
    }
};

