#include <iostream>
#include <cmath>
#include <vector>

namespace GeometryTopology {

    class Coordinate {
    public:
        Coordinate(double x, double y, double z) : x_(x), y_(y), z_(z) {}

        double GetX() const { return x_; }
        double GetY() const { return y_; }
        double GetZ() const { return z_; }

        double DistanceTo(const Coordinate& other) const {
            return std::sqrt(std::pow(x_ - other.x_, 2) +
                             std::pow(y_ - other.y_, 2) +
                             std::pow(z_ - other.z_, 2));
        }

    private:
        double x_, y_, z_;
    };

    class Angle {
    public:
        typedef std::vector<Coordinate*> CoordinateVector;

        Angle() : angle_(0.0) {}

        CoordinateVector GetCoordinates() {
            return coordinates_;
        }

        double GetAngle() {
            return angle_;
        }

        void SetCoordinates(CoordinateVector coordinates) {
            coordinates_ = coordinates;
        }

        void AddCoordinate(Coordinate* coordinate) {
            coordinates_.push_back(coordinate);
        }

        void SetAngle(double angle) {
            angle_ = angle;
        }

        void CalculateAngle() {
            if (coordinates_.size() != 3) {
                throw std::runtime_error("Exactly three coordinates are required to calculate an angle.");
            }

            Coordinate* A = coordinates_[0];
            Coordinate* B = coordinates_[1];
            Coordinate* C = coordinates_[2];

            // Vector AB
            double ABx = B->GetX() - A->GetX();
            double ABy = B->GetY() - A->GetY();
            double ABz = B->GetZ() - A->GetZ();

            // Vector BC
            double BCx = C->GetX() - B->GetX();
            double BCy = C->GetY() - B->GetY();
            double BCz = C->GetZ() - B->GetZ();

            // Dot product
            double dot = ABx * BCx + ABy * BCy + ABz * BCz;

            // Magnitudes of AB and BC
            double magnitudeAB = A->DistanceTo(*B);
            double magnitudeBC = B->DistanceTo(*C);

            // Calculate the angle in radians and then convert to degrees
            double angleRadians = std::acos(dot / (magnitudeAB * magnitudeBC));
            angle_ = angleRadians * (180.0 / M_PI);
        }

        double GetAngleInRadians() const {
            return angle_ * (M_PI / 180.0);
        }

        void Print(std::ostream& out = std::cout) {
            out << "Angle: " << angle_ << " degrees" << std::endl;
        }

    private:
        CoordinateVector coordinates_;
        double angle_;
    };

}

int main() {
    using namespace GeometryTopology;

    // Test cases
    Coordinate A(0, 0, 0);
    Coordinate B(1, 0, 0);
    Coordinate C(0, 1, 0);

    Angle angleABC;
    angleABC.AddCoordinate(&A);
    angleABC.AddCoordinate(&B);
    angleABC.AddCoordinate(&C);

    try {
        angleABC.CalculateAngle();
        angleABC.Print();
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
