    void registerComponent(const std::string& name, IComponent* component) {
        assert(component != nullptr && "Component cannot be null");
        auto result = components.insert({name, component});
        if (!result.second) {
            std::cerr << "Component with name '" << name << "' is already registered." << std::endl;
            delete component;
        }
    }

    IComponent* getComponent(const std::string& name) {
        auto it = components.find(name);
        if (it != components.end()) {
            return it->second;
        }
        return nullptr;
    }

    void connectComponents(const std::string& sourceName, const std::string& targetName, const std::string& facetName) {
        IComponent* sourceComponent = getComponent(sourceName);
        IComponent* targetComponent = getComponent(targetName);

        assert(sourceComponent != nullptr && "Source component not found");
        assert(targetComponent != nullptr && "Target component not found");

        IPort* sourcePort = dynamic_cast<IPort*>(sourceComponent->getMember(facetName));
        assert(sourcePort != nullptr && "Facet not found in source component");

        IService* targetService = targetComponent->getServiceAt(sourcePort);
        assert(targetService != nullptr && "Service not found in target component");

        sourceComponent->setServiceAt(sourcePort, targetService);
    }
};

