#include <bits/stdc++.h>
using namespace std;
const int INF = 1e9+7;

int n;
vector<vector<int>> capacity;
vector<vector<int>> adj;
vector<int> parent;

int bfs(int s, int t) {
    fill(parent.begin(), parent.end(), -1);
    parent[s] = -2;
    queue<pair<int, int>> q;
    q.push({s, INF});
    while (!q.empty()) {
        int curr = q.front().first;
        int flow = q.front().second;
        q.pop();
        for (int nxt : adj[curr]) {
            if (parent[nxt] == -1 && capacity[curr][nxt]) {
                int new_flow = min(flow, capacity[curr][nxt]);
                parent[nxt] = curr;
                if (nxt == t)
                    return new_flow;
                q.push({nxt, new_flow});
            }
        }
    }
    return 0;
}

int getmaxflow(int s, int t) {
    int new_flow;
    parent = vector<int>(n);
    int flow = 0;
    while (new_flow = bfs(s, t)) {
        flow += new_flow;
        int curr = t;
        while (curr != s) {
            int par = parent[curr];
            capacity[par][curr] -= new_flow;
            capacity[curr][par] += new_flow;
            curr = par;
        }
    }
    return flow;
}

int main() {
    int m, u, v, c;
    cin >> n >> m;
    capacity.assign(n, vector<int>(n, 0));
    adj.assign(n, vector<int>());
    for (int i = 0; i < m; ++i) {
        cin >> u >> v >> c;
        adj[u].push_back(v);
        adj[v].push_back(u); // For the residual graph
        capacity[u][v] = c;
    }
    int s, t;
    cin >> s >> t;
    cout << getmaxflow(s, t) << endl;
    return 0;
}
