// Function to trim whitespace from both ends of a string
std::string trim(const std::string& str) {
    size_t first = str.find_first_not_of(' ');
    if (std::string::npos == first) {
        return str;
    }
    size_t last = str.find_last_not_of(' ');
    return str.substr(first, (last - first + 1));
}

// Function to parse the configuration file and return a map of flags
std::unordered_map<std::string, std::string> parseConfigFile(const std::string& filename) {
    std::ifstream file(filename);
    std::unordered_map<std::string, std::string> config;
    std::string line;

    while (std::getline(file, line)) {
        line = trim(line);
        if (line.empty() || line[0] == '#') continue; // Skip empty lines and comments

        size_t delimiterPos = line.find('=');
        std::string key = trim(line.substr(0, delimiterPos));
        std::string value = trim(line.substr(delimiterPos + 1));

        config[key] = value;
    }

    return config;
}

// Function to generate the header file content based on the configuration map
std::string generateHeaderFileContent(const std::unordered_map<std::string, std::string>& config) {
    std::string content;
    std::unordered_map<std::string, std::string> processedFlags;

    for (const auto& pair : config) {
        const std::string& key = pair.first;
        const std::string& value = pair.second;

        if (value == "DEFAULT") continue; // Skip default values

        // Check for conflicting flags
        std::string noKey = "NO_" + key;
        if ((value == "ON" && config.find(noKey) != config.end() && config.at(noKey) == "ON") ||
            (value == "OFF" && config.find(noKey) != config.end() && config.at(noKey) == "OFF")) {
            content += "#error Cannot force " + key + " to both ON and OFF\n";
            continue;
        }

        // Add define directive
        if (value == "ON") {
            content += "#define " + key + "\n";
        } else if (value == "OFF") {
            content += "#define " + noKey + "\n";
        }

        processedFlags[key] = value;
    }

    return content;
}

// Main function to read the configuration file and generate the header file
int main() {
    std::string configFilename = "config.txt"; // Replace with your config file path
    std::string headerFilename = "generated_config.hpp"; // Replace with your desired output header file path

    auto config = parseConfigFile(configFilename);
    std::string headerContent = generateHeaderFileContent(config);

    std::ofstream headerFile(headerFilename);
    if (headerFile.is_open()) {
        headerFile << headerContent;
        headerFile.close();
        std::cout << "Header file generated successfully." << std::endl;
    } else {
        std::cerr << "Unable to open header file for writing." << std::endl;
        return 1;
    }

    return 0;
}
