#include <iostream>
#include <vector>
#include <algorithm>
#include <ctime>

using namespace std;

// Structure to represent an item which stores weight and corresponding
// value of Item
struct Item {
    float weight;
    float profit;
    float ratio; // ratio of profit to weight
};

// Comparison function to sort Item according to val/weight ratio
bool cmp(Item a, Item b) {
    return a.ratio > b.ratio;
}

// Main greedy function to solve the knapsack problem
float fractionalKnapsack(int n, vector<Item> &items, float capacity) {
    // Sorting items on basis of ratio
    sort(items.begin(), items.end(), cmp);

    int curWeight = 0;  // Current weight in knapsack
    float finalProfit = 0.0; // Result (profit in Knapsack)

    // Looping through all Items
    for (int i = 0; i < n; i++) {
        // If adding Item won't overflow, add it completely
        if (curWeight + items[i].weight <= capacity) {
            curWeight += items[i].weight;
            finalProfit += items[i].profit;
        } else {
            // If we can't add current Item, add fractional part of it
            int remain = capacity - curWeight;
            finalProfit += items[i].profit * ((float)remain / items[i].weight);
            break; // Since the knapsack is full
        }
    }

    // Returning final profit
    return finalProfit;
}

int main() {
    int n;
    float capacity;
    cout << "Enter number of items: ";
    cin >> n;
    cout << "Enter the capacity of knapsack: ";
    cin >> capacity;

    vector<Item> items(n);

    // Taking input for items
    for (int i = 0; i < n; i++) {
        cout << "Enter item " << i + 1 << " profit: ";
        cin >> items[i].profit;
        cout << "Enter item " << i + 1 << " weight: ";
        cin >> items[i].weight;
        items[i].ratio = items[i].profit / items[i].weight;
    }

    // Timing the knapsack function
    clock_t start = clock();
    float maxProfit = fractionalKnapsack(n, items, capacity);
    clock_t stop = clock();

    cout << "Maximum profit in knapsack: " << maxProfit << endl;
    cout << "Time taken: " << (double)(stop - start) / CLOCKS_PER_SEC << " seconds" << endl;

    return 0;
}
