#include<iostream>
#include<vector>
using namespace std;

class MaxHeap {
private:
    vector<int> heap;

    void heapify(int index) {
        int largest = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;

        if (left < heap.size() && heap[left] > heap[largest])
            largest = left;

        if (right < heap.size() && heap[right] > heap[largest])
            largest = right;

        if (largest != index) {
            swap(heap[index], heap[largest]);
            heapify(largest);
        }
    }

public:
    void insert(int element) {
        heap.push_back(element);
        int i = heap.size() - 1;
        while (i != 0 && heap[(i - 1) / 2] < heap[i]) {
            swap(heap[(i - 1) / 2], heap[i]);
            i = (i - 1) / 2;
        }
    }

    void buildHeap() {
        for (int i = heap.size() / 2 - 1; i >= 0; i--)
            heapify(i);
    }

    void heapSort() {
        int n = heap.size();
        for (int i = n - 1; i >= 0; i--) {
            swap(heap[0], heap[i]);
            heap.pop_back();
            heapify(0);
        }
    }

    void display() {
        for (int i = 0; i < heap.size(); i++)
            cout << heap[i] << " ";
        cout << endl;
    }

    int size() {
        return heap.size();
    }
};

int main() {
    MaxHeap maxHeap;
    int n, element;
    cout << "Enter the number of elements: ";
    cin >> n;
    cout << "Enter " << n << " elements:" << endl;
    for (int i = 0; i < n; i++) {
        cin >> element;
        maxHeap.insert(element);
    }

    cout << "Heap after construction:" << endl;
    maxHeap.buildHeap();
    maxHeap.display();

    cout << "Array after heap sort:" << endl;
    maxHeap.heapSort();
    maxHeap.display();

    cout << "Size of the array after sorting: " << maxHeap.size() << endl;
    return 0;
}
