/**
 * @brief The RouterInterface class represents a router interface with its details.
 */
class RouterInterface {
public:
    long resourceOwnerId;
    std::string clientToken;
    std::string regionId;
    std::string resourceOwnerAccount;
    std::string ownerAccount;
    std::string routerInterfaceId;

    RouterInterface(long ownerId, const std::string& token, const std::string& region,
                    const std::string& resOwnerAcc, const std::string& ownAcc, const std::string& routerId)
        : resourceOwnerId(ownerId), clientToken(token), regionId(region),
          resourceOwnerAccount(resOwnerAcc), ownerAccount(ownAcc), routerInterfaceId(routerId) {}
};

/**
 * @brief The RouterInterfaceManager class manages router interfaces.
 */
class RouterInterfaceManager {
private:
    std::unordered_map<std::string, RouterInterface> interfaces;
    long nextId;

    std::string generateRouterInterfaceId() {
        return "ri-" + std::to_string(++nextId);
    }

public:
    RouterInterfaceManager() : nextId(0) {}

    std::string addRouterInterface(long ownerId, const std::string& token, const std::string& region,
                                   const std::string& resOwnerAcc, const std::string& ownAcc) {
        std::string routerId = generateRouterInterfaceId();
        interfaces[routerId] = RouterInterface(ownerId, token, region, resOwnerAcc, ownAcc, routerId);
        return routerId;
    }

    bool deleteRouterInterface(const std::string& routerId) {
        auto it = interfaces.find(routerId);
        if (it != interfaces.end()) {
            interfaces.erase(it);
            return true;
        }
        return false;
    }

    bool getRouterInterface(const std::string& routerId, RouterInterface& routerInterface) {
        auto it = interfaces.find(routerId);
        if (it != interfaces.end()) {
            routerInterface = it->second;
            return true;
        }
        return false;
    }
};

int main() {
    RouterInterfaceManager manager;

    // Test case 1: Add a router interface
    std::string routerId = manager.addRouterInterface(12345, "token123", "us-west-1", "resOwnerAcc", "ownerAcc");
    std::cout << "Added Router Interface with ID: " << routerId << std::endl;

    // Test case 2: Retrieve the router interface
    RouterInterface retrievedInterface;
    if (manager.getRouterInterface(routerId, retrievedInterface)) {
        std::cout << "Retrieved Router Interface with ID: " << retrievedInterface.routerInterfaceId << std::endl;
    } else {
        std::cout << "Router Interface not found." << std::endl;
    }

    // Test case 3: Delete the router interface
    if (manager.deleteRouterInterface(routerId)) {
        std::cout << "Router Interface with ID: " << routerId << " deleted successfully." << std::endl;
    } else {
        std::cout << "Failed to delete Router Interface with ID: " << routerId << std::endl;
    }

    // Test case 4: Attempt to retrieve the deleted router interface
    if (manager.getRouterInterface(routerId, retrievedInterface)) {
        std::cout << "Retrieved Router Interface with ID: " << retrievedInterface.routerInterfaceId << std::endl;
    } else {
        std::cout << "Router Interface not found." << std::endl;
    }

    return 0;
}
