#include <chrono>
#include <condition_variable>
#include <iostream>
#include <memory>
#include <mutex>
#include <string>
#include <thread>

// Mock classes and functions for the purpose of this example
class Timestamp {};
class KVEngine {
public:
    void checkpoint() {
        // Simulate checkpointing operation
        std::this_thread::sleep_for(std::chrono::seconds(1));
    }
};
class ServiceContext {};
void LOGV2_DEBUG(int, int, const std::string&, const std::string&) {}
void LOGV2(int, const std::string&) {}

// The Checkpointer class
class Checkpointer {
public:
    Checkpointer(KVEngine* kvEngine, int checkpointIntervalSecs)
        : _kvEngine(kvEngine), _checkpointIntervalSecs(checkpointIntervalSecs), _running(false) {}

    void run() {
        _running = true;
        LOGV2_DEBUG(22307, 1, "Starting thread", "Checkpointer");

        while (_running) {
            std::unique_lock<std::mutex> lock(_mutex);
            if (!_triggerCheckpoint) {
                _sleepCV.wait_for(lock, std::chrono::seconds(_checkpointIntervalSecs));
            }

            if (!_running) {
                break;
            }

            _triggerCheckpoint = false;
            lock.unlock();

            const auto startTime = std::chrono::high_resolution_clock::now();
            _kvEngine->checkpoint();
            const auto endTime = std::chrono::high_resolution_clock::now();
            const auto secondsElapsed = std::chrono::duration_cast<std::chrono::seconds>(endTime - startTime).count();

            if (secondsElapsed >= 30) {
                LOGV2_DEBUG(22308, 1, "Checkpoint was slow to complete", std::to_string(secondsElapsed));
            }
        }

        LOGV2_DEBUG(22309, 1, "Stopping thread", "Checkpointer");
    }

    void triggerCheckpoint() {
        std::lock_guard<std::mutex> lock(_mutex);
        _triggerCheckpoint = true;
        _sleepCV.notify_one();
    }

    void shutdown() {
        std::lock_guard<std::mutex> lock(_mutex);
        _running = false;
        _sleepCV.notify_one();
    }

    bool isRunning() const {
        return _running;
    }

private:
    KVEngine* _kvEngine;
    int _checkpointIntervalSecs;
    mutable std::mutex _mutex;
    std::condition_variable _sleepCV;
    bool _triggerCheckpoint = false;
    bool _running;
};

// Test cases
int main() {
    KVEngine kvEngine;
    Checkpointer checkpointer(&kvEngine, 5); // Set checkpoint interval to 5 seconds

    // Start the checkpoint thread
    std::thread checkpointThread(&Checkpointer::run, &checkpointer);

    // Trigger a manual checkpoint after 2 seconds
    std::this_thread::sleep_for(std::chrono::seconds(2));
    checkpointer.triggerCheckpoint();

    // Shutdown the checkpoint thread after 10 seconds
    std::this_thread::sleep_for(std::chrono::seconds(10));
    checkpointer.shutdown();

    // Wait for the checkpoint thread to finish
    if (checkpointThread.joinable()) {
        checkpointThread.join();
    }

    return 0;
}
