#include <iostream>
#include <cstddef>
#include <string>

// Forward declaration of ICharacter to resolve circular dependency
class ICharacter;

// AMateria interface
class AMateria {
public:
    virtual ~AMateria() {}
    virtual AMateria* clone() const = 0;
    virtual void use(ICharacter& target) = 0;
};

// ICharacter interface
class ICharacter {
public:
    virtual ~ICharacter() {}
    virtual const std::string& getName() const = 0;
};

// FireSpell concrete AMateria
class FireSpell : public AMateria {
public:
    FireSpell* clone() const override {
        return new FireSpell(*this);
    }

    void use(ICharacter& target) override {
        std::cout << "* casts a fire spell on " << target.getName() << " *" << std::endl;
    }
};

// Character class
class Character : public ICharacter {
private:
    static const int _size = 4;
    std::string _name;
    AMateria* _slot[_size] = {nullptr};

    int _findEmptySlot() const {
        for (int i = 0; i < _size; ++i)
            if (_slot[i] == nullptr)
                return i;
        return -1;
    }

public:
    Character(const std::string& name) : _name(name) {}

    Character(const Character& c) : _name(c.getName()) {
        for (int i = 0; i < _size; ++i) {
            if (c._slot[i])
                _slot[i] = c._slot[i]->clone();
        }
    }

    ~Character() {
        for (int i = 0; i < _size; ++i) {
            delete _slot[i];
        }
    }

    Character& operator=(const Character& c) {
        if (this != &c) {
            _name = c.getName();
            for (int i = 0; i < _size; ++i) {
                delete _slot[i];
                _slot[i] = c._slot[i] ? c._slot[i]->clone() : nullptr;
            }
        }
        return *this;
    }

    const std::string& getName() const override {
        return _name;
    }

    void equip(AMateria* am) {
        int idx = _findEmptySlot();
        if (idx != -1)
            _slot[idx] = am;
    }

    void unequip(int idx) {
        if (idx >= 0 && idx < _size && _slot[idx]) {
            _slot[idx] = nullptr;
        }
    }

    void use(int idx, ICharacter& target) {
        if (idx >= 0 && idx < _size && _slot[idx]) {
            _slot[idx]->use(target);
        }
    }
};

// Test cases
int main() {
    Character hero("Hero");
    FireSpell fire;

    hero.equip(&fire);
    Character villain("Villain");
    hero.use(0, villain); // Should print: * casts a fire spell on Villain *

    Character heroCopy(hero);
    heroCopy.use(0, villain); // Should print: * casts a fire spell on Villain *

    hero.unequip(0);
    hero.use(0, villain); // Should not print anything

    return 0;
}
