#include <bits/stdc++.h>
using namespace std;

void printCombinations(vector<int>& arr, int k) {
    int n = arr.size();
    vector<int> index(k);
    iota(index.begin(), index.end(), 0); // Initialize the first combination

    while (true) {
        // Print current combination
        for (int i = 0; i < k; ++i) {
            cout << arr[index[i]] << " ";
        }
        cout << endl;

        // Find the rightmost index that can be incremented
        int i = k - 1;
        while (i >= 0 && index[i] == n - k + i) {
            --i;
        }

        // If no such index is found, all combinations have been generated
        if (i < 0) {
            break;
        }

        // Increment this index and adjust the subsequent ones
        ++index[i];
        for (int j = i + 1; j < k; ++j) {
            index[j] = index[j - 1] + 1;
        }
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    cin >> n >> k;
    vector<int> arr(n);
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }
    sort(arr.begin(), arr.end()); // Ensure the list is sorted

    printCombinations(arr, k);

    return 0;
}
