std::vector<double> convolve_vectors(const std::vector<double>& a, const std::vector<double>& b) {
    std::vector<double> result(a.size() + b.size() - 1);
    VSLConvTaskPtr task;
    MKL_INT mode = VSL_CONV_MODE_AUTO;
    MKL_INT status = vsldConvNewTask1D(&task, mode, a.size(), b.size(), result.size());
    if (status != VSL_STATUS_OK) {
        throw std::runtime_error(esl::internal::mkl_vsl_status_string(status));
    }

    status = vsldConvExec1D(task, a.data(), 1, b.data(), 1, result.data(), 1);
    if (status != VSL_STATUS_OK) {
        vslConvDeleteTask(&task);
        throw std::runtime_error(esl::internal::mkl_vsl_status_string(status));
    }

    vslConvDeleteTask(&task);
    return result;
}

