// Function to decode the message
string decodeMessage(const string& encoded) {
    char map[26];
    for (int i = 0; i < 26; i++) {
        map[i] = 'a' + i;
    }

    string decoded = "";
    int length = encoded.length();
    encoded.push_back('$'); // Append sentinel characters to avoid index out of range
    encoded.push_back('$');
    encoded.push_back('$');

    for (int i = 0; i < length;) {
        if (encoded[i] == '0') {
            // If a zero is encountered, the next two characters represent a letter
            int num = stoi(encoded.substr(i + 1, 2));
            decoded.push_back(map[num - 1]);
            i += 3; // Skip the next two digits and the zero
        } else {
            // Otherwise, each digit represents a letter
            decoded.push_back(map[encoded[i] - '1']);
            i += 1; // Move to the next digit
        }
    }
    return decoded;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        string encoded;
        cin >> encoded;
        cout << decodeMessage(encoded) << endl;
