// Abstract base class representing a component in the file system
class Component {
public:
    virtual ~Component() {}
    virtual int getSize() const = 0;
    virtual void display(int depth = 0) const = 0;
};

// File class representing a single file
class File : public Component {
private:
    std::string name;
    int size;
public:
    File(const std::string& name, int size) : name(name), size(size) {}
    int getSize() const override {
        return size;
    }
    void display(int depth = 0) const override {
        std::cout << std::string(depth, ' ') << "- " << name << " (" << size << " bytes)" << std::endl;
    }
};

// Directory class representing a directory that can contain files and subdirectories
class Directory : public Component {
private:
    std::string name;
    std::vector<Component*> children;
public:
    Directory(const std::string& name) : name(name) {}
    ~Directory() {
        for (Component* child : children) {
            delete child;
        }
    }
    void add(Component* component) {
        children.push_back(component);
    }
    int getSize() const override {
        int totalSize = 0;
        for (const Component* child : children) {
            totalSize += child->getSize();
        }
        return totalSize;
    }
    void display(int depth = 0) const override {
        std::cout << std::string(depth, ' ') << name << "/" << std::endl;
        for (const Component* child : children) {
            child->display(depth + 2);
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    // Create files
    Component* file1 = new File("file1.txt", 120);
    Component* file2 = new File("file2.txt", 200);
    Component* file3 = new File("file3.txt", 150);

    // Create directories
    Directory* dir1 = new Directory("dir1");
    Directory* dir2 = new Directory("dir2");

