using namespace std;

bool vis[1001][1001];
int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

void updateWater(vector<vector<int>> &v, vector<vector<int>> &water, int time) {
    int n = v.size();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (v[i][j] <= time)
                water[i][j] = 1;
        }
    }
}

bool safe(int x, int y, int n) {
    return x >= 0 && x < n && y >= 0 && y < n;
}

bool dfs(int x, int y, vector<vector<int>> &water) {
    int n = water.size();
    if (x == n - 1 && y == n - 1) {
        return true;
    }
    vis[x][y] = true;
    for (int i = 0; i < 4; i++) {
        int nx = x + dx[i];
        int ny = y + dy[i];
        if (safe(nx, ny, n) && !vis[nx][ny] && water[nx][ny] == 1) {
            if (dfs(nx, ny, water)) {
                return true;
            }
        }
    }
    return false;
}

int findMinimumTime(vector<vector<int>> &v) {
    int n = v.size();
    vector<vector<int>> water(n, vector<int>(n, 0));
    int time = 0;
    while (true) {
        updateWater(v, water, time);
        if (water[0][0] == 1) {
            memset(vis, false, sizeof(vis));
            if (dfs(0, 0, water)) {
                return time;
            }
        }
        time++;
        if (time > 10000) { // Arbitrary large number to prevent infinite loop
            break;
        }
    }
    return -1;
}

int main() {
    int n;
    cin >> n;
    vector<vector<int>> v(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++)
            cin >> v[i][j];
    }
    int ans = findMinimumTime(v);
    cout << ans << endl;
    return 0;
}
