#include <iostream>
#include <fstream>
#include <vector>
#include <chrono>
#include <cstring>
#include <cstdlib>

/**
 * @brief A simplified version of the dd utility for copying blocks of data from an input file to an output file.
 * 
 * @param argc The number of command-line arguments.
 * @param argv The command-line arguments.
 * @return int Returns 0 on success, or 1 on failure.
 */
int main(int argc, char* argv[]) {
    std::string input_file = "";
    std::string output_file = "";
    size_t block_size = 512;
    size_t count = 0;
    size_t skip = 0;
    size_t seek = 0;

    // Parse command-line arguments
    for (int i = 1; i < argc; ++i) {
        std::string arg = argv[i];
        if (arg.find("if=") == 0) {
            input_file = arg.substr(3);
        } else if (arg.find("of=") == 0) {
            output_file = arg.substr(3);
        } else if (arg.find("bs=") == 0) {
            block_size = std::stoul(arg.substr(3));
        } else if (arg.find("count=") == 0) {
            count = std::stoul(arg.substr(6));
        } else if (arg.find("skip=") == 0) {
            skip = std::stoul(arg.substr(5));
        } else if (arg.find("seek=") == 0) {
            seek = std::stoul(arg.substr(5));
        } else {
            std::cerr << "Unknown option: " << arg << std::endl;
            return 1;
        }
    }

    std::ifstream input(input_file, std::ios::binary);
    std::ofstream output(output_file, std::ios::binary | std::ios::trunc);

    if (!input.is_open() || !output.is_open()) {
        std::cerr << "Error opening files." << std::endl;
        return 1;
    }

    // Skip blocks in the input file
    input.seekg(skip * block_size, std::ios::beg);

    // Skip blocks in the output file
    output.seekp(seek * block_size, std::ios::beg);

    std::vector<char> buffer(block_size);
    size_t blocks_copied = 0;
    auto start_time = std::chrono::high_resolution_clock::now();

    while ((count == 0 || blocks_copied < count) && input.read(buffer.data(), block_size)) {
        size_t bytes_read = input.gcount();
        output.write(buffer.data(), bytes_read);
        if (!output) {
            std::cerr << "Error writing to output file." << std::endl;
            return 1;
        }
        ++blocks_copied;
    }

    auto end_time = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double, std::milli> elapsed = end_time - start_time;

    std::cout << "Copied " << blocks_copied * block_size << " bytes in " << elapsed.count() << " ms." << std::endl;

    return 0;
}
