using namespace std;

const int NM = 1e5 + 10;
const long long oo = 99999999999;
vector<long long> a(NM, 0);
vector<vector<long long>> s(NM, vector<long long>(3, -oo));
int n;

void readInput() {
    cin >> n;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
    }
}

long long dp(int x, int y) {
    if (x <= 0 || y > n || x >= n || x >= y) return 0;
    if (a[x] == -1) return dp(x - 1, y);
    if (a[y] == -1) return dp(x, y + 1);
    long long &res = s[y][0];
    if (s[y][0] != -oo) return s[y][0];
    if (a[x] != a[y]) return max({dp(x + 1, y + 1), dp(x - 1, y - 1)});
    a[x] = -1;
    a[y]++;
    res = max(res, 1 + dp(y, y + 1));
    res = max(res, 1 + dp(x - 1, y));
    res = max(res, 1 + dp(y + 1, y + 2));
    a[y]--;
    a[x] = a[y];
    res = max(res, dp(y + 1, y + 2));
    res = max(res, dp(x - 2, y - 2));
    res = max(res, dp(y, y + 1));
    return res;
}

void solve() {
    long long ans = -oo;
    for (int i = 1; i < n; i++) {
        ans = max(ans, dp(i, i + 1));
    }
    cout << n - ans << '\n';
}

int main() {
    ios_base::sync_with_stdio(0);
    cin.tie(0);
    cout.tie(0);

    readInput();
    solve();
    return 0;
}
