#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
using namespace std;

const int MAXN = 2e5 + 10;
const int INF = INT_MAX;
typedef pair<int, int> PII;

struct Node {
    int mx[2], mi[2]; // 0 for weight 0, 1 for weight 1
} node[MAXN];

struct Tree {
    int l, r, mi, sum;
} tr[MAXN << 2];

#define ls (u << 1)
#define rs (u << 1 | 1)

void build(int u, int l, int r) {
    tr[u] = {l, r, INF, 0};
    if (l == r) return;
    int mid = (l + r) >> 1;
    build(ls, l, mid);
    build(rs, mid + 1, r);
}

void pushup(int u) {
    tr[u].mi = min(tr[ls].mi, tr[rs].mi);
    tr[u].sum = tr[ls].sum + tr[rs].sum;
}

void modify(int u, int pos, int x) {
    if (tr[u].l == tr[u].r) {
        tr[u].mi = x;
        tr[u].sum = 1;
    } else {
        int mid = (tr[u].l + tr[u].r) >> 1;
        if (pos <= mid) modify(ls, pos, x);
        else modify(rs, pos, x);
        pushup(u);
    }
}

vector<int> e[MAXN];
int col[MAXN], w[MAXN][2];
int tot, idx;
int n, m;

bool dfs(int x, int color, vector<vector<int>> &v) {
    if (color == 0) v[0].push_back(x);
    else v[1].push_back(x);
    col[x] = color;
    for (int j : e[x]) {
        if (col[j] == -1) {
            if (!dfs(j, color ^ 1, v)) return false;
        } else if (col[x] == col[j]) return false;
    }
    return true;
}

void solve() {
    cin >> n >> m;
    for (int i = 1; i <= n; ++i) e[i].clear(), col[i] = -1;
    for (int i = 0; i < m; ++i) {
        int a, b;
        cin >> a >> b;
        e[a].push_back(b);
        e[b].push_back(a);
    }
    for (int i = 1; i <= n; ++i) cin >> w[i][0] >> w[i][1];

    tot = idx = 0;
    vector<PII> aa(MAXN << 1);
    for (int i = 1; i <= n; ++i) {
        if (col[i] != -1) continue;
        ++tot;
        auto &mx = node[tot].mx, &mi = node[tot].mi;
        vector<vector<int>> v(2);
        if (!dfs(i, 0, v)) {
            cout << "IMPOSSIBLE" << endl;
            return;
        }
        for (int k = 0; k < 2; ++k) {
            mx[k] = 0;
            mi[k] = INF;
            for (int j : v[0]) {
                mx[k] = max(mx[k], w[j][k]);
                mi[k] = min(mi[k], w[j][k]);
            }
            for (int j : v[1]) {
                mx[k] = max(mx[k], w[j][k ^ 1]);
                mi[k] = min(mi[k], w[j][k ^ 1]);
            }
        }
        aa[++idx] = {mx[0], tot};
        aa[++idx] = {mx[1], tot};
    }
    build(1, 1, tot);
    int ans = INF;
    sort(aa.begin() + 1, aa.begin() + 1 + idx);
    for (int i = 1; i <= idx; ++i) {
        int ed = aa[i].first;
        int pos = aa[i].second;
        int x = 0;
        if (node[pos].mx[0] <= ed) x = node[pos].mi[0];
        if (node[pos].mx[1] <= ed) x = max(x, node[pos].mi[1]);
        modify(1, pos, x);
        if (tr[1].sum == tot) ans = min(ans, ed - tr[1].mi);
    }
    cout << ans << endl;
}

int main() {
    int t;
    cin >> t;
    for (int cas = 1; cas <= t; ++cas) {
        cout << "Case #" << cas << ": ";
        solve();
    }
    return 0;
}
