#include <cstdint>
#include <array>
#include <algorithm>
#include <chrono>

// Constants
constexpr int32_t MILLISECONDS_PER_SECOND = 1000;
constexpr int32_t SAMPLE_NUMBER = 60;
constexpr float MAX_FPS = 60.0f;

// FPS calculation methods
enum class FPSCalculateType {
    FPS_CT_FIXED_TIME,
    FPS_CT_AVERAGE_SAMPLING,
    FPS_CT_PRECISE_SAMPLING
};

class FPSCounter {
public:
    FPSCounter() : fps_(0.f), needResetFPS_(true), calculateType_(FPSCalculateType::FPS_CT_FIXED_TIME) {}

    void SetCalculateType(FPSCalculateType type) {
        calculateType_ = type;
        ResetFPS();
    }

    void UpdateFPS(uint32_t currentTime) {
        switch (calculateType_) {
            case FPSCalculateType::FPS_CT_FIXED_TIME:
                UpdateFPSByFixedTimeMethod(currentTime);
                break;
            case FPSCalculateType::FPS_CT_AVERAGE_SAMPLING:
                UpdateFPSByAverageSamplingMethod(currentTime);
                break;
            case FPSCalculateType::FPS_CT_PRECISE_SAMPLING:
                UpdateFPSByPreciseSamplingMethod(currentTime);
                break;
        }
    }

    float GetFPS() const {
        return fps_;
    }

    void ResetFPS() {
        needResetFPS_ = true;
    }

private:
    float fps_;
    bool needResetFPS_;
    FPSCalculateType calculateType_;

    void UpdateFPSByFixedTimeMethod(uint32_t currentTime) {
        static uint16_t frameCount = 0;
        static uint32_t lastTime = currentTime;
        if (needResetFPS_) {
            frameCount = 0;
            lastTime = currentTime;
            needResetFPS_ = false;
            fps_ = 0.f;
            return;
        }

        frameCount++;

        if (currentTime - lastTime > MILLISECONDS_PER_SECOND) {
            fps_ = static_cast<float>(frameCount) / (currentTime - lastTime) * MILLISECONDS_PER_SECOND;
            fps_ = std::min(fps_, MAX_FPS);
            frameCount = 0;
            lastTime = currentTime;
        }
    }

    void UpdateFPSByAverageSamplingMethod(uint32_t currentTime) {
        static float avgDuration = 0.f;
        static float alpha = 1.f / SAMPLE_NUMBER;
        static bool firstFrame = true;
        static uint32_t lastTime = currentTime;
        if (needResetFPS_) {
            avgDuration = 0.f;
            alpha = 1.f / SAMPLE_NUMBER;
            firstFrame = true;
            lastTime = currentTime;
            needResetFPS_ = false;
            fps_ = 0.f;
            return;
        }
        uint32_t deltaTime = currentTime - lastTime;
        lastTime = currentTime;

        if (firstFrame) {
            avgDuration = static_cast<float>(deltaTime);
            firstFrame = false;
        } else {
            avgDuration = avgDuration * (1 - alpha) + deltaTime * alpha;
        }
        fps_ = 1.f / avgDuration * MILLISECONDS_PER_SECOND;
    }

    void UpdateFPSByPreciseSamplingMethod(uint32_t currentTime) {
        static std::array<int32_t, SAMPLE_NUMBER> deltaTimeQueue = {0};
        static int32_t frameCount = 0;
        static int32_t sumDuration = 0;
        static bool isQueueFull = false;
        static uint32_t lastTime = currentTime;
        if (needResetFPS_) {
            std::fill(deltaTimeQueue.begin(), deltaTimeQueue.end(), 0);
            frameCount = 0;
            sumDuration = 0;
            isQueueFull = false;
            lastTime = currentTime;
            needResetFPS_ = false;
            fps_ = 0.f;
            return;
        }
        int32_t deltaTime = currentTime - lastTime;
        lastTime = currentTime;

        if (!isQueueFull && (frameCount == SAMPLE_NUMBER)) {
            isQueueFull = true;
        }
        frameCount %= SAMPLE_NUMBER;
        sumDuration -= deltaTimeQueue[frameCount];
        sumDuration += deltaTime;
        deltaTimeQueue[frameCount++] = deltaTime;
        if (isQueueFull) {
            fps_ = static_cast<float>(SAMPLE_NUMBER) / sumDuration * MILLISECONDS_PER_SECOND;
        } else {
            fps_ = static_cast<float>(frameCount) / sumDuration * MILLISECONDS_PER_SECOND;
        }
    }
};

// Test cases
int main() {
    FPSCounter fpsCounter;

    // Set the FPS calculation method to Fixed Time Method
    fpsCounter.SetCalculateType(FPSCalculateType::FPS_CT_FIXED_TIME);

    // Simulate frame updates and FPS calculation
    auto startTime = std::chrono::steady_clock::now();
    for (int i = 0; i < 100; ++i) {
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedTime = std::chrono::duration_cast<std::chrono::milliseconds>(currentTime - startTime).count();
        fpsCounter.UpdateFPS(static_cast<uint32_t>(elapsedTime));
        // Simulate a frame render time
        std::this_thread::sleep_for(std::chrono::milliseconds(16)); // ~60 FPS
    }

    // Print the calculated FPS
    std::cout << "Calculated FPS (Fixed Time Method): " << fpsCounter.GetFPS() << std::endl;

    // Reset FPS counter and change method
    fpsCounter.ResetFPS();
    fpsCounter.SetCalculateType(FPSCalculateType::FPS_CT_AVERAGE_SAMPLING);

    // Simulate frame updates and FPS calculation using Average Sampling Method
    startTime = std::chrono::steady_clock::now();
    for (int i = 0; i < 100; ++i) {
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedTime = std::chrono::duration_cast<std::chrono::milliseconds>(currentTime - startTime).count();
        fpsCounter.UpdateFPS(static_cast<uint32_t>(elapsedTime));
        // Simulate a frame render time
        std::this_thread::sleep_for(std::chrono::milliseconds(16)); // ~60 FPS
    }

    // Print the calculated FPS
    std::cout << "Calculated FPS (Average Sampling Method): " << fpsCounter.GetFPS() << std::endl;

    // Reset FPS counter and change method
    fpsCounter.ResetFPS();
    fpsCounter.SetCalculateType(FPSCalculateType::FPS_CT_PRECISE_SAMPLING);

    // Simulate frame updates and FPS calculation using Precise Sampling Method
    startTime = std::chrono::steady_clock::now();
    for (int i = 0; i < 100; ++i) {
        auto currentTime = std::chrono::steady_clock::now();
        auto elapsedTime = std::chrono::duration_cast<std::chrono::milliseconds>(currentTime - startTime).count();
        fpsCounter.UpdateFPS(static_cast<uint32_t>(elapsedTime));
        // Simulate a frame render time
        std::this_thread::sleep_for(std::chrono::milliseconds(16)); // ~60 FPS
    }

    // Print the calculated FPS
    std::cout << "Calculated FPS (Precise Sampling Method): " << fpsCounter.GetFPS() << std::endl;

    return 0;
}
