#include <gtest/gtest.h>

// Define the type_list template
template <typename... Types>
struct type_list {
  // Return the size of the type list
  static constexpr std::size_t size() { return sizeof...(Types); }
};

// Define the concat_type template
template <typename T, typename List>
struct concat_type;

template <typename T, typename... Types>
struct concat_type<T, type_list<Types...>> {
  using result = type_list<T, Types...>;
};

// Define the remove_type template
template <typename T, typename List>
struct remove_type;

template <typename T>
struct remove_type<T, type_list<>> {
  using result = type_list<>;
};

template <typename T, typename... Types>
struct remove_type<T, type_list<T, Types...>> {
  using result = typename remove_type<T, type_list<Types...>>::result;
};

template <typename T, typename U, typename... Types>
struct remove_type<T, type_list<U, Types...>> {
  using result = typename concat_type<U, typename remove_type<T, type_list<Types...>>::result>::result;
};

// Unit tests
namespace {

TEST(TypeListTest, Size) {
  EXPECT_EQ((type_list<>::size()), 0);
  EXPECT_EQ((type_list<int>::size()), 1);
  EXPECT_EQ((type_list<int, float>::size()), 2);
}

TEST(TypeListTest, Concat) {
  using t1 = typename concat_type<int, type_list<>>::result;
  using r1 = type_list<int>;
  ::testing::StaticAssertTypeEq<t1, r1>();

  using t2 = typename concat_type<int, type_list<float>>::result;
  using r2 = type_list<int, float>;
  ::testing::StaticAssertTypeEq<t2, r2>();

  using t3 = typename concat_type<type_list<float>, int>::result;
  using r3 = type_list<type_list<float>, int>;
  ::testing::StaticAssertTypeEq<t3, r3>();
}

TEST(TypeListTest, Remove) {
  using t1 = typename remove_type<int, type_list<float, int>>::result;
  using r1 = type_list<float>;
  ::testing::StaticAssertTypeEq<t1, r1>();

  using t2 = typename remove_type<int, type_list<int, int>>::result;
  using r2 = type_list<>;
  ::testing::StaticAssertTypeEq<t2, r2>();

  using t3 = typename remove_type<float, type_list<int, float, double>>::result;
  using r3 = type_list<int, double>;
  ::testing::StaticAssertTypeEq<t3, r3>();
}

}  // namespace

int main(int argc, char **argv) {
  ::testing::InitGoogleTest(&argc, argv);
  return RUN_ALL_TESTS();
}
