#include <QHash>
#include <QObject>
#include <QString>
#include <QDebug>

namespace berry
{

class TweakKey_base
{
public:
  QString tweakClass;

  TweakKey_base(const QString& _tweakClass);
  bool operator==(const TweakKey_base& obj) const;
  bool operator<(const TweakKey_base& obj) const;
};

class Tweaklets
{
private:
  static QHash<TweakKey_base, QObject*> defaults;
  static QHash<TweakKey_base, QObject*> tweaklets;

public:
  static void SetDefault(const TweakKey_base& definition, QObject* implementation);
  static void SetTweaklet(const TweakKey_base& definition, QObject* implementation);
  static QObject* GetTweaklet(const TweakKey_base& definition);
  static void ResetTweaklet(const TweakKey_base& definition);
  static void Clear();
};

// Implementation of TweakKey_base methods
TweakKey_base::TweakKey_base(const QString& _tweakClass) : tweakClass(_tweakClass) {}

bool TweakKey_base::operator==(const TweakKey_base& obj) const
{
  return this == &obj || tweakClass == obj.tweakClass;
}

bool TweakKey_base::operator<(const TweakKey_base& obj) const
{
  return tweakClass < obj.tweakClass;
}

// Implementation of Tweaklets methods
QHash<TweakKey_base, QObject*> Tweaklets::defaults;
QHash<TweakKey_base, QObject*> Tweaklets::tweaklets;

void Tweaklets::SetDefault(const TweakKey_base& definition, QObject* implementation)
{
  defaults.insert(definition, implementation);
}

void Tweaklets::SetTweaklet(const TweakKey_base& definition, QObject* implementation)
{
  tweaklets.insert(definition, implementation);
}

QObject* Tweaklets::GetTweaklet(const TweakKey_base& definition)
{
  return tweaklets.value(definition, defaults.value(definition));
}

void Tweaklets::ResetTweaklet(const TweakKey_base& definition)
{
  tweaklets.remove(definition);
}

void Tweaklets::Clear()
{
  tweaklets.clear();
  defaults.clear();
}

} // namespace berry

// Hash function for TweakKey_base
uint qHash(const berry::TweakKey_base& key)
{
  return qHash(key.tweakClass);
}

// Test cases
int main()
{
  // Create some dummy QObject implementations for testing
  QObject defaultImpl;
  QObject customImpl;

  // Define a tweak key
  berry::TweakKey_base key("SortingAlgorithm");

  // Set a default implementation
  berry::Tweaklets::SetDefault(key, &defaultImpl);

  // Replace the default implementation with a custom one
  berry::Tweaklets::SetTweaklet(key, &customImpl);

  // Retrieve the current implementation (should be the custom one)
  QObject* currentImpl = berry::Tweaklets::GetTweaklet(key);
  qDebug() << "Current implementation is custom:" << (currentImpl == &customImpl);

  // Reset the tweaklet to its default implementation
  berry::Tweaklets::ResetTweaklet(key);

  // Retrieve the current implementation again (should be the default one)
  currentImpl = berry::Tweaklets::GetTweaklet(key);
  qDebug() << "Current implementation is default:" << (currentImpl == &defaultImpl);

  return 0;
}
