// Mock I2C class for testing purposes
class MockI2C {
public:
    void ExpectWrite(const std::vector<uint8_t>& data) {
        // Store the expected write data for verification
        expectedWrites.push_back(data);
    }

    void ExpectRead(const std::vector<uint8_t>& data) {
        // Store the expected read data for verification
        expectedReads.push_back(data);
    }

    void Write(const std::vector<uint8_t>& data) {
        // Verify that the write data matches the expected data
        if (expectedWrites.empty() || expectedWrites.front() != data) {
            throw std::runtime_error("Unexpected I2C write operation");
        }
        expectedWrites.erase(expectedWrites.begin());
    }

    std::vector<uint8_t> Read(size_t length) {
        // Provide the expected read data
        if (expectedReads.empty()) {
            throw std::runtime_error("Unexpected I2C read operation");
        }
        std::vector<uint8_t> data = expectedReads.front();
        expectedReads.erase(expectedReads.begin());
        if (data.size() != length) {
            throw std::runtime_error("I2C read operation length mismatch");
        }
        return data;
    }

    void VerifyAndClear() {
        // Verify that all expected operations have been performed
        if (!expectedWrites.empty() || !expectedReads.empty()) {
            throw std::runtime_error("Not all expected I2C operations were performed");
        }
    }

private:
    std::vector<std::vector<uint8_t>> expectedWrites;
    std::vector<std::vector<uint8_t>> expectedReads;
};

// RGBLightController class definition
class RGBLightController {
public:
    RGBLightController(MockI2C& i2c) : i2c(i2c) {}

    void Init() {
        // Initialize the device (mocked)
        i2c.ExpectWrite({0x00, 0x40}); // Example initialization sequence
        i2c.Write({0x00, 0x40});
    }

    void SetRGB(uint32_t index, float red, float green, float blue) {
        // Set the RGB values for the light at the given index (mocked)
        i2c.ExpectWrite({static_cast<uint8_t>(index), ToByteValue(red), ToByteValue(green), ToByteValue(blue)});
        i2c.Write({static_cast<uint8_t>(index), ToByteValue(red), ToByteValue(green), ToByteValue(blue)});
    }

    void GetRGB(uint32_t index, float& red, float& green, float& blue) {
        // Get the current RGB values for the light at the given index (mocked)
        i2c.ExpectRead({ToByteValue(red), ToByteValue(green), ToByteValue(blue)});
        std::vector<uint8_t> rgbValues = i2c.Read(3);
        red = ToFloatValue(rgbValues[0]);
        green = ToFloatValue(rgbValues[1]);
        blue = ToFloatValue(rgbValues[2]);
    }

    void SetBrightness(uint32_t index, float brightness) {
        // Set the brightness for the light at the given index (mocked)
        i2c.ExpectWrite({static_cast<uint8_t>(index), ToByteValue(brightness)});
        i2c.Write({static_cast<uint8_t>(index), ToByteValue(brightness)});
    }

    void GetBrightness(uint32_t index, float& brightness) {
        // Get the current brightness for the light at the given index (mocked)
        i2c.ExpectRead({ToByteValue(brightness)});
        std::vector<uint8_t> brightnessValue = i2c.Read(1);
        brightness = ToFloatValue(brightnessValue[0]);
    }

    void Verify() {
        // Verify that all expected I2C operations have been performed
        i2c.VerifyAndClear();
    }

private:
    MockI2C& i2c;

    static uint8_t ToByteValue(float value) {
        // Convert a float value in the range [0.0, 1.0] to a byte value in the range [0, 255]
        return static_cast<uint8_t>(std::round(value * 255.0f));
    }

    static float ToFloatValue(uint8_t value) {
        // Convert a byte value in the range [0, 255] to a float value in the range [0.0, 1.0]
        return static_cast<float>(value) / 255.0f;
    }
};

// Example usage and test cases
int main() {
    MockI2C mockI2C;
    RGBLightController controller(mockI2C);

    // Test initialization
    controller.Init();

    // Test setting RGB values
    controller.SetRGB(0, 0.5f, 0.5f, 0.5f);

    // Test getting RGB values
    float red, green, blue;
    controller.GetRGB(0, red, green, blue);

    // Test setting brightness
    controller.SetBrightness(0, 0.75f);

    // Test getting brightness
    float brightness;
    controller.GetBrightness(0, brightness);

    // Verify all mock I2C operations
    controller.Verify();

    std::cout << "All tests passed successfully!" << std::endl;

    return 0;
}
