#include <bits/stdc++.h>
using namespace std;

#define FOR(i, a, b) for (int i = (a); i < (b); ++i)
#define F0R(i, a) FOR(i, 0, a)
#define each(a, x) for (auto& a: x)
#define pb push_back
#define mp make_pair
#define f first
#define s second
#define sz(x) (int)(x).size()
#define all(x) begin(x), end(x)

const int INF = 1e9;

void solve() {
    int n, k; cin >> n >> k;
    vector<int> a(n);
    map<int, pair<int,int>> idx;

    F0R(i, n) {
        cin >> a[i];
        if(idx.find(a[i]) == idx.end()) {
            idx[a[i]] = mp(INF, -INF);
        }
        idx[a[i]].f = min(idx[a[i]].f, i);
        idx[a[i]].s = max(idx[a[i]].s, i);
    }

    F0R(i, k) {
        int u, v; cin >> u >> v;
        if(idx.find(u) == idx.end() || idx.find(v) == idx.end() || idx[v].s - idx[u].f < 0) {
            cout << "NO" << "\n";
        } else {
            cout << "YES" << "\n";
        }
    }
}

int main() {
    ios::sync_with_stdio(0);
    cin.tie(0);

    int t; cin >> t;
    while(t--) {
        solve();
    }
    return 0;
}
