    vector<int> num(100001, 0);
    int a = n, ans = 0;
    while (!num[a]) {
        ans++;
        num[a] = ans;
        int b = a, cnt = 0;
        while (b != 0) {
            cnt += b % 10;
            b /= 10;
        }
        a = (a + cnt) % 100000;
    }
    int T = ans - num[a] + 1;
    if (k <= num[a]) {
        cout << find(num.begin(), num.end(), k) - num.begin() << endl;
    } else {
        cout << find(num.begin(), num.end(), ((k - num[a]) % T) + num[a]) - num.begin() << endl;
    }
