#include <iostream>

enum class BlendFactor {
  Zero,
  One,
  SrcColor,
  OneMinusSrcColor,
  DstColor,
  OneMinusDstColor,
  SrcAlpha,
  OneMinusSrcAlpha,
  DstAlpha,
  OneMinusDstAlpha
};

enum class BlendEquation {
  Add,
  Subtract,
  ReverseSubtract
};

class CustomBlendMode {
public:
  BlendFactor srcColorFactor;
  BlendFactor dstColorFactor;
  BlendFactor srcAlphaFactor;
  BlendFactor dstAlphaFactor;
  BlendEquation colorEquation;
  BlendEquation alphaEquation;

  CustomBlendMode(BlendFactor srcColor, BlendFactor dstColor, BlendFactor srcAlpha, BlendFactor dstAlpha, BlendEquation colorEq, BlendEquation alphaEq)
    : srcColorFactor(srcColor), dstColorFactor(dstColor), srcAlphaFactor(srcAlpha), dstAlphaFactor(dstAlpha), colorEquation(colorEq), alphaEquation(alphaEq) {}

  bool operator==(const CustomBlendMode& other) const {
    return srcColorFactor == other.srcColorFactor &&
           dstColorFactor == other.dstColorFactor &&
           srcAlphaFactor == other.srcAlphaFactor &&
           dstAlphaFactor == other.dstAlphaFactor &&
           colorEquation == other.colorEquation &&
           alphaEquation == other.alphaEquation;
  }

  bool operator!=(const CustomBlendMode& other) const {
    return !(*this == other);
  }

  void print() const {
    std::cout << "CustomBlendMode(" << static_cast<int>(srcColorFactor) << ", "
                                      << static_cast<int>(dstColorFactor) << ", "
                                      << static_cast<int>(srcAlphaFactor) << ", "
                                      << static_cast<int>(dstAlphaFactor) << ", "
                                      << static_cast<int>(colorEquation) << ", "
                                      << static_cast<int>(alphaEquation) << ")" << std::endl;
  }
};

// Test cases to verify the solution correctness
int main() {
  CustomBlendMode alphaBlending(BlendFactor::SrcAlpha, BlendFactor::OneMinusSrcAlpha, BlendFactor::One, BlendFactor::OneMinusSrcAlpha, BlendEquation::Add, BlendEquation::Add);
  CustomBlendMode additiveBlending(BlendFactor::SrcAlpha, BlendFactor::One, BlendFactor::Zero, BlendFactor::One, BlendEquation::Add, BlendEquation::Add);
  CustomBlendMode multiplicativeBlending(BlendFactor::DstColor, BlendFactor::Zero, BlendFactor::One, BlendFactor::Zero, BlendEquation::Add, BlendEquation::Add);
  CustomBlendMode noBlending(BlendFactor::One, BlendFactor::Zero, BlendFactor::One, BlendFactor::Zero, BlendEquation::Add, BlendEquation::Add);

  // Print blend modes
  alphaBlending.print();
  additiveBlending.print();
  multiplicativeBlending.print();
  noBlending.print();

  // Check equality
  CustomBlendMode anotherAlphaBlending = alphaBlending;
  if (alphaBlending == anotherAlphaBlending) {
    std::cout << "Alpha blending modes are equal." << std::endl;
  } else {
    std::cout << "Alpha blending modes are not equal." << std::endl;
  }

  if (alphaBlending != additiveBlending) {
    std::cout << "Alpha blending and additive blending modes are not equal." << std::endl;
  } else {
    std::cout << "Alpha blending and additive blending modes are equal." << std::endl;
  }

  return 0;
}
