#include <iostream>
#include <vector>

using namespace std;

/**
 * Calculates the prize money for the selected participant after the game show commission.
 * 
 * @param participants A vector of integers representing the money contributed by each participant.
 * @param selectedIndex The index of the selected participant (1-indexed).
 * @param commissionPercent The percentage commission taken by the game show.
 * @return The prize money for the selected participant.
 */
int calculatePrizeMoney(const vector<int>& participants, int selectedIndex, int commissionPercent) {
    int sum = 0;
    for (int money : participants) {
        sum += money;
    }

    if (participants[selectedIndex - 1] == 0) {
        return 0;
    }

    int prizeMoney = sum * (100 - commissionPercent) / participants[selectedIndex - 1];
    return prizeMoney;
}

int main() {
    int N, M, P;

    while (true) {
        cin >> N >> M >> P;
        if (N == 0 && M == 0 && P == 0) break;

        vector<int> participants(N);
        for (int i = 0; i < N; ++i) {
            cin >> participants[i];
        }

        int prize = calculatePrizeMoney(participants, M, P);
        cout << prize << endl;
    }

    return 0;
}
