struct Time {
    int year, month, day, hour, minute, second;

    std::string to_string() const {
        std::stringstream ss;
        ss << std::setfill('0') << std::setw(4) << year << "-"
           << std::setw(2) << month << "-"
           << std::setw(2) << day << " "
           << std::setw(2) << hour << ":"
           << std::setw(2) << minute << ":"
           << std::setw(2) << second;
        return ss.str();
    }
