// Generic timer class
class Timer {
public:
    Timer() : running_(false), time_(0.f), start_point_() {};
    ~Timer() {};

    void start() {
        if (!running_) {
            start_point_ = std::chrono::high_resolution_clock::now();
            running_ = true;
        }
    }

    void stop() {
        if (running_) {
            auto end_point = std::chrono::high_resolution_clock::now();
            time_ += std::chrono::duration<float>(end_point - start_point_).count();
            running_ = false;
        }
    }

    void reset() {
        if (!running_) {
            time_ = 0.f;
        }
    }

    float get_elapsed_time() const {
        if (running_) {
            auto current_point = std::chrono::high_resolution_clock::now();
            return time_ + std::chrono::duration<float>(current_point - start_point_).count();
        }
        return time_;
    }

    static Time get_current_time_info() {
        auto now = std::chrono::system_clock::now();
        auto in_time_t = std::chrono::system_clock::to_time_t(now);

        std::tm buf;
#ifdef _WIN32
        localtime_s(&buf, &in_time_t);
#else
        localtime_r(&in_time_t, &buf);
#endif

        Time current_time;
        current_time.year = 1900 + buf.tm_year;
        current_time.month = 1 + buf.tm_mon;
        current_time.day = buf.tm_mday;
        current_time.hour = buf.tm_hour;
        current_time.minute = buf.tm_min;
        current_time.second = buf.tm_sec;

        return current_time;
    }

private:
    bool running_;
    float time_;
    std::chrono::high_resolution_clock::time_point start_point_;

    // Prevent to clone this class
    Timer(Timer&&) = delete;
    Timer(const Timer&) = delete;
    Timer& operator=(Timer&&) = delete;
    Timer& operator=(const Timer&) = delete;
};

jeEnd

