using namespace std;

/**
 * Function to calculate the sum of digits of a number.
 * @param num The number whose sum of digits is to be calculated.
 * @return The sum of digits of the number.
 */
int sumOfDigits(int num) {
    int sum = 0;
    while (num > 0) {
        sum += num % 10;
        num /= 10;
    }
    return sum;
}

/**
 * Function to find the maximum sum of digits of a product of any two distinct elements in an array.
 * @param arr The array of integers.
 * @return The maximum sum of digits of any product.
 */
int maxSumOfProductDigits(const vector<int>& arr) {
    int maxSum = -1;
    for (size_t i = 0; i < arr.size(); ++i) {
        for (size_t j = 0; j < arr.size(); ++j) {
            if (i != j) {
                int product = arr[i] * arr[j];
                int sum = sumOfDigits(product);
                if (sum > maxSum) {
                    maxSum = sum;
                }
            }
        }
    }
    return maxSum;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> a(n);
        for (int i = 0; i < n; i++)
            cin >> a[i];
        cout << maxSumOfProductDigits(a) << endl;
    }
    return 0;
}
