// Function to return the maximum value between two numbers
long long max(long long a, long long b) {
    return (a > b) ? a : b;
}

// Map to store the computed maximum values for memoization
map<long long, long long> memo;

// Recursive function to calculate the maximum value of a coin
long long maxCoinValue(long long n) {
    // Base case: if n is 0, the maximum value is 0
    if (n == 0)
        return 0;

    // Check if the value has already been computed
    if (memo.find(n) == memo.end()) {
        // If not computed, calculate it by taking the maximum between the value of the coin
        // and the sum of the maximum values of the coins obtained by exchanging it
        memo[n] = max(n, maxCoinValue(n / 2) + maxCoinValue(n / 3) + maxCoinValue(n / 4));
    }

    // Return the computed maximum value for the coin
    return memo[n];
}

int main() {
    long long n;
    // Read input until EOF
    while (cin >> n) {
        // Output the maximum value for the coin
        cout << maxCoinValue(n) << endl;
    }
    return 0;
}
