#include <iostream>
#include <cstring>
#include <cstdlib>
using namespace std;

typedef struct TreeNode {
    char word[100];
    struct TreeNode *leftchild;
    struct TreeNode *rightchild;
    struct TreeNode *parent;
} NODE, *NODEPTR;

NODEPTR insert(NODEPTR ptr, const char* w) {
    if (ptr == NULL) {
        ptr = (NODE *) malloc(sizeof(NODE));
        strcpy(ptr->word, w);
        ptr->leftchild = NULL;
        ptr->rightchild = NULL;
        ptr->parent = NULL;
        return ptr;
    }

    NODEPTR q = (NODE *) malloc(sizeof(NODE)), tmp = NULL, root = ptr;
    strcpy(q->word, w);
    q->leftchild = NULL;
    q->rightchild = NULL;
    q->parent = NULL;

    while (ptr != NULL) {
        tmp = ptr;
        if (strcasecmp(ptr->word, w) > 0)
            ptr = ptr->leftchild;
        else if (strcasecmp(ptr->word, w) < 0)
            ptr = ptr->rightchild;
        else {
            free(q); // The word is already in the tree, free the allocated node.
            return root;
        }
    }

    ptr = q;
    ptr->parent = tmp;
    if (strcasecmp(tmp->word, w) > 0)
        tmp->leftchild = ptr;
    else
        tmp->rightchild = ptr;

    return root;
}

void inorder(NODEPTR node) {
    if (node == NULL)
        return;
    inorder(node->leftchild);
    cout << node->word << " ";
    inorder(node->rightchild);
}

void freeTree(NODEPTR node) {
    if (node == NULL)
        return;
    freeTree(node->leftchild);
    freeTree(node->rightchild);
    free(node);
}

int main() {
    int n;
    cout << "Enter the number of words: ";
    cin >> n;
    NODEPTR root = NULL;
    char word[100];

    for (int i = 0; i < n; i++) {
        cout << "Enter word " << i + 1 << ": ";
        cin >> word;
        root = insert(root, word);
    }

    cout << "\nIn-order traversal:\n";
    inorder(root);
    cout << endl;

    freeTree(root); // Free the allocated memory for the BST
    return 0;
}
