#include<iostream>
#include<vector>
#include<climits>

struct edge {
    int v;
    int weight;
    edge(int _v, int w) : v{_v}, weight{w} {}
};

void solve(int i, std::vector<edge> g[], int n, std::vector<int> &out, int **a, bool **visit) {
    if (i >= out.size()) return;
    int *arr = *a;
    bool *v = *visit;
    for (int j = 0; j < g[out[i]].size(); j++) {
        arr[g[out[i]][j].v]--;
        if (arr[g[out[i]][j].v] == 0 && !v[g[out[i]][j].v]) {
            out.push_back(g[out[i]][j].v);
            v[g[out[i]][j].v] = true;
        }
    }
    solve(++i, g, n, out, a, visit);
}

std::vector<int> topologicalSorting(std::vector<edge> g[], int n) {
    std::vector<int> out;
    bool *visited = new bool[n]();
    int *indegree = new int[n]();
    for (int i = 0; i < n; i++) {
        for (edge &e : g[i]) {
            indegree[e.v]++;
        }
    }
    for (int i = 0; i < n; i++) {
        if (indegree[i] == 0 && !visited[i]) {
            out.push_back(i);
            visited[i] = true;
        }
    }
    solve(0, g, n, out, &indegree, &visited);
    delete[] indegree;
    delete[] visited;
    return out;
}

std::vector<int> shortestPath(std::vector<edge> g[], int n) {
    std::vector<int> topo = topologicalSorting(g, n);
    std::vector<int> dist(n, INT_MAX);
    dist[topo[0]] = 0;
    for (int u : topo) {
        for (edge &e : g[u]) {
            if (dist[u] != INT_MAX && dist[e.v] > dist[u] + e.weight) {
                dist[e.v] = dist[u] + e.weight;
            }
        }
    }
    return dist;
}

int main() {
    int v, e;
    std::cout << "Enter number of vertices and number of edges: ";
    std::cin >> v >> e;
    std::vector<edge> g[v];
    std::cout << "Enter edges in the format 'u v w':\n";
    for (int i = 0; i < e; i++) {
        int u, v1, w;
        std::cin >> u >> v1 >> w;
        g[u].emplace_back(v1, w);
    }
    std::vector<int> distances = shortestPath(g, v);
    std::cout << "Shortest path distances from vertex 0:\n";
    for (int dist : distances) {
        if (dist == INT_MAX) {
            std::cout << "INF ";
        } else {
            std::cout << dist << " ";
        }
    }
    std::cout << "\n";
    return 0;
}
