        items.emplace_back(type, name, price);
    }

    bool removeItem(const std::string& name) {
        auto it = std::find_if(items.begin(), items.end(), [&name](const StoreItem& item) {
            return item.get_name() == name;
        });
        if (it != items.end()) {
            items.erase(it);
            return true;
        }
        return false;
    }

    bool updatePrice(const std::string& name, const double& newPrice) {
        for (auto& item : items) {
            if (item.get_name() == name) {
                item.set_price(newPrice);
                return true;
            }
        }
        return false;
    }

    void listItems() const {
        for (const auto& item : items) {
            std::cout << "Name: " << item.get_name() << ", Type: " << static_cast<int>(item.get_type())
                      << ", Price: $" << item.get_price() << std::endl;
        }
    }

    bool findItem(const std::string& name) const {
        for (const auto& item : items) {
            if (item.get_name() == name) {
                std::cout << "Item found - Name: " << item.get_name() << ", Type: " << static_cast<int>(item.get_type())
                          << ", Price: $" << item.get_price() << std::endl;
                return true;
            }
        }
