      : width(w), height(h), capture_time_ms(capture_ms), rtp_timestamp(rtp_ts), spatial_layers_count(layers) {}

  void SetData(const std::vector<uint8_t>& payload) {
    data = payload;
  }
};

class IvfFileWriter {
public:
  IvfFileWriter(const std::string& filename) : file_(filename, std::ios::binary) {
    assert(file_.is_open());
    WriteHeader();
  }

  ~IvfFileWriter() {
    file_.close();
  }

  void WriteFrame(const EncodedImage& frame, VideoCodecType codec_type) {
    // Write frame header (simplified for this example)
    uint32_t frame_size = static_cast<uint32_t>(frame.data.size());
    file_.write(reinterpret_cast<const char*>(&frame_size), sizeof(frame_size));
    file_.write(reinterpret_cast<const char*>(&frame.rtp_timestamp), sizeof(frame.rtp_timestamp));

    // Write frame data
    file_.write(reinterpret_cast<const char*>(frame.data.data()), frame.data.size());
  }

private:
  void WriteHeader() {
    // Write a simple IVF header (simplified for this example)
    const char header[] = "DKIF";
    file_.write(header, 4);
  }

  std::ofstream file_;
};

class IvfFileReader {
public:
  IvfFileReader(const std::string& filename) : file_(filename, std::ios::binary) {
    assert(file_.is_open());
    ReadHeader();
  }

  ~IvfFileReader() {
    file_.close();
  }

  EncodedImage ReadFrame() {
    // Read frame header (simplified for this example)
    uint32_t frame_size;
    uint32_t rtp_timestamp;
    file_.read(reinterpret_cast<char*>(&frame_size), sizeof(frame_size));
    file_.read(reinterpret_cast<char*>(&rtp_timestamp), sizeof(rtp_timestamp));

    // Read frame data
    std::vector<uint8_t> data(frame_size);
    file_.read(reinterpret_cast<char*>(data.data()), frame_size);

    // Create EncodedImage (simplified, assuming fixed width, height, and layers)
    EncodedImage frame(320, 240, 0, rtp_timestamp, 1);
    frame.SetData(data);
    return frame;
  }

private:
  void ReadHeader() {
    // Read and validate IVF header (simplified for this example)
    char header[4];
    file_.read(header, 4);
    assert(std::strncmp(header, "DKIF", 4) == 0);
  }

  std::ifstream file_;
};

