    assert(frame.width == width);
    assert(frame.height == height);
    assert(frame.rtp_timestamp == static_cast<uint32_t>(i));
    assert(std::memcmp(frame.data.data(), dummy_payload.data(), dummy_payload.size()) == 0);
  }

  // Clean up
  std::remove(filename.c_str());
}

