#include <iostream>
#include <vector>
#include <stdexcept>
#include <gnu_gama/local/acord/acordalgorithm.h>

using namespace GNU_gama::local;

class MatrixInversionAlgorithm : public AcordAlgorithm {
public:
    std::vector<std::vector<double>> invertMatrix(const std::vector<std::vector<double>>& matrix) {
        size_t n = matrix.size();
        std::vector<std::vector<double>> inverse(n, std::vector<double>(n, 0.0));
        std::vector<std::vector<double>> augmented = matrix;

        // Initialize the inverse matrix as an identity matrix
        for (size_t i = 0; i < n; ++i) {
            inverse[i][i] = 1.0;
        }

        // Perform Gauss-Jordan elimination
        for (size_t i = 0; i < n; ++i) {
            // Find pivot
            double pivot = augmented[i][i];
            if (pivot == 0) {
                throw std::runtime_error("Matrix is not invertible.");
            }

            // Normalize pivot row
            for (size_t j = 0; j < n; ++j) {
                augmented[i][j] /= pivot;
                inverse[i][j] /= pivot;
            }

            // Eliminate other rows
            for (size_t k = 0; k < n; ++k) {
                if (k != i) {
                    double factor = augmented[k][i];
                    for (size_t j = 0; j < n; ++j) {
                        augmented[k][j] -= factor * augmented[i][j];
                        inverse[k][j] -= factor * inverse[i][j];
                    }
                }
            }
        }

        return inverse;
    }
};

int main() {
    MatrixInversionAlgorithm algorithm;

    // Test case 1: Invertible matrix
    std::vector<std::vector<double>> matrix = {
        {4, 7},
        {2, 6}
    };

    try {
        std::vector<std::vector<double>> invertedMatrix = algorithm.invertMatrix(matrix);
        std::cout << "Inverted matrix:" << std::endl;
        for (const auto& row : invertedMatrix) {
            for (double val : row) {
                std::cout << val << " ";
            }
            std::cout << std::endl;
        }
    } catch (const std::runtime_error& e) {
        std::cout << "Error: " << e.what() << std::endl;
    }

    // Test case 2: Non-invertible matrix
    std::vector<std::vector<double>> nonInvertibleMatrix = {
        {1, 2},
        {2, 4}
    };

    try {
        std::vector<std::vector<double>> result = algorithm.invertMatrix(nonInvertibleMatrix);
    } catch (const std::runtime_error& e) {
        std::cout << "Error: " << e.what() << std::endl;
    }

    return 0;
}
