int calculateCrossings(int lengthA, int lengthB) {
    int posA = 0, posB = 0;
    int output = 0;
    char direction;
    int steps;

    // Process path A
    for (int i = 0; i < lengthA; i++) {
        cin >> steps >> direction;
        posA += (direction == 'L') ? -steps : steps;
    }

    // Process path B and count crossings
    for (int i = 0; i < lengthB; i++) {
        int prevPosB = posB;
        cin >> steps >> direction;
        posB += (direction == 'L') ? -steps : steps;

        // Check for crossings
        if ((prevPosB < posA && posB > posA) || (prevPosB > posA && posB < posA) || posB == posA) {
            output++;
        }
    }

    return output;
}

int main() {
    int lengthA, lengthB;
    cin >> lengthA >> lengthB;
    cout << calculateCrossings(lengthA, lengthB);
    return 0;
}

