    // Print k-3 ones, as they do not affect the LCM
    for (int i = 0; i < k - 3; ++i) {
        cout << 1 << " ";
    }

    // Handle the last three numbers
    if ((n - k + 3) % 2 == 1) {
        // If n - k + 3 is odd, print 1, (n-k+3)/2, (n-k+3)/2
        cout << 1 << " " << (n - k + 3) / 2 << " " << (n - k + 3) / 2;
    } else if ((n - k + 3) % 4 == 0) {
        // If n - k + 3 is divisible by 4, print (n-k+3)/2, (n-k+3)/4, (n-k+3)/4
        cout << (n - k + 3) / 2 << " " << (n - k + 3) / 4 << " " << (n - k + 3) / 4;
    } else {
        // Otherwise, print 2, (n-k+3)/2 - 1, (n-k+3)/2 - 1
        cout << 2 << " " << (n - k + 3) / 2 - 1 << " " << (n - k + 3) / 2 - 1;
    }
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int t;
    cin >> t;
    while (t--) {
        solve();
        cout << "\n";
    }
    return 0;
}
