namespace ioData {

class DataReader {
public:
    std::vector<std::pair<int, std::string>> readFromFile(const std::string& filePath) {
        std::vector<std::pair<int, std::string>> data;
        std::ifstream file(filePath);
        if (!file.is_open()) {
            throw std::runtime_error("Unable to open file for reading.");
        }

        std::string line;
        while (std::getline(file, line)) {
            size_t commaPos = line.find(',');
            if (commaPos != std::string::npos) {
                int id = std::stoi(line.substr(0, commaPos));
                std::string name = line.substr(commaPos + 1);
                data.emplace_back(id, name);
            }
        }

        file.close();
        return data;
    }
};

class DataWriter {
public:
    void writeToFile(const std::string& filePath, const std::vector<std::pair<int, std::string>>& data) {
        std::ofstream file(filePath);
        if (!file.is_open()) {
            throw std::runtime_error("Unable to open file for writing.");
        }

        for (const auto& record : data) {
            file << record.first << "," << record.second << std::endl;
        }

        file.close();
    }
};

} // namespace ioData

// Test cases
int main() {
    ioData::DataReader reader;
    ioData::DataWriter writer;

    std::string filePath = "data.txt";
    std::vector<std::pair<int, std::string>> dataToWrite = {
        {1, "Alice"},
        {2, "Bob"},
        {3, "Charlie"}
    };

    try {
        writer.writeToFile(filePath, dataToWrite);
        std::vector<std::pair<int, std::string>> dataRead = reader.readFromFile(filePath);

