// Include the BigInteger library
#include <helper/BigInteger.hpp>

/**
 * Finds the value of D (2 <= D <= limit) for which the largest value of x is obtained
 * in the minimal solution of the Diophantine equation x^2 - Dy^2 = 1.
 *
 * @param limit The upper bound for the value of D.
 * @return The value of D that produces the largest x in the minimal solution.
 */
int findLargestXInMinimalDiophantineSolution(int limit) {
    BigInteger maxX = 0;
    int bestD = 0;

    for (int D = 2; D <= limit; ++D) {
        const BigInteger root = static_cast<int>(std::sqrt(D));
        if (root * root == D) continue; // Skip perfect squares

        BigInteger m = 0;
        BigInteger d = 1;
        BigInteger a = root;

        BigInteger num1 = 1;
        BigInteger num2 = a;
        BigInteger den1 = 0;
        BigInteger den2 = 1;

        while (num2 * num2 - D * den2 * den2 != 1) {
            m = d * a - m;
            d = (D - m * m) / d;
            a = (root + m) / d;

            BigInteger num3 = a * num2 + num1;
            BigInteger den3 = a * den2 + den1;

            num1 = num2;
            den1 = den2;
            num2 = num3;
            den2 = den3;
        }

        if (num2 > maxX) {
            maxX = num2;
            bestD = D;
        }
    }

    return bestD;
}

int main() {
    int limit = 1000;
    int result = findLargestXInMinimalDiophantineSolution(limit);
    std::cout << "The value of D that produces the largest x in the minimal solution is: " << result << std::endl;
    return 0;
}
