// Function prototypes
void PrintDirectoryTree(const std::string& directoryPath, int level);
void PrintIndentation(int level);
bool IsDirectory(const WIN32_FIND_DATA& findData);

int main() {
    // Start the recursive directory tree printing from the current directory
    PrintDirectoryTree(".", 0);
    return 0;
}

void PrintDirectoryTree(const std::string& directoryPath, int level) {
    WIN32_FIND_DATA findData;
    HANDLE hFind = FindFirstFile((directoryPath + "\\*").c_str(), &findData);

    if (hFind == INVALID_HANDLE_VALUE) {
        std::cerr << "Error accessing directory: " << directoryPath << std::endl;
        return;
    }

    do {
        // Skip the current and parent directory entries
        if (strcmp(findData.cFileName, ".") == 0 || strcmp(findData.cFileName, "..") == 0) {
            continue;
        }

        // Print indentation based on the level of depth
        PrintIndentation(level);

        // Check if the entry is a directory or a file and print accordingly
        if (IsDirectory(findData)) {
            std::cout << "[D] " << findData.cFileName << std::endl;
            // Recursively print the contents of the directory
            PrintDirectoryTree(directoryPath + "\\" + findData.cFileName, level + 1);
        } else {
            std::cout << "[F] " << findData.cFileName << std::endl;
        }
    } while (FindNextFile(hFind, &findData) != 0);

    FindClose(hFind);
}

void PrintIndentation(int level) {
    for (int i = 0; i < level; ++i) {
        std::cout << "    ";
    }
}

bool IsDirectory(const WIN32_FIND_DATA& findData) {
    return (findData.dwFileAttributes & FILE_ATTRIBUTE_DIRECTORY) != 0;
}
