using namespace std;

/**
 * Simulates a game where two players (S and D) take turns to pick either the first
 * or last element from a list of integers to maximize their sum. Player S starts first.
 * 
 * @param l The list of integers to pick from.
 * @return A pair of integers representing the sum of elements collected by S and D.
 */
pair<int, int> playGame(vector<int> l) {
    vector<int> s, d;
    int m;

    while (!l.empty()) {
        if (l.size() == 1) {
            m = l.front();
            s.push_back(m);
            l.erase(find(l.begin(), l.end(), m));
            break;
        }
        m = max(l.front(), l.back());
        s.push_back(m);
        l.erase(find(l.begin(), l.end(), m));
        if (!l.empty()) {
            m = max(l.front(), l.back());
            d.push_back(m);
            l.erase(find(l.begin(), l.end(), m));
        }
    }

    int sumS = accumulate(s.begin(), s.end(), 0);
    int sumD = accumulate(d.begin(), d.end(), 0);
    return make_pair(sumS, sumD);
}

int main() {
    int n, a;
    vector<int> l;
    cin >> n;
    for (int i = 0; i < n; ++i) {
        cin >> a;
        l.push_back(a);
    }

    pair<int, int> result = playGame(l);
    cout << result.first << " " << result.second << "\n";
    return 0;
}

