// Recursive function to find all unique partitions of N
void uniquePartition(int N, vector<int> &currentPartition, int last) {
    // Base case: if N is 0, print the current partition
    if (N == 0) {
        cout << "(";
        for (size_t i = 0; i < currentPartition.size(); ++i) {
            cout << currentPartition[i];
            if (i < currentPartition.size() - 1) {
                cout << ",";
            }
        }
        cout << ") ";
        return;
    }

    // Start from the last number used to avoid duplicates
    for (int i = last; i <= N; ++i) {
        currentPartition.push_back(i);
        uniquePartition(N - i, currentPartition, i); // Recur with reduced N
        currentPartition.pop_back();
    }
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int N;
        cin >> N;
        vector<int> currentPartition;
        uniquePartition(N, currentPartition, 1); // Start with the smallest number 1
        cout << endl;
    }
    return 0;
}
