/**
 * Finds the missing number in a sequence of unique integers ranging from 1 to n.
 * Uses XOR to avoid integer overflow.
 * @param sequence A vector of integers representing the sequence.
 * @return The missing number in the sequence.
 */
int findMissingNumber(const vector<int>& sequence) {
    int n = sequence.size() + 1;
    int xor_all_numbers = 0;
    int xor_sequence = 0;

    // XOR all numbers from 1 to n
    for (int i = 1; i <= n; ++i) {
        xor_all_numbers ^= i;
    }

    // XOR all numbers in the sequence
    for (int num : sequence) {
        xor_sequence ^= num;
    }

    // XOR of xor_all_numbers and xor_sequence gives the missing number
    return xor_all_numbers ^ xor_sequence;
}

int main() {
    // Test case
    vector<int> sequence = {5, 2, 3, 4, 6, 7, 8, 9};
    int missingNumber = findMissingNumber(sequence);
    cout << "The missing number from the sequence is: " << missingNumber << endl;
    return 0;
}
