// Function to perform element-wise square of a matrix
std::vector<std::vector<double>> elementWiseSquare(const std::vector<std::vector<double>>& mat) {
    std::vector<std::vector<double>> result(mat.size(), std::vector<double>(mat[0].size()));
    for (size_t i = 0; i < mat.size(); ++i) {
        for (size_t j = 0; j < mat[i].size(); ++j) {
            result[i][j] = mat[i][j] * mat[i][j];
        }
    }
    return result;
}

// Function to perform matrix multiplication
std::vector<std::vector<double>> matrixMultiply(const std::vector<std::vector<double>>& matA,
                                                const std::vector<std::vector<double>>& matB) {
    assert(matA[0].size() == matB.size()); // Ensure the matrices are compatible for multiplication
    std::vector<std::vector<double>> result(matA.size(), std::vector<double>(matB[0].size(), 0.0));
    for (size_t i = 0; i < matA.size(); ++i) {
        for (size_t j = 0; j < matB[0].size(); ++j) {
            for (size_t k = 0; k < matB.size(); ++k) {
                result[i][j] += matA[i][k] * matB[k][j];
            }
        }
    }
    return result;
}

// Function to perform the matrix squared difference and scaling operation
std::vector<std::vector<double>> matrixSquaredDifferenceAndScaling(const std::vector<std::vector<double>>& matA,
                                                                   const std::vector<std::vector<double>>& matB,
                                                                   double scalar) {
    auto squaredA = elementWiseSquare(matA);
    auto squaredB = elementWiseSquare(matB);
    auto productAB = matrixMultiply(matA, matB);
    auto squaredProductAB = elementWiseSquare(productAB);
    auto productSquaredAB = matrixMultiply(squaredA, squaredB);

    assert(squaredProductAB.size() == productSquaredAB.size()); // Ensure the result matrices are compatible
    std::vector<std::vector<double>> result(squaredProductAB.size(), std::vector<double>(squaredProductAB[0].size()));
    for (size_t i = 0; i < squaredProductAB.size(); ++i) {
        for (size_t j = 0; j < squaredProductAB[i].size(); ++j) {
            result[i][j] = (squaredProductAB[i][j] - productSquaredAB[i][j]) * scalar;
        }
    }
    return result;
}

// Test cases to verify the solution correctness
int main() {
    std::vector<std::vector<double>> matA = {
        {1, 2},
        {3, 4}
    };
    std::vector<std::vector<double>> matB = {
        {5, 6},
        {7, 8}
    };
    double scalar = 2.0;

    auto result = matrixSquaredDifferenceAndScaling(matA, matB, scalar);

    // Expected output: [[-18, -20], [-42, -48]]
    for (const auto& row : result) {
        for (const auto& val : row) {
            std::cout << val << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
