```cpp
#include <iostream>
#include <string>
#include <rapidjson/document.h>
#include <rapidjson/writer.h>
#include <rapidjson/stringbuffer.h>

using namespace std;
using namespace rapidjson;

class JsonResponseParser {
private:
    string m_requestId;
    string m_executionResourceName;
    string m_startDate;
    bool m_executionResourceNameHasBeenSet;
    bool m_startDateHasBeenSet;

public:
    JsonResponseParser() : m_executionResourceNameHasBeenSet(false), m_startDateHasBeenSet(false) {}

    bool Parse(const string &payload) {
        Document d;
        d.Parse(payload.c_str());
        if (d.HasParseError() || !d.IsObject()) {
            cerr << "Response not in JSON format" << endl;
            return false;
        }

        if (!d.HasMember("Response") || !d["Response"].IsObject()) {
            cerr << "Response object is missing" << endl;
            return false;
        }

        const Value &rsp = d["Response"];

        if (!rsp.HasMember("RequestId") || !rsp["RequestId"].IsString()) {
            cerr << "RequestId is missing or not a string" << endl;
            return false;
        }
        m_requestId = rsp["RequestId"].GetString();

        if (rsp.HasMember("ExecutionResourceName") && !rsp["ExecutionResourceName"].IsNull()) {
            if (!rsp["ExecutionResourceName"].IsString()) {
                cerr << "ExecutionResourceName is not a string" << endl;
                return false;
            }
            m_executionResourceName = rsp["ExecutionResourceName"].GetString();
            m_executionResourceNameHasBeenSet = true;
        }

        if (rsp.HasMember("StartDate") && !rsp["StartDate"].IsNull()) {
            if (!rsp["StartDate"].IsString()) {
                cerr << "StartDate is not a string" << endl;
                return false;
            }
            m_startDate = rsp["StartDate"].GetString();
            m_startDateHasBeenSet = true;
        }

        return true;
    }

    string ToJsonString() const {
        Document doc;
        doc.SetObject();
        Document::AllocatorType& allocator = doc.GetAllocator();

        if (m_executionResourceNameHasBeenSet) {
            Value keyExecutionResourceName("ExecutionResourceName", allocator);
            doc.AddMember(keyExecutionResourceName, Value(m_executionResourceName.c_str(), allocator), allocator);
        }

        if (m_startDateHasBeenSet) {
            Value keyStartDate("StartDate", allocator);
            doc.AddMember(keyStartDate, Value(m_startDate.c_str(), allocator), allocator);
        }

        Value keyRequestId("RequestId", allocator);
        doc.AddMember(keyRequestId, Value(m_requestId.c_str(), allocator), allocator);

        StringBuffer buffer;
        Writer<StringBuffer> writer(buffer);
        doc.Accept(writer);
        return buffer.GetString();
    }

    string GetRequestId() const {
        return m_requestId;
    }

    string GetExecutionResourceName() const {
        return m_executionResourceName;
    }

    bool ExecutionResourceNameHasBeenSet() const {
        return m_executionResourceNameHasBeenSet;
    }

    string GetStartDate() const {
        return m_startDate;
    }

    bool StartDateHasBeenSet() const {
        return m_startDateHasBeenSet;
    }
};

// Test cases to verify the solution correctness
int main() {
    JsonResponseParser parser;
    string jsonResponse = R"({
        "Response": {
            "RequestId": "12345",
            "ExecutionResourceName": "myResource",
            "StartDate": "2021-01-01T00:00:00Z"
        }
