#include <iostream>
#include <map>
#include <string>
#include <sqlite3.h>

class Logger {
public:
    static void error(const std::string& message) {
        std::cerr << "Error: " << message << std::endl;
    }
};

class KeyValueStore {
private:
    sqlite3* db;

    // Prepare a SQL statement and return the prepared statement object
    sqlite3_stmt* prepareStatement(const std::string& sql) {
        sqlite3_stmt* stmt;
        if (sqlite3_prepare_v2(db, sql.c_str(), -1, &stmt, nullptr) != SQLITE_OK) {
            throw std::runtime_error(sqlite3_errmsg(db));
        }
        return stmt;
    }

public:
    KeyValueStore(const std::string& dbPath) {
        if (sqlite3_open(dbPath.c_str(), &db) != SQLITE_OK) {
            throw std::runtime_error(sqlite3_errmsg(db));
        }
    }

    ~KeyValueStore() {
        sqlite3_close(db);
    }

    bool load(std::map<std::string, std::string>& values) {
        const std::string sql = "SELECT key, value FROM store;";
        try {
            sqlite3_stmt* stmt = prepareStatement(sql);
            while (sqlite3_step(stmt) == SQLITE_ROW) {
                values[reinterpret_cast<const char*>(sqlite3_column_text(stmt, 0))] =
                    reinterpret_cast<const char*>(sqlite3_column_text(stmt, 1));
            }
            sqlite3_finalize(stmt);
            return true;
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
            return false;
        }
    }

    bool has(const std::string& key) {
        const std::string sql = "SELECT COUNT(*) FROM store WHERE key = ?;";
        try {
            sqlite3_stmt* stmt = prepareStatement(sql);
            sqlite3_bind_text(stmt, 1, key.c_str(), -1, SQLITE_STATIC);
            if (sqlite3_step(stmt) == SQLITE_ROW && sqlite3_column_int(stmt, 0) > 0) {
                sqlite3_finalize(stmt);
                return true;
            }
            sqlite3_finalize(stmt);
            return false;
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
            return false;
        }
    }

    bool get(const std::string& key, std::string& value) {
        const std::string sql = "SELECT value FROM store WHERE key = ?;";
        try {
            sqlite3_stmt* stmt = prepareStatement(sql);
            sqlite3_bind_text(stmt, 1, key.c_str(), -1, SQLITE_STATIC);
            if (sqlite3_step(stmt) == SQLITE_ROW) {
                value = reinterpret_cast<const char*>(sqlite3_column_text(stmt, 0));
                sqlite3_finalize(stmt);
                return true;
            }
            sqlite3_finalize(stmt);
            return false;
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
            return false;
        }
    }

    bool save(const std::map<std::string, std::string>& values) {
        const std::string sql = "INSERT INTO store (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value;";
        try {
            sqlite3_exec(db, "BEGIN;", nullptr, nullptr, nullptr);
            for (const auto& pair : values) {
                sqlite3_stmt* stmt = prepareStatement(sql);
                sqlite3_bind_text(stmt, 1, pair.first.c_str(), -1, SQLITE_STATIC);
                sqlite3_bind_text(stmt, 2, pair.second.c_str(), -1, SQLITE_STATIC);
                sqlite3_step(stmt);
                sqlite3_finalize(stmt);
            }
            sqlite3_exec(db, "COMMIT;", nullptr, nullptr, nullptr);
            return true;
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
            sqlite3_exec(db, "ROLLBACK;", nullptr, nullptr, nullptr);
            return false;
        }
    }

    bool save(const std::string& key, const std::string& value) {
        const std::string sql = "INSERT INTO store (key, value) VALUES (?, ?) ON CONFLICT(key) DO UPDATE SET value = excluded.value;";
        try {
            sqlite3_stmt* stmt = prepareStatement(sql);
            sqlite3_bind_text(stmt, 1, key.c_str(), -1, SQLITE_STATIC);
            sqlite3_bind_text(stmt, 2, value.c_str(), -1, SQLITE_STATIC);
            sqlite3_step(stmt);
            sqlite3_finalize(stmt);
            return true;
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
            return false;
        }
    }

    void remove(const std::string& key) {
        const std::string sql = "DELETE FROM store WHERE key = ?;";
        try {
            sqlite3_stmt* stmt = prepareStatement(sql);
            sqlite3_bind_text(stmt, 1, key.c_str(), -1, SQLITE_STATIC);
            sqlite3_step(stmt);
            sqlite3_finalize(stmt);
        } catch (const std::runtime_error& e) {
            Logger::error(e.what());
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    KeyValueStore store("key_value_store.db");

    // Test save and load
    std::map<std::string, std::string> valuesToSave = {{"key1", "value1"}, {"key2", "value2"}};
    store.save(valuesToSave);

    std::map<std::string, std::string> loadedValues;
    store.load(loadedValues);
    for (const auto& pair : loadedValues) {
        std::cout << pair.first << " => " << pair.second << std::endl;
    }

    // Test has and get
    std::string value;
    if (store.has("key1") && store.get("key1", value)) {
        std::cout << "Retrieved value for 'key1': " << value << std::endl;
    } else {
        std::cout << "'key1' not found." << std::endl;
    }

    // Test remove
    store.remove("key1");
    if (!store.has("key1")) {
        std::cout << "'key1' successfully removed." << std::endl;
    }

    return 0;
}
