#include <iostream>
#include <vector>
#include <set>
#include <algorithm>
using namespace std;

class Solution {
public:
    int findPairs(vector<int>& nums, int k) {
        if (k < 0) {
            return 0;
        }
        sort(nums.begin(), nums.end());
        set<pair<int, int>> uniquePairs;
        int n = nums.size();
        int left = 0, right = 1;

        while (right < n && left < n) {
            int diff = abs(nums[left] - nums[right]);
            if (left == right) {
                right++;
                continue;
            }
            if (diff == k) {
                uniquePairs.insert({nums[left], nums[right]});
                left++;
                right++;
            } else if (diff > k) {
                left++;
            } else {
                right++;
            }
        }
        return uniquePairs.size();
    }
};

int main() {
    Solution solution;
    vector<int> nums1 = {3, 1, 4, 1, 5};
    int k1 = 2;
    cout << "Test Case 1: " << solution.findPairs(nums1, k1) << endl; // Expected output: 2

    vector<int> nums2 = {1, 2, 3, 4, 5};
    int k2 = 1;
    cout << "Test Case 2: " << solution.findPairs(nums2, k2) << endl; // Expected output: 4

    vector<int> nums3 = {1, 3, 1, 5, 4};
    int k3 = 0;
    cout << "Test Case 3: " << solution.findPairs(nums3, k3) << endl; // Expected output: 1

    return 0;
}
