  std::vector<MX> get_constraints() override {
    std::vector<MX> constraints{};
    for (int k = 0; k < N; ++k) {
      const auto &x_next = ode_->state_space_->X()(Slice(), k) + integrator(
          ode_->f(),
          (1 / static_cast<double>(N)) * tf,
          ode_->state_space_->X()(Slice(), k),
          ode_->control_space_->U()(Slice(), k));
      constraints.push_back(ode_->state_space_->X()(Slice(), k + 1) - x_next);
    }
    return constraints;
  }

  void set_J_real() override {
    MX g_sum{0.0};
    for (int k = 0; k < N; ++k) {
      const auto &x_next = ode_->state_space_->X()(Slice(), k) + integrator(
          ode_->f(),
          (1 / static_cast<double>(N)) * tf,
          ode_->state_space_->X()(Slice(), k),
          ode_->control_space_->U()(Slice(), k));
      g_sum += sum1(ode_->state_space_->X()(Slice(), k + 1) - x_next);
    }
    J_real_ = Function("J_real", {ode_->state_space_->X(), ode_->control_space_->U(), tf}, {g_sum});
