#include <stack>

// Mock implementations for ObjectId and UserData classes
class ObjectId {
public:
    ObjectId(int id) : m_id(id) {}
    int id() const { return m_id; }
private:
    int m_id;
};

class UserData {
public:
    using Properties = std::unordered_map<std::string, std::string>;

    Properties& properties(const std::string& group) {
        return m_properties[group];
    }

private:
    std::unordered_map<std::string, Properties> m_properties;
};

// UserDataManager class definition
class UserDataManager {
public:
    void setProperties(const ObjectId& objectId, const std::string& group, const UserData::Properties& properties) {
        // Save current state for undo
        saveStateForUndo(objectId, group);

        // Set new properties
        m_userData[objectId.id()].properties(group) = properties;
    }

    UserData::Properties getProperties(const ObjectId& objectId, const std::string& group) {
        return m_userData[objectId.id()].properties(group);
    }

    void undo() {
        if (!m_undoStack.empty()) {
            auto& action = m_undoStack.top();
            m_userData[action.objectId].properties(action.group) = action.oldProperties;
            m_redoStack.push(action);
            m_undoStack.pop();
        }
    }

    void redo() {
        if (!m_redoStack.empty()) {
            auto& action = m_redoStack.top();
            m_userData[action.objectId].properties(action.group) = action.newProperties;
            m_undoStack.push(action);
            m_redoStack.pop();
        }
    }

private:
    struct Action {
        int objectId;
        std::string group;
        UserData::Properties oldProperties;
        UserData::Properties newProperties;
    };

    std::unordered_map<int, UserData> m_userData;
    std::stack<Action> m_undoStack;
    std::stack<Action> m_redoStack;

    void saveStateForUndo(const ObjectId& objectId, const std::string& group) {
        UserData::Properties& currentProperties = m_userData[objectId.id()].properties(group);
        Action action = { objectId.id(), group, currentProperties, currentProperties };
        m_undoStack.push(action);
    }
};

// Test cases to verify the solution correctness
int main() {
    UserDataManager manager;
    ObjectId obj1(1);
    ObjectId obj2(2);

    // Set properties for obj1, group "Layer1"
    manager.setProperties(obj1, "Layer1", {{"color", "red"}, {"opacity", "80"}});
    // Set properties for obj2, group "Layer2"
    manager.setProperties(obj2, "Layer2", {{"color", "blue"}, {"opacity", "50"}});

