using ll = long long;

// Function to calculate the greatest common divisor (GCD) of two numbers.
ll gcd(ll a, ll b) {
    return b == 0 ? a : gcd(b, a % b);
}

int main() {
    ll K;
    cin >> K;
    ll ans = 0;

    // Iterate over all possible triplets (a, b, c) where 1 <= a, b, c <= K.
    for (ll a = 1; a <= K; ++a) {
        for (ll b = 1; b <= K; ++b) {
            for (ll c = 1; c <= K; ++c) {
                // Calculate the GCD of the current triplet and add it to the answer.
                ans += gcd(gcd(a, b), c);
            }
        }
    }

    // Output the final answer.
    cout << ans << endl;
    return 0;
}

