    : _id(id), _is_green(is_green), _is_yellow(is_yellow), _is_red(is_red) {}
};

// Define the TrafficLightManager class
class TrafficLightManager {
private:
  std::unordered_map<int, LightState> lights;
  std::unordered_map<std::string, bool> clientStates;

public:
  void Initialize() {
    // Initialization code if needed
  }

  void Deinitialize() {
    // Deinitialization code if needed
  }

  void RegisterLight(const LightState& light) {
    if (lights.find(light._id) != lights.end()) {
      std::cerr << "Light Id overlapping" << std::endl;
      return;
    }
    lights[light._id] = light;
  }

  void UnregisterLight(int lightId) {
    lights.erase(lightId);
  }

  std::vector<LightState> GetLights(const std::string& client) {
    clientStates[client] = false;
    std::vector<LightState> result;
    for (const auto& light : lights) {
      result.push_back(light.second);
    }
    return result;
  }

  void SetLights(const std::string& client, const std::vector<LightState>& lightsToSet) {
    clientStates[client] = true;
    for (const auto& lightState : lightsToSet) {
      auto it = lights.find(lightState._id);
      if (it != lights.end()) {
        it->second = lightState;
      }
    }
    SetClientStatesDirty(client);
  }

  void SetClientStatesDirty(const std::string& clientThatUpdated) {
    for (auto& client : clientStates) {
      if (client.first != clientThatUpdated) {
        client.second = true;
      }
    }
  }
};

// Test cases
