  TrafficLightManager manager;
  manager.Initialize();

  // Register some lights
  manager.RegisterLight(LightState(1, true, false, false));
  manager.RegisterLight(LightState(2, false, true, false));
  manager.RegisterLight(LightState(3, false, false, true));

