#include <vector>
#include <map>

using namespace std;
typedef vector<int> vi;

int main() {
    int N, M;
    cin >> N >> M;

    map<int, vi> prerequisites;
    vi inDegree(N + 1, 0);

    for (int i = 0; i < M; i++) {
        int t, prev = -1, now;
        cin >> t;

        while (t--) {
            cin >> now;

            if (prev != -1) {
                prerequisites[prev].push_back(now);
                inDegree[now]++;
            }

            prev = now;
        }
    }

    queue<int> q;
    for (int i = 1; i <= N; i++) {
        if (inDegree[i] == 0) {
            q.push(i);
        }
    }

    vi order;
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        order.push_back(current);

        for (int next: prerequisites[current]) {
            inDegree[next]--;
            if (inDegree[next] == 0) {
                q.push(next);
            }
        }
    }

    if (order.size() == N) {
        for (int problem : order) {
            cout << problem << '\n';
        }
    } else {
        cout << 0 << '\n';
    }

    return 0;
}
