using namespace std;

/**
 * Finds the median of a given array of integers.
 * 
 * @param array A vector of integers.
 * @return The median of the array as a double.
 */
double median_of_sorted_array(vector<int> array) {
    sort(array.begin(), array.end());
    int n = array.size();
    double median;

    if (n % 2 == 0) {
        // If the size of the array is even, the median is the average of the two middle numbers.
        median = (array[n / 2 - 1] + array[n / 2]) / 2.0;
    } else {
        // If the size of the array is odd, the median is the middle number.
        median = array[n / 2];
    }

    return median;
}

// Test cases to verify the solution
