using namespace std;

struct Node{
    int data;
    Node *left;
    Node *right;
    Node(int val){
        data = val;
        left = NULL;
        right = NULL;
    }
};

map<int,int> hm;

void dfs(Node *root, int horizontalDistance){
    if(!root) return;
    dfs(root->left, horizontalDistance - 1);
    hm[horizontalDistance] += root->data;
    dfs(root->right, horizontalDistance + 1); 
}

void printHashMap(){
    for(auto it = hm.begin(); it != hm.end(); ++it){
        cout << it->second << " ";
    }
}

int main(){
    // Construct the binary tree
    Node *root = new Node(1);
    root->left = new Node(2);
    root->right = new Node(3);
    root->left->left = new Node(4);
    root->left->right = new Node(5);
    root->right->left = new Node(6);
    root->right->right = new Node(7);

    // Calculate the vertical sum of the binary tree
    dfs(root, 0);

    // Print the vertical sum
    printHashMap();

    return 0;
}
