using namespace std;

class UnionFind {
private:
    vector<int> parent;

    // Find the root of the set in which element x is located
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]); // Path compression
        }
        return parent[x];
    }

public:
    // Initialize UnionFind with size n
    UnionFind(int n) : parent(n + 1) {
        for (int i = 0; i <= n; ++i) {
            parent[i] = i;
        }
    }

    // Connect elements a and b
    void unite(int a, int b) {
        int rootA = find(a);
        int rootB = find(b);
        if (rootA != rootB) {
            parent[rootB] = rootA; // Union the sets
        }
    }

    // Check if elements a and b are connected
    bool connected(int a, int b) {
        return find(a) == find(b);
    }

    // Count the number of disconnected components
    int countComponents() {
        int count = 0;
        for (size_t i = 1; i < parent.size(); ++i) {
            if (parent[i] == i) {
                ++count;
            }
        }
        return count;
    }
};

int main() {
    int n;
    cin >> n;
    UnionFind uf(n);

    char command;
    int a, b;
    while (cin >> command && command != 'S') {
        if (command == 'C') {
            cin >> a >> b;
            cout << (uf.connected(a, b) ? "yes" : "no") << endl;
        } else if (command == 'I') {
            cin >> a >> b;
            uf.unite(a, b);
        }
    }

    int components = uf.countComponents();
    if (components == 1) {
        cout << "The network is connected." << endl;
    } else {
        cout << "There are " << components << " components." << endl;
    }

    return 0;
}

// Test cases
