class Solution {
public:
    /**
     * Determines the number of employees who have met or exceeded the target number of hours.
     * @param hours A vector of integers representing the hours worked by each employee.
     * @param target An integer representing the target number of hours.
     * @return The number of employees who have met or exceeded the target number of hours.
     */
    int numberOfEmployeesWhoMetTarget(std::vector<int>& hours, int target) {
        std::sort(hours.begin(), hours.end());
        if (target > hours.back()) return 0;
        if (target <= hours.front()) return hours.size();
        int e = 0;
        for (; e < hours.size() && hours[e] < target; e++);
        return hours.size() - e;
    }
