#include <array>
#include <cmath>
#include <cassert>
#include <Eigen/Dense>

// Define a 3D vector using Eigen for convenience
using Vector3 = Eigen::Vector3d;

// Define a 2D vector for the cylindrical coordinates (r, z)
using Vector2 = Eigen::Vector2d;

// Define a grid in cylindrical coordinates (r, z)
class CylindricalGrid {
public:
    CylindricalGrid(double r_min, double r_max, size_t r_bins, double z_min, double z_max, size_t z_bins)
        : r_min_(r_min), r_max_(r_max), z_min_(z_min), z_max_(z_max),
          r_bins_(r_bins), z_bins_(z_bins), grid_(r_bins * z_bins) {
        assert(r_max > r_min && z_max > z_min);
        assert(r_bins > 0 && z_bins > 0);
        populateGrid();
    }

    // Check if a point is inside the grid
    bool isInside(const Vector3& pos) const {
        double r = pos.head<2>().norm(); // Calculate the radial distance
        double z = pos.z();
        return r >= r_min_ && r <= r_max_ && z >= z_min_ && z <= z_max_;
    }

    // Interpolate the magnetic field at a given position
    Vector3 interpolate(const Vector3& pos) const {
        assert(isInside(pos));
        double r = pos.head<2>().norm();
        double z = pos.z();

        // Find the indices of the grid points surrounding the position
        size_t r_idx = static_cast<size_t>((r - r_min_) / r_step());
        size_t z_idx = static_cast<size_t>((z - z_min_) / z_step());

        // Calculate interpolation weights
        double r_frac = (r - (r_min_ + r_idx * r_step())) / r_step();
        double z_frac = (z - (z_min_ + z_idx * z_step())) / z_step();

        // Perform trilinear interpolation
        Vector3 b000 = grid_[index(r_idx, z_idx)];
        Vector3 b100 = grid_[index(r_idx + 1, z_idx)];
        Vector3 b010 = grid_[index(r_idx, z_idx + 1)];
        Vector3 b110 = grid_[index(r_idx + 1, z_idx + 1)];

        Vector3 b_interp = (1 - r_frac) * (1 - z_frac) * b000 +
                           r_frac * (1 - z_frac) * b100 +
                           (1 - r_frac) * z_frac * b010 +
                           r_frac * z_frac * b110;

        return b_interp;
    }

private:
    double r_min_, r_max_, z_min_, z_max_;
    size_t r_bins_, z_bins_;
    std::vector<Vector3> grid_;

    // Calculate the index in the grid vector for given r and z indices
    size_t index(size_t r_idx, size_t z_idx) const {
        return r_idx + r_bins_ * z_idx;
    }

    // Calculate the step size in r direction
    double r_step() const {
        return (r_max_ - r_min_) / r_bins_;
    }

    // Calculate the step size in z direction
    double z_step() const {
        return (z_max_ - z_min_) / z_bins_;
    }

    // Populate the grid with the magnetic field values
    void populateGrid() {
        for (size_t i = 0; i <= r_bins_; ++i) {
            for (size_t j = 0; j <= z_bins_; ++j) {
                double r = r_min_ + i * r_step();
                double z = z_min_ + j * z_step();
                grid_[index(i, j)] = Vector3(r * z, 3 * r, -2 * z);
            }
        }
    }
};

// Test cases to verify the correctness of the interpolation
int main() {
    CylindricalGrid grid(0.0, 4.0, 4, -5.0, 5.0, 5);

    // Test points
    std::vector<Vector3> test_points = {
        {1.0, 0.0, 0.0},
        {2.0, 2.0, 1.0},
        {3.0, 3.0, -2.0},
        {0.0, 0.0, 4.0},
        {4.0, 0.0, -5.0}
    };

    // Expected results
    std::vector<Vector3> expected_results = {
        {0.0, 0.0, 0.0},
        {4.0, 6.0, -2.0},
        {-18.0, 9.0, 4.0},
        {0.0, 0.0, -8.0},
        {-100.0, 12.0, 10.0}
    };

    for (size_t i = 0; i < test_points.size(); ++i) {
        Vector3 interpolated = grid.interpolate(test_points[i]);
        assert(interpolated.isApprox(expected_results[i]));
        std::cout << "Test case " << i + 1 << " passed." << std::endl;
    }

    return 0;
}
