/**
 * Finds the most frequent two-letter substring in a given string.
 * If there are multiple substrings with the same highest frequency,
 * the one that appears first in the string is returned.
 * 
 * @param str The input string to search.
 * @return The most frequent two-letter substring.
 */
string findMostFrequentTwoLetterSubstring(const string& str) {
    unordered_map<string, int> substringCount;
    int maxCount = 0;
    string mostFrequentSubstring;

    for (int i = 1; i < str.length(); ++i) {
        string tmp = str.substr(i - 1, 2);
        ++substringCount[tmp];

        if (substringCount[tmp] > maxCount) {
            maxCount = substringCount[tmp];
            mostFrequentSubstring = tmp;
        }
    }

    return mostFrequentSubstring;
}

int main() {
