class Solution {
public:
    int stringToInteger(std::string s) {
        int i = 0;
        int sign = 1;
        long long result = 0; // Use long long to handle overflow

        // Discard leading whitespaces
        while (i < s.length() && s[i] == ' ') {
            i++;
        }

        // Check for sign
        if (i < s.length() && (s[i] == '-' || s[i] == '+')) {
            sign = (s[i++] == '-') ? -1 : 1;
        }

        // Convert digits to integer
        while (i < s.length() && std::isdigit(s[i])) {
            int digit = s[i] - '0';

            // Check for overflow
            if (result > (INT_MAX - digit) / 10) {
                return (sign == 1) ? INT_MAX : INT_MIN;
            }

            result = result * 10 + digit;
            i++;
        }

        return static_cast<int>(result * sign);
    }
};

// Test cases
int main() {
    Solution sol;

    std::cout << sol.stringToInteger("42") << std::endl; // Output: 42
    std::cout << sol.stringToInteger("   -42") << std::endl; // Output: -42
    std::cout << sol.stringToInteger("4193 with words") << std::endl; // Output: 4193
    std::cout << sol.stringToInteger("words and 987") << std::endl; // Output: 0
    std::cout << sol.stringToInteger("-91283472332") << std::endl; // Output: -2147483648 (INT_MIN)
    std::cout << sol.stringToInteger("91283472332") << std::endl; // Output: 2147483647 (INT_MAX)

    return 0;
}
