/**
 * Finds the pivot index in a rotated sorted array.
 * The pivot index is the index of the highest element in the array.
 * If the array is not rotated, the function returns -1.
 * 
 * @param arr The array to search for the pivot index.
 * @param N The size of the array.
 * @return The pivot index, or -1 if the array is not rotated.
 */
int find_pivot(int arr[], int N) {
    int low = 0, high = N - 1;
    if (arr[low] < arr[high]) return -1; // Array is not rotated
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (mid > 0 && arr[mid] < arr[mid - 1]) return mid - 1;
        if (mid < N - 1 && arr[mid] > arr[mid + 1]) return mid;
        if (arr[mid] < arr[low]) high = mid - 1;
        else low = mid + 1;
    }
    return -1;
}

int main() {
    int N;
    cin >> N;
    int arr[N];
    for (int i = 0; i < N; i++) cin >> arr[i];

    int pivot = find_pivot(arr, N);
    cout << pivot << endl;

    return 0;
}

// Test cases to verify the solution
int main() {
    // Test case 1
    int arr1[] = {4, 5, 6, 7, 0, 1, 2};
    int N1 = sizeof(arr1) / sizeof(arr1[0]);
    cout << "Pivot index of arr1: " << find_pivot(arr1, N1) << endl; // Expected output: 3

    // Test case 2
    int arr2[] = {1, 2, 3, 4, 5};
    int N2 = sizeof(arr2) / sizeof(arr2[0]);
    cout << "Pivot index of arr2: " << find_pivot(arr2, N2) << endl; // Expected output: -1

