// Check if the identifier is registered as a type
#define IS_TYPE(id) BOOST_PP_IS_BEGINNING(REGISTER_TYPE(id), TYPE_REGISTRATION_PREFIX)

// Determine the type of the identifier
#define IDENTIFIER_TYPE(id) \
    BOOST_PP_IF(IS_NUMBER(id), "Number", \
    BOOST_PP_IF(IS_TYPE(id), "Type", "Unknown"))

// Helper macro to check if the concatenation result starts with a given prefix
#define BOOST_PP_IS_BEGINNING(result, prefix) \
    BOOST_PP_EQUAL(BOOST_PP_SEQ_SIZE(BOOST_PP_SEQ_FILTER(BOOST_PP_IS_BEGINNING_PRED, prefix, BOOST_PP_SEQ_HEAD(BOOST_PP_CAT(prefix##_CHECK_, result)))), 1)

#define BOOST_PP_IS_BEGINNING_PRED(d, prefix, elem) BOOST_PP_EQUAL(BOOST_PP_SEQ_ELEM(0, elem), prefix)

