// Function to count the number of lines in the file.
int countLines(const std::string& fileName) {
    std::ifstream file(fileName);
    std::string line;
    int count = 0;
    while (getline(file, line)) {
        count++;
    }
    return count;
}

// Function to count the total size of the file in bytes.
int countSize(const std::string& fileName) {
    std::ifstream file(fileName, std::ios::binary | std::ios::ate);
    return file.tellg();
}

// Function to count the number of words in the file.
int countWords(const std::string& fileName) {
    std::ifstream file(fileName);
    int count = 0;
    std::string word;
    while (file >> word) {
        count++;
    }
    return count;
}

// Function to calculate the average number of bytes per word.
int averageBytesPerWord(const std::string& fileName) {
    std::ifstream file(fileName);
    std::string word;
    int totalBytes = 0;
    int wordCount = 0;
    while (file >> word) {
        totalBytes += word.length();
        wordCount++;
    }
    return wordCount > 0 ? totalBytes / wordCount : 0;
}

int main(int argc, char** argv) {
    std::string filePath;
    bool displayLines = false, displayBytes = false, displayWords = false;

    // Parse command-line arguments.
    for (int i = 1; i < argc; ++i) {
        std::string arg = argv[i];
        if (arg == "--lines" || arg == "-l") {
            displayLines = true;
        } else if (arg == "--bytes" || arg == "-c") {
            displayBytes = true;
        } else if (arg == "--words" || arg == "-w") {
            displayWords = true;
        } else {
            filePath = arg;
        }
    }

    // If no options are provided, display all statistics.
    if (!displayLines && !displayBytes && !displayWords) {
        displayLines = displayBytes = displayWords = true;
    }

    // Display requested statistics.
    if (displayLines) {
        std::cout << "Lines: " << countLines(filePath) << std::endl;
    }
    if (displayBytes) {
        std::cout << "Bytes: " << countSize(filePath) << std::endl;
        std::cout << "Average bytes per word: " << averageBytesPerWord(filePath) << std::endl;
    }
    if (displayWords) {
        std::cout << "Words: " << countWords(filePath) << std::endl;
    }

    return 0;
}

