// Make sure to include the necessary Qt modules in your .pro file:
// QT += core network

class NetworkDeviceScanner : public QThread {
    Q_OBJECT

public:
    NetworkDeviceScanner(QUuid id, QList<QString> ipList);
    ~NetworkDeviceScanner();

    void run() override;
    bool getIsStart();
    void stopScan();

signals:
    void deviceFound(QUuid id, QString mac, QString ip);
    void scanComplete(QUuid id);

private:
    bool isStart;
    QUuid id;
    QList<QString> mIpList;
    QList<QProcess*> mProcessList;
    QMutex mutex_;
};

NetworkDeviceScanner::NetworkDeviceScanner(QUuid id, QList<QString> ipList)
    : isStart(true), id(id), mIpList(ipList) {}

NetworkDeviceScanner::~NetworkDeviceScanner() {
    stopScan();
    qDebug() << "~NetworkDeviceScanner";
}

void NetworkDeviceScanner::run() {
    for (int i = 0; i < mIpList.length() && isStart; i++) {
        QString ip = mIpList.at(i);
        int exitCode;
        qDebug() << "ping " + ip;

        QString strArg = "ping " + ip + " -n 1 -w 1000";
        exitCode = QProcess::execute(strArg);

        if (0 == exitCode) {
            QStringList arguments;
            arguments << "/c" << "arp -a " << ip;
            QProcess* process = new QProcess();
            mProcessList.append(process);
            process->start("cmd.exe", arguments);
            process->waitForStarted();
            process->waitForFinished();
            mutex_.lock();
            mProcessList.removeOne(process);
            mutex_.unlock();
            QString dosRet = QString::fromLocal8Bit(process->readAllStandardOutput());
            delete process;

            QString pattern("([0-9A-Fa-f]{2})(-[0-9A-Fa-f]{2}){5}");
            QRegExp rx(pattern);
            int pos = dosRet.indexOf(rx);
            qDebug() << "mac: " + dosRet;
            if (pos >= 0 && isStart) {
                QString mac = dosRet.mid(pos, 17);
                emit deviceFound(id, mac, ip);
            }
        } else {
            qDebug() << "shell ping " + ip + " failed!";
        }
    }

    isStart = false;
    emit scanComplete(id);
}

bool NetworkDeviceScanner::getIsStart() {
    return isStart;
}

void NetworkDeviceScanner::stopScan() {
    isStart = false;
    requestInterruption();
    quit();
    wait(); // Wait for the thread to finish
    for (QProcess* p : mProcessList) {
        if (p) {
            p->kill();
            delete p;
        }
    }
    mProcessList.clear();
}

