#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

/**
 * Calculates the maximum profit that can be made by buying and selling a stock at most twice.
 * @param prices A vector of integers representing the price of a stock on different days.
 * @return The maximum profit that can be made with at most two transactions.
 */
int maxProfitWithTwoTransactions(vector<int> prices) {
    if (prices.empty()) return 0;

    int n = prices.size();
    vector<int> firstTransactionProfit(n, 0);
    vector<int> secondTransactionProfit(n, 0);

    // Forward pass to calculate max profit until day i with one transaction
    int minPrice = prices[0];
    for (int i = 1; i < n; ++i) {
        minPrice = min(minPrice, prices[i]);
        firstTransactionProfit[i] = max(firstTransactionProfit[i - 1], prices[i] - minPrice);
    }

    // Backward pass to calculate max profit from day i with one transaction
    int maxPrice = prices[n - 1];
    for (int i = n - 2; i >= 0; --i) {
        maxPrice = max(maxPrice, prices[i]);
        secondTransactionProfit[i] = max(secondTransactionProfit[i + 1], maxPrice - prices[i]);
    }

    // Combine the profits from the two transactions
    int maxProfit = 0;
    for (int i = 0; i < n; ++i) {
        maxProfit = max(maxProfit, firstTransactionProfit[i] + secondTransactionProfit[i]);
    }

    return maxProfit;
}

int main() {
    vector<int> prices1 = {12, 11, 13, 9, 12, 8, 14, 13, 15};
    cout << "Maximum profit for prices1: " << maxProfitWithTwoTransactions(prices1) << endl;

    vector<int> prices2 = {12, 11, 10, 9, 8, 7, 6, 5, 8};
    cout << "Maximum profit for prices2: " << maxProfitWithTwoTransactions(prices2) << endl;

    return 0;
}
