private:
    set<int> intSet;

public:
    // Inserts an integer into the collection
    bool insert(int value) {
        pair<set<int>::iterator, bool> result = intSet.insert(value);
        return result.second;
    }

    // Prints all elements in the collection in ascending order
    void print() const {
        for (set<int>::const_iterator it = intSet.begin(); it != intSet.end(); ++it) {
            cout << *it << " ";
        }
        cout << endl;
    }

    // Checks if a given integer is present in the collection
    bool contains(int value) const {
        return intSet.find(value) != intSet.end();
    }

    // Removes a given integer from the collection
    bool remove(int value) {
        return intSet.erase(value) > 0;
    }
};

void testSetOperations() {
    IntegerCollection collection;

    // Test insertion
    cout << "Inserting 10: " << (collection.insert(10) ? "success" : "fail") << endl;
