        for (int i = 0; i < n; i++) {
            string s;
            cin >> s;
            for (char c : s) {
                if (c == '0') zeros++;
                else ones++;
            }
            lengths.push_back(s.size());
        }
        sort(lengths.begin(), lengths.end());
        int reduced_strings = 0;
        for (int len : lengths) {
            while (zeros >= 2 && len >= 2) {
                len -= 2;
                zeros -= 2;
            }
            while (ones >= 2 && len >= 2) {
                len -= 2;
                ones -= 2;
            }
            if (len == 1) {
                if (zeros > 0) {
                    zeros--;
                } else if (ones > 0) {
                    ones--;
                }
                len--;
            }
            if (len == 0) {
                reduced_strings++;
            }
        }
        cout << reduced_strings << "\n";
    }
    return 0;
