using namespace std;

/**
 * Rotates the elements of the given vector to the right by k steps.
 * This function modifies the input vector in-place.
 * 
 * @param nums The vector of integers to be rotated.
 * @param k The number of steps to rotate the vector.
 */
void rotateArray(vector<int>& nums, int k) {
    int n = nums.size();
    if (n == 0 || k <= 0) {
        return;
    }
    k = k % n; // In case k is greater than the size of the array

    // Reverse the entire vector
    reverse(nums.begin(), nums.end());
    // Reverse the first k elements
    reverse(nums.begin(), nums.begin() + k);
    // Reverse the remaining n-k elements
    reverse(nums.begin() + k, nums.end());
}

int main() {
