#include <iostream>
#include <sstream>
#include <string>
#include <tuple>
#include <array>
#include <algorithm>

#include "gtest/gtest.h"

template <size_t Capacity>
class CircularBuffer {
public:
    CircularBuffer() : readPos(0), writePos(0), count(0) {}

    bool writeData(const uint8_t* data, size_t length) {
        if (length > availableSpace()) {
            return false;
        }
        for (size_t i = 0; i < length; ++i) {
            buffer[(writePos + i) % Capacity] = data[i];
        }
        writePos = (writePos + length) % Capacity;
        count += length;
        return true;
    }

    std::tuple<uint8_t*, size_t> readData() {
        return std::make_tuple(&buffer[readPos], std::min(count, Capacity - readPos));
    }

    void shiftBuffer(size_t length) {
        size_t shiftAmount = std::min(length, count);
        readPos = (readPos + shiftAmount) % Capacity;
        count -= shiftAmount;
        if (count == 0) {
            // Reset positions if buffer is empty
            readPos = writePos = 0;
        }
    }

    void clear() {
        readPos = writePos = count = 0;
    }

private:
    std::array<uint8_t, Capacity> buffer;
    size_t readPos, writePos, count;

    size_t availableSpace() const {
        return Capacity - count;
    }
};

bool checkContent(CircularBuffer<10>& buffer, const char* content) {
    std::ostringstream dataSs;
    auto readData = buffer.readData();
    dataSs.write(reinterpret_cast<char *>(std::get<0>(readData)), std::get<1>(readData));
    const std::string data = dataSs.str();
    return (data.compare(content) == 0);
}

TEST(CircularBufferTest, BasicOperations) {
    CircularBuffer<10> buffer;
    bool writeSucceedFlag;

    // Test writing to the buffer
    writeSucceedFlag = buffer.writeData(reinterpret_cast<const uint8_t *>("test"), 4);
    ASSERT_TRUE(writeSucceedFlag);
    ASSERT_TRUE(checkContent(buffer, "test"));

    // Test reading from the buffer
    auto readData = buffer.readData();
    ASSERT_EQ(std::string(reinterpret_cast<char*>(std::get<0>(readData)), std::get<1>(readData)), "test");

    // Test shifting the buffer
    buffer.shiftBuffer(2);
    ASSERT_TRUE(checkContent(buffer, "st"));

    // Test clearing the buffer
    buffer.clear();
    ASSERT_TRUE(checkContent(buffer, ""));
}

TEST(CircularBufferTest, WriteToFullBuffer) {
    CircularBuffer<10> buffer;
    bool writeSucceedFlag;

    // Fill the buffer
    writeSucceedFlag = buffer.writeData(reinterpret_cast<const uint8_t *>("1234567890"), 10);
    ASSERT_TRUE(writeSucceedFlag);

    // Attempt to write to a full buffer
    writeSucceedFlag = buffer.writeData(reinterpret_cast<const uint8_t *>("fail"), 4);
    ASSERT_FALSE(writeSucceedFlag);
}

// Additional test cases would be similar to the ones provided in the original snippet,
// testing various scenarios of writing, shifting, and clearing the buffer.

int main(int argc, char **argv) {
    ::testing::InitGoogleTest(&argc, argv);
    return RUN_ALL_TESTS();
}
