class CustomStack {
    int max = 0;
    vector<int> v;
public:
    CustomStack(int maxSize) {
        max = maxSize;
    }

    void push(int x) {
        if(v.size() < max){
            v.push_back(x);
        }
    }

    int pop() {
        if(v.empty()){
            return -1;
        }
        int ans = v.back();
        v.pop_back();
        return ans;
    }

    void increment(int k, int val) {
        for(int i = 0; i < min(k, static_cast<int>(v.size())); i++){
            v[i] += val;
        }
    }
};

// Test cases
int main() {
    CustomStack customStack(3); // Stack is empty and has maxSize = 3
    customStack.push(1);        // stack becomes [1]
    customStack.push(2);        // stack becomes [1, 2]
    int pop1 = customStack.pop(); // returns 2 --> stack becomes [1]
    customStack.push(2);        // stack becomes [1, 2]
    customStack.push(3);        // stack becomes [1, 2, 3]
    customStack.push(4);        // stack still [1, 2, 3], 4 is not pushed as the stack is full
    customStack.increment(2, 100); // stack becomes [101, 102, 3]
    customStack.increment(5, 100); // stack becomes [201, 202, 103]
    int pop2 = customStack.pop(); // returns 103 --> stack becomes [201, 202]
    int pop3 = customStack.pop(); // returns 202 --> stack becomes [201]
    int pop4 = customStack.pop(); // returns 201 --> stack becomes []
    int pop5 = customStack.pop(); // returns -1 --> stack is empty

    // Output the results
    cout << "Pop 1: " << pop1 << endl;
    cout << "Pop 2: " << pop2 << endl;
    cout << "Pop 3: " << pop3 << endl;
    cout << "Pop 4: " << pop4 << endl;
    cout << "Pop 5: " << pop5 << endl;

