class Solution {
public:
    Solution() {}

    int binSearch(const std::vector<int> &vec, const int &des, int &des_ID) {
        int min_ID = 0;
        int max_ID = vec.size() - 1;
        int mid_ID = 0;
        int mid = 0;

        while (min_ID <= max_ID) {
            mid_ID = int((min_ID + max_ID) / 2.0);
            mid = vec[mid_ID];
            if (des == mid) {
                des_ID = mid_ID;
                return 1;
            } else if (des < mid) {
                max_ID = mid_ID - 1;
            } else {
                min_ID = mid_ID + 1;
            }
        }
        return 0;
    }

    std::vector<int> twoSum(std::vector<int> &nums, int target) {
        std::unordered_map<int, int> hash;

        for (int i = 0; i < nums.size(); i++) {
            auto iter = hash.find(target - nums[i]);

            if (iter != hash.end()) {
                return std::vector<int> {iter->second, i};
            }
            hash[nums[i]] = i;
        }
        return std::vector<int>();
    }
};

int main() {
    Solution solution;
    std::vector<int> sortedVec = {1, 3, 5, 7, 9};
    int desired = 7;
    int index;
    int found = solution.binSearch(sortedVec, desired, index);
    std::cout << "Binary Search: " << (found ? "Found at index " + std::to_string(index) : "Not found") << std::endl;

    std::vector<int> nums = {2, 7, 11, 15};
    int target = 9;
    std::vector<int> result = solution.twoSum(nums, target);
    std::cout << "Two Sum: ";
    if (!result.empty()) {
        std::cout << "Indices [" << result[0] << ", " << result[1] << "]" << std::endl;
    } else {
        std::cout << "No solution found" << std::endl;
    }

    return 0;
}
