using namespace std;

/**
 * Calculates the maximum constant speed at which a car can travel to reach the
 * destination at the same time as the slowest of several other cars.
 *
 * @param d The distance to the destination.
 * @param n The number of other cars.
 * @param positions The starting positions of the other cars.
 * @param speeds The speeds of the other cars.
 * @return The maximum constant speed to reach the destination with the slowest car.
 */
double calculateMaxConstantSpeed(double d, int n, const double positions[], const double speeds[]) {
    double time = 0;
    for (int i = 0; i < n; i++) {
        time = max(time, (d - positions[i]) / speeds[i]);
    }
    return d / time;
}

int main() {
    int TN;
    scanf("%d", &TN);
    for (int casen = 1; casen <= TN; casen++) {
        printf("Case #%d: ", casen);
        double d;
        int n;
        scanf("%lf %d", &d, &n);
        double *positions = new double[n];
        double *speeds = new double[n];
        for (int i = 0; i < n; i++) {
            scanf("%lf %lf", &positions[i], &speeds[i]);
        }
        double maxSpeed = calculateMaxConstantSpeed(d, n, positions, speeds);
        printf("%.9f\n", maxSpeed);
        delete[] positions;
        delete[] speeds;
    }
    return 0;
}

