#include <iostream>
#include <string>
#include <vector>
#include <unordered_set>
using namespace std;

class Solution {
public:
    bool solve(string& s, unordered_set<string>& st, vector<int>& dp, int idx) {
        if (idx >= s.length()) return true;
        else if (dp[idx] != -1) return dp[idx]; // if it's been visited before

        for (int i = 1; i < (s.length() - idx + 1); i++) {
            if (st.find(s.substr(idx, i)) != st.end()) {
                if (solve(s, st, dp, idx+i)) return dp[idx] = true;
            }
        }
        return dp[idx] = false;
    }

    bool wordBreak(string s, vector<string>& wordDict) {
        unordered_set<string> st;
        for (auto& word: wordDict) st.insert(word);

        vector<int> dp(s.length(), -1);

        return solve(s, st, dp, 0);
    }
};

// Test cases
int main() {
    Solution solution;
    vector<string> wordDict1 = {"leet", "code"};
    string s1 = "leetcode";
    cout << "Can the word 'leetcode' be segmented into dictionary words? " << (solution.wordBreak(s1, wordDict1) ? "Yes" : "No") << endl;

    vector<string> wordDict2 = {"apple", "pen"};
    string s2 = "applepenapple";
    cout << "Can the word 'applepenapple' be segmented into dictionary words? " << (solution.wordBreak(s2, wordDict2) ? "Yes" : "No") << endl;

    vector<string> wordDict3 = {"cats", "dog", "sand", "and", "cat"};
    string s3 = "catsandog";
    cout << "Can the word 'catsandog' be segmented into dictionary words? " << (solution.wordBreak(s3, wordDict3) ? "Yes" : "No") << endl;

