    Cloud(double initialVapor);
    ~Cloud();
    void addVapor(double amount);
    double rain(double amount);
    double getVaporAmount() const;
};

Cloud::Cloud(double initialVapor) : waterVapor(std::max(0.0, initialVapor))
{
}

Cloud::~Cloud()
{
}

void Cloud::addVapor(double amount)
{
    if (amount > 0)
    {
        waterVapor += amount;
    }
}

double Cloud::rain(double amount)
{
    if (amount <= 0)
    {
        return 0.0;
    }

    double rainedAmount = std::min(amount, waterVapor);
    waterVapor -= rainedAmount;
    return rainedAmount;
}

double Cloud::getVaporAmount() const
{
    return waterVapor;
}

// Test cases to verify the solution correctness
int main()
{
    Cloud cloud(50.0); // Initialize cloud with 50 units of water vapor

