    }

    int Sum()
    {
        int iSum = 0;
        for(int iCnt = 0; iCnt < iSize; iCnt++)
        {
            iSum += Arr[iCnt];
        }
        return iSum;
    }

    int Max()
    {
        int iMax = Arr[0];
        for(int iCnt = 1; iCnt < iSize; iCnt++)
        {
            if(Arr[iCnt] > iMax)
            {
                iMax = Arr[iCnt];
            }
        }
        return iMax;
    }

    int Min()
    {
        int iMin = Arr[0];
        for(int iCnt = 1; iCnt < iSize; iCnt++)
        {
            if(Arr[iCnt] < iMin)
            {
                iMin = Arr[iCnt];
            }
        }
        return iMin;
