 *         The sequence ends when the number 0 is read. It prints the average with a
 *         precision of 2 decimal places. If the first number is 0, it prints a message
 *         indicating that there are no numbers to calculate the average.
 * @bug    There are no known bugs.
 * @see    https://jutge.org/problems/P78142_enhanced
 */

#include <iostream>
#include <iomanip>

int main() {
    int number;
    int sum = 0;
    int count = 0;

    while (std::cin >> number && number != 0) {
        sum += number;
        ++count;
    }

    if (count == 0) {
        std::cout << "No numbers to calculate average" << std::endl;
    } else {
        double average = static_cast<double>(sum) / count;
        std::cout << std::fixed << std::setprecision(2) << average << std::endl;
    }

    return 0;
}
