#include <iostream>
#include <string>
#include <string_view>
#include <vector>
#include <cctype>
// Include the given token class here

namespace chemparser {

// Token class definition from the given code snippet

class tokenizer {
public:
  explicit tokenizer(std::string_view equation) : equation_(equation), position_(0) {}

  token next_token() {
    while (position_ < equation_.size() && std::isspace(equation_[position_])) {
      ++position_; // Skip whitespace
    }

    if (position_ == equation_.size()) {
      return token(token::type::end, "");
    }

    char current_char = equation_[position_];

    if (std::isdigit(current_char)) {
      return parse_number();
    } else if (std::isupper(current_char)) {
      return parse_element();
    } else if (current_char == '(') {
      ++position_;
      return token(token::type::left_parenthesis, "(");
    } else if (current_char == ')') {
      ++position_;
      return token(token::type::right_parenthesis, ")");
    }

    // If we reach this point, the character is not recognized
    ++position_;
    return token(token::type::undefined, std::string_view(&current_char, 1));
  }

private:
  std::string_view equation_;
  size_t position_;

  token parse_number() {
    size_t start = position_;
    while (position_ < equation_.size() && std::isdigit(equation_[position_])) {
      ++position_;
    }
    return token(token::type::coefficient, equation_.substr(start, position_ - start));
  }

  token parse_element() {
    size_t start = position_;
    ++position_; // Skip the first uppercase letter
    if (position_ < equation_.size() && std::islower(equation_[position_])) {
      ++position_; // Include the second lowercase letter if present
    }
    return token(token::type::element, equation_.substr(start, position_ - start));
  }
};

std::ostream &operator<<(std::ostream &os, token const token) {
  return os << token.get_type_as_string() << ": " << token.value();
}

} // namespace chemparser

// Test cases
int main() {
  using namespace chemparser;

  std::string equation = "2H2 + O2 -> 2H2O";
  tokenizer tk(equation);
  token tkn;

  while ((tkn = tk.next_token()).get_type() != token::type::end) {
    std::cout << tkn << std::endl;
  }

  return 0;
}
