using namespace std;

class Compte {
protected:
    int accountNumber;
    double balance;

public:
    Compte(int accNum, double bal) : accountNumber(accNum), balance(bal) {}

    virtual void deposer(double amount) {
        balance += amount;
    }

    virtual bool retirer(double amount) = 0; // Pure virtual function

    virtual void afficher() const {
        cout << "Account Number: " << accountNumber << ", Balance: " << balance << endl;
    }
};

class CompteEpargne : public Compte {
private:
    double interestRate;

public:
    CompteEpargne(int accNum, double bal, double intRate) : Compte(accNum, bal), interestRate(intRate) {}

    void appliquerInteret() {
        balance += balance * interestRate / 100;
    }

    bool retirer(double amount) override {
        if (amount <= balance) {
            balance -= amount;
            return true;
        }
        return false;
    }

    void afficher() const override {
        Compte::afficher();
        cout << "Interest Rate: " << interestRate << "%" << endl;
    }
};

class CompteCourant : public Compte {
private:
    double overdraftLimit;

public:
    CompteCourant(int accNum, double bal, double overdraft) : Compte(accNum, bal), overdraftLimit(overdraft) {}

    bool retirer(double amount) override {
        if (amount <= balance + overdraftLimit) {
            balance -= amount;
            return true;
        }
        return false;
    }

    void afficher() const override {
        Compte::afficher();
        cout << "Overdraft Limit: " << overdraftLimit << endl;
    }
};

class Banque {
private:
    string name;
    string city;
    vector<Compte*> accounts;

public:
    Banque(string n, string c) : name(n), city(c) {}

    void ajouter(Compte& compte) {
        accounts.push_back(&compte);
    }

    void afficher() const {
        cout << "Bank: " << name << ", City: " << city << endl;
        for (const auto& compte : accounts) {
            compte->afficher();
        }
    }
};

int main() {
    Banque maBanque("MaBanque", "MaVille");

    CompteEpargne ce1(1, 1000.0, 3.0);
    CompteCourant cc1(2, 200.0, 500.0);

    maBanque.ajouter(ce1);
    maBanque.ajouter(cc1);

    maBanque.afficher();

    ce1.deposer(500.0);
    ce1.retirer(200.0);
    ce1.appliquerInteret();

    cc1.deposer(300.0);
    cc1.retirer(400.0);

    maBanque.afficher();

    return 0;
}
