#include <iostream>
#include <string>
#include <array>
using namespace std;

class Solution {
public:
    int numberOfSubstrings(string s) {
        long n = s.size();
        int t2 = atMostK(s, 2);
        long t1 = n * (n + 1) / 2;
        return t1 - t2;
    }

private:
    int atMostK(string& s, int k){
        int n = s.size();
        int ans = 0;
        array<int, 3> freq = {0};
        int front = 0;
        int rear = 0;
        while(front < n){
            freq[s[front] - 'a']++;
            front++;
            while(inValid(freq, k)){
                freq[s[rear] - 'a']--;
                rear++;
            }
            ans += front - rear;
        }
        return ans;
    }

    bool inValid(array<int, 3>& freq, int k){
        int count = 0;
        for(int i = 0; i < 3; i++){
            if(freq[i])
                count++;
        }
        return count > k;
    }
};

// Test cases
int main() {
    Solution solution;
    cout << solution.numberOfSubstrings("abcabc") << endl; // Output: 10
    cout << solution.numberOfSubstrings("aaacb") << endl; // Output: 3
    cout << solution.numberOfSubstrings("abc") << endl; // Output: 1
    return 0;
}
