    virtual std::string GetID() const = 0;
    virtual GUIElementType GetType() const = 0;
};

// Derived class for Button
class Button : public Component {
public:
    Button(const std::string& id) : _id(id) {}
    std::string GetID() const override { return _id; }
    GUIElementType GetType() const override { return GUI_TYPE_BUTTON; }
private:
    std::string _id;
};

// Derived class for TextField
class TextField : public Component {
public:
    TextField(const std::string& id) : _id(id) {}
    std::string GetID() const override { return _id; }
    GUIElementType GetType() const override { return GUI_TYPE_TEXTFIELD; }
private:
    std::string _id;
};

// Derived class for Slider
class Slider : public Component {
public:
    Slider(const std::string& id) : _id(id) {}
    std::string GetID() const override { return _id; }
    GUIElementType GetType() const override { return GUI_TYPE_SLIDER; }
private:
    std::string _id;
};

// Inspector class
class Inspector {
public:
    Inspector() : _value(nullptr) {}
    void Inspect(Component* component) { _value = component; }
    Component* GetValue() const { return _value; }
    GUIElementType GetType() { return _value ? _value->GetType() : GUI_TYPE_INSPECTOR; }
    ~Inspector() {}
private:
    Component* _value;
};

