#include "clang/Tooling/JSONCompilationDatabase.h"
#include "llvm/Support/raw_ostream.h"

namespace ct = clang::tooling;

// Utility function to print compile commands
void printCompCommands(llvm::raw_ostream &OS, const std::vector<ct::CompileCommand> &compCommands) {
    for (const auto &command : compCommands) {
        OS << std::format("File: {}\n", command.Filename);
        OS << "Compile command: ";
        for (const auto &arg : command.CommandLine) {
            OS << arg << " ";
        }
        OS << "\n";
    }
}

int main(int argc, char** argv) {
    std::string errString;
    if (argc < 2) {
        llvm::errs() << "No JSON compilation database specified\n";
        return 1;
    }
    std::string pathname = argv[1];
    std::unique_ptr<ct::CompilationDatabase> compDatabase;
    compDatabase = ct::JSONCompilationDatabase::loadFromFile(pathname, errString, ct::JSONCommandLineSyntax::AutoDetect);
    if (!compDatabase) {
        llvm::errs() << std::format("ERROR: {}\n", errString);
        return 1;
    }
    std::vector<std::string> sourcePaths = compDatabase->getAllFiles();
    for (const auto& sourcePath : sourcePaths) {
        llvm::outs() << std::format("Source file: {}\n", sourcePath);
    }
    std::vector<ct::CompileCommand> compCommands = compDatabase->getAllCompileCommands();
    printCompCommands(llvm::outs(), compCommands);
    for (int i = 2; i < argc; ++i) {
        std::vector<ct::CompileCommand> fileCompCommands = compDatabase->getCompileCommands(argv[i]);
        printCompCommands(llvm::outs(), fileCompCommands);
    }
    return 0;
}
