#include <iostream>
#include <algorithm> // For std::min and std::max

class Rectangulo {
private:
    float x, y, area, perim;

    void calcAreaPerim() {
        area = x * y;
        perim = 2 * x + 2 * y;
    }

public:
    Rectangulo(float a, float b) {
        x = a;
        y = b;
        calcAreaPerim();
    }

    void setRectangulo(float a, float b) {
        x = a;
        y = b;
        calcAreaPerim();
    }

    void getRectangulo() {
        std::cout << "Long x = " << x << std::endl
                  << "Long y = " << y << std::endl
                  << "Area = " << area << std::endl
                  << "Perimetro = " << perim << std::endl;
    }

    bool estaDentroDe(Rectangulo r) {
        return x <= r.x && y <= r.y;
    }

    float areaInterseccion(Rectangulo r) {
        if (estaDentroDe(r)) {
            return area;
        } else if (r.estaDentroDe(*this)) {
            return r.area;
        } else {
            float x_overlap = std::max(0.0f, std::min(x, r.x) - std::max(0.0f, x + r.x - (x + r.x)));
            float y_overlap = std::max(0.0f, std::min(y, r.y) - std::max(0.0f, y + r.y - (y + r.y)));
            return x_overlap * y_overlap;
        }
    }
};

int main() {
    // Test cases
    Rectangulo rect1(4, 5);
    Rectangulo rect2(3, 6);
    Rectangulo rect3(5, 7);

    rect1.getRectangulo();
