using namespace std;

/**
 * Generates and prints all prime numbers less than n using the Sieve of Eratosthenes algorithm.
 * 
 * @param n The upper limit (exclusive) for generating prime numbers.
 */
void generatePrimes(int n) {
    vector<bool> isPrime(n, true);
    isPrime[0] = false;
    isPrime[1] = false;

    for (int i = 2; i * i < n; ++i) {
        if (isPrime[i]) {
            for (int j = i * i; j < n; j += i) {
                isPrime[j] = false;
            }
        }
    }

    for (int i = 2; i < n; ++i) {
        if (isPrime[i]) {
            cout << i << endl;
        }
    }
}

int main() {
    int n;
    cout << "Enter the upper limit for prime numbers: ";
    cin >> n;
    cout << "Prime numbers less than " << n << " are:" << endl;
    generatePrimes(n);
    return 0;
}

// Test cases to verify the solution correctness
