using namespace std;

class QuadtreeEncoder {
private:
    vector<vector<int>> matrix;
    int size;

    string compress(int x, int y, int currentSize) {
        if (currentSize == 1) {
            return to_string(matrix[x][y]);
        }

        bool zero = true, one = true;
        for (int i = x; i < x + currentSize; i++) {
            for (int j = y; j < y + currentSize; j++) {
                if (matrix[i][j]) zero = false;
                else one = false;
            }
        }

        if (zero) return "0";
        if (one) return "1";

        int halfSize = currentSize / 2;
        string topLeft = compress(x, y, halfSize);
        string topRight = compress(x, y + halfSize, halfSize);
        string bottomLeft = compress(x + halfSize, y, halfSize);
        string bottomRight = compress(x + halfSize, y + halfSize, halfSize);

        return "(" + topLeft + topRight + bottomLeft + bottomRight + ")";
    }

public:
    QuadtreeEncoder(int n) : size(n) {
        matrix.resize(n, vector<int>(n));
    }

    void readMatrix() {
        for (int i = 0; i < size; i++) {
            for (int j = 0; j < size; j++) {
                cin >> matrix[i][j];
            }
        }
    }

    string encode() {
        return compress(0, 0, size);
    }
};

int main() {
    int N;
    cin >> N;

    QuadtreeEncoder encoder(N);
    encoder.readMatrix();
    cout << encoder.encode() << endl;

    return 0;
}
