namespace net {

enum class SchemeHostPortMatcherResult {
  kInclude,
  kNoMatch,
  kExclude
};

class SchemeHostPortMatcher {
public:
  void AddRule(std::unique_ptr<SchemeHostPortMatcherRule> rule) {
    rules_.push_back(std::move(rule));
  }

  SchemeHostPortMatcherResult Evaluate(const GURL& url) const {
    for (const auto& rule : rules_) {
      SchemeHostPortMatcherResult result = rule->Evaluate(url);
      if (result != SchemeHostPortMatcherResult::kNoMatch) {
        return result;
      }
    }
    return SchemeHostPortMatcherResult::kNoMatch;
  }

private:
  std::vector<std::unique_ptr<SchemeHostPortMatcherRule>> rules_;
};

}  // namespace net

// Test cases to verify the solution correctness
int main() {
  using net::SchemeHostPortMatcher;
  using net::SchemeHostPortMatcherResult;
  using net::SchemeHostPortMatcherRule;

  SchemeHostPortMatcher matcher;

  // Add rules to the matcher
  matcher.AddRule(SchemeHostPortMatcherRule::FromUntrimmedRawString("https://*.example.com"));
  matcher.AddRule(SchemeHostPortMatcherRule::FromUntrimmedRawString("http://[::1]"));
  matcher.AddRule(SchemeHostPortMatcherRule::FromUntrimmedRawString("192.168.1.0/24"));
  matcher.AddRule(SchemeHostPortMatcherRule::FromUntrimmedRawString("*.test.com:8080"));

  // Test URLs
  assert(matcher.Evaluate(GURL("https://www.example.com")) == SchemeHostPortMatcherResult::kInclude);
  assert(matcher.Evaluate(GURL("http://[::1]:80")) == SchemeHostPortMatcherResult::kInclude);
  assert(matcher.Evaluate(GURL("http://192.168.1.10")) == SchemeHostPortMatcherResult::kInclude);
  assert(matcher.Evaluate(GURL("http://www.test.com:8080")) == SchemeHostPortMatcherResult::kInclude);
  assert(matcher.Evaluate(GURL("https://www.test.com:8080")) == SchemeHostPortMatcherResult::kNoMatch);
  assert(matcher.Evaluate(GURL("https://www.notexample.com")) == SchemeHostPortMatcherResult::kNoMatch);

  std::cout << "All test cases passed!" << std::endl;

  return 0;
}
