#define MOD 1000000007
#define ll unsigned long long

using namespace std;

// Function to calculate (base^exponent) % MOD
ll mod_pow(ll base, ll exponent, ll modulus) {
    ll result = 1;
    while (exponent > 0) {
        if (exponent % 2 == 1) {
            result = (result * base) % modulus;
        }
        base = (base * base) % modulus;
        exponent /= 2;
    }
    return result;
}

int main() {
    ifstream fin("input.txt");
    ofstream fout("output.txt");

    int n;
    fin >> n;

    // Calculate 3^(3n) mod (10^9 + 7)
    ll num = mod_pow(3, 3 * n, MOD);

    // Calculate 7^n mod (10^9 + 7)
    ll sum6 = mod_pow(7, n, MOD);

    // Calculate the non-negative difference
    ll result = (num - sum6 + MOD) % MOD;

    fout << result << endl;

    fin.close();
    fout.close();

    return 0;
}
