/**
 * Determines if two floating-point numbers are approximately equal.
 * Two numbers are approximately equal if the absolute difference
 * between them is less than a small threshold, epsilon.
 *
 * @param a The first floating-point number.
 * @param b The second floating-point number.
 * @param epsilon The threshold for determining approximate equality.
 * @return True if the numbers are approximately equal, false otherwise.
 */
bool areApproximatelyEqual(double a, double b, double epsilon = 1e-8) {
    return abs(a - b) < epsilon;
}

int main() {
    double a, b;
    cin >> a >> b;
    if (areApproximatelyEqual(a, b)) {
