// GateLibraryParser interface
class GateLibraryParser {
public:
    virtual ~GateLibraryParser() = default;
    virtual bool parse_library(const std::string& file_path) = 0;
};

// HGLParser class
class HGLParser : public GateLibraryParser {
public:
    bool parse_library(const std::string& file_path) override {
        std::cout << "Parsing HGL file: " << file_path << std::endl;
        // Simulate parsing process
        return true;
    }
};

// Plugin interface
class BasePluginInterface {
public:
    virtual ~BasePluginInterface() = default;
    virtual std::string get_name() const = 0;
    virtual std::string get_version() const = 0;
    virtual void on_load() = 0;
    virtual void on_unload() = 0;
};

// HGLParserPlugin class
class HGLParserPlugin : public BasePluginInterface {
public:
    std::string get_name() const override {
        return std::string("hgl_parser");
    }

    std::string get_version() const override {
        return std::string("0.1");
    }

    void on_load() override {
        // Register the HGL parser in the PluginManager
        PluginManager::instance().register_parser("Default HGL Parser", []() { return std::make_unique<HGLParser>(); }, {".hgl"});
    }

    void on_unload() override {
        // Unregister the HGL parser from the PluginManager
        PluginManager::instance().unregister_parser("Default HGL Parser");
    }
};

// PluginManager class
class PluginManager {
private:
    std::unordered_map<std::string, std::function<std::unique_ptr<GateLibraryParser>()>> parsers;
    std::unordered_map<std::string, std::vector<std::string>> extensions;

    PluginManager() = default;

public:
    static PluginManager& instance() {
        static PluginManager instance;
        return instance;
    }

    void register_parser(const std::string& name, std::function<std::unique_ptr<GateLibraryParser>()> create_function, const std::vector<std::string>& supported_extensions) {
        parsers[name] = create_function;
        for (const auto& ext : supported_extensions) {
            extensions[ext].push_back(name);
        }
    }

    void unregister_parser(const std::string& name) {
        parsers.erase(name);
        // Remove the parser from the extensions map as well
        for (auto& pair : extensions) {
            auto& vec = pair.second;
            vec.erase(std::remove(vec.begin(), vec.end(), name), vec.end());
        }
    }

    std::unique_ptr<GateLibraryParser> find_parser(const std::string& extension) {
        if (extensions.find(extension) != extensions.end() && !extensions[extension].empty()) {
            return parsers[extensions[extension].front()]();
        }
        return nullptr;
    }

    void list_registered_parsers() {
        std::cout << "Registered parsers:" << std::endl;
        for (const auto& pair : parsers) {
            std::cout << " - " << pair.first << std::endl;
        }
    }
};

// Main function
int main() {
    // Create an instance of the HGLParserPlugin and load it
    auto hgl_plugin = std::make_unique<HGLParserPlugin>();
    hgl_plugin->on_load();

    // List all registered parsers
    PluginManager::instance().list_registered_parsers();

    // Find and use the HGL parser
    auto parser = PluginManager::instance().find_parser(".hgl");
    if (parser) {
        parser->parse_library("example.hgl");
    }

    // Unload the HGLParserPlugin
    hgl_plugin->on_unload();

    return 0;
}
