#include<iostream>
using namespace std;

class Node {
public:
    int data;
    Node* next;

    Node(int d) {
        data = d;
        next = NULL;
    }
};

void insertAtTail(Node*& head, int data) {
    if (head == NULL) {
        head = new Node(data);
        return;
    }
    Node* tail = head;
    while (tail->next != NULL) {
        tail = tail->next;
    }
    tail->next = new Node(data);
}

void print(Node* head) {
    while (head != NULL) {
        cout << head->data << "->";
        head = head->next;
    }
    cout << "NULL" << endl;
}

Node* take_input() {
    int d;
    cin >> d;
    Node* head = NULL;
    while (d != -1) {
        insertAtTail(head, d);
        cin >> d;
    }
    return head;
}

ostream& operator<<(ostream &os, Node* head) {
    print(head);
    return os;
}

istream& operator>>(istream &is, Node*& head) {
    head = take_input();
    return is;
}

void rotate(Node*& head, int k) {
    if (head == NULL || k == 0) return;

    Node* current = head;
    int count = 1;
    while (count < k && current != NULL) {
        current = current->next;
        count++;
    }

    if (current == NULL) return;

    Node* kthNode = current;
    while (current->next != NULL) {
        current = current->next;
    }

    current->next = head;
    head = kthNode->next;
    kthNode->next = NULL;
}

int main() {
    Node* head = NULL;
    cout << "Enter elements of linked list terminated by -1: ";
    cin >> head;
    cout << "Original Linked List: " << head;

    int k;
    cout << "Enter number of positions to rotate: ";
    cin >> k;

    rotate(head, k);
    cout << "Linked List after rotation: " << head;

    return 0;
}
