#include <iostream>
#include <vector>
#include <climits>
using namespace std;

double findMedianSortedArrays(vector<int>& A, vector<int>& B) {
    int n = A.size(), m = B.size();
    if (m < n) {
        return findMedianSortedArrays(B, A);
    }
    int sze = (n + m + 1) / 2;
    int lo = 0, hi = n;
    bool even = (n + m) % 2 == 0;
    while (lo <= hi) {
        int cut1 = (lo + hi) / 2;
        int left1Size = cut1;
        int left2Size = sze - cut1;

        int left1 = left1Size > 0 ? A[left1Size - 1] : INT_MIN;
        int left2 = left2Size > 0 ? B[left2Size - 1] : INT_MIN;

        int right1 = left1Size < n ? A[left1Size] : INT_MAX;
        int right2 = left2Size < m ? B[left2Size] : INT_MAX;

        if (left1 <= right2 && left2 <= right1) {
            if (even) {
                return (max(left1, left2) + min(right1, right2)) / 2.0;
            } else {
                return max(left1, left2);
            }
        } else if (left1 > right2) {
            hi = cut1 - 1;
        } else {
            lo = cut1 + 1;
        }
    }
    return -1;
}

int main() {
    vector<int> v1 = {1, 3};
    vector<int> v2 = {2};
    cout << "The median is: " << findMedianSortedArrays(v1, v2) << endl; // Output: The median is: 2

    vector<int> v3 = {1, 2};
    vector<int> v4 = {3, 4};
    cout << "The median is: " << findMedianSortedArrays(v3, v4) << endl; // Output: The median is: 2.5

    return 0;
}
