    vector<string> output;

    while (cin >> test_case_num && test_case_num != 0) {
        vector<Balloon> balloons;
        int max_count = 0;
        string most_popular_balloon;

        string balloon_name;
        for (int i = 0; i < test_case_num; i++) {
            cin >> balloon_name;
            bool found = false;

            for (auto &balloon : balloons) {
                if (balloon.name == balloon_name) {
                    balloon.count++;
                    found = true;
                    if (balloon.count > max_count) {
                        max_count = balloon.count;
                        most_popular_balloon = balloon.name;
                    }
                    break;
                }
            }

            if (!found) {
                balloons.push_back({balloon_name, 1});
                if (max_count == 0) {
                    max_count = 1;
                    most_popular_balloon = balloon_name;
                }
            }
        }

        output.push_back(most_popular_balloon);
    }

    // Show the output
    for (const auto &name : output) {
        cout << name << endl;
    }

    return 0;
}
