#include <iostream>
#include <map>
using namespace std;

/**
 * Counts the number of subarrays whose sum is divisible by the size of the array.
 * 
 * @param arr The array of integers.
 * @param n The size of the array.
 * @return The number of such subarrays.
 */
long long countDivisibleSubarrays(const int arr[], int n) {
    long long ans = 0;
    int s = 0;
    map<int, int> prefixSumMod;
    prefixSumMod[0] = 1; // A prefix sum of 0 means a subarray from the start is divisible by n

    for (int i = 0; i < n; ++i) {
        s += arr[i];
        s %= n;
        while (s < 0) {
            s += n; // Adjust for negative numbers
        }
        ans += prefixSumMod[s]; // Add the number of times this mod has been seen before
        ++prefixSumMod[s]; // Increment the count for this mod
    }

    return ans;
}

int main() {
    ios_base::sync_with_stdio(0); cin.tie(0);
    int n;
    cin >> n;
    int* arr = new int[n];
    for (int i = 0; i < n; ++i) {
        cin >> arr[i];
    }
    cout << countDivisibleSubarrays(arr, n) << endl;
    delete[] arr;
    return 0;
}

// Test cases to verify the solution
void test() {
    int test1[] = {1, 3, -2, 5, -4};
    cout << "Test 1: " << (countDivisibleSubarrays(test1, 5) == 4 ? "Passed" : "Failed") << endl;

    int test2[] = {4, 5, 0, -2, -3, 1};
    cout << "Test 2: " << (countDivisibleSubarrays(test2, 6) == 5 ? "Passed" : "Failed") << endl;

    int test3[] = {1, 1, 1, 1, 1, 1};
    cout << "Test 3: " << (countDivisibleSubarrays(test3, 6) == 21 ? "Passed" : "Failed") << endl;

    int test4[] = {-1, 2, 9};
    cout << "Test 4: " << (countDivisibleSubarrays(test4, 3) == 2 ? "Passed" : "Failed") << endl;
}

int main() {
    test(); // Run test cases
    return 0;
}
