#include <iostream>
#include <stdexcept>

class SafeArray {
private:
    int* array;
    size_t size;

public:
    // Constructor
    SafeArray(size_t size) : size(size) {
        array = new int[size](); // Initialize array with zeros
    }

    // Copy constructor
    SafeArray(const SafeArray& other) : size(other.size) {
        array = new int[size];
        for (size_t i = 0; i < size; ++i) {
            array[i] = other.array[i];
        }
    }

    // Destructor
    ~SafeArray() {
        delete[] array;
    }

    // Deleted copy assignment operator
    SafeArray& operator=(const SafeArray&) = delete;

    // Overloaded operator[] for safe access
    int& operator[](size_t index) {
        if (index >= size) {
            throw std::out_of_range("Index out of bounds");
        }
        return array[index];
    }

    // Get size of the array
    size_t getSize() const {
        return size;
    }

    // Print array elements
    void printArray() const {
        for (size_t i = 0; i < size; ++i) {
            std::cout << array[i] << " ";
        }
        std::cout << std::endl;
    }
};

// Test cases
int main() {
    try {
        SafeArray arr(5);
        for (size_t i = 0; i < arr.getSize(); ++i) {
            arr[i] = static_cast<int>(i * 10);
        }
        arr.printArray();

        // Copy constructor test
        SafeArray arrCopy = arr;
        arrCopy.printArray();

        // Out of bounds access test
        std::cout << arr[10] << std::endl; // Should throw an exception
    } catch (const std::out_of_range& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
