using namespace std;

/**
 * Finds the minimum number of elements to remove from the sequence
 * so that the remaining sequence is sorted in strictly increasing order
 * starting from 1. If it is not possible, returns -1.
 * 
 * @param n The number of elements in the sequence.
 * @param num The sequence of integers.
 * @return The minimum number of removals or -1 if not possible.
 */
int min_removals_to_sort(int n, const vector<int>& num) {
    int ans = 0;
    bool flag = false;
    for (int i = 0, j = 1; i < n; i++) {
        if (num[i] != j) {
            ans++;
        } else {
            j++;
            flag = true;
        }
    }
    return flag ? ans : -1;
}

int main() {
    // Test cases
    vector<int> test1 = {1, 2, 3, 4, 5}; // Should return 0
    vector<int> test2 = {4, 3, 2, 1}; // Should return -1
    vector<int> test3 = {2, 3, 2, 1, 4}; // Should return 2
    vector<int> test4 = {1, 6, 2, 5, 3, 4}; // Should return 2

    cout << "Test Case 1: " << min_removals_to_sort(test1.size(), test1) << endl;
    cout << "Test Case 2: " << min_removals_to_sort(test2.size(), test2) << endl;
    cout << "Test Case 3: " << min_removals_to_sort(test3.size(), test3) << endl;
