#include <iostream>
#include <stack>
#include <string>

using namespace std;

/**
 * Normalizes a Unix-style file path.
 *
 * @param path The input file path.
 * @return The simplified canonical path.
 */
string normalizePath(string path) {
    string current = "";
    string answer = "";
    stack<string> st;
    path.push_back('/');
    for (auto letter : path) {
        if (letter == '/') {
            if (current == ".." && !st.empty()) {
                st.pop();
            } else if (current != "" && current != "." && current != "..") {
                st.push(current);
            }
            current = "";
        } else {
            current += letter;
        }
    }
    while (!st.empty()) {
        answer = "/" + st.top() + answer;
        st.pop();
    }
    return answer.empty() ? "/" : answer;
}

int main() {
    // Test cases
    cout << normalizePath("/home/") << endl; // Output: "/home"
    cout << normalizePath("/../") << endl; // Output: "/"
    cout << normalizePath("/home//foo/") << endl; // Output: "/home/foo"
    cout << normalizePath("/a/./b/../../c/") << endl; // Output: "/c"
    return 0;
}
