#include <unordered_map>
#include <algorithm>

enum LinkType {
  LINK_TYPE_NONE,
  LINK_TYPE_POINT_TO_POINT,
  LINK_TYPE_MULTI_ACCESS
};

class Face {
public:
  Face(int id, const std::string& localUriScheme, const std::string& remoteUriScheme, LinkType linkType)
    : id(id), localUriScheme(localUriScheme), remoteUriScheme(remoteUriScheme), linkType(linkType) {}

  int getId() const { return id; }
  std::string getLocalUriScheme() const { return localUriScheme; }
  std::string getRemoteUriScheme() const { return remoteUriScheme; }
  LinkType getLinkType() const { return linkType; }

private:
  int id;
  std::string localUriScheme;
  std::string remoteUriScheme;
  LinkType linkType;
};

class FaceSystem {
public:
  void addFace(const Face& face) {
    faces[face.getId()] = face;
  }

  Face* getFaceById(int id) {
    auto it = faces.find(id);
    if (it != faces.end()) {
      return &it->second;
    }
    return nullptr;
  }

  std::vector<Face> listFacesByScheme(const std::string& scheme, LinkType linkType = LINK_TYPE_NONE) {
    std::vector<Face> filteredFaces;
    for (const auto& pair : faces) {
      const Face& face = pair.second;
      if ((face.getLocalUriScheme() == scheme || face.getRemoteUriScheme() == scheme) &&
          (linkType == LINK_TYPE_NONE || face.getLinkType() == linkType)) {
        filteredFaces.push_back(face);
      }
    }
    return filteredFaces;
  }

private:
  std::unordered_map<int, Face> faces;
};

int main() {
  FaceSystem faceSystem;

  // Adding faces to the system
  faceSystem.addFace(Face(1, "udp", "udp", LINK_TYPE_POINT_TO_POINT));
  faceSystem.addFace(Face(2, "tcp", "tcp", LINK_TYPE_MULTI_ACCESS));
  faceSystem.addFace(Face(3, "ws", "ws", LINK_TYPE_NONE));

  // Retrieving a face by ID
  Face* face = faceSystem.getFaceById(1);
  if (face) {
    std::cout << "Retrieved Face ID: " << face->getId() << std::endl;
  } else {
    std::cout << "Face not found." << std::endl;
  }

  // Listing faces by URI scheme
  std::vector<Face> udpFaces = faceSystem.listFacesByScheme("udp");
  std::cout << "UDP Faces: " << std::endl;
  for (const Face& f : udpFaces) {
    std::cout << " - Face ID: " << f.getId() << std::endl;
  }

  // Listing faces by URI scheme with link type filter
  std::vector<Face> tcpFaces = faceSystem.listFacesByScheme("tcp", LINK_TYPE_MULTI_ACCESS);
  std::cout << "TCP Faces with MULTI_ACCESS link type: " << std::endl;
  for (const Face& f : tcpFaces) {
    std::cout << " - Face ID: " << f.getId() << std::endl;
  }

  return 0;
}
