    {
        auto input  = lexy::zstring_input("abc,abc,abc,");
        auto result = lexy::match<production>(input);
        CHECK(!result);
    }
    SUBCASE("invalid sequence with non-abc element")
    {
        auto input  = lexy::zstring_input("abc,def,abc");
        auto result = lexy::match<production>(input);
        CHECK(!result);
    }
    SUBCASE("valid single abc")
    {
        auto input  = lexy::zstring_input("abc");
        auto result = lexy::match<production>(input);
        CHECK(result);
    }
