#include <iostream>
using namespace std;

// Definition for singly-linked list.
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(nullptr) {}
};

class Solution {
public:
    ListNode* oddEvenList(ListNode* head) {
        if (head == nullptr || head->next == nullptr) return head;

        ListNode* odd = head;
        ListNode* even = head->next;
        ListNode* evenHead = even;

        while (even && even->next) {
            odd->next = odd->next->next;
            even->next = even->next->next;
            odd = odd->next;
            even = even->next;
        }

        odd->next = evenHead;
        return head;
    }
};

// Helper function to create a list from an array of values
ListNode* createList(const vector<int>& values) {
    ListNode dummy(0), *tail = &dummy;
    for (int val : values) {
        tail->next = new ListNode(val);
        tail = tail->next;
    }
    return dummy.next;
}

// Helper function to print the list
void printList(ListNode* head) {
    while (head) {
        cout << head->val << "->";
        head = head->next;
    }
    cout << "NULL" << endl;
}

int main() {
    // Test cases
    Solution solution;
    ListNode* test1 = createList({1, 2, 3, 4, 5});
    ListNode* test2 = createList({2, 1, 3, 5, 6, 4, 7});

    cout << "Original list 1: ";
    printList(test1);
    ListNode* result1 = solution.oddEvenList(test1);
    cout << "Reordered list 1: ";
    printList(result1);

    cout << "Original list 2: ";
    printList(test2);
    ListNode* result2 = solution.oddEvenList(test2);
    cout << "Reordered list 2: ";
    printList(result2);

    return 0;
}
