```cpp
#include <vector>
#include <stack>

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode() : val(0), left(nullptr), right(nullptr) {}
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
    TreeNode(int x, TreeNode *left, TreeNode *right) : val(x), left(left), right(right) {}
};

class Solution {
public:
    vector<int> postorderTraversal(TreeNode* root) {
        vector<int> result;
        if (!root) return result;

        stack<TreeNode*> s;
        TreeNode* current = root;
        TreeNode* lastVisited = nullptr;

        while (!s.empty() || current) {
            if (current) {
                s.push(current);
                current = current->left;
            } else {
                TreeNode* topNode = s.top();
                if (topNode->right && lastVisited != topNode->right) {
                    current = topNode->right;
                } else {
                    result.push_back(topNode->val);
                    lastVisited = topNode;
                    s.pop();
                }
            }
        }
        return result;
    }
};

// Test cases
int main() {
    // Test case 1
    TreeNode* root1 = new TreeNode(1);
    root1->right = new TreeNode(2);
    root1->right->left = new TreeNode(3);
    Solution sol1;
    vector<int> result1 = sol1.postorderTraversal(root1); // Expected output: [3, 2, 1]

    // Test case 2
    TreeNode* root2 = new TreeNode(1);
    root2->left = new TreeNode(2);
    root2->right = new TreeNode(3);
    root2->left->left = new TreeNode(4);
    root2->left->right = new TreeNode(5);
    Solution sol2;
    vector<int> result2 = sol2.postorderTraversal(root2); // Expected output: [4, 5, 2, 3, 1]

    // Clean up allocated memory
    delete root1->right->left;
    delete root1->right;
    delete root1;

    delete root2->left->right;
    delete root2->left->left;
    delete root2->left;
    delete root2->right;
    delete root2;

    return 0;
}
