#include <iostream>
#include <vector>
#include <string>
using namespace std;

class Book {
    string title;
    string author;
    int stock;

public:
    Book(string t, string a, int s) : title(t), author(a), stock(s) {}
    ~Book() {
        cout << "Destroying \"" << title << "\" by " << author << endl;
    }

    void set_title(string t) { title = t; }
    void set_author(string a) { author = a; }
    void set_stock(int s) { stock = s; }

    string get_title() const { return title; }
    string get_author() const { return author; }
    int get_stock() const { return stock; }

    void restock(int n) {
        stock += n;
    }

    bool sell(int n) {
        if (n > stock) {
            cout << "Not enough stock to sell " << n << " copies of \"" << title << "\"." << endl;
            return false;
        }
        stock -= n;
        return true;
    }
};

class Bookstore {
    vector<Book> inventory;
    int total_stock;

public:
    Bookstore() : total_stock(0) {}

    void add_book(const Book& book) {
        inventory.push_back(book);
        total_stock += book.get_stock();
    }

    void restock_book(string title, int n) {
        for (auto& book : inventory) {
            if (book.get_title() == title) {
                book.restock(n);
                total_stock += n;
                return;
            }
        }
        cout << "Book not found in inventory: " << title << endl;
    }

    void sell_book(string title, int n) {
        for (auto& book : inventory) {
            if (book.get_title() == title) {
                if (book.sell(n)) {
                    total_stock -= n;
                }
                return;
            }
        }
        cout << "Book not found in inventory: " << title << endl;
    }

    int get_total_stock() const {
        return total_stock;
    }

    void display_inventory() const {
        for (const auto& book : inventory) {
            cout << "Title: " << book.get_title() << ", Author: " << book.get_author() << ", Stock: " << book.get_stock() << endl;
        }
    }
};

int main() {
    Bookstore myStore;

    myStore.add_book(Book("The Great Gatsby", "F. Scott Fitzgerald", 5));
    myStore.add_book(Book("1984", "George Orwell", 8));
    myStore.add_book(Book("To Kill a Mockingbird", "Harper Lee", 3));

    cout << "Initial total stock: " << myStore.get_total_stock() << endl;
    myStore.display_inventory();

