#include <iostream>
#include <vector>
#include <thread>
#include <queue>
#include <mutex>
#include <condition_variable>
#include <functional>

class threadPool {
public:
    threadPool() : endProc(false) {}
    ~threadPool() { stop(); }

    void start(int threadNum);
    void queueJob(const std::function<void()>& job);
    bool busy();
    void stop();

private:
    void threadLoop();

    std::vector<std::thread> threads;
    std::queue<std::function<void()>> jobs;
    std::mutex queue_mutex;
    std::condition_variable mutex_condition;
    bool endProc;
};

void threadPool::start(int threadNum) {
    threads.resize(threadNum);
    for (int i = 0; i < threadNum; i++) {
        threads.at(i) = std::thread(&threadPool::threadLoop, this);
    }
}

void threadPool::threadLoop() {
    while (true) {
        std::function<void()> job;
        {
            std::unique_lock<std::mutex> lock(queue_mutex);
            mutex_condition.wait(lock, [this] {
                return (!jobs.empty() || endProc);
            });
            if (jobs.empty() && endProc) {
                return;
            }
            job = jobs.front();
            jobs.pop();
        }
        job();
    }
}

void threadPool::queueJob(const std::function<void()>& job) {
    {
        std::unique_lock<std::mutex> lock(queue_mutex);
        jobs.push(job);
    }
    mutex_condition.notify_one();
}

bool threadPool::busy() {
    std::unique_lock<std::mutex> lock(queue_mutex);
    return !jobs.empty();
}

void threadPool::stop() {
    {
        std::unique_lock<std::mutex> lock(queue_mutex);
        endProc = true;
    }
    mutex_condition.notify_all();
    for (std::thread& t : threads) {
        if (t.joinable()) {
            t.join();
        }
    }
    threads.clear();
}

// Test cases to verify the solution correctness
int main() {
    threadPool pool;
    pool.start(4); // Start the thread pool with 4 worker threads

    // Queue some jobs
    pool.queueJob([]() { std::cout << "Job 1 executed\n"; });
    pool.queueJob([]() { std::cout << "Job 2 executed\n"; });
    pool.queueJob([]() { std::cout << "Job 3 executed\n"; });
    pool.queueJob([]() { std::cout << "Job 4 executed\n"; });

    // Wait for a moment to let some jobs finish
    std::this_thread::sleep_for(std::chrono::seconds(1));

    // Check if the pool is busy (should be true if there are still jobs to do)
    std::cout << "Is the pool busy? " << (pool.busy() ? "Yes" : "No") << std::endl;

    // Stop the thread pool
    pool.stop();

    // After stopping, the pool should not be busy
    std::cout << "Is the pool busy after stopping? " << (pool.busy() ? "Yes" : "No") << std::endl;

    return 0;
}
