#include <iostream>
#include <cstring>
#include <unistd.h>
#include <sys/types.h>
#include <sys/socket.h>
#include <netdb.h>
#include <fcntl.h>
#include <errno.h>

#define PORT "3490"
#define BUF_SIZE 1024
#define SEND_SIZE 40

class Client {
private:
    struct addrinfo *servInfo;

public:
    Client() : servInfo(nullptr) {}
    ~Client() {
        if (servInfo != nullptr) {
            freeaddrinfo(servInfo);
        }
    }

    int Connect(int &connFd);
    int GetInfo();
};

void *get_addr_in(struct sockaddr *sa) {
    if (sa->sa_family == AF_INET) {
        return &(((struct sockaddr_in *)sa)->sin_addr);
    } else {
        return &(((struct sockaddr_in6 *)sa)->sin6_addr);
    }
}

int Client::Connect(int &connFd) {
    GetInfo();
    if (servInfo == nullptr)
        return -1;

    struct addrinfo *res;
    int s;
    for (res = servInfo; res != nullptr; res = res->ai_next) {
        connFd = socket(res->ai_family, res->ai_socktype, res->ai_protocol);
        if (connFd == -1) {
            perror("Socket");
            continue;
        }

        s = connect(connFd, res->ai_addr, res->ai_addrlen);
        if (s == -1) {
            close(connFd);
            perror("Connect");
            continue;
        }
        break;
    }

    if (res == nullptr) {
        std::cerr << "Can't create socket from the info list" << std::endl;
        return -1;
    }

    char ss[INET6_ADDRSTRLEN];
    inet_ntop(res->ai_family, get_addr_in(res->ai_addr), ss, sizeof(ss));
    std::cout << "Connecting to: " << ss << std::endl;

    freeaddrinfo(servInfo);
    servInfo = nullptr;
    return 0;
}

int Client::GetInfo() {
    struct addrinfo hints;
    memset(&hints, 0, sizeof(struct addrinfo));
    hints.ai_family = AF_UNSPEC;
    hints.ai_socktype = SOCK_STREAM;
    hints.ai_flags = AI_PASSIVE;

    int s = getaddrinfo(NULL, PORT, &hints, &servInfo);
    if (s != 0) {
        std::cerr << "getaddrinfo: " << gai_strerror(s) << std::endl;
        return -1;
    }
    std::cout << "Client get info finish" << std::endl;
    return 0;
}

int main() {
    Client client;
    int connFd;
    if (client.Connect(connFd) == -1) {
        return EXIT_FAILURE;
    }

    char sendBuf[SEND_SIZE];
    memset(sendBuf, 'A', SEND_SIZE);
    ssize_t bytesSent = send(connFd, sendBuf, SEND_SIZE, 0);
    if (bytesSent == -1) {
        perror("send");
        close(connFd);
        return EXIT_FAILURE;
    }
    std::cout << "Sent " << bytesSent << " bytes to server." << std::endl;

    char recvBuf[BUF_SIZE];
    ssize_t bytesReceived = recv(connFd, recvBuf, BUF_SIZE, 0);
    if (bytesReceived == -1) {
        perror("recv");
        close(connFd);
        return EXIT_FAILURE;
    }
    recvBuf[bytesReceived] = '\0'; // Null-terminate the received string
    std::cout << "Received " << bytesReceived << " bytes: " << recvBuf << std::endl;

    close(connFd);
    return EXIT_SUCCESS;
}
