 * The base of the triangle has 'n' asterisks, and each subsequent
 * row has one less asterisk than the row above it.
 *
 * @param n The number of asterisks in the base of the triangle.
 */
void printInvertedTriangle(int n) {
    for(int i = n; i >= 1; i--) {
        for(int j = 1; j <= i; j++) {
            cout << "*";
        }
        cout << endl;
    }
}

