 * given their rates, the maximum number of each fruit, and the available cash.
 * 
 * @param apple_rate The rate (price per unit) of apples.
 * @param banana_rate The rate (price per unit) of bananas.
 * @param mango_rate The rate (price per unit) of mangoes.
 * @param fruit_max The maximum number of each fruit that can be bought.
 * @param cash The total amount of cash available for buying fruits.
 */
void findFruitCombinations(float apple_rate, float banana_rate, float mango_rate, int fruit_max, float cash) {
    for(int a_num = 0; a_num <= fruit_max; a_num++) {
        for(int b_num = 0; b_num <= fruit_max; b_num++) {
            for(int m_num = 0; m_num <= fruit_max; m_num++) {
                // Check if the total number of fruits is less than or equal to the maximum allowed
                if(a_num + b_num + m_num <= 100) {
                    // Check if the total cost is within the available cash
                    if((a_num * apple_rate) + (b_num * banana_rate) + (m_num * mango_rate) <= cash) {
                        // Display the combination
                        cout << "Combination: " << a_num << " apples, " << b_num << " bananas, " << m_num << " mangoes" << endl;
                    }
                }
            }
        }
    }
}

