// Abstract base class for log sinks
class LogSink {
public:
    virtual ~LogSink() = default;
    virtual void write(const std::string& message) = 0;
};

// Concrete log sink that writes messages to the console
class ConsoleLogSink : public LogSink {
public:
    void write(const std::string& message) override {
        std::cout << message << std::endl;
    }
};

// Concrete log sink that writes messages to a file
class FileLogSink : public LogSink {
private:
    std::ofstream fileStream;

public:
    FileLogSink(const std::string& filename) {
        fileStream.open(filename, std::ios::out | std::ios::app);
        if (!fileStream.is_open()) {
            throw std::runtime_error("Unable to open file: " + filename);
        }
    }

    ~FileLogSink() {
        if (fileStream.is_open()) {
            fileStream.close();
        }
    }

    void write(const std::string& message) override {
        fileStream << message << std::endl;
    }
};

// Logger class that can attach multiple log sinks
class Logger {
private:
    std::vector<std::shared_ptr<LogSink>> sinks;

public:
    void attachSink(const std::shared_ptr<LogSink>& sink) {
        sinks.push_back(sink);
    }

    void logMessage(const std::string& message) {
        for (const auto& sink : sinks) {
            sink->write(message);
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    try {
        Logger logger;

        // Attach console log sink
        auto consoleSink = std::make_shared<ConsoleLogSink>();
        logger.attachSink(consoleSink);

        // Attach file log sink
        auto fileSink = std::make_shared<FileLogSink>("log.txt");
        logger.attachSink(fileSink);

        // Log some messages
        logger.logMessage("This is a test message to the console and file.");
        logger.logMessage("Logging system is working as expected.");

        std::cout << "Messages logged successfully." << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Exception occurred: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
