struct CheckInstruction
{
    std::function<bool()> Function;
    std::string_view OnError;
};

class Checker
{
public:
    using CheckSequence = std::initializer_list<CheckInstruction>;

    static bool PerformSequence(spdlog::level::level_enum severity, const CheckSequence& sequence)
    {
        bool allChecksPassed = true;
        for (const auto& instruction : sequence)
        {
            if (!instruction.Function())
            {
                spdlog::log(severity, "{}", instruction.OnError);
                allChecksPassed = false;
            }
        }
        return allChecksPassed;
    }
};

// Example usage and test cases
int main()
{
    // Initialize the spdlog library (console logger in this case)
    spdlog::set_level(spdlog::level::debug); // Set global log level to debug
    auto console = spdlog::stdout_color_mt("console");

    // Define some check functions
    auto checkPositive = []() -> bool { return 5 > 0; };
    auto checkNegative = []() -> bool { return -1 > 0; };

    // Create a sequence of checks
    Checker::CheckSequence checks = {
        {checkPositive, "Value should be positive."},
        {checkNegative, "Value should not be negative."}
    };

    // Perform the sequence of checks
    bool result = Checker::PerformSequence(spdlog::level::warn, checks);

    // Output the result
    console->info("All checks passed: {}", result ? "Yes" : "No");

    return 0;
}
