#include <iostream>
using namespace std;

class Node {
public:
    int val;
    Node *next;
    Node(int val) : val(val), next(NULL) {}
};

class LinkedList {
private:
    Node *head;

public:
    LinkedList() : head(NULL) {}

    ~LinkedList() {
        Node *current = head;
        while (current != NULL) {
            Node *next = current->next;
            delete current;
            current = next;
        }
        head = NULL;
    }

    void addNode(int v) {
        Node *newNode = new Node(v);
        if (head == NULL) {
            head = newNode;
        } else {
            Node *tmp = head;
            while (tmp->next != NULL) {
                tmp = tmp->next;
            }
            tmp->next = newNode;
        }
    }

    void insertNode(int pos, int v) {
        Node *newNode = new Node(v);
        if (pos == 0 || head == NULL) {
            newNode->next = head;
            head = newNode;
        } else {
            Node *tmp = head;
            for (int i = 0; tmp->next != NULL && i < pos - 1; i++) {
                tmp = tmp->next;
            }
            newNode->next = tmp->next;
            tmp->next = newNode;
        }
    }

    void deleteNode(int pos) {
        if (head == NULL || pos < 0) return;
        Node *tmp = head;
        if (pos == 0) {
            head = head->next;
            delete tmp;
            return;
        }
        for (int i = 0; tmp != NULL && i < pos - 1; i++) {
            tmp = tmp->next;
        }
        if (tmp == NULL || tmp->next == NULL) return;
        Node *next = tmp->next->next;
        delete tmp->next;
        tmp->next = next;
    }

    void printList() {
        Node *tmp = head;
        while (tmp != NULL) {
            cout << tmp->val << " ";
            tmp = tmp->next;
        }
        cout << endl;
    }
};

int main() {
    LinkedList list;

    list.addNode(10);
    list.addNode(20);
    list.addNode(30);
    list.addNode(40);
    list.addNode(50);

    list.printList(); // Expected output: 10 20 30 40 50

    list.insertNode(2, 100);
    list.printList(); // Expected output: 10 20 100 30 40 50

    list.insertNode(0, 500);
    list.printList(); // Expected output: 500 10 20 100 30 40 50

    list.deleteNode(3);
    list.printList(); // Expected output: 500 10 20 30 40 50

    list.deleteNode(0);
    list.printList(); // Expected output: 10 20 30 40 50

    return 0;
}
