#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int minimumTotal(vector<vector<int>>& triangle) {
        int height = triangle.size();
        vector<int> sum(triangle.back());
        for (int i = height - 2; i >= 0; --i) {
            for (int j = 0; j <= i; ++j) {
                sum[j] = triangle[i][j] + min(sum[j], sum[j + 1]);
            }
        }
        return sum[0];
    }
};

int main() {
    // Test cases
    vector<vector<int>> triangle1 = {
        {2},
        {3, 4},
