// Function to calculate the sum of digits of an integer
int sumDigits(int n) {
    int sum = 0;
    while (n != 0) {
        sum += n % 10;
        n /= 10;
    }
    return sum;
}

// Function to reverse the digits of an integer
int reverse(int n) {
    int rev = 0;
    while (n != 0) {
        rev = (rev * 10) + (n % 10);
        n /= 10;
    }
    return rev;
}

// Function to check if an integer is a palindrome
bool isPalindrome(int n) {
    return n == reverse(n);
}

int main() {
    int num;
    cout << "Enter an integer to obtain the sum of its digits, its reverse, and check if it's a palindrome: ";
    cin >> num;
    cout << "Sum of digits of " << num << " is " << sumDigits(num) << endl;
    cout << "Reverse of " << num << " is " << reverse(num) << endl;
    cout << "The number " << num << (isPalindrome(num) ? " is" : " is not") << " a palindrome." << endl;
    return 0;
}

