using namespace std;

/**
 * Returns the N-th character from the end of the given string S.
 * If N is larger than the length of the string, returns "Invalid position".
 *
 * @param N The position from the end of the string.
 * @param S The input string.
 * @return The N-th character from the end of the string or an error message.
 */
string getNthCharFromEnd(int N, const string& S) {
    if (N > S.length()) {
        return "Invalid position";
    }
    return string(1, S[S.length() - N]);
}

int main() {
    int N;
    string S;
    cin >> N >> S;
    cout << getNthCharFromEnd(N, S) << endl;
    return 0;
}

