    std::bernoulli_distribution dist(prob);
    return dist(gen) ? 1 : 0;
}

int UniformDistribution(int a, int b) {
    std::uniform_int_distribution<int> dist(a, b);
    return dist(gen);
}

int TriangularDistribution(int a, int b, int c) {
    std::uniform_real_distribution<double> dist(0.0, 1.0);
    double F = (b - a) / double(c - a);
    double randValue = dist(gen);
    if (randValue < F) {
        return a + std::sqrt(randValue * (b - a) * (c - a));
    } else {
        return c - std::sqrt((1 - randValue) * (c - b) * (c - a));
    }
}

