#include<bits/stdc++.h>
using namespace::std;

const int MOD = 5557;

typedef vector<int> vi;
typedef pair<int, int> ii;

int add(int a, int b, int m = MOD){
	return (a + b) % m;
}

int mul(int a, int b, int m = MOD){
	return (a * b) % m;
}

struct matrix{
	int n, m;
	vector<vi> M;
	matrix(int n, int m) : n(n), m(m), M(n, vi(m, 0)){}

	matrix operator * (const matrix &b) const {
		matrix res(n, b.m);
		for(int i = 0; i < n; i++){
			for(int j = 0; j < b.m; j++){
				for(int k = 0; k < m; k++){
					res.M[i][j] = add(res.M[i][j], mul(M[i][k], b.M[k][j]));
				}
			}
		}
		return res;
	}

	matrix operator + (const matrix &b) const {
		matrix res = *this;
		for(int i = 0; i < n; i++){
			for(int j = 0; j < m; j++){
				res.M[i][j] = add(res.M[i][j], b.M[i][j]);
			}
		}
		return res;
	}

	matrix pow(int exponent) const {
		matrix res(n, n), base = *this;
		for(int i = 0; i < n; i++) res.M[i][i] = 1;
		while(exponent > 0){
			if(exponent & 1) res = res * base;
			base = base * base;
			exponent >>= 1;
		}
		return res;
	}
};

int main(){
	int n, m, T;
	scanf("%d %d", &n, &m);
	vector<vector<ii>> G(n);
	for(int i = 0; i < m; i++){
		int u, v;
		char s[5];
		scanf("%d %d %s", &u, &v, s);
		u--; v--;
		int mask = 0;
		for(int j = 0; s[j]; j++){
			mask |= 1 << (s[j] - 'A');
		}
		G[u].emplace_back(mask, v);
	}
	scanf("%d", &T);
	matrix adj(n, n), res(n, n);
	for(int i = 0; i < n; i++) res.M[i][i] = 1;
	for(auto &edges : G){
		for(auto &e : edges){
			if(e.first == 0) adj.M[e.second][e.second] = add(adj.M[e.second][e.second], 1);
		}
	}
	res = res + adj.pow(T);
	printf("%d\n", res.M[0][1]);
	return 0;
}
