    int size;
    MPI_Comm_size(MPI_COMM_WORLD, &size);

    // Assuming we want to spawn 4 child processes
    int number_of_children = 4;
    MPI_Comm intercomm;
    MPI_Comm_spawn("child", MPI_ARGV_NULL, number_of_children, MPI_INFO_NULL, 0, MPI_COMM_SELF, &intercomm, MPI_ERRCODES_IGNORE);

    std::vector<int> messages(number_of_children);
    for (int i = 0; i < number_of_children; ++i) {
        MPI_Recv(&messages[i], 1, MPI_INT, i, MPI_ANY_TAG, intercomm, MPI_STATUS_IGNORE);
        std::cout << "Received message from child " << i << ": " << messages[i] << std::endl;
    }

    MPI_Finalize();
    return 0;
}

// child.cpp
#include <mpi.h>
#include <iostream>

int main(int argc, char* argv[]) {
    MPI_Init(&argc, &argv);
    int rank, size;

    MPI_Comm intercomm;
    MPI_Comm_get_parent(&intercomm);

    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(intercomm, &size);

    if (rank == 2) {
        MPI_Send(&size, 1, MPI_INT, 0, rank, intercomm);
    } else {
        MPI_Send(&rank, 1, MPI_INT, 0, rank, intercomm);
    }

    MPI_Finalize();
    return 0;
}
