                  << conn->localAddr() << " is "
                  << (conn->connected() ? "UP" : "DOWN") << std::endl;
        std::cout << conn->getTcpInfoString() << std::endl;

        conn->send("hello\n");
    }

    void onMessage(const TCPConnectionPtr& conn, std::string& buf)
    {
        std::string msg;
        buf.swap(msg);
        std::cout << conn->name() << " recv " << msg.size() << " bytes" << std::endl;
        if (msg == "exit\n")
        {
            conn->send("bye\n");
            conn->shutdown();
        }
        else if (msg == "quit\n")
        {
            loop_->quit();
        }
        else
        {
            conn->send(msg);
        }
    }

    EventLoop* loop_;
    TCPServer server_;
};

