#include<iostream>
#include<cmath>
#include<algorithm>
using namespace std;

/**
 * Performs jump search on a sorted array to find a specific key.
 * 
 * @param array The sorted array in which to search.
 * @param n The size of the array.
 * @param key The element to search for.
 * @return The index of the key if found, otherwise -1.
 */
int jumpSearch(int array[], int n, int key) {
    int jump = static_cast<int>(sqrt(n));
    int steps = jump;
    int prev = 0;
    while (array[min(steps, n) - 1] < key) {
        prev = steps;
        steps += jump;
        if (prev >= n) {
            return -1;
        }
    }
    while (array[prev] < key) {
        prev++;
        if (prev == min(steps, n)) {
            return -1;
        }
    }
    if (array[prev] == key) {
        return prev;
    }
    return -1;
}

int main() {
    int n;
    cin >> n;
    int *arr = new int[n]; // Dynamic allocation for variable-sized array
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    int key = 0;
    cin >> key;
    int index = jumpSearch(arr, n, key);
    cout << index << endl;
    delete[] arr; // Deallocate the array
    return 0;
}

