class BodyNode {
public:
    std::string name;
    Inertia inertia;
    bool isCollidable;
    double frictionCoeff;
    double restitutionCoeff;
    bool gravityMode;
    Eigen::Vector3d position;
    Eigen::Vector3d velocity;
    Eigen::Vector3d force;

    BodyNode(const std::string& name = "BodyNode",
             const Inertia& inertia = Inertia(),
             bool isCollidable = true,
             double frictionCoeff = 1.0,
             double restitutionCoeff = 0.0,
             bool gravityMode = true)
        : name(name), inertia(inertia), isCollidable(isCollidable),
          frictionCoeff(frictionCoeff), restitutionCoeff(restitutionCoeff),
          gravityMode(gravityMode), position(Eigen::Vector3d::Zero()),
          velocity(Eigen::Vector3d::Zero()), force(Eigen::Vector3d::Zero()) {}
};

// Define the RigidBodyDynamics class
class RigidBodyDynamics {
private:
    std::vector<BodyNode> bodyNodes;
    double timeStep;
    Eigen::Vector3d gravity;

public:
    RigidBodyDynamics(double timeStep = 0.01, const Eigen::Vector3d& gravity = Eigen::Vector3d(0, 0, -9.81))
        : timeStep(timeStep), gravity(gravity) {}

    void addBodyNode(const BodyNode& bodyNode) {
        bodyNodes.push_back(bodyNode);
    }

    void applyExternalForce(const std::string& nodeName, const Eigen::Vector3d& force) {
        for (auto& bodyNode : bodyNodes) {
            if (bodyNode.name == nodeName) {
                bodyNode.force += force;
                break;
            }
        }
    }

    void simulateStep() {
        for (auto& bodyNode : bodyNodes) {
            if (bodyNode.gravityMode) {
                bodyNode.force += bodyNode.inertia.mass * gravity;
            }
            Eigen::Vector3d acceleration = bodyNode.force / bodyNode.inertia.mass;
            bodyNode.velocity += acceleration * timeStep;
            bodyNode.position += bodyNode.velocity * timeStep;
            bodyNode.force.setZero(); // Reset force for the next step
        }
    }

    std::vector<std::pair<BodyNode, BodyNode>> detectCollisions() {
        std::vector<std::pair<BodyNode, BodyNode>> collisions;
        // Collision detection logic goes here (not implemented for simplicity)
        return collisions;
    }
};

