using namespace std;

/**
 * Merges two words by alternating the letters from each word.
 * If one word is longer than the other, appends the remaining letters from the longer word.
 * @param word1 The first word to merge.
 * @param word2 The second word to merge.
 * @return The merged word.
 */
string mergeWords(const string& word1, const string& word2) {
    string merged;
    int len1 = word1.length(), len2 = word2.length();
    int i = 0, j = 0;

    // Alternate letters from both words
    while (i < len1 && j < len2) {
        merged += word1[i++];
        merged += word2[j++];
    }

    // Append the remaining letters from the longer word
    while (i < len1) {
        merged += word1[i++];
    }
    while (j < len2) {
        merged += word2[j++];
    }

    return merged;
}

int main() {
    int n;
    cin >> n;

    while (n--) {
        string word1, word2;
        cin >> word1 >> word2;
        cout << mergeWords(word1, word2) << endl;
    }

    return 0;
}
