public:
    std::vector<std::vector<T>> data;
    Mat2(size_t rows, size_t cols) : data(rows, std::vector<T>(cols)) {}

    std::vector<T>& operator[](size_t i) { return data[i]; }
    const std::vector<T>& operator[](size_t i) const { return data[i]; }

    size_t numRows() const { return data.size(); }
    size_t numCols() const { return data[0].size(); }
};

// Assuming Global.hh includes global definitions and utility functions.
typedef unsigned int UINT;

namespace Priorities {

void calcPriorities(Mat2<UINT> &priorities) {
    Mat2<UINT> copy = priorities; // Make a copy to avoid modifying the original data while calculating priorities.
    for (size_t i = 0; i < priorities.numRows(); ++i) {
        for (size_t j = 0; j < priorities.numCols(); ++j) {
            UINT count = 0;
            for (int di = -1; di <= 1; ++di) {
                for (int dj = -1; dj <= 1; ++dj) {
                    if (di == 0 && dj == 0) continue; // Skip the current cell.
                    size_t ni = i + di;
                    size_t nj = j + dj;
                    if (ni >= 0 && ni < priorities.numRows() && nj >= 0 && nj < priorities.numCols() && copy[ni][nj] == 0) {
                        ++count;
                    }
                }
            }
            priorities[i][j] = count;
        }
    }
}

} // namespace Priorities

// Test cases to verify the solution correctness.
