    Mat2<UINT> grid(3, 3);
    grid[0] = {1, 0, 2};
    grid[1] = {0, 3, 0};
    grid[2] = {4, 0, 5};

    Priorities::calcPriorities(grid);

    for (size_t i = 0; i < grid.numRows(); ++i) {
        for (size_t j = 0; j < grid.numCols(); ++j) {
            std::cout << grid[i][j] << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
