typedef long long ll;

// Function to calculate the sum of all odd numbers in the range [i, j]
ll sum_of_odds(int i, int j) {
    ll res = 0;
    // Adjust i and j to be the nearest odd numbers within the range
    if (!(i & 1)) i++;
    if (!(j & 1)) j--;
    // Calculate the sum using arithmetic progression formula for odd numbers
    res = ((ll)(j + i) * (ll)((j - i) / 2 + 1)) / 2;
    return res;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int i, j;
        cin >> i >> j;
        cout << sum_of_odds(i, j) << endl;
    }
    return 0;
}
