#include <vector>

/**
 * Calculates the maximum total weight that can be accumulated by climbing
 * the staircase from the bottom to the top, moving either one or two steps at a time.
 *
 * @param n The number of steps in the staircase.
 * @param a The vector of weights associated with each step.
 * @return The maximum total weight that can be accumulated.
 */
int MaxWeightOfStair(unsigned n, const std::vector<int>& a) {
    if (n == 0) return 0;
    std::vector<int> D(n + 1);  // Array to store the maximum weights at each step
    D[0] = 0;
    D[1] = a[1];

    for (unsigned v = 2; v <= n; v++) {
        D[v] = std::max(D[v - 1] + a[v], D[v - 2] + a[v]);
    }
    return D[n];
}

int main() {
    unsigned n;
    std::cin >> n;
    std::vector<int> a(n + 1);  // Vector representing the weights of the steps
    a[0] = 0;  // The ground step has a weight of 0

    for (unsigned i = 1; i <= n; ++i) {
        std::cin >> a[i];
    }

    int result = MaxWeightOfStair(n, a);
    std::cout << result << std::endl;
    return 0;
}

// Test cases to verify the solution
int main() {
    // Test case 1
    unsigned n1 = 5;
    std::vector<int> a1 = {0, 1, 2, 3, 4, 5};  // Weights of the steps
    std::cout << "Test case 1 - Expected Result: 15, Actual Result: " << MaxWeightOfStair(n1, a1) << std::endl;

    // Test case 2
