#include <vector>
#include <unordered_set>
using namespace std;

class Solution {
public:
    int longestConsecutive(vector<int>& nums) {
        if (nums.size() <= 1) {
            return nums.size();
        }

        unordered_set<int> num_set(nums.begin(), nums.end());
        int len = 0;
        int max_len = 0;

        for (int num : nums) {
            if (num_set.find(num) == num_set.end()) {
                continue;
            }
            num_set.erase(num);
            len = 1;

            // Explore to the left
            int left = num - 1;
            while (num_set.find(left) != num_set.end()) {
                num_set.erase(left);
                left--;
                len++;
            }

            // Explore to the right
            int right = num + 1;
            while (num_set.find(right) != num_set.end()) {
                num_set.erase(right);
                right++;
                len++;
            }

            max_len = max(max_len, len);
        }
        return max_len;
    }
};

// Test cases
int main() {
    Solution solution;
    vector<int> test1 = {100, 4, 200, 1, 3, 2};
    vector<int> test2 = {0, -1};
    vector<int> test3 = {9, 1, 4, 7, 3, -2, 0, 5, 8, -1, 6};

    cout << "Test Case 1: " << solution.longestConsecutive(test1) << endl; // Expected output: 4
    cout << "Test Case 2: " << solution.longestConsecutive(test2) << endl; // Expected output: 2
    cout << "Test Case 3: " << solution.longestConsecutive(test3) << endl; // Expected output: 10

    return 0;
}
