// Assuming Point and Color classes are defined elsewhere
// For the sake of this example, minimal implementations are provided below.

class Point {
public:
    double x, y;

    Point(double x = 0.0, double y = 0.0) : x(x), y(y) {}

    double distanceTo(const Point& other) const {
        return std::sqrt((x - other.x) * (x - other.x) + (y - other.y) * (y - other.y));
    }
};

class Color {
public:
    int red, green, blue;

    Color(int red = 0, int green = 0, int blue = 0) : red(red), green(green), blue(blue) {}
};

class Pixel {
private:
    Point point_;
    Color color_;
    static size_t count;

public:
    Pixel() : point_(Point()), color_(Color()) { ++count; }
    Pixel(Point point) : point_(point), color_(Color()) { ++count; }
    Pixel(Point point, Color color) : point_(point), color_(color) { ++count; }
    Pixel(const Pixel& other) : point_(other.point_), color_(other.color_) { ++count; }
    ~Pixel() { --count; }

    Pixel& operator=(const Pixel& other) {
        if (this != &other) {
            point_ = other.point_;
            color_ = other.color_;
        }
        return *this;
    }

    bool operator==(const Pixel& other) const {
        return point_.x == other.point_.x && point_.y == other.point_.y &&
               color_.red == other.color_.red && color_.green == other.color_.green &&
               color_.blue == other.color_.blue;
    }

    Point getPoint() const { return point_; }
    Color getColor() const { return color_; }

    void setPoint(Point point) { point_ = point; }
    void setColor(Color color) { color_ = color; }

    void print() const {
        std::cout << "Pixel at (" << point_.x << ", " << point_.y << ") with color ("
                  << color_.red << ", " << color_.green << ", " << color_.blue << ")" << std::endl;
    }

    bool read() {
        std::cout << "Enter point (x y): ";
        if (!(std::cin >> point_.x >> point_.y)) return false;
        std::cout << "Enter color (r g b): ";
        if (!(std::cin >> color_.red >> color_.green >> color_.blue)) return false;
        return true;
    }

    void move(double delta_x, double delta_y) {
        point_.x += delta_x;
        point_.y += delta_y;
    }

    double dist(const Point& other) const {
        return point_.distanceTo(other);
    }

    static size_t getCount() {
        return count;
    }
};

size_t Pixel::count = 0;

// Test cases to verify the solution correctness
int main() {
    Pixel p1;
    Pixel p2(Point(5, 5), Color(255, 0, 0));
    Pixel p3 = p2;
    Pixel p4(Point(10, 10));

    p1.print();
    p2.print();
    p3.print();
    p4.print();

    std::cout << "Number of pixels created: " << Pixel::getCount() << std::endl;

    Point newPoint(15, 15);
    p1.setPoint(newPoint);
    Color newColor(0, 255, 0);
    p1.setColor(newColor);
    p1.print();

    p4.move(5, -5);
    p4.print();

    std::cout << "Distance between p1 and p4: " << p1.dist(p4.getPoint()) << std::endl;

    return 0;
}
