/**
 * Checks if the given string is balanced according to the following rule:
 * The string is balanced if the number of 'A's plus the number of 'C's is equal to the number of 'B's.
 * 
 * @param s The string to check.
 * @return A string "YES" if the string is balanced, "NO" otherwise.
 */
string isBalanced(const string& s) {
    int a = 0, b = 0, c = 0;

    for (char ch : s) {
        if (ch == 'A') a++;
        else if (ch == 'B') b++;
        else if (ch == 'C') c++;
    }

    return (a + c == b) ? "YES" : "NO";
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    int t;
    cin >> t;
    while (t--) {
        string s;
        cin >> s;
        cout << isBalanced(s) << '\n';
    }

    return 0;
}
