#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

/**
 * @brief Counts the number of unique strings after performing a transformation.
 * 
 * The transformation involves reversing each string and comparing it with the
 * original. If the reversed string is lexicographically smaller, it replaces
 * the original string. The function then counts the number of unique strings
 * in the transformed list.
 * 
 * @param n The number of strings in the list.
 * @param s The list of strings to be transformed.
 * @return int The count of unique strings after transformation.
 */
int countUniqueTransformedStrings(int n, vector<string>& s) {
  for (int i = 0; i < n; i++) {
    string tmp;
    for (int j = s[i].size() - 1; j >= 0; j--) {
      tmp += s[i][j];
    }
    if (s[i].compare(tmp) > 0) s[i] = tmp;
  }

  sort(s.begin(), s.end());

  int ans = 1;
  string cur = s[0];
  for (int i = 1; i < n; i++) {
    if (cur.compare(s[i]) != 0) {
      ans++;
      cur = s[i];
    }
  }
  return ans;
}

int main() {
  ios::sync_with_stdio(false);
  cin.tie(nullptr); cout.tie(nullptr);

  int n;
  cin >> n;
  vector<string> s(n);
  for (int i = 0; i < n; i++) {
    cin >> s[i];
  }

  cout << countUniqueTransformedStrings(n, s) << "\n";
  return 0;
}
