class RpcBuilder {
public:
    ErrorNo RegisterService(RpcService *rpc);

private:
    std::unordered_map<std::string, RpcService*> serviceLists_;
};

// RpcService class definition
class RpcService {
public:
    RpcService(const std::string& name) : serviceName_(name) {}

    std::string GetServiceName() const {
        return serviceName_;
    }

private:
    std::string serviceName_;
};

// Implementation of RpcBuilder::RegisterService
ErrorNo RpcBuilder::RegisterService(RpcService *rpc) {
    if (rpc == nullptr) {
        LOG_EX("invalid parameter");
        return ErrorNo::FAILURE;
    }
    std::string svName = rpc->GetServiceName();
    if (serviceLists_.count(svName) > 0) {
        LOG_EX("service %s already exists", svName.c_str());
        return ErrorNo::FAILURE;
    }

    serviceLists_[svName] = rpc;
    return ErrorNo::SUCCESS;
}

// Test cases
