using namespace std;

int maxEqualHeight(vector<int>& s1, vector<int>& s2, vector<int>& s3) {
    int sum1 = accumulate(s1.begin(), s1.end(), 0);
    int sum2 = accumulate(s2.begin(), s2.end(), 0);
    int sum3 = accumulate(s3.begin(), s3.end(), 0);

    int top1 = 0, top2 = 0, top3 = 0;
    int ans = 0;
    while (true) {
        if (top1 == s1.size() || top2 == s2.size() || top3 == s3.size()) {
            ans = 0;
            break;
        }
        if (sum1 == sum2 && sum2 == sum3) {
            ans = sum1;
            break;
        }
        if (sum1 >= sum2 && sum1 >= sum3) {
            sum1 -= s1[top1++];
        }
        if (sum2 >= sum1 && sum2 >= sum3) {
            sum2 -= s2[top2++];
        }
        if (sum3 >= sum2 && sum3 >= sum1) {
            sum3 -= s3[top3++];
        }
    }
    return ans;
}

int main() {
    int n1, n2, n3;
    cin >> n1 >> n2 >> n3;
    vector<int> s1(n1), s2(n2), s3(n3);
    for (int i = 0; i < n1; i++) cin >> s1[i];
    for (int i = 0; i < n2; i++) cin >> s2[i];
    for (int i = 0; i < n3; i++) cin >> s3[i];

    cout << maxEqualHeight(s1, s2, s3) << endl;
    return 0;
}
