#include <iostream>
#include <queue>
#include <fstream>
using namespace std;

// Function to add a number to the appropriate heap
void addNumber(int number, priority_queue<int, vector<int>, greater<int>> &minHeap, priority_queue<int> &maxHeap) {
    if (minHeap.empty() || number > minHeap.top()) {
        minHeap.push(number);
    } else {
        maxHeap.push(number);
    }
}

// Function to rebalance the heaps so their sizes differ by at most one
void rebalanceHeaps(priority_queue<int, vector<int>, greater<int>> &minHeap, priority_queue<int> &maxHeap) {
    int minHeapSize = minHeap.size();
    int maxHeapSize = maxHeap.size();
    if (minHeapSize - maxHeapSize > 1) {
        maxHeap.push(minHeap.top());
        minHeap.pop();
    } else if (maxHeapSize - minHeapSize > 1) {
        minHeap.push(maxHeap.top());
        maxHeap.pop();
    }
}

// Function to get the current median
int getMedian(priority_queue<int, vector<int>, greater<int>> &minHeap, priority_queue<int> &maxHeap) {
    int minHeapSize = minHeap.size();
    int maxHeapSize = maxHeap.size();
    if (minHeapSize == maxHeapSize) {
        return maxHeap.top();
    } else {
        return (minHeapSize > maxHeapSize) ? minHeap.top() : maxHeap.top();
    }
}

int main() {
    int currentNumber;
    long long unsigned int total = 0;
    fstream numberFile;
    numberFile.open("numbers.txt");

    priority_queue<int, vector<int>, greater<int>> minHeap; // Min-heap for the larger half
    priority_queue<int> maxHeap; // Max-heap for the smaller half

    if (numberFile.is_open()) {
        while (numberFile >> currentNumber) {
            addNumber(currentNumber, minHeap, maxHeap);
            rebalanceHeaps(minHeap, maxHeap);
            int median = getMedian(minHeap, maxHeap);
            cout << "Current median: " << median << endl;
            total += median;
        }
    } else {
        cerr << "Unable to open file 'numbers.txt'" << endl;
        return 1;
    }

    total = total % 10000;
    cout << "Final result: " << total << endl;

    return 0;
}
