    // Function to return Breadth First Traversal of given graph.
    vector<int> bfsOfGraph(int V, vector<int> adj[]) {
        vector<int> visited(V, 0);
        vector<int> res;
        queue<int> q;
        q.push(0);
        visited[0] = 1;

        while (!q.empty()) {
            int val = q.front();
            q.pop();
            res.push_back(val);
            for (auto it : adj[val]) {
                if (!visited[it]) {
                    q.push(it);
                    visited[it] = 1;
                }
            }
        }
        return res;
    }
