int main()
{  
   const int N = 2000000; // Limit up to which we want to find prime numbers
   clock_t cstart = clock(); // Start the clock to measure time

   bitset<N + 1> b; // Create a bitset for marking non-prime numbers
   int count = 0; // Counter for prime numbers
   int i;
   // Initialize all numbers as prime
   for (i = 2; i <= N; i++)
      b.set(i);
   // Sieve of Eratosthenes algorithm
   i = 2;
   while (i * i <= N)
   {  
      if (b.test(i)) // If the number is marked as prime
      {  
         count++;
         int k = 2 * i;
         // Mark all multiples of i as non-prime
         while (k <= N)
         {  
            b.reset(k);
            k += i;
         }
      }
      i++;
   }
   // Count the remaining primes
   while (i <= N)
   {  
      if (b.test(i))
         count++;
      i++;
   }

   clock_t cend = clock(); // End the clock
   double millis = 1000.0 * (cend - cstart) / CLOCKS_PER_SEC; // Calculate time taken

   cout << count << " primes\n" << millis << " milliseconds\n"; // Output the result

   return 0;
}
