using namespace std;

typedef long long ll;

/**
 * Calculates the maximum points a player can score in a game with given rules.
 * 
 * @param n The total number of actions the player can perform.
 * @param a The number of points scored each time Action A is performed.
 * @param b The number of points scored when Action B is performed after 'a' Action A's.
 * @return The maximum number of points the player can score.
 */
ll max_points(ll n, ll a, ll b) {
    ll div = n / (a + 1);
    if (n % (a + 1) == 0ll)
        return div * a;
    ll res = div * a;
    ll remain = n - div * (a + 1);
    remain = min(a, remain);
    return res + remain;
}

int main() {
    // Test cases
    cout << max_points(10, 2, 3) << endl; // Should output 8
    cout << max_points(15, 5, 10) << endl; // Should output 15
    cout << max_points(7, 1, 2) << endl; // Should output 6
    cout << max_points(0, 1, 2) << endl; // Should output 0
    cout << max_points(1, 1, 2) << endl; // Should output 1
    return 0;
}
