using namespace std;

class SampleGraph {
public:
    static vector<int>* create(int numberOfNodes, int numberOfConnections, bool isDirected);
    static void print(vector<int>* graph, int numberOfNodes);
};

vector<int>* SampleGraph::create(int numberOfNodes, int numberOfConnections, bool isDirected) {
    vector<int>* result = new vector<int>[numberOfNodes];
    int counter = 0;
    while (counter < numberOfConnections) {
        int source = rand() % numberOfNodes;
        int target = rand() % numberOfNodes;
        if (source != target) {
            if (find(result[source].begin(), result[source].end(), target) == result[source].end()) {
                result[source].push_back(target);
                if (!isDirected)
                    result[target].push_back(source);
                counter++;
            }
        }
    }
    for (int i = 0; i < numberOfNodes; i++) {
        sort(result[i].begin(), result[i].end());
    }
    return result;
}

void SampleGraph::print(vector<int>* graph, int numberOfNodes) {
    for (int i = 0; i < numberOfNodes; i++) {
        cout << "Node " << i << "\t";
        for (int node : graph[i]) {
            cout << node << ", ";
        }
        cout << endl;
    }
}

bool isConnected(vector<int>* graph, int numberOfNodes, int nodeA, int nodeB) {
    vector<bool> visited(numberOfNodes, false);
    queue<int> q;
    q.push(nodeA);
    visited[nodeA] = true;
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        if (current == nodeB) {
            return true;
        }
        for (int neighbor : graph[current]) {
            if (!visited[neighbor]) {
                visited[neighbor] = true;
                q.push(neighbor);
            }
        }
    }
    return false;
}

int findShortestPath(vector<int>* graph, int numberOfNodes, int start, int end) {
    if (start == end) return 0;
    vector<int> distance(numberOfNodes, -1);
    queue<int> q;
    q.push(start);
    distance[start] = 0;
    while (!q.empty()) {
        int current = q.front();
        q.pop();
        for (int neighbor : graph[current]) {
            if (distance[neighbor] == -1) {
                distance[neighbor] = distance[current] + 1;
                q.push(neighbor);
                if (neighbor == end) {
                    return distance[neighbor];
                }
            }
        }
    }
    return -1;
}

int main() {
    srand(15);
    const int NUMBER_OF_NODES = 7;
    const int NUMBER_OF_CONNECTIONS = 12;
    vector<int>* graph = SampleGraph::create(NUMBER_OF_NODES, NUMBER_OF_CONNECTIONS, true);
    SampleGraph::print(graph, NUMBER_OF_NODES);

    int nodeA = 0;
    int nodeB = 6;
    cout << "Is there a path between " << nodeA << " and " << nodeB << "? " << (isConnected(graph, NUMBER_OF_NODES, nodeA, nodeB) ? "Yes" : "No") << endl;
    cout << "Shortest path length between " << nodeA << " and " << nodeB << ": " << findShortestPath(graph, NUMBER_OF_NODES, nodeA, nodeB) << endl;

    delete[] graph;
    return 0;
}
