            std::string szfilename = blockfilename + ".bsize";
            FILE * f = fopen(szfilename.c_str(), "w");
            fwrite(&size, 1, sizeof(int), f);
            fclose(f);

            if (size > 20000000) {
                logstream(LOG_DEBUG, "Block " + blockfilename + " size:" + std::to_string(size));
            }
        }

        static void delete_block_uncompressed_sizefile(const std::string& blockfilename) {
