    template <typename ET>
    class DynamicDataBlock {
    private:
        int nitems;
        uint8_t * data;
        ET * chivecs;

    public:
        DynamicDataBlock() : nitems(0), data(NULL), chivecs(NULL) {}

        DynamicDataBlock(int nitems, uint8_t * data, int datasize) : nitems(nitems) {
            chivecs = new ET[nitems];
            uint8_t * ptr = data;
            for(int i = 0; i < nitems; i++) {
                assert(ptr - data <= datasize);
                typename ET::sizeword_t * sz = reinterpret_cast<typename ET::sizeword_t *>(ptr);
                ptr += sizeof(typename ET::sizeword_t);
                chivecs[i] = ET(sz->size, sz->capacity, reinterpret_cast<typename ET::element_type_t *>(ptr));
                ptr += sz->capacity * sizeof(typename ET::element_type_t);
            }
        }

        ET& edgevec(int i) {
            assert(i < nitems);
            assert(chivecs != NULL);
            return chivecs[i];
        }

        void write(uint8_t ** outdata, int & size) {
            // First compute size
            size = 0;
            for(int i = 0; i < nitems; i++) {
                size += chivecs[i].capacity() * sizeof(typename ET::element_type_t) + sizeof(typename ET::sizeword_t);
            }

            *outdata = static_cast<uint8_t *>(malloc(size));
            uint8_t * ptr = *outdata;
            for(int i = 0; i < nitems; i++) {
                ET & vec = chivecs[i];
                reinterpret_cast<uint16_t *>(ptr)[0] = static_cast<uint16_t>(vec.size());
                reinterpret_cast<uint16_t *>(ptr)[1] = static_cast<uint16_t>(vec.capacity());

                ptr += sizeof(typename ET::sizeword_t);
                vec.write(reinterpret_cast<typename ET::element_type_t *>(ptr));
                ptr += vec.capacity() * sizeof(typename ET::element_type_t);
            }
        }

        ~DynamicDataBlock() {
            if (chivecs != NULL) {
                delete [] chivecs;
            }
        }
    };

    // Example usage of DynamicDataBlock with a mock ET class
    struct MockET {
        using sizeword_t = struct { uint16_t size; uint16_t capacity; };
        using element_type_t = int;

        sizeword_t sizeword;
        element_type_t *elements;

        MockET(uint16_t size, uint16_t capacity, element_type_t *elements)
            : sizeword({size, capacity}), elements(elements) {}

        uint16_t size() const { return sizeword.size; }
        uint16_t capacity() const { return sizeword.capacity; }

        void write(element_type_t *dest) {
            for (uint16_t i = 0; i < sizeword.capacity; ++i) {
                dest[i] = elements[i];
            }
        }
    };

    // Test cases
    void test_block_file_manager() {
        std::string filename = "test_block";
        int defaultSize = 1024;
        int newSize = 25000000;

        // Write new size
        BlockFileManager::write_block_uncompressed_size(filename, newSize);

        // Read size
        int readSize = BlockFileManager::get_block_uncompressed_size(filename, defaultSize);
        assert(readSize == newSize);

        // Delete size file
        BlockFileManager::delete_block_uncompressed_sizefile(filename);

        // Read size after deletion, should return default size
        readSize = BlockFileManager::get_block_uncompressed_size(filename, defaultSize);
