#include <iostream>
using namespace std;

class Complex {
private:
    int real;
    int img;

public:
    Complex(int x = 0, int y = 0) : real(x), img(y) {}

    Complex operator-(const Complex& c) const {
        return Complex(real - c.real, img - c.img);
    }

    Complex operator*(const Complex& c) const {
        return Complex(real * c.real - img * c.img, real * c.img + img * c.real);
    }

    Complex& operator--() {
        --real;
        --img;
        return *this;
    }

    Complex operator--(int) {
        Complex temp = *this;
        --(*this);
        return temp;
    }

    friend ostream& operator<<(ostream& os, const Complex& c) {
        os << c.real << " + i" << c.img;
        return os;
    }
};

int main() {
    Complex c1(7, 8);
    Complex c2(5, 6);

    cout << "c1 = " << c1 << endl;
    cout << "c2 = " << c2 << endl;

    Complex c3 = c1 - c2;
    cout << "c1 - c2 = " << c3 << endl;

    cout << "c1-- = ";
    c1--;
    cout << c1 << endl;

    cout << "--c2 = ";
    --c2;
    cout << c2 << endl;

    Complex c4 = c1 * c2;
    cout << "c1 * c2 = " << c4 << endl;

    return 0;
}
