using namespace std;

/**
 * Finds the maximum product of all elements in the array except for the element at the same index.
 * 
 * @param nums The input array of integers.
 * @return A vector<int> where each element is the maximum product of all other elements.
 */
vector<int> findMaxProduct(vector<int>& nums) {
    int sz = nums.size();
    vector<int> maxProduct(sz, 0);
    if(sz <= 1) return maxProduct;

    maxProduct[0] = 1;
    for(int i = 1; i < sz; i++) {
        maxProduct[i] = maxProduct[i-1] * nums[i-1];
    }

    int rightProduct = nums[sz-1];
    for(int i = sz - 2; i >= 0; i--) {
        maxProduct[i] *= rightProduct;
        rightProduct *= nums[i];
    }

    return maxProduct;
}

int main() {
    // Test cases
    vector<int> test1 = {1, 2, 3, 4};
    vector<int> test2 = {2, 3, 4, 5};
    vector<int> test3 = {0, 0};
    vector<int> test4 = {0, 1, 2, 3, 4};
    vector<int> test5 = {1};

    vector<vector<int>> testCases = {test1, test2, test3, test4, test5};
    for (auto& test : testCases) {
        vector<int> result = findMaxProduct(test);
        for (int num : result) {
            cout << num << " ";
        }
        cout << endl;
    }
    return 0;
}
