#include <stdexcept>

// Define a simple Task structure.
struct Task {
    int id;
    std::string description;
    std::string status;
};

// TaskManager class to handle task operations.
class TaskManager {
private:
    std::map<int, Task> tasks;
    int next_id;
    std::string db_file;

    void loadTasks() {
        std::ifstream file(db_file);
        std::string line;
        while (getline(file, line)) {
            std::istringstream iss(line);
            Task task;
            if (!(iss >> task.id >> task.status)) { break; } // error
            std::getline(iss, task.description);
            tasks[task.id] = task;
            next_id = std::max(next_id, task.id + 1);
        }
        file.close();
    }

    void saveTasks() {
        std::ofstream file(db_file);
        for (const auto& pair : tasks) {
            const Task& task = pair.second;
            file << task.id << " " << task.status << " " << task.description << std::endl;
        }
        file.close();
    }

public:
    TaskManager(const std::string& filename) : next_id(1), db_file(filename) {
        loadTasks();
    }

    void init() {
        tasks.clear();
        next_id = 1;
        saveTasks();
    }

    void addTask(const std::string& description) {
        Task task = {next_id++, description, "pending"};
        tasks[task.id] = task;
        saveTasks();
    }

    void removeTask(int id) {
        if (tasks.erase(id) == 0) {
            throw std::runtime_error("Task ID not found.");
        }
        saveTasks();
    }

    void listTasks() {
        for (const auto& pair : tasks) {
            const Task& task = pair.second;
            std::cout << task.id << ": " << task.description << " [" << task.status << "]" << std::endl;
        }
    }
};

// Main function to handle command-line arguments and invoke TaskManager methods.
int main(int argc, char* argv[]) {
    if (argc < 2) {
        std::cerr << "Usage: " << argv[0] << " <command> [arguments]" << std::endl;
        return 1;
    }

    TaskManager manager("tasks.db");
    std::string command = argv[1];

    try {
        if (command == "init") {
            manager.init();
        } else if (command == "add") {
            if (argc < 3) {
                throw std::runtime_error("Missing task description.");
            }
            manager.addTask(argv[2]);
        } else if (command == "remove") {
            if (argc < 3) {
                throw std::runtime_error("Missing task ID.");
            }
            manager.removeTask(std::stoi(argv[2]));
        } else if (command == "list") {
            manager.listTasks();
        } else if (command == "help") {
            std::cout << "Available commands:" << std::endl;
            std::cout << "  init - Initializes the task database." << std::endl;
            std::cout << "  add <description> - Adds a new task." << std::endl;
            std::cout << "  remove <id> - Removes a task by ID." << std::endl;
            std::cout << "  list - Lists all tasks." << std::endl;
            std::cout << "  help - Shows this help message." << std::endl;
        } else {
            throw std::runtime_error("Unknown command: " + command);
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return 1;
    }

    return 0;
}
