    Student(std::string n, int s, int id) : name(n), score(s), stu_id(id) {}
    int getScore() const { return score; }
    int getStuId() const { return stu_id; }
    const std::string& getName() const { return name; }

    bool operator<(const Student& s) const { return score < s.score; }
    bool operator==(const Student& s) const { return stu_id == s.stu_id; }
    bool operator>(const Student& s) const { return stu_id > s.stu_id; }
    Student& operator=(const Student& s) {
        if (this != &s) {
            name = s.name;
            score = s.score;
            stu_id = s.stu_id;
        }
        return *this;
    }

    friend std::ostream& operator<<(std::ostream& o, const Student& s) {
        o << "name: " << s.name << " stu_id: " << s.stu_id << " score: " << s.score;
        return o;
    }
};

enum class CompareMode { Normal, Reverse };

template<CompareMode mode, typename MemberType, MemberType Student::*Member>
struct Compare {
    bool operator()(const Student& s1, const Student& s2) const {
        if (mode == CompareMode::Normal) {
            return s1.*Member < s2.*Member;
        } else {
            return s1.*Member > s2.*Member;
        }
    }
};

int main() {
    srand(static_cast<unsigned>(time(nullptr)));

    // Create a set of Students sorted by score in descending order
    std::set<Student, Compare<CompareMode::Reverse, int, &Student::getScore>> studentsByScore;
    for (int i = 0; i < 10; ++i) {
        studentsByScore.insert(Student("Student_" + std::to_string(i), rand() % 100, i));
    }

    // Print the students sorted by score
    std::cout << "Students sorted by score (descending):" << std::endl;
    for (const auto& student : studentsByScore) {
        std::cout << student << std::endl;
    }

    // Create a set of Students sorted by name in ascending order
    std::set<Student, Compare<CompareMode::Normal, std::string, &Student::getName>> studentsByName;
    for (const auto& student : studentsByScore) {
        studentsByName.insert(student);
    }

    // Print the students sorted by name
    std::cout << "\nStudents sorted by name (ascending):" << std::endl;
    for (const auto& student : studentsByName) {
        std::cout << student << std::endl;
    }

    return 0;
}
