const int ARRAY_SIZE = 10; // Define the size of the array

void reverseArray(int *arr, int size) {
  // Function to reverse the array using pointers
  int *start = arr;
  int *end = arr + size - 1;
  while (start < end) {
    // Swap the values at the start and end pointers
    int temp = *start;
    *start = *end;
    *end = temp;
    // Move the pointers towards the center of the array
    ++start;
    --end;
  }
}

int main() {
  int ia[ARRAY_SIZE];

  // Initialize the array with consecutive integers starting from 1
  for (int i = 0; i < ARRAY_SIZE; ++i) {
    ia[i] = i + 1;
  }

  // Reverse the array
  reverseArray(ia, ARRAY_SIZE);

  // Print the reversed array
  for (int i = 0; i < ARRAY_SIZE; ++i) {
    cout << ia[i] << " ";
  }
