// Function to count the number of bits set to 1 in the binary representation of a number
int countBits(long long n) {
    int count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);

    long long ans = 0;
    int t;
    cin >> t;
    for (int i = 1; i <= t; ++i) {
        long long n, m;
        cin >> n >> m;
        int cnt = countBits(n);
        if (cnt <= m) ans ^= i;
        else ans ^= (i - 1);
        cout << ans << '\n';
    }
    return 0;
}
