#include <iostream>
#include <vector>
using namespace std;

long long merge_inv(vector<int>& a, int left, int mid, int right) {
    int i = left, j = mid, k = 0;
    vector<int> tempArr(right - left + 1);
    long long cnt = 0;
    while (i < mid && j <= right) {
        if (a[i] <= a[j]) {
            tempArr[k++] = a[i++];
        } else {
            cnt += (mid - i); // Count the inversions
            tempArr[k++] = a[j++];
        }
    }
    while (i < mid) {
        tempArr[k++] = a[i++];
    }
    while (j <= right) {
        tempArr[k++] = a[j++];
    }
    for (int i = left, k = 0; i <= right; i++, k++) {
        a[i] = tempArr[k];
    }
    return cnt;
}

long long mergeSort(vector<int>& a, int left, int right) {
    long long cnt = 0;
    if (right > left) {
        int mid = left + (right - left) / 2;
        long long leftCount = mergeSort(a, left, mid);
        long long rightCount = mergeSort(a, mid + 1, right);
        long long mergeCount = merge_inv(a, left, mid + 1, right);
        return leftCount + rightCount + mergeCount;
    }
    return cnt;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> ar(n);
        for (int i = 0; i < n; i++) {
            cin >> ar[i];
        }
        cout << mergeSort(ar, 0, n - 1) << endl;
    }
    return 0;
}
