        sort(intervals.begin(), intervals.end(), cmp);
        vector<interval> merged;

        for (const auto& interv : intervals) {
            if (merged.empty() || merged.back().end < interv.start) {
                merged.push_back(interv);
            } else {
                merged.back().end = max(merged.back().end, interv.end);
            }
        }

        for (const auto& interv : merged) {
            cout << interv.start << ' ' << interv.end << endl;
        }
    }

