/**
 * Calculates the geometric property q based on the given formula and arrays.
 * 
 * @param x Array of floats representing the first set of dimensions.
 * @param y Array of floats representing the second set of dimensions.
 * @param z Array of floats representing the third set of dimensions.
 * @param n Size of the first array.
 * @param m Size of the second array.
 * @param k Size of the third array.
 * @param a Floating-point number used in the formula.
 * @param b Floating-point number used in the formula.
 * @return The calculated value of q.
 */
float calculateGeometricProperty(float x[], float y[], float z[], int n, int m, int k, float a, float b) {
    float c = a / b;
    sort(x, x + n);
    sort(y, y + m);
    sort(z, z + k);

    float r1 = x[n - 1];
    float p1 = y[m - 1];
    float p2 = z[0];

    float q = sqrt((r1 * r1 * p1) / (p2 * c + p1));

    cout << setprecision(8) << q;
    return q;
}

int main() {
    int n, m, k;
    float a, b;

    cin >> n;
    vector<float> x(n);
    for (int i = 0; i < n; i++) {
        cin >> x[i];
    }

    cin >> m;
    vector<float> y(m);
    for (int i = 0; i < m; i++) {
        cin >> y[i];
    }

    cin >> k;
    vector<float> z(k);
    for (int i = 0; i < k; i++) {
        cin >> z[i];
    }

    cin >> a >> b;
    calculateGeometricProperty(x.data(), y.data(), z.data(), n, m, k, a, b);
    return 0;
}

