/**
 * Finds the largest integer within the range [n, m] whose sum of digits equals k.
 * @param n The start of the range.
 * @param m The end of the range.
 * @param k The target digit sum.
 * @return The largest integer with digit sum k, or -1 if no such number exists.
 */
int findLargestWithDigitSum(int n, int m, int k) {
    for (int i = m; i >= n; --i) {
        int a = i, sum = 0;
        while (a) {
            sum += (a % 10);
            a /= 10;
        }
        if (sum == k) {
            return i;
        }
    }
    return -1;
}

