const double DEG_TO_RAD = M_PI / 180.0;

/**
 * Converts geographic coordinates from latitude and longitude to Cartesian coordinates on a unit sphere.
 * @param lat The latitude in degrees.
 * @param lon The longitude in degrees.
 * @param x Reference to the X coordinate to be set.
 * @param y Reference to the Y coordinate to be set.
 * @param z Reference to the Z coordinate to be set.
 */
void LatLonToXYZ(double lat, double lon, double& x, double& y, double& z) {
    if (lat < -90.0 || lat > 90.0 || lon < -180.0 || lon > 180.0) {
        std::cerr << "Invalid latitude or longitude value." << std::endl;
        return;
    }
    double lat_rad = lat * DEG_TO_RAD;
    double lon_rad = lon * DEG_TO_RAD;
    double r = std::cos(lat_rad);
    x = r * std::cos(lon_rad);
    y = std::sin(lat_rad);
    z = r * std::sin(lon_rad);
}

