#include <iostream>
#include <vector>
#include <limits>
#include <algorithm>

using namespace std;

class RangeQueryProcessor {
private:
    vector<int> rangeMin;
    vector<int> rangeMax;
    int n;

    int buildSegmentTree(const vector<int>& arr, int left, int right, int node, bool isMin) {
        if (left == right) {
            if (isMin) {
                return rangeMin[node] = arr[left];
            } else {
                return rangeMax[node] = arr[left];
            }
        }
        int mid = (left + right) / 2;
        int leftVal = buildSegmentTree(arr, left, mid, node * 2, isMin);
        int rightVal = buildSegmentTree(arr, mid + 1, right, node * 2 + 1, isMin);
        if (isMin) {
            return rangeMin[node] = min(leftVal, rightVal);
        } else {
            return rangeMax[node] = max(leftVal, rightVal);
        }
    }

    int query(int left, int right, int node, int nodeLeft, int nodeRight, bool isMin) {
        if (right < nodeLeft || left > nodeRight) {
            return isMin ? numeric_limits<int>::max() : numeric_limits<int>::min();
        }
        if (left <= nodeLeft && right >= nodeRight) {
            return isMin ? rangeMin[node] : rangeMax[node];
        }
        int mid = (nodeLeft + nodeRight) / 2;
        int leftVal = query(left, right, node * 2, nodeLeft, mid, isMin);
        int rightVal = query(left, right, node * 2 + 1, mid + 1, nodeRight, isMin);
        return isMin ? min(leftVal, rightVal) : max(leftVal, rightVal);
    }

    void update(int index, int newValue, int node, int nodeLeft, int nodeRight) {
        if (index < nodeLeft || index > nodeRight) {
            return;
        }
        if (nodeLeft == nodeRight) {
            rangeMin[node] = newValue;
            rangeMax[node] = newValue;
            return;
        }
        int mid = (nodeLeft + nodeRight) / 2;
        update(index, newValue, node * 2, nodeLeft, mid);
        update(index, newValue, node * 2 + 1, mid + 1, nodeRight);
        rangeMin[node] = min(rangeMin[node * 2], rangeMin[node * 2 + 1]);
        rangeMax[node] = max(rangeMax[node * 2], rangeMax[node * 2 + 1]);
    }

public:
    RangeQueryProcessor(const vector<int>& arr) {
        n = arr.size();
        rangeMin.resize(n * 4);
        rangeMax.resize(n * 4);
        buildSegmentTree(arr, 0, n - 1, 1, true);
        buildSegmentTree(arr, 0, n - 1, 1, false);
    }

    int queryMin(int left, int right) {
        return query(left, right, 1, 0, n - 1, true);
    }

    int queryMax(int left, int right) {
        return query(left, right, 1, 0, n - 1, false);
    }

    void update(int index, int value) {
        update(index, value, 1, 0, n - 1);
    }
};

int main() {
    vector<int> arr = {1, 3, 5, 7, 9, 11};
    RangeQueryProcessor rqp(arr);

    // Test cases
    cout << "QueryMin(1, 4): " << rqp.queryMin(1, 4) << endl; // Should return 3
    cout << "QueryMax(1, 4): " << rqp.queryMax(1, 4) << endl; // Should return 9

    rqp.update(2, 2); // Update index 2 to value 2

    cout << "QueryMin(1, 4) after update: " << rqp.queryMin(1, 4) << endl; // Should return 2
    cout << "QueryMax(1, 4) after update: " << rqp.queryMax(1, 4) << endl; // Should return 9

    return 0;
}
