Design a class `BinarySearchTree` that encapsulates the operations of a binary search tree (BST) and provides the following functionalities:

1. `insert(int value)`: Inserts a new value into the BST.
2. `findTargetSum(int target)`: Returns `true` if there exist two elements in the BST that add up to the given target sum, otherwise returns `false`.
3. `flattenToLinkedList()`: Flattens the BST into a sorted linked list in-place (using the right pointers to point to the next node in the list).
4. `balance()`: Balances an unbalanced BST to become a height-balanced BST.
5. `constructFromPreorder(vector<int> &preorder)`: Constructs a BST from a given preorder traversal vector.

The BST nodes should have the following structure:

```cpp
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
```

The linked list nodes should have the following structure:

```cpp
struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};
```

output:
```cpp
#include <iostream>
#include <vector>
#include <climits>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

struct ListNode {
    int val;
    ListNode *next;
    ListNode(int x) : val(x), next(NULL) {}
};

class BinarySearchTree {
private:
    TreeNode *root;

    void inorder(TreeNode *node, vector<int> &values) {
        if (node == NULL) {
            return;
        }
        inorder(node->left, values);
        values.push_back(node->val);
        inorder(node->right, values);
    }

    TreeNode *inorderToBST(int start, int end, vector<int> &values) {
        if (start > end) {
            return NULL;
        }
        int mid = start + (end - start) / 2;
        TreeNode *node = new TreeNode(values[mid]);
        node->left = inorderToBST(start, mid - 1, values);
        node->right = inorderToBST(mid + 1, end, values);
        return node;
    }

    TreeNode *constructBSTFromPreorder(vector<int> &preorder, int mini, int maxi, int &i) {
        if (i >= preorder.size() || preorder[i] < mini || preorder[i] > maxi) {
            return NULL;
        }
        TreeNode *node = new TreeNode(preorder[i++]);
        node->left = constructBSTFromPreorder(preorder, mini, node->val, i);
        node->right = constructBSTFromPreorder(preorder, node->val, maxi, i);
        return node;
    }

    void insertIntoBST(TreeNode *&node, int value) {
        if (node == NULL) {
            node = new TreeNode(value);
            return;
        }
        if (value < node->val) {
            insertIntoBST(node->left, value);
        } else {
            insertIntoBST(node->right, value);
        }
    }

    void flatten(TreeNode *node, TreeNode *&prev) {
        if (node == NULL) {
            return;
        }
        flatten(node->right, prev);
        flatten(node->left, prev);
        node->right = prev;
        node->left = NULL;
        prev = node;
    }

public:
    BinarySearchTree() : root(NULL) {}

    void insert(int value) {
        insertIntoBST(root, value);
    }

    bool findTargetSum(int target) {
        vector<int> values;
        inorder(root, values);
        int i = 0, j = values.size() - 1;
        while (i < j) {
            int sum = values[i] + values[j];
            if (sum == target) {
                return true;
            } else if (sum > target) {
                j--;
            } else {
                i++;
            }
        }
        return false;
    }

    ListNode* flattenToLinkedList() {
        TreeNode *prev = NULL;
        flatten(root, prev);
        ListNode *head = NULL, *current = NULL;
        while (prev != NULL) {
            if (head == NULL) {
                head = new ListNode(prev->val);
                current = head;
            } else {
                current->next = new ListNode(prev->val);
                current = current->next;
            }
            prev = prev->right;
        }
        return head;
    }

    void balance() {
        vector<int> values;
        inorder(root, values);
        root = inorderToBST(0, values.size() - 1, values);
    }

    void constructFromPreorder(vector<int> &preorder) {
        int i = 0;
        root = constructBSTFromPreorder(preorder, INT_MIN, INT_MAX, i);
    }
};

// Test cases
int main() {
    BinarySearchTree bst;
    bst.insert(10);
    bst.insert(5);
    bst.insert(15);
    bst.insert(2);
    bst.insert(7);
    bst.insert(12);
    bst.insert(17);

    cout << "Find target sum 9: " << (bst.findTargetSum(9) ? "True" : "False") << endl;
    cout << "Find target sum 22: " << (bst.findTargetSum(22) ? "True" : "False") << endl;

    ListNode *flattenedList = bst.flattenToLinkedList();
    cout << "Flattened BST to Linked List: ";
    for (ListNode *current = flattenedList; current != NULL; current = current->next) {
        cout << current->val << " ";
    }
    cout << endl;

    bst.balance();
    cout << "Balanced BST inorder traversal: ";
    vector<int> balancedInorder;
    bst.inorder(bst.root, balancedInorder);
    for (int val : balancedInorder) {
        cout << val << " ";
    }
    cout << endl;

