// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    void inorderTraversal(TreeNode *root, std::vector<int> &elements) {
        if (!root) return;
        inorderTraversal(root->left, elements);
        elements.push_back(root->val);
        inorderTraversal(root->right, elements);
    }

    std::vector<int> getAllElements(TreeNode *root1, TreeNode *root2) {
        std::vector<int> elements;
        inorderTraversal(root1, elements);
        inorderTraversal(root2, elements);
        std::sort(elements.begin(), elements.end());
        return elements;
    }
};

// Helper function to create a new TreeNode.
TreeNode* newNode(int value) {
    return new TreeNode(value);
}

// Test cases to verify the solution correctness.
int main() {
    // Create test trees using newNode.
    TreeNode *root1 = newNode(2);
    root1->left = newNode(1);
    root1->right = newNode(4);

    TreeNode *root2 = newNode(1);
    root2->left = newNode(0);
    root2->right = newNode(3);

    Solution solution;
    std::vector<int> result = solution.getAllElements(root1, root2);

    // Expected output: [0,1,1,2,3,4]
    for (int num : result) {
        std::cout << num << " ";
    }

    return 0;
}
