int weighted_sum(initializer_list<int> numbers, initializer_list<int> weights)
{
    if (numbers.size() != weights.size())
    {
        throw invalid_argument("Numbers and weights lists must be of the same length.");
    }

    int sum = 0;
    auto num_it = numbers.begin();
    auto weight_it = weights.begin();

    while (num_it != numbers.end())
    {
        sum += (*num_it) * (*weight_it);
        ++num_it;
        ++weight_it;
    }

    return sum;
}

