/**
 * Merges two sorted arrays into one sorted array.
 * 
 * @param arr1 The first sorted array with enough space to hold elements from arr2.
 * @param m The number of initialized elements in arr1.
 * @param arr2 The second sorted array.
 * @param n The number of elements in arr2.
 */
void mergeAndSortArrays(std::vector<int>& arr1, int m, const std::vector<int>& arr2, int n) {
    int writeIndex = m + n - 1; // Index to write the merged element
    int index1 = m - 1; // Last initialized element in arr1
    int index2 = n - 1; // Last element in arr2

    // Merge arr2 into arr1 starting from the end
    while (index1 >= 0 && index2 >= 0) {
        if (arr1[index1] > arr2[index2]) {
            arr1[writeIndex] = arr1[index1];
            --index1;
        } else {
            arr1[writeIndex] = arr2[index2];
            --index2;
        }
        --writeIndex;
    }

    // If there are remaining elements in arr2, copy them
    while (index2 >= 0) {
        arr1[writeIndex] = arr2[index2];
        --index2;
        --writeIndex;
    }

    // No need to copy the remaining elements from arr1, as they are already in place
}

// Test cases
int main() {
    std::vector<int> arr1 = {1, 2, 3, 0, 0, 0};
    std::vector<int> arr2 = {2, 5, 6};
    int m = 3, n = 3;

    mergeAndSortArrays(arr1, m, arr2, n);

    // Output should be: [1, 2, 2, 3, 5, 6]
    for (int num : arr1) {
        std::cout << num << " ";
    }
    std::cout << std::endl;

    return 0;
}
