#include <iostream>
#include <iomanip>
#include <cmath>

// Function to calculate the position of the Sun in the ecliptic coordinate system
void calculateSunPosition(uint16_t year, uint8_t month, uint8_t day, uint8_t hour, uint16_t minute, uint8_t second, double& r, double& r_x, double& r_y, double& r_z) {
    // Computes Julian day number at 0 UT for any year between 1900 and 2100
    double julian_days = 367 * year -
                         static_cast<int>(7 * (year + static_cast<int>((month + 9) / 12)) / 4) +
                         static_cast<int>(275 * month / 9) +
                         day + 1721013.5 +
                         hour / 24.0 + minute / 1440.0 + second / 86400.0;

    double T = (julian_days - 2451545.0) / 36525.0;
    double lambda_M = 280.460 + 36000.771 * T;
    double M = 357.5291092 + 35999.05034 * T;
    double lambda_ecliptic = lambda_M + 1.914666471 * sin(M * M_PI / 180.0) +
                             0.019994643 * sin(2 * M * M_PI / 180.0);
    double epsilon = 23.439291 - 0.0130042 * T;

    r = 1.000140612 - 0.016708617 * cos(M * M_PI / 180.0) - 0.000139589 * cos(2 * M * M_PI / 180.0);

    r_x = r * cos(lambda_ecliptic * M_PI / 180.0);
    r_y = r * cos(epsilon * M_PI / 180.0) * sin(lambda_ecliptic * M_PI / 180.0);
    r_z = r * sin(epsilon * M_PI / 180.0) * sin(lambda_ecliptic * M_PI / 180.0);
}

int main() {
    // Input
    uint16_t year = 2021;
    uint8_t month = 8;
    uint8_t day = 26;
    uint8_t hour = 0;
    uint16_t minute = 0;
    uint8_t second = 0;

    double r, r_x, r_y, r_z;
    calculateSunPosition(year, month, day, hour, minute, second, r, r_x, r_y, r_z);

    // Output
    std::cout << std::fixed << std::setprecision(5);
    std::cout << "Sun's position in the ecliptic coordinate system on " << year << "-" << static_cast<int>(month) << "-" << static_cast<int>(day) << " at " << static_cast<int>(hour) << ":" << minute << ":" << static_cast<int>(second) << " UT" << std::endl;
    std::cout << "r (AU) = " << r << std::endl;
    std::cout << "r_x (AU) = " << r_x << std::endl;
    std::cout << "r_y (AU) = " << r_y << std::endl;
    std::cout << "r_z (AU) = " << r_z << std::endl;

    return 0;
}
