#include <iostream>
#include <string>
using namespace std;

class RefCountedString {
public:
    // Constructor allocates a new string and a new counter, sets the counter to 1
    RefCountedString(const string &s = string()) : ps(new string(s)), use(new size_t(1)) {}

    // Copy constructor copies all three data members and increments the counter
    RefCountedString(const RefCountedString &p) : ps(p.ps), use(p.use) { ++*use; }

    // Copy assignment operator
    RefCountedString &operator=(const RefCountedString &rhs) {
        // Increment the right-hand side object's reference count
        ++*rhs.use;
        // Decrement the left-hand side's reference count and delete if it reaches 0
        if (--*use == 0) {
            delete ps;
            delete use;
        }
        ps = rhs.ps;
        use = rhs.use;
        return *this;
    }

    // Destructor
    ~RefCountedString() {
        if (--*use == 0) {
            delete ps;
            delete use;
        }
    }

    // Swap function
    friend void swap(RefCountedString &, RefCountedString &);

    // Print function
    void print() const {
        cout << "String: " << *ps << endl;
        cout << "Reference count: " << *use << endl;
    }

private:
    string *ps;     // Pointer to the string
    size_t *use;    // Pointer to the reference count
};

// Swap function definition
inline void swap(RefCountedString &lhs, RefCountedString &rhs) {
    using std::swap;
    swap(lhs.ps, rhs.ps); // Swap pointers, not string data
    // Reference counts are not swapped
}

// Main function with test cases
int main() {
    RefCountedString rcs1("hello");
    RefCountedString rcs2("world");
    RefCountedString rcs3 = rcs1; // Copy constructor

    cout << "After initialization:" << endl;
    rcs1.print();
    rcs2.print();
    rcs3.print();

    rcs2 = rcs1; // Copy assignment

    cout << "After assignment rcs2 = rcs1:" << endl;
    rcs1.print();
    rcs2.print();
    rcs3.print();

    swap(rcs1, rcs2); // Swap rcs1 and rcs2

    cout << "After swap(rcs1, rcs2):" << endl;
    rcs1.print();
    rcs2.print();
    rcs3.print();

    return 0;
}
