    }

    std::unique_ptr<sql::ResultSet> executeQuery(PreparedQuery& prepared_query, const std::vector<std::string>& parameters) {
        auto statement = prepared_query.getStatement();
        if (!statement) {
            throw std::runtime_error("Prepared statement is not initialized.");
        }
        // Bind parameters to the prepared statement.
        for (size_t i = 0; i < parameters.size(); ++i) {
            statement->setString(i + 1, parameters[i]);
        }
        // Execute the prepared statement and return the result set.
        return std::unique_ptr<sql::ResultSet>(statement->executeQuery());
    }

private:
    std::string connection_string_;
    std::unique_ptr<sql::Connection> connection_;
};

