Person deserializePerson(const std::string &filename) {
    std::ifstream ifs(filename);
    if (!ifs.is_open()) {
        throw std::runtime_error("Could not open file for reading");
    }
    boost::archive::text_iarchive ia(ifs);
    Person person;
    ia >> person;
    return person;
