/**
 * Calculates the x-coordinate of the crossing point of the line segment with the x-axis.
 * The line segment is defined by two points (sx, sy) and (gx, gy).
 * It is guaranteed that the line segment crosses the x-axis.
 *
 * @param sx The x-coordinate of the starting point of the line segment.
 * @param sy The y-coordinate of the starting point of the line segment.
 * @param gx The x-coordinate of the end point of the line segment.
 * @param gy The y-coordinate of the end point of the line segment.
 * @return The x-coordinate of the crossing point with the x-axis.
 */
double findCrossingPoint(double sx, double sy, double gx, double gy) {
    return ((gx - sx) * (-sy) / (gy - sy)) + sx;
}

