void bfs(int source) {
    queue<int> toVisit;
    toVisit.push(source);
    distances[source] = 0;
    visited[source] = true;

    while (!toVisit.empty()) {
        int current = toVisit.front();
        toVisit.pop();

        for (auto &neighborAndDist : graph[current]) {
            int neighbor = neighborAndDist.first;
            int dist = neighborAndDist.second;

            if (!visited[neighbor]) {
                distances[neighbor] = distances[current] + dist;
                visited[neighbor] = true;
                toVisit.push(neighbor);
            }
        }
    }
}

