#include <iostream>
#include <cassert>
#include <cstdlib>

using namespace std;

typedef int Value;

// Dummy implementation of BTList and DLink for the purpose of this example
template <typename T>
class BTList {
public:
    struct iterator {
        T* ptr;
        iterator(T* p) : ptr(p) {}
        T& operator*() { return *ptr; }
        iterator& operator++() { ptr++; return *this; }
        iterator& operator--() { ptr--; return *this; }
        bool operator!=(const iterator& other) const { return ptr != other.ptr; }
    };

    void erase(T* value, bool) { value->removed = true; }
};

struct DLink {
    Value value;
    bool removed;
};

class Domain {
    const int initSize;
    const Value distanceToZero;
    DLink *all;

    void init(Value inf, Value sup) {
        // Dummy initialization for the purpose of this example
        all = new DLink[sup - inf + 1];
        for (int i = 0; i <= sup - inf; ++i) {
            all[i].value = inf + i;
            all[i].removed = false;
        }
    }

    // make it private because we don't want copy nor assignment
    Domain(const Domain &s);
    Domain& operator=(const Domain &s);

public:
    typedef BTList<Value>::iterator iterator;

    Domain(Value inf, Value sup) : initSize(sup - inf + 1), distanceToZero(inf) {
        init(inf, sup);
    }

    ~Domain() { if (initSize >= 1) delete[] all; }

    bool canbe(Value v) const { return !all[v - distanceToZero].removed; }
    bool cannotbe(Value v) const { return all[v - distanceToZero].removed; }

    void erase(Value v) { BTList<Value>::erase(&all[v - distanceToZero], true); }

    Value increase(Value v) {
        for (Value i = distanceToZero; i < v; ++i) {
            if (canbe(i)) erase(i);
        }
        return v;
    }

    Value decrease(Value v) {
        for (Value i = initSize + distanceToZero - 1; i > v; --i) {
            if (canbe(i)) erase(i);
        }
        return v;
    }

    iterator lower_bound(Value v) {
        for (Value i = v; i < initSize + distanceToZero; ++i) {
            if (canbe(i)) return iterator(&all[i]);
        }
        return iterator(&all[initSize]);
    }

    iterator upper_bound(Value v) {
        for (Value i = v; i >= distanceToZero; --i) {
            if (canbe(i)) return iterator(&all[i]);
        }
        return iterator(&all[initSize]);
    }
};

int main() {
    Domain d(1, 10);

    // Test cases
    assert(d.canbe(5) == true);
    assert(d.cannotbe(5) == false);

    d.erase(5);
    assert(d.canbe(5) == false);
    assert(d.cannotbe(5) == true);

    Value newLowerBound = d.increase(3);
    assert(newLowerBound == 3);
    assert(d.canbe(2) == false);

    Value newUpperBound = d.decrease(8);
    assert(newUpperBound == 8);
    assert(d.canbe(9) == false);

    Domain::iterator lb = d.lower_bound(4);
    assert(*lb == 6);

    Domain::iterator ub = d.upper_bound(7);
    assert(*ub == 7);

    cout << "All tests passed!" << endl;

    return 0;
}
