const int MAXN = 110;
vector<pair<int, int>> switches[MAXN][MAXN];
bool lightsOn[MAXN][MAXN], visited[MAXN][MAXN];
int dx[4] = {-1, 1, 0, 0};
int dy[4] = {0, 0, -1, 1};

int main() {
    int N, M;
    cin >> N >> M;

    for (int i = 0; i < M; ++i) {
        int A, B, X, Y;
        cin >> A >> B >> X >> Y;
        switches[A][B].emplace_back(X, Y);
    }

    queue<pair<int, int>> q;
    q.emplace(1, 1);
    lightsOn[1][1] = visited[1][1] = true;

    while (!q.empty()) {
        int x = q.front().first;
        int y = q.front().second;
        q.pop();

        for (auto& switchLocation : switches[x][y]) {
            int newX = switchLocation.first;
            int newY = switchLocation.second;
            lightsOn[newX][newY] = true;

            for (int i = 0; i < 4; ++i) {
                int adjX = newX + dx[i];
                int adjY = newY + dy[i];
                if (adjX >= 1 && adjX <= N && adjY >= 1 && adjY <= N && visited[adjX][adjY]) {
                    q.emplace(newX, newY);
                    break;
                }
            }
        }

        for (int i = 0; i < 4; ++i) {
            int newX = x + dx[i];
            int newY = y + dy[i];
            if (newX >= 1 && newX <= N && newY >= 1 && newY <= N && lightsOn[newX][newY] && !visited[newX][newY]) {
                visited[newX][newY] = true;
                q.emplace(newX, newY);
            }
        }
    }

    int count = 0;
    for (int i = 1; i <= N; ++i) {
        for (int j = 1; j <= N; ++j) {
            if (lightsOn[i][j]) {
                ++count;
            }
        }
    }

    cout << count << endl;
    return 0;
}
