#include <signal.h>
#include <errno.h>
#include "utils.hpp"

// Implementation of utility functions
namespace utils {
    int setnonblocking(int fd) {
        int old_option = fcntl(fd, F_GETFL);
        int new_option = old_option | O_NONBLOCK;
        fcntl(fd, F_SETFL, new_option);
        return old_option;
    }

    int add_sig(int signo, void (*handler)(int)) {
        struct sigaction sa;
        memset(&sa, '\0', sizeof(sa));
        sa.sa_handler = handler;
        sigfillset(&sa.sa_mask);
        if (sigaction(signo, &sa, nullptr) == -1) {
            return -1;
        }
        return 0;
    }

    void sigpipe_handler(int signo) {
        // Log the signal and ignore it to prevent the server from terminating
        std::cout << "Caught SIGPIPE signal: " << signo << std::endl;
    }

    void sigalarm_handler(int signo) {
        // This can be used to handle client timeouts
        std::cout << "Caught SIGALRM signal: " << signo << std::endl;
        // Disconnect idle clients or perform other timeout-related tasks
    }
}

// Main server class
class TCPServer {
private:
    int server_fd;
    std::vector<int> client_fds;

public:
    TCPServer(int port) {
        server_fd = socket(AF_INET, SOCK_STREAM, 0);
        if (server_fd < 0) {
            throw std::runtime_error("Failed to create socket");
        }

        struct sockaddr_in server_addr;
        server_addr.sin_family = AF_INET;
        server_addr.sin_addr.s_addr = INADDR_ANY;
        server_addr.sin_port = htons(port);

        if (bind(server_fd, (struct sockaddr *)&server_addr, sizeof(server_addr)) < 0) {
            throw std::runtime_error("Failed to bind socket");
        }

        if (listen(server_fd, 5) < 0) {
            throw std::runtime_error("Failed to listen on socket");
        }

        utils::setnonblocking(server_fd);
        utils::add_sig(SIGPIPE, utils::sigpipe_handler);
        utils::add_sig(SIGALRM, utils::sigalarm_handler);
    }

    ~TCPServer() {
        close(server_fd);
        for (int client_fd : client_fds) {
            close(client_fd);
        }
    }

    void run() {
        while (true) {
            struct sockaddr_in client_addr;
            socklen_t client_addr_len = sizeof(client_addr);
            int client_fd = accept(server_fd, (struct sockaddr *)&client_addr, &client_addr_len);

            if (client_fd > 0) {
                utils::setnonblocking(client_fd);
                client_fds.push_back(client_fd);
                std::cout << "New client connected: " << client_fd << std::endl;
            } else if (errno != EWOULDBLOCK && errno != EAGAIN) {
                std::cerr << "Failed to accept client" << std::endl;
            }

            for (auto it = client_fds.begin(); it != client_fds.end();) {
                char buffer[1024];
                int bytes_read = read(*it, buffer, sizeof(buffer));
                if (bytes_read > 0) {
                    write(*it, buffer, bytes_read); // Echo back the data
                } else if (bytes_read == 0 || (bytes_read < 0 && errno != EWOULDBLOCK && errno != EAGAIN)) {
                    close(*it);
                    it = client_fds.erase(it);
                    std::cout << "Client disconnected: " << *it << std::endl;
                } else {
                    ++it;
                }
            }
        }
    }
};

int main() {
    try {
        TCPServer server(8080);
        server.run();
    } catch (const std::exception& e) {
        std::cerr << "Exception: " << e.what() << std::endl;
        return EXIT_FAILURE;
    }
    return EXIT_SUCCESS;
}
