using namespace std;

/**
 * @brief Finds the maximum sum of two adjacent numbers in a sequence.
 * 
 * @param numbers A vector of integers representing the sequence.
 * @return int The maximum sum of two adjacent numbers.
 */
int findMaxAdjacentSum(const vector<int>& numbers) {
    int maxSum = numeric_limits<int>::min(); // Initialize to the smallest possible integer
    for (size_t i = 0; i < numbers.size() - 1; ++i) {
        int currentSum = numbers[i] + numbers[i + 1];
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }
    return maxSum;
}

int main() {
    int n;
    cout << "Enter the number of elements: ";
    cin >> n;

    if (n <= 1) {
        cerr << "The number of elements must be greater than 1." << endl;
        return 1;
    }

    vector<int> numbers(n);
    cout << "Enter the elements: ";
    for (int i = 0; i < n; ++i) {
        cin >> numbers[i];
    }

    int maxSum = findMaxAdjacentSum(numbers);
    cout << "The maximum sum of two adjacent numbers: " << maxSum << endl;

    return 0;
}

