#include <string>
#include <vector>
using namespace std;

class Solution
{
public:
    bool isInterleave(string s1, string s2, string s3)
    {
        int len1 = s1.size();
        int len2 = s2.size();
        int len3 = s3.size();
        if (len1 + len2 != len3)
        {
            return false;
        }
        vector<vector<int>> dp(len1 + 1, vector<int>(len2 + 1, 0));
        dp[0][0] = 1;

        for (int i = 0; i <= len1; i++)
        {
            for (int j = 0; j <= len2; j++)
            {
                if (i > 0)
                {
                    dp[i][j] |= (dp[i - 1][j] && s1[i - 1] == s3[i + j - 1]);
                }
                if (j > 0)
                {
                    dp[i][j] |= (dp[i][j - 1] && s2[j - 1] == s3[i + j - 1]);
                }
            }
        }
        return dp[len1][len2];
    }
};

// Test cases
int main() {
    Solution solution;
    // Test case 1
    string s1 = "abc";
    string s2 = "def";
    string s3 = "dabecf";
    bool result1 = solution.isInterleave(s1, s2, s3); // Expected: true

    // Test case 2
    s1 = "aabcc";
    s2 = "dbbca";
    s3 = "aadbbcbcac";
    bool result2 = solution.isInterleave(s1, s2, s3); // Expected: true

    // Test case 3
    s1 = "aabcc";
    s2 = "dbbca";
    s3 = "aadbbbaccc";
    bool result3 = solution.isInterleave(s1, s2, s3); // Expected: false

