/**
 * Finds the minimum distance between two specified elements in an array.
 * 
 * @param arr The array of integers.
 * @param n The size of the array.
 * @param x The first element to find the minimum distance.
 * @param y The second element to find the minimum distance.
 * @return The minimum distance between the two elements or -1 if not found.
 */
int minDist(const std::vector<int>& arr, int n, int x, int y) {
    int min_dist = INT_MAX;
    int last_pos_x = -1;
    int last_pos_y = -1;

    for (int i = 0; i < n; i++) {
        if (arr[i] == x) {
            last_pos_x = i;
            if (last_pos_y != -1) {
                min_dist = std::min(min_dist, abs(last_pos_x - last_pos_y));
            }
        } else if (arr[i] == y) {
            last_pos_y = i;
            if (last_pos_x != -1) {
                min_dist = std::min(min_dist, abs(last_pos_x - last_pos_y));
            }
        }
    }

    if (min_dist == INT_MAX) {
        return -1;
    }
    return min_dist;
}

int main() {
    int n, x, y;
    std::cout << "Enter size of the array: ";
    std::cin >> n;

    if (n <= 0) {
        std::cerr << "Invalid array size." << std::endl;
        return 1;
    }

    std::vector<int> arr(n);
    for (int i = 0; i < n; i++) {
        std::cout << "Enter element " << i + 1 << ": ";
        std::cin >> arr[i];
    }

    std::cout << "Enter the first element (x): ";
    std::cin >> x;
    std::cout << "Enter the second element (y): ";
    std::cin >> y;

    int distance = minDist(arr, n, x, y);
    if (distance != -1) {
        std::cout << "Minimum distance between " << x << " and " << y << " is " << distance << std::endl;
    } else {
        std::cout << "Elements are not present in the array or are the same." << std::endl;
    }

    return 0;
}
