using namespace std;

class StackUsingQueues {
    queue<int> q1, q2;

public:
    StackUsingQueues() {}

    int getSize() {
        return q1.size();
    }

    bool isEmpty() {
        return q1.empty();
    }

    void push(int element) {
        q1.push(element);
    }

    int pop() {
        if (q1.empty()) return -1;
        while (q1.size() > 1) {
            q2.push(q1.front());
            q1.pop();
        }
        int topElement = q1.front();
        q1.pop();
        swap(q1, q2);
        return topElement;
    }

    int top() {
        if (q1.empty()) return -1;
        while (q1.size() > 1) {
            q2.push(q1.front());
            q1.pop();
        }
        int topElement = q1.front();
        q2.push(q1.front());
        q1.pop();
        swap(q1, q2);
        return topElement;
    }
};

int main() {
    // Test cases to verify the solution
    StackUsingQueues stack;

    // Test case 1: Push elements
    stack.push(1);
    stack.push(2);
    stack.push(3);
    cout << "Top element (should be 3): " << stack.top() << endl;

    // Test case 2: Pop elements
    cout << "Popped element (should be 3): " << stack.pop() << endl;
    cout << "Top element after pop (should be 2): " << stack.top() << endl;

    // Test case 3: Check if stack is empty
    cout << "Is stack empty? (should be 0): " << stack.isEmpty() << endl;

    // Test case 4: Get size of the stack
    cout << "Size of stack (should be 2): " << stack.getSize() << endl;

    // Test case 5: Pop remaining elements
    cout << "Popped element (should be 2): " << stack.pop() << endl;
    cout << "Popped element (should be 1): " << stack.pop() << endl;
    cout << "Is stack empty? (should be 1): " << stack.isEmpty() << endl;
    cout << "Size of stack (should be 0): " << stack.getSize() << endl;

    // Test case 6: Pop from empty stack
    cout << "Popped element from empty stack (should be -1): " << stack.pop() << endl;

    return 0;
}
