using namespace std;

typedef long long int ll;
const ll INF = 998244353;

/**
 * Finds the minimum number of sides for a regular polygon such that one of its
 * interior angles is exactly equal to the given angle.
 * 
 * @param angle The interior angle in degrees.
 * @return The minimum number of sides, or -1 if no such polygon exists.
 */
ll min_polygon_sides(ll angle) {
    ll tmp = angle, ans = INF;
    while (tmp > 0) {
        if ((angle % tmp) == 0 && (180 % tmp) == 0) {
            ll n = (180 / tmp);
            while ((((n - 2) * 180) / n) < angle && n < INF)
                n *= 2;
            ans = min(ans, n);
        }
        tmp--;
    }
    return (ans == INF) ? -1 : ans;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int Test;
    cin >> Test;
    while (Test--) {
        ll angle;
        cin >> angle;
        ll result = min_polygon_sides(angle);
        cout << result << endl;
    }
    return 0;
}
