class ArrayRotator {
private:
    void reverse(int arr[], int start, int end) {
        while (start < end) {
            int temp = arr[start];
            arr[start] = arr[end];
            arr[end] = temp;
            start++;
            end--;
        }
    }

public:
    void rotateRight(int arr[], int n, int k) {
        if (n == 0) return;
        k = k % n;
        if (k == 0) return;
        reverse(arr, 0, n - k - 1);
        reverse(arr, n - k, n - 1);
        reverse(arr, 0, n - 1);
    }

    void rotateLeft(int arr[], int n, int d) {
        d = d % n;
        if (d == 0) return;
        reverse(arr, 0, d - 1);
        reverse(arr, d, n - 1);
        reverse(arr, 0, n - 1);
    }
};

// Test cases
