    int delete_element(int n) {
        Node *ptr = head;
        Node *prev = NULL;

        if (head == NULL) {
            cout << "No element to delete";
            return 0;
        }

        if (ptr->val == n) {
            head = ptr->next;
            delete ptr;
            return 1;
        }

        while (ptr != NULL && ptr->val != n) {
            prev = ptr;
            ptr = ptr->next;
        }

        if (ptr == NULL) {
            return 0;
        }

        if (ptr == tail) {
            tail = prev;
        }

        if (prev != NULL) {
            prev->next = ptr->next;
        }

        delete ptr;
        return 1;
    }

    void display() {
        for (Node *ptr = head; ptr != NULL; ptr = ptr->next) {
            cout << ptr->val << " ";
        }
        cout << endl;
    }
};

int main() {
    LinkedList l1;
    for (int i = 1; i <= 10; i++) {
        l1.add_end(i);
    }

    for (int i = 0; i < 20; i++) {
        cout << "At i = " << i + 1 << ", the result is " << (l1.delete_element(i + 1) == 1 ? "true" : "false");
        cout << endl;
    }

    cout << "Remaining elements in the list: ";
    l1.display();

    return 0;
}
