class TreeNode {
public:
    int data;
    TreeNode *left;
    TreeNode *right;

    TreeNode(int x) : data(x), left(NULL), right(NULL) {}
};

void printPost(TreeNode* root) {
    if (root == NULL)
        return;
    printPost(root->left);
    printPost(root->right);
    cout << root->data << " ";
}

TreeNode* buildTreeUtil(vector<int>& in, vector<int>& pre, int& preIndex, int inStart, int inEnd, unordered_map<int, int>& inMap) {
    if (inStart > inEnd) {
        return NULL;
    }
    int current = pre[preIndex++];
    TreeNode* tNode = new TreeNode(current);
    if (inStart == inEnd) {
        return tNode;
    }
    int inIndex = inMap[current];
    tNode->left = buildTreeUtil(in, pre, preIndex, inStart, inIndex - 1, inMap);
    tNode->right = buildTreeUtil(in, pre, preIndex, inIndex + 1, inEnd, inMap);
    return tNode;
}

TreeNode* buildTree(vector<int>& in, vector<int>& pre, int n) {
    int preIndex = 0;
    unordered_map<int, int> inMap;
    for (int i = 0; i < n; i++) {
        inMap[in[i]] = i;
    }
    return buildTreeUtil(in, pre, preIndex, 0, n - 1, inMap);
}

void freeTree(TreeNode* node) {
    if (node == NULL) return;
    freeTree(node->left);
    freeTree(node->right);
    delete node;
}

int main() {
    int t, n;
    cin >> t;
    while (t--) {
        cin >> n;
        vector<int> preOrder(n), inOrder(n);
        for (int i = 0; i < n; i++) {
            cin >> preOrder[i];
        }
        for (int i = 0; i < n; i++) {
            cin >> inOrder[i];
        }
        TreeNode* tree = buildTree(inOrder, preOrder, n);
        printPost(tree);
        cout << endl;
        freeTree(tree);
    }
    return 0;
}
