using namespace std;

int minJumpsToEnd(int arr[], int n) {
    int dp[2001];
    for(int i = 0; i < n; i++) {
        dp[i] = INT_MAX;
    }
    dp[0] = 0;
    for(int i = 0; i < n; i++) {
        for(int j = i + 1; j <= i + arr[i] && j < n; j++) {
            dp[j] = min(dp[i] + 1, dp[j]);
        }
    }
    return dp[n - 1] == INT_MAX ? -1 : dp[n - 1];
}

int main() {
