// Define the Binary Tree Node structure
template <typename T>
class BinaryTreeNode {
public:
    T data;
    BinaryTreeNode<T> *left;
    BinaryTreeNode<T> *right;

    BinaryTreeNode(T data) {
        this->data = data;
        left = NULL;
        right = NULL;
    }
};

// Function to perform level-order traversal
std::vector<std::vector<int>> getLevelOrderTraversal(BinaryTreeNode<int> *root) {
    std::vector<std::vector<int>> result;
    if (root == NULL) {
        return result;
    }

    std::queue<BinaryTreeNode<int>*> q;
    q.push(root);

    while (!q.empty()) {
        int levelSize = q.size();
        std::vector<int> currentLevel;

        for (int i = 0; i < levelSize; ++i) {
            BinaryTreeNode<int>* node = q.front();
            q.pop();
            currentLevel.push_back(node->data);

            if (node->left != NULL) {
                q.push(node->left);
            }
            if (node->right != NULL) {
                q.push(node->right);
            }
        }

        result.push_back(currentLevel);
    }

    return result;
}

// Test cases to verify the solution
int main() {
    // Create a binary tree
    //       3
    //      / \
    //     9  20
    //       /  \
    //      15   7
    BinaryTreeNode<int>* root = new BinaryTreeNode<int>(3);
    root->left = new BinaryTreeNode<int>(9);
    root->right = new BinaryTreeNode<int>(20);
    root->right->left = new BinaryTreeNode<int>(15);
    root->right->right = new BinaryTreeNode<int>(7);

    // Get level-order traversal
    std::vector<std::vector<int>> traversal = getLevelOrderTraversal(root);

    // Print the level-order traversal
    for (const auto& level : traversal) {
        for (int value : level) {
            std::cout << value << " ";
        }
        std::cout << std::endl;
    }

    // Expected output:
    // 3
    // 9 20
    // 15 7

    // Clean up the allocated nodes
    delete root->right->right;
    delete root->right->left;
    delete root->right;
    delete root->left;
    delete root;

    return 0;
}
