#include <memory>
#include <algorithm>
#include <cstdlib>
#include <ctime>

class HTree {
public:
    using key_type = int;
    using value_type = int;
    using tree_ptr_t = std::shared_ptr<HTree>;

    HTree(key_type key, value_type value, tree_ptr_t left = nullptr, tree_ptr_t right = nullptr)
        : key_(key), value_(value), left_(left), right_(right) {}

    key_type get_key() const { return key_; }
    value_type get_value() const { return value_; }
    tree_ptr_t get_left() const { return left_; }
    tree_ptr_t get_right() const { return right_; }

private:
    key_type key_;
    value_type value_;
    tree_ptr_t left_;
    tree_ptr_t right_;
};

class HForest {
public:
    void add_tree(HTree::tree_ptr_t tree) {
        heap_.push_back(tree);
        std::push_heap(heap_.begin(), heap_.end(), compare_trees);
    }

    HTree::tree_ptr_t pop_tree() {
        if (heap_.empty()) return nullptr;
        std::pop_heap(heap_.begin(), heap_.end(), compare_trees);
        auto tree = heap_.back();
        heap_.pop_back();
        return tree;
    }

    size_t size() const { return heap_.size(); }

    static bool compare_trees(const HTree::tree_ptr_t& a, const HTree::tree_ptr_t& b) {
        return a->get_value() > b->get_value();
    }

private:
    std::vector<HTree::tree_ptr_t> heap_;
};

HTree::tree_ptr_t create_htree_from_vector(const std::vector<int>& vector) {
    if (vector.size() % 2 != 0) {
        throw std::invalid_argument("Vector must contain an even number of elements.");
    }

    if (vector.empty()) {
        return nullptr;
    }

    std::vector<HTree::tree_ptr_t> nodes;
    for (size_t i = 0; i < vector.size(); i += 2) {
        nodes.push_back(std::make_shared<HTree>(vector[i], vector[i + 1]));
    }

    while (nodes.size() > 1) {
        std::sort(nodes.begin(), nodes.end(), [](const HTree::tree_ptr_t& a, const HTree::tree_ptr_t& b) {
            return a->get_value() < b->get_value();
        });
        auto left = nodes.front();
        nodes.erase(nodes.begin());
        auto right = nodes.front();
        nodes.erase(nodes.begin());
        auto merged = std::make_shared<HTree>(-1, left->get_value() + right->get_value(), left, right);
        nodes.push_back(merged);
    }

    return nodes.front();
}

std::vector<int> generate_random_vector(size_t size) {
    std::vector<int> output(size);
