int main() {
    int N, M;
    std::cin >> N >> M;

    // Calculate the range of possible sums
    const int min_sum = 2;
    const int max_sum = N + M;

    // Vector to store the frequency of each sum
    std::vector<int> frequency(max_sum + 1, 0);

    // Calculate the frequency of each sum
    for (int i = 1; i <= N; ++i) {
        for (int j = 1; j <= M; ++j) {
            ++frequency[i + j];
        }
    }

    // Find the maximum frequency
    int max_frequency = *std::max_element(frequency.begin(), frequency.end());

    // Print the sums with the maximum frequency
    for (int sum = min_sum; sum <= max_sum; ++sum) {
        if (frequency[sum] == max_frequency) {
