#include <vector>
#include <functional>

class OutputBufferManager {
public:
    bool startBuffer(std::function<std::string(const std::string&)> callback = nullptr, int chunkSize = 0, int flags = 0) {
        buffers.emplace_back(Buffer{callback});
        return true;
    }

    void cleanBuffer() {
        if (!buffers.empty()) {
            buffers.back().contents.clear();
        }
    }

    void flushBuffer() {
        if (!buffers.empty()) {
            std::string &contents = buffers.back().contents;
            if (buffers.back().callback) {
                contents = buffers.back().callback(contents);
            }
            output += contents;
            cleanBuffer();
        }
    }

    bool endBufferClean() {
        if (buffers.empty()) {
            return false;
        }
        cleanBuffer();
        buffers.pop_back();
        return true;
    }

    bool endBufferFlush() {
        if (buffers.empty()) {
            return false;
        }
        flushBuffer();
        buffers.pop_back();
        return true;
    }

    std::string getBufferContents() const {
        if (buffers.empty()) {
            return "";
        }
        return buffers.back().contents;
    }

    size_t getBufferLength() const {
        if (buffers.empty()) {
            return 0;
        }
        return buffers.back().contents.size();
    }

    int getBufferLevel() const {
        return static_cast<int>(buffers.size());
    }

    // For testing purposes, we expose the output
    std::string getOutput() const {
        return output;
    }

private:
    struct Buffer {
        std::function<std::string(const std::string&)> callback;
        std::string contents;
    };

    std::vector<Buffer> buffers;
    std::string output;
};

// Test cases to verify the solution correctness
int main() {
    OutputBufferManager obm;

    // Start a new buffer and add some content
    obm.startBuffer();
    std::cout << "Buffer level: " << obm.getBufferLevel() << std::endl; // Should output 1

    // Get the current buffer contents (should be empty)
    std::cout << "Current buffer contents: '" << obm.getBufferContents() << "'" << std::endl; // Should output ''

    // Clean the buffer (should have no effect since it's already empty)
    obm.cleanBuffer();

    // Flush the buffer (should output the contents and clean the buffer)
    obm.flushBuffer();
    std::cout << "Output after flush: '" << obm.getOutput() << "'" << std::endl; // Should output ''

    // End the buffer with cleaning
    obm.endBufferClean();
    std::cout << "Buffer level after end clean: " << obm.getBufferLevel() << std::endl; // Should output 0

    // Start a new buffer, add content, and end with flush
    obm.startBuffer();
    std::cout << "Buffer level: " << obm.getBufferLevel() << std::endl; // Should output 1
    obm.endBufferFlush();
    std::cout << "Output after end flush: '" << obm.getOutput() << "'" << std::endl; // Should output ''

    return 0;
}
