using LL = long long;

const int MOD = 1e9 + 7;

// Function to calculate (a^p) % MOD
LL mod_pow(LL a, LL p) {
    LL res = 1;
    a %= MOD;
    while (p) {
        if (p & 1) {
            res *= a;
            res %= MOD;
        }
        a *= a;
        a %= MOD;
        p >>= 1;
    }
    return res;
}

// Function to calculate the number of distinct team combinations
int calculate_team_combinations(int N) {
    if (N <= 2)
        return 0;
    // Calculate 2^(N-1) - 2 and take modulo MOD
    return (mod_pow(2, N - 1) - 2 + MOD) % MOD;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    int T, N;
    std::cin >> T;
    while (T--) {
        std::cin >> N;
        std::cout << calculate_team_combinations(N) << "\n";
    }
    return 0;
}
