#include <iostream>
using namespace std;

/**
 * Calculates A raised to the power B modulo M.
 *
 * This function uses the binary exponentiation method to efficiently compute
 * large powers modulo M. It reduces the computational complexity by breaking
 * down the exponent into powers of two.
 *
 * @param A The base.
 * @param B The exponent.
 * @param M The modulus.
 * @return The result of A^B % M.
 */
long long power_modulo(long long A, long long B, long long M) {
    A %= M; // Ensure A is within the bounds of M to prevent overflow
    long long result = 1;
    while (B > 0) {
        if (B % 2 == 1) {
            // If B is odd, multiply the result by A
            result = (result * A) % M;
        }
        // Square A and reduce B by half
        A = (A * A) % M;
        B /= 2;
    }
    return result;
}

int main() {
    long long a, n, m;
    cout << "Enter base (A), exponent (B), and modulus (M): ";
    cin >> a >> n >> m;
    cout << "The result of " << a << "^" << n << " mod " << m << " is: ";
    cout << power_modulo(a, n, m) << endl;
    return 0;
}

// Test cases to verify the solution correctness
void test() {
    cout << "Test 1: " << (power_modulo(2, 10, 1000000007) == 1024 ? "Passed" : "Failed") << endl;
    cout << "Test 2: " << (power_modulo(3, 13, 1000000007) == 1594323 ? "Passed" : "Failed") << endl;
    cout << "Test 3: " << (power_modulo(10, 1000, 1000000007) == 776627963145224192 ? "Passed" : "Failed") << endl;
}

int main() {
    test(); // Run test cases
    return 0;
}
