int custom_asprintf(char** strp, const char* format, ...) {
  va_list args;
  int ret;
  char buf[64];
  size_t strp_buflen;

  // Use a constant-sized buffer to determine the length.
  va_start(args, format);
  ret = vsnprintf(buf, sizeof(buf), format, args);
  va_end(args);
  if (ret < 0) {
    *strp = nullptr;
    return -1;
  }

  // Allocate a new buffer, with space for the NUL terminator.
  strp_buflen = static_cast<size_t>(ret) + 1;
  *strp = static_cast<char*>(malloc(strp_buflen));
  if (*strp == nullptr) {
    return -1;
  }

  // Return early if we have all the bytes.
  if (strp_buflen <= sizeof(buf)) {
    memcpy(*strp, buf, strp_buflen);
    return ret;
  }

  // Try again using the larger buffer.
  va_start(args, format);
  ret = vsnprintf(*strp, strp_buflen, format, args);
  va_end(args);
  if (static_cast<size_t>(ret) == strp_buflen - 1) {
    return ret;
  }

  // This should never happen.
  free(*strp);
  *strp = nullptr;
  return -1;
}

// Test cases to verify the solution correctness.
int main() {
  char* result;
  int len;

  // Test case 1: Simple string
  len = custom_asprintf(&result, "Hello, %s!", "World");
  printf("Formatted string: %s (Length: %d)\n", result, len);
  free(result);

  // Test case 2: Integer formatting
  len = custom_asprintf(&result, "Value: %d", 42);
  printf("Formatted string: %s (Length: %d)\n", result, len);
  free(result);

  // Test case 3: Literal percent sign
  len = custom_asprintf(&result, "Percent sign: %%");
  printf("Formatted string: %s (Length: %d)\n", result, len);
  free(result);

  // Test case 4: Multiple formatting
  len = custom_asprintf(&result, "Multiple formatting: %s %d %%", "Test", 123);
  printf("Formatted string: %s (Length: %d)\n", result, len);
  free(result);

  return 0;
