#include "base/task/promise/abstract_promise.h"
#include "base/threading/sequenced_task_runner_handle.h"

namespace base {

class PromiseManager {
public:
    PromiseManager() = default;
    ~PromiseManager() {
        Clear();
    }

    void AddPromise(scoped_refptr<internal::AbstractPromise> promise) {
        promises_.push_back(std::move(promise));
    }

    void CancelPromise(scoped_refptr<internal::AbstractPromise> promise) {
        auto it = std::find(promises_.begin(), promises_.end(), promise);
        if (it != promises_.end()) {
            (*it)->OnCanceled();
            promises_.erase(it);
        }
    }

    void ExecuteAll() {
        for (auto& promise : promises_) {
            if (!promise->IsCanceled()) {
                promise->Execute();
            }
        }
        promises_.clear();
    }

    void Clear() {
        for (auto& promise : promises_) {
            if (!promise->IsCanceled()) {
                promise->OnCanceled();
            }
        }
        promises_.clear();
    }

private:
    std::vector<scoped_refptr<internal::AbstractPromise>> promises_;
};

}  // namespace base

// Example usage:
int main() {
    base::PromiseManager manager;
    auto task_runner = base::GetCurrentSequence();

    // Create and add promises to the manager
    auto promise1 = base::internal::ConstructManualPromiseResolverPromise(
        FROM_HERE, base::internal::RejectPolicy::kMustCatchRejection, true, true);
    auto promise2 = base::internal::ConstructManualPromiseResolverPromise(
        FROM_HERE, base::internal::RejectPolicy::kMustCatchRejection, true, true);

    manager.AddPromise(promise1);
    manager.AddPromise(promise2);

    // Cancel a promise
    manager.CancelPromise(promise1);

    // Execute all promises
    manager.ExecuteAll();

    // Clear all promises
    manager.Clear();

    return 0;
}
