#include <cassert>
#include <algorithm>
#include <cmath>

// Assuming Vec3 is a 3D vector class with the following methods:
// - len() returns the length of the vector.
// - Dot(Vec3) returns the dot product with another vector.
// - GetNormalized() returns a normalized copy of the vector.
// - operator-(Vec3) returns the vector resulting from the subtraction of two vectors.
class Vec3 {
public:
    float x, y, z;

    Vec3(float x, float y, float z) : x(x), y(y), z(z) {}

    float len() const {
        return std::sqrt(x * x + y * y + z * z);
    }

    Vec3 GetNormalized() const {
        float length = len();
        return Vec3(x / length, y / length, z / length);
    }

    float Dot(const Vec3& other) const {
        return x * other.x + y * other.y + z * other.z;
    }

    Vec3 operator-(const Vec3& other) const {
        return Vec3(x - other.x, y - other.y, z - other.z);
    }
};

enum CoverUsage { eCU_Hide, eCU_UnHide };

struct Params {
    Vec3 location;
    Vec3 userLocation;
    Vec3 target;
    Vec3 direction;
    float totalLength;
    CoverUsage usage;
};

class CoverScorer {
public:
    float ScoreByDistance(const Params& params) const {
        float distance = (params.location - params.userLocation).len();
        float maxDistance = params.totalLength;
        if (maxDistance < distance)
            maxDistance = distance;

        assert(distance <= maxDistance);

        float score = 1.0f;
        if (maxDistance >= 0.1f)
            score = 1.0f - std::min(1.0f, distance / maxDistance);

        return score;
    }

    float ScoreByDistanceToTarget(const Params& params) const {
        float locationToTarget = (params.location - params.target).len();

        const float ConsiderClose = 10.0f;
        const float ConsiderFar = 25.0f;

        bool isClose = (locationToTarget < ConsiderClose);
        bool isFar = (locationToTarget > ConsiderFar);

        float score = 1.0f;
        if (isClose)
            score = (locationToTarget / ConsiderClose);
        else if (isFar)
            score = 1.0f - std::max(0.0f, (locationToTarget - ConsiderFar) / ConsiderFar);

        return score;
    }

    float ScoreByAngle(const Params& params) const {
        Vec3 locationToTargetDir = (params.target - params.location).GetNormalized();
        float angleCos = locationToTargetDir.Dot(params.direction);
        if (angleCos <= 0.1f)
            return 0.0f;

        return angleCos;
    }

    float Score(const Params& params) const {
        float score = 0.0f;

        switch (params.usage) {
        case eCU_Hide:
            score += 0.2f * ScoreByDistance(params);
            score += 0.3f * ScoreByAngle(params);
            score += 0.5f * ScoreByDistanceToTarget(params);
            break;
        case eCU_UnHide:
            score += 0.5f * ScoreByDistance(params);
            score += 0.0f * ScoreByAngle(params);
            score += 0.5f * ScoreByDistanceToTarget(params);
            break;
        default:
            assert(0);
            break;
        }

        return score;
    }
};

// Test cases
int main() {
    CoverScorer scorer;
    Params params;

    // Test case 1: Hiding scenario
    params = {Vec3(10, 0, 0), Vec3(0, 0, 0), Vec3(20, 0, 0), Vec3(1, 0, 0), 30.0f, eCU_Hide};
    assert(std::abs(scorer.Score(params) - 0.8f) < 0.01f);

    // Test case 2: Unhiding scenario
    params = {Vec3(10, 0, 0), Vec3(0, 0, 0), Vec3(20, 0, 0), Vec3(1, 0, 0), 30.0f, eCU_UnHide};
    assert(std::abs(scorer.Score(params) - 0.833333f) < 0.01f);

    // Add more test cases as needed

    return 0;
}
