#include <iostream>
#include <vector>
#include <algorithm>
#include <tuple>
#include <cassert>
using namespace std;

#define FOR(I, X, Y) for (int I = (X); I < (Y); I++)
using ll = int64_t;

ll maximizeSumOfSubarrays(int n, int m, int k, const vector<ll>& ls) {
  // Compute prefix sums
  vector<ll> ps(n + 1);
  FOR(i, 0, n) { ps[i + 1] = ps[i] + ls[i]; }

  // dp[k][n] = max sum of disjoint m-segment x k for [1, n]
  vector<vector<ll>> dp(k + 1, vector<ll>(n + 1));

  FOR(i, m, n + 1) {
    ll s = ps[i] - ps[i - m];
    FOR(l, 1, k + 1) {
      // Pick [i-m, i] or not
      dp[l][i] = max(dp[l - 1][i - m] + s, dp[l][i - 1]);
    }
  }
  return dp[k][n];
}

int main() {
  // Test cases
  {
    int n = 5, m = 2, k = 1;
    vector<ll> ls = {1, 2, 3, 4, 5};
    assert(maximizeSumOfSubarrays(n, m, k, ls) == 9);
  }
