class ScopedFilePtr {
private:
    scoped_ptr<fstream> file_ptr;

public:
    explicit ScopedFilePtr(const char *file_name) {
        file_ptr.reset(new fstream(file_name, fstream::in | fstream::out | fstream::trunc));
        if (!file_ptr->is_open()) {
            throw runtime_error("Failed to open file.");
        }
        cout << "File opened: " << file_name << endl;
    }

    ~ScopedFilePtr() {
        if (file_ptr) {
            file_ptr->close();
            cout << "File closed." << endl;
        }
    }

    void write(const string &data) {
        if (!file_ptr->good()) {
            throw runtime_error("File stream is not good for writing.");
        }
        *file_ptr << data;
        file_ptr->flush();
    }

    void read(string &data) {
        if (!file_ptr->good()) {
            throw runtime_error("File stream is not good for reading.");
        }
        stringstream buffer;
        buffer << file_ptr->rdbuf();
        data = buffer.str();
    }
};

int main() {
    try {
        const char *test_file = "test.txt";
        ScopedFilePtr file_ptr(test_file);

        string data_to_write = "Hello, ScopedFilePtr!";
        file_ptr.write(data_to_write);

        string data_read;
        file_ptr.read(data_read);

        cout << "Data read from file: " << data_read << endl;

        // ScopedFilePtr goes out of scope here, file should be closed automatically.
    } catch (const std::exception &e) {
        cerr << "Exception caught: " << e.what() << endl;
        return 1;
    }

    return 0;
}
