#include <iostream>
#include <fstream>
#include <string>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <chrono>
#include <memory>

#include <grpc++/grpc++.h>
#include <google/protobuf/util/json_util.h>

// Mock includes for the purpose of this example
#include "SignalService.grpc.pb.h" // gRPC service definitions
#include "Utility.h" // Utility functions like WaitForChannelReady, MakeUnique, etc.
#include "Logging.h" // Logging functions like CLOG, CLOG_THROTTLED, etc.
#include "GRPCUtil.h" // gRPC utility functions
#include "ProtoUtil.h" // Protobuf utility functions

namespace collector {

enum class SignalHandler {
  PROCESSED,
  ERROR,
  NEEDS_REFRESH
};

class SignalServiceClient {
public:
  SignalServiceClient() : stream_active_(false), first_write_(true) {}

  void Start() {
    thread_.Start([this] { EstablishGRPCStream(); });
  }

  void Stop() {
    stream_interrupted_.notify_one();
    thread_.Stop();
    if (context_) {
      context_->TryCancel();
    }
    context_.reset();
  }

  SignalHandler::Result PushSignals(const SignalStreamMessage& msg) {
    if (!stream_active_.load(std::memory_order_acquire)) {
      CLOG_THROTTLED(ERROR, std::chrono::seconds(10))
          << "GRPC stream is not established";
      return SignalHandler::ERROR;
    }

    if (first_write_) {
      first_write_ = false;
      return SignalHandler::NEEDS_REFRESH;
    }

    if (!writer_->Write(msg)) {
      auto status = writer_->FinishNow();
      if (!status.ok()) {
        CLOG(ERROR) << "GRPC writes failed: " << status.error_message();
      }
      writer_.reset();

      stream_active_.store(false, std::memory_order_release);
      CLOG(ERROR) << "GRPC stream interrupted";
      stream_interrupted_.notify_one();
      return SignalHandler::ERROR;
    }

    return SignalHandler::PROCESSED;
  }

protected:
  bool EstablishGRPCStreamSingle() {
    std::mutex mtx;
    std::unique_lock<std::mutex> lock(mtx);
    stream_interrupted_.wait(lock, [this]() { return !stream_active_.load(std::memory_order_acquire) || thread_.should_stop(); });
    if (thread_.should_stop()) {
      return false;
    }

    CLOG(INFO) << "Trying to establish GRPC stream for signals ...";

    if (!WaitForChannelReady(channel_, [this]() { return thread_.should_stop(); })) {
      return false;
    }
    if (thread_.should_stop()) {
      return false;
    }

    // stream writer
    context_ = MakeUnique<grpc::ClientContext>();
    writer_ = DuplexClient::CreateWithReadsIgnored(&SignalService::Stub::AsyncPushSignals, channel_, context_.get());
    if (!writer_->WaitUntilStarted(std::chrono::seconds(30))) {
      CLOG(ERROR) << "Signal stream not ready after 30 seconds. Retrying ...";
      CLOG(ERROR) << "Error message: " << writer_->FinishNow().error_message();
      writer_.reset();
      return true;
    }
    CLOG(INFO) << "Successfully established GRPC stream for signals.";

    first_write_ = true;
    stream_active_.store(true, std::memory_order_release);
    return true;
  }

  void EstablishGRPCStream() {
    while (EstablishGRPCStreamSingle())
      ;
    CLOG(INFO) << "Signal service client terminating.";
  }

  std::unique_ptr<grpc::ClientContext> context_;
  std::unique_ptr<DuplexClient<SignalStreamMessage, google::protobuf::Empty>> writer_;
  std::atomic<bool> stream_active_;
  bool first_write_;
  std::condition_variable stream_interrupted_;
  Utility::Thread thread_;
  std::shared_ptr<grpc::Channel> channel_;
};

class StdoutSignalServiceClient : public SignalServiceClient {
public:
  SignalHandler::Result PushSignals(const SignalStreamMessage& msg) override {
    std::string output;
    google::protobuf::util::MessageToJsonString(msg, &output, google::protobuf::util::JsonPrintOptions{});
    CLOG(DEBUG) << "GRPC: " << output;
    return SignalHandler::PROCESSED;
  }
};

}  // namespace collector

// Test cases to verify the solution correctness
int main() {
  // Create a SignalStreamMessage object with mock data
  SignalStreamMessage msg;
  msg.set_id(1);
  msg.set_value(42);

  // Initialize the client
  collector::StdoutSignalServiceClient client;

  // Start the client
  client.Start();

  // Push signals to the server
  auto result = client.PushSignals(msg);

  // Stop the client
  client.Stop();

  // Check the result of the PushSignals call
  if (result == collector::SignalHandler::PROCESSED) {
    std::cout << "Signal processed successfully." << std::endl;
  } else {
    std::cerr << "Failed to process signal." << std::endl;
  }

  return 0;
}
