// Position class to represent the position of the Ant
class Position {
public:
    int x, y;
    Position(int x, int y) : x(x), y(y) {}
    int getX() const { return x; }
    int getY() const { return y; }
};

// World class to represent the grid and its operations
class World {
private:
    int sizeX, sizeY;
    std::vector<std::vector<char>> grid;

public:
    World(int sizeX = 10, int sizeY = 10) : sizeX(sizeX), sizeY(sizeY), grid(sizeY, std::vector<char>(sizeX, '.')) {}

    void ResizeUD(int direction) {
        // Resize the grid upwards or downwards
        if (direction == 0) {
            // Resize upwards
            grid.insert(grid.begin(), std::vector<char>(sizeX, '.'));
        } else {
            // Resize downwards
            grid.push_back(std::vector<char>(sizeX, '.'));
        }
        sizeY++;
    }

    void ResizeLR(int direction) {
        // Resize the grid left or right
        for (auto& row : grid) {
            if (direction == 0) {
                // Resize left
                row.insert(row.begin(), '.');
            } else {
                // Resize right
                row.push_back('.');
            }
        }
        sizeX++;
    }

    int getSizeX() const { return sizeX; }
    int getSizeY() const { return sizeY; }

    void Write(const Position& pos, char mark = 'A') {
        if (pos.getY() < sizeY && pos.getX() < sizeX) {
            grid[pos.getY()][pos.getX()] = mark;
        }
    }

    void Display() const {
        for (const auto& row : grid) {
            for (char cell : row) {
                std::cout << cell << ' ';
            }
            std::cout << std::endl;
        }
    }
};

// Ant class to represent the Ant and its operations
class Ant {
private:
    Position position;
    World* world;

public:
    Ant(World* world, int startX, int startY) : world(world), position(startX, startY) {}

    Position getPosition() const { return position; }

    void setPosition(int x, int y) {
        position.x = x;
        position.y = y;
    }

    void Write(World* world) {
        world->Write(position);
    }
};

// Universe class that contains the World and the Ant
class Universe {
private:
    World* world_;
    Ant ant_;

public:
    Universe() : world_(new World()), ant_(world_, 1, 1) {}

    ~Universe() {
        delete world_;
    }

    World* getWorld() {
        return world_;
    }

    void Loop() {
        if (ant_.getPosition().getX() == 0) {
            world_->ResizeUD(0);
            ant_.setPosition(ant_.getPosition().getX() + 5, ant_.getPosition().getY());
        }
        else if (ant_.getPosition().getY() == 0) {
            world_->ResizeLR(0);
            ant_.setPosition(ant_.getPosition().getX(), ant_.getPosition().getY() + 5);
        }
        else if (ant_.getPosition().getX() == world_->getSizeX() - 1) {
            world_->ResizeUD(1);
        }
        else if (ant_.getPosition().getY() == world_->getSizeY() - 1) {
            world_->ResizeLR(1);
        }
        ant_.Write(world_);
    }
};

int main() {
    Universe universe;
    universe.Loop(); // Perform one iteration of the loop
    universe.getWorld()->Display(); // Display the world grid

    // Additional test cases can be added here to verify the correctness of the implementation
    return 0;
}
