using namespace std;

class Solution {
public:
    int minimumDifference(vector<int>& arr) {
        int sum = 0;
        int n = arr.size();
        for (int i = 0; i < n; i++)
            sum += abs(arr[i]);
        vector<vector<bool>> dp(n + 1, vector<bool>(sum + 1, 0));
        for (int i = 0; i <= n; i++)
            dp[i][0] = 1;
        if (arr[0] <= sum)
            dp[1][arr[0]] = 1;
        for (int i = 1; i < n; i++) {
            for (int target = 1; target <= sum; target++) {
                bool notTake = dp[i][target];
                bool take = false;
                if (arr[i] <= target)
                    take = dp[i][target - arr[i]];
                dp[i + 1][target] = take || notTake;
            }
        }
        int minDiff = INT_MAX;
        for (int i = 0; i <= sum / 2; i++) {
            if (dp[n][i]) {
                minDiff = min(minDiff, abs(i - (sum - i)));
            }
        }
        return minDiff;
    }
};

int main() {
    Solution solution;
    vector<int> test1 = {3, 1, 2, 4};
    cout << "Minimum Difference (Test 1): " << solution.minimumDifference(test1) << endl; // Output: 0

    vector<int> test2 = {1, 6, 5, 11};
    cout << "Minimum Difference (Test 2): " << solution.minimumDifference(test2) << endl; // Output: 1

    return 0;
}
