#include <iostream>
#include <vector>
#include <string>
using namespace std;

class WordSearch {
private:
    int m;
    int n;
    vector<vector<int>> directions = {
        {1, 0},
        {-1, 0},
        {0, 1},
        {0, -1}
    };
    vector<vector<char>> board;

    bool recursive(vector<vector<bool>>& visited, const string& word, int r, int c, int index) {
        if (index == word.size()) return true;
        visited[r][c] = true;
        for (const auto& dir : directions) {
            int nr = r + dir[0];
            int nc = c + dir[1];
            if (nr < 0 || nr >= m || nc < 0 || nc >= n || visited[nr][nc] || board[nr][nc] != word[index]) {
                continue;
            }
            if (recursive(visited, word, nr, nc, index + 1)) {
                return true;
            }
        }
        visited[r][c] = false;
        return false;
    }

public:
    WordSearch(vector<vector<char>>& board) : board(board) {
        m = board.size();
        n = board[0].size();
    }

    bool findWord(string word) {
        vector<vector<bool>> visited(m, vector<bool>(n, false));
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < n; ++j) {
                if (board[i][j] == word[0] && recursive(visited, word, i, j, 1)) {
                    return true;
                }
            }
        }
        return false;
    }

    int countWords(vector<string>& words) {
        int count = 0;
        for (const string& word : words) {
            if (findWord(word)) {
                ++count;
            }
        }
        return count;
    }
};

int main() {
    vector<vector<char>> board = {
        {'A', 'B', 'C', 'E'},
        {'S', 'F', 'C', 'S'},
        {'A', 'D', 'E', 'E'}
    };
    WordSearch game(board);

    // Test cases
    cout << boolalpha; // Print bools as true/false
    cout << "Does 'ABCCED' exist? " << game.findWord("ABCCED") << endl;
    cout << "Does 'SEE' exist? " << game.findWord("SEE") << endl;
    cout << "Does 'ABCB' exist? " << game.findWord("ABCB") << endl;

    vector<string> words = {"ABCCED", "SEE", "ABCB"};
    cout << "Number of words found: " << game.countWords(words) << endl;

    return 0;
}
