using namespace std;
using namespace cv;

int main() {
    // Create a grayscale image of size 100x200 with random pixel values
    Mat_<uchar> img(100, 200, CV_8UC1);
    randu(img, Scalar(1), Scalar(200)); // Fill img with random values from 1 to 200

    // Initialize the cumulative sum matrix with the same size as the original image
    Mat_<float> cumulativeSumMatrix(img.rows, img.cols, CV_32F, Scalar(0));

    // Compute the cumulative sum matrix
    for (int row = 0; row < img.rows; ++row) {
        for (int col = 0; col < img.cols; ++col) {
            float sum = img.at<uchar>(row, col);
            if (row > 0) sum += cumulativeSumMatrix.at<float>(row - 1, col);
            if (col > 0) sum += cumulativeSumMatrix.at<float>(row, col - 1);
            if (row > 0 && col > 0) sum -= cumulativeSumMatrix.at<float>(row - 1, col - 1);
            cumulativeSumMatrix.at<float>(row, col) = sum;
        }
    }

    // Display the original random image
    imshow("Original Random Image", img);

    // Display the cumulative sum matrix
    imshow("Cumulative Sum Matrix", cumulativeSumMatrix);

    // Wait for a key press before exiting
    waitKey(0);
    return 0;
