using kmldom::FeaturePtr;
using kmldom::StylePtr;
using kmlengine::KmlFile;
using kmlengine::KmlFilePtr;

// This function resolves and prints the style of a KML feature given its URL and ID.
void ResolveAndPrintKmlFeatureStyle(const std::string& kml_url, const std::string& id) {
  // Networked style resolution requires a KmlCache to fetch through.
  CurlNetFetcher curl_net_fetcher;
  kmlengine::KmlCache kml_cache(&curl_net_fetcher, 2);

  // KmlCache fetches this URL using the supplied CurlNetFetcher,
  // parses the KML into a KmlFile, and sets the URL and KmlCache
  // of the KmlFile.
  const KmlFilePtr kml_file = kml_cache.FetchKmlAbsolute(kml_url);
  if (!kml_file) {
    std::cerr << "Failed to parse or fetch KML file: " << kml_url << std::endl;
    return;
  }

  // Look up the Feature by ID
  const FeaturePtr feature = kmldom::AsFeature(kml_file->GetObjectById(id));
  if (!feature) {
    std::cerr << "No feature found with ID: " << id << std::endl;
    return;
  }

  // Create a resolved style for the Feature and print it.
  // Since this KmlFile came from a KmlCache, CreateResolvedStyle()
  // will fetch any remote styleUrl's through this KmlCache.
  StylePtr style = kmlengine::CreateResolvedStyle(feature, kml_file, kmldom::STYLESTATE_NORMAL);
  if (style) {
    std::cout << "Resolved Style:" << std::endl;
    std::cout << kmldom::SerializePretty(style) << std::endl;
  } else {
    std::cerr << "Failed to resolve style for feature with ID: " << id << std::endl;
  }
}

int main(int argc, char** argv) {
  if (argc != 3) {
    std::cerr << "Usage: " << argv[0] << " <kml_url> <feature_id>" << std::endl;
    return -1;
  }

  ResolveAndPrintKmlFeatureStyle(argv[1], argv[2]);
  return 0;
}
