#include<iostream>
using namespace std;

/**
 * Prints a character pyramid pattern with the specified number of rows.
 * Each row of the pyramid contains a sequence of increasing characters
 * from 'A' up to a certain point, and then the sequence decreases symmetrically.
 * 
 * @param n The number of rows in the pyramid.
 */
void printCharacterPyramid(int n) {
    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= i; j++) {
            char ch = 'A' + j - 1;
            cout << ch;
        }
        for(int j = i - 1; j >= 1; j--) {
            char ch = 'A' + j - 1;
            cout << ch;
        }
        cout << endl;
    }
}

int main() {
    int n;
    cout << "Enter the number of rows for the pyramid (max 26): ";
    cin >> n;
    if(n < 1 || n > 26) {
        cout << "Invalid number of rows. Please enter a number between 1 and 26." << endl;
        return 1;
    }
    printCharacterPyramid(n);
    return 0;
}

