bool IsPermutationOfPalindrome(const string& s) {
    unordered_map<char, int> char_counts;
    for (char c : s) {
        if (isalpha(c)) {
            char_counts[tolower(c)]++;
        }
    }

    bool has_odd = false;
    for (const auto& kv : char_counts) {
        if (kv.second % 2 == 1) {
            if (has_odd) {
                return false;
            }
            has_odd = true;
        }
    }
    return true;
}

