    for (int num : result1) {
        cout << num << " ";
    }
    cout << endl;

    // Test case 2
    cout << "Spiral Order of matrix2: ";
    for (int num : result2) {
        cout << num << " ";
    }
    cout << endl;

    return 0;
}
