#include <algorithm>
#include <unordered_set>

using namespace std;

class Solution {
public:
    int longestConsecutive(vector<int>& nums) {
        unordered_set<int> num_set(nums.begin(), nums.end());
        int longestStreak = 0;

        for (int num : num_set) {
            if (!num_set.count(num - 1)) {
                int currentNum = num;
                int currentStreak = 1;

                while (num_set.count(currentNum + 1)) {
                    currentNum += 1;
                    currentStreak += 1;
                }

                longestStreak = max(longestStreak, currentStreak);
            }
        }

        return longestStreak;
    }
};

int main() {
    Solution solution;
    vector<int> test1 = {100, 4, 200, 1, 3, 2};
    vector<int> test2 = {0, -1};
    vector<int> test3 = {};
    vector<int> test4 = {9,1,4,7,3,-1,0,5,8,-1,6};

    cout << "Test 1: " << solution.longestConsecutive(test1) << endl; // Should output 4
    cout << "Test 2: " << solution.longestConsecutive(test2) << endl; // Should output 2
    cout << "Test 3: " << solution.longestConsecutive(test3) << endl; // Should output 0
    cout << "Test 4: " << solution.longestConsecutive(test4) << endl; // Should output 7

