};*/

class Solution
{
    private:
    void transformUtil(Node* node, int& sum)
    {
        if (node == NULL) return;

        // Recur for right subtree first so that we get all larger values first
        transformUtil(node->right, sum);

        // Update the sum of all greater nodes
        sum += node->data;

        // Assign the sum of all greater nodes to current node
        node->data = sum - node->data;

        // Recur for left subtree so that the transformation is done in reverse in-order
        transformUtil(node->left, sum);
    }

    public:
    void transformTree(Node* root)
    {
        int sum = 0;
        transformUtil(root, sum);
    }
};

