    void StartConfigFile(const KeyName& schemaName) {
        // Initialize the QDomDocument and create the root element
        doc.clear();
        QDomElement root = doc.createElement(schemaName.ToQString());
        doc.appendChild(root);
    }

    void WriteKey(const KeyName& keyName, const KeyValue& keyValue, const KeyId& keyId = KeyId()) {
        // Find or create the current element
        QDomElement currentElement = doc.documentElement();
        QDomElement newElement = doc.createElement(keyName.ToQString());

        // If an ID is provided, set it as an attribute
        if (!keyId.ToQString().isEmpty()) {
            newElement.setAttribute(xmlIdAttribute, keyId.ToQString());
        }

        // Append the key values
        for (const QString& value : keyValue.values) {
            QDomElement valueElement = doc.createElement("_" + QString::number(newElement.childNodes().count()));
            valueElement.appendChild(doc.createTextNode(value));
            newElement.appendChild(valueElement);
        }

        currentElement.appendChild(newElement);
    }

    void StartGroup(const KeyName& groupName, const KeyId& groupId = KeyId()) {
        // Create a new group element and set it as the current element
        QDomElement currentElement = doc.documentElement();
        QDomElement groupElement = doc.createElement(groupName.ToQString());

        // If an ID is provided, set it as an attribute
        if (!groupId.ToQString().isEmpty()) {
            groupElement.setAttribute(xmlIdAttribute, groupId.ToQString());
        }

