        // Write a reference to a sub-configuration file
        WriteKey(subConfigKeyName, KeyValue::from(subConfigFile.filePath()), subConfigId);
    }

    void EndConfigFile(const KeyName& schemaName) {
        // No specific action needed for ending the configuration file in this implementation
    }

    bool WriteTo(QIODevice& device) {
        // Write the XML content to the provided IO device
        if (!device.open(QIODevice::WriteOnly)) {
            return false;
        }

        QByteArray xmlData = doc.toByteArray();
        device.write(xmlData);
        device.close();
