#include <vector>
#include <iostream>
#include <stack>
#include <queue>
#include <string>
#include <map>
#include <algorithm>

using namespace std;

class Solution {
public:
    // Utility function to swap two characters
    void swap(char &a, char &b){
        char temp = a;
        a = b;
        b = temp;
    }

    // Function to reverse a string in place
    void reverseString(vector<char>& s) {
        int i = 0, j = s.size() - 1;

        while (i < j){
            swap(s[i], s[j]);
            i++;
            j--;
        }
    }

    // Function to reverse the words in a string
    string reverseWords(string s) {
        // Remove leading and trailing spaces
        s.erase(0, s.find_first_not_of(" "));
        s.erase(s.find_last_not_of(" ") + 1);

        // Convert string to vector of characters for in-place operations
        vector<char> strVec(s.begin(), s.end());

        // Reverse the entire string
        reverseString(strVec);

        // Reverse each word in the reversed string
        int start = 0;
        for (int i = 0; i <= strVec.size(); ++i) {
            if (i == strVec.size() || strVec[i] == ' ') {
                int end = i - 1;
                while (start < end) {
                    swap(strVec[start], strVec[end]);
                    start++;
                    end--;
                }
                start = i + 1;
            }
        }

        // Convert vector of characters back to string
        string result(strVec.begin(), strVec.end());

        // Remove extra spaces between words
        auto new_end = unique(result.begin(), result.end(), [](char a, char b) {
            return a == ' ' && b == ' ';
        });
        result.erase(new_end, result.end());

        return result;
    }
};

int main() {
    Solution solution;
    string test1 = "  hello world!  ";
    string result1 = solution.reverseWords(test1);
    cout << "Reversed: \"" << result1 << "\"" << endl; // Should print: "Reversed: "world! hello""

    string test2 = "  The sky is blue  ";
    string result2 = solution.reverseWords(test2);
    cout << "Reversed: \"" << result2 << "\"" << endl; // Should print: "Reversed: "blue is sky The""

    return 0;
}
