#include <iostream>
using namespace std;

void printHourglass(int n) {
    int st = n; // Number of asterisks to print
    int sp = 0; // Number of spaces to print before asterisks

    for (int i = 0; i < n; i++) {
        // Print leading spaces
        for (int j = 0; j < sp; j++) {
            cout << " ";
        }
        // Print asterisks
        for (int j = 0; j < st; j++) {
            if (j == 0 || j == st - 1 || i == 0 || i == n - 1) {
                cout << "* ";
            } else {
                cout << "  ";
            }
        }
        cout << endl;

        // Update the number of asterisks and spaces for next row
        if (i < n / 2) {
            st -= 2;
            sp++;
        } else {
            st += 2;
            sp--;
        }
    }
}

int main() {
    int n;
    cout << "Enter an odd number for the hourglass pattern: ";
    cin >> n;

    // Check if the input is an odd number
    if (n % 2 == 0) {
        cout << "Please enter an odd number." << endl;
        return 1;
    }

    // Print the hourglass pattern
    printHourglass(n);

    return 0;
}

