using namespace std;

/**
 * @brief Get the value of segments of a given character in a string.
 * 
 * @param L Reference to a vector to store the lengths of segments.
 * @param S The input string.
 * @param given_ch The character to look for in the string.
 */
void get_value(vector<int> &L, const string &S, char given_ch) {
    int current_segment = 0;
    for (size_t i = 0; i < S.size(); i++) {
        if (S[i] == given_ch) {
            current_segment++;
        } else if (current_segment != 0) {
            L.push_back(current_segment);
            current_segment = 0;
        }
    }
    if (current_segment != 0) {
        L.push_back(current_segment);
    }
}

/**
 * @brief Main function to calculate the maximum length of a contiguous segment of '1's.
 * 
 * @return int The maximum length of a contiguous segment of '1's.
 */
int main() {
    int length, max_flips;
    string S;
    cin >> length >> max_flips >> S;

    vector<int> zero_segments;
    get_value(zero_segments, S, '0');

    vector<int> one_segments;
    get_value(one_segments, S, '1');

    int max_length = 0, current_0_length = 0, current_1_length = 0, left_segment = 0;

    for (size_t i = 0; i < zero_segments.size() || i < one_segments.size(); i++) {
        if (i < zero_segments.size()) {
            current_0_length += zero_segments[i];
        }

        if (i < one_segments.size()) {
            current_1_length += one_segments[i];
        }

        if (i >= static_cast<size_t>(max_flips)) {
            current_0_length -= zero_segments[left_segment];
            current_1_length -= one_segments[left_segment];
            left_segment++;
        }

        int extra = 0;
        if (S[0] == '0' && left_segment != 0) {
            extra = one_segments[left_segment - 1];
        }

        if (S[0] == '1' && i + 1 < one_segments.size()) {
            extra = one_segments[i + 1];
        }

        int current_length = current_0_length + current_1_length + extra;
        max_length = max(max_length, current_length);
    }

    cout << max_length;
    return 0;
}
