using namespace std;

/**
 * Finds the median of a sorted vector of double values.
 * @param sortedList A vector of double values, assumed to be sorted in non-decreasing order.
 * @return The median of the vector.
 */
double findMedian(const vector<double>& sortedList) {
    size_t size = sortedList.size();
    if (size % 2 == 0) {
        // Even number of elements - return the average of the two middle elements
        return (sortedList[size / 2 - 1] + sortedList[size / 2]) / 2.0;
    } else {
        // Odd number of elements - return the middle element
        return sortedList[size / 2];
    }
