namespace nt2 { namespace tag
  {
    struct laguerre_ : std::unary_function<double, double> {};
  }

  double laguerre(int n, double x) {
    if (n == 0) {
      return 1;
    } else if (n == 1) {
      return 1 - x;
    } else {
      double L_nm1 = 1 - x; // L_1(x)
      double L_nm2 = 1;     // L_0(x)
      double L_n = 0;

      for (int k = 2; k <= n; ++k) {
        L_n = ((2 * k - 1 - x) * L_nm1 - (k - 1) * L_nm2) / k;
        L_nm2 = L_nm1;
        L_nm1 = L_n;
      }

      return L_n;
    }
  }
}

