  assert(laguerre(0, 0.5) == 1);
  assert(laguerre(1, 0.5) == 0.5);
  assert(laguerre(2, 0.5) == 0.125);
  assert(laguerre(3, 0.5) == -0.125);
  assert(laguerre(4, 0.5) == -0.1875);

