#include <iostream>
#include <stdexcept>

namespace structures {

template<typename T>
class LinkedStack {
 public:
  LinkedStack();
  ~LinkedStack();

  void clear();
  void push(const T& data);
  T pop();
  T& top();
  const T& top() const;
  bool empty() const;
  std::size_t size() const;

 private:
  class Node {
   public:
    explicit Node(const T& data):
      data_{data},
      next_{nullptr}
    {}

    Node(const T& data, Node* next):
      data_{data},
      next_{next}
    {}

    T& data() {
      return data_;
    }

    const T& data() const {
      return data_;
    }

    Node* next() {
      return next_;
    }

    const Node* next() const {
      return next_;
    }

    void next(Node* node) {
      next_ = node;
    }

   private:
    T data_;
    Node* next_;
  };

  Node* top_;
  std::size_t size_;
};

template<typename T>
LinkedStack<T>::LinkedStack() : top_{nullptr}, size_{0u} {}

template<typename T>
LinkedStack<T>::~LinkedStack() {
  clear();
}

template<typename T>
void LinkedStack<T>::clear() {
  while (!empty()) {
    pop();
  }
}

template<typename T>
void LinkedStack<T>::push(const T& data) {
  Node* new_node = new Node(data, top_);
  if (new_node == nullptr) {
    throw std::out_of_range("Full stack");
  }
  top_ = new_node;
  size_++;
}

template<typename T>
T LinkedStack<T>::pop() {
  if (empty()) {
    throw std::out_of_range("Cannot pop from empty stack");
  }
  Node* out = top_;
  T data = out->data();
  top_ = top_->next();
  size_--;
  delete out;
  return data;
}

template<typename T>
T& LinkedStack<T>::top() {
  if (empty()) {
    throw std::out_of_range("Stack is empty");
  }
  return top_->data();
}

template<typename T>
const T& LinkedStack<T>::top() const {
  if (empty()) {
    throw std::out_of_range("Stack is empty");
  }
  return top_->data();
}

template<typename T>
bool LinkedStack<T>::empty() const {
  return size_ == 0;
}

template<typename T>
std::size_t LinkedStack<T>::size() const {
  return size_;
}

}  // namespace structures

// Test cases
int main() {
  structures::LinkedStack<int> stack;

  // Test push and top
  stack.push(1);
  stack.push(2);
  stack.push(3);
  std::cout << "Top element should be 3: " << stack.top() << std::endl;

  // Test pop
  std::cout << "Popped element should be 3: " << stack.pop() << std::endl;
  std::cout << "Top element should now be 2: " << stack.top() << std::endl;

  // Test size
  std::cout << "Size should be 2: " << stack.size() << std::endl;

  // Test clear
  stack.clear();
  std::cout << "Stack should be empty: " << stack.empty() << std::endl;

  // Test pop on empty stack
  try {
    stack.pop();
  } catch (const std::out_of_range& e) {
    std::cout << "Caught exception on pop from empty stack: " << e.what() << std::endl;
  }

  // Test top on empty stack
  try {
    stack.top();
  } catch (const std::out_of_range& e) {
    std::cout << "Caught exception on top of empty stack: " << e.what() << std::endl;
  }

  return 0;
}
