class UrlUtility {
public:
    static std::string UrlEncode(const std::string& str) {
        std::string encoded;
        for (char c : str) {
            if (isalnum(c) || c == '-' || c == '_' || c == '.' || c == '~') {
                encoded += c;
            } else if (c == ' ') {
                encoded += '+';
            } else {
                encoded += '%';
                encoded += ToHex(static_cast<unsigned char>(c) >> 4);
                encoded += ToHex(static_cast<unsigned char>(c) & 0x0F);
            }
        }
        return encoded;
    }

    static std::string UrlDecode(const std::string& str) {
        std::string decoded;
        for (size_t i = 0; i < str.length(); ++i) {
            if (str[i] == '+') {
                decoded += ' ';
            } else if (str[i] == '%') {
                unsigned char high = FromHex(str[++i]);
                unsigned char low = FromHex(str[++i]);
                decoded += static_cast<char>(high * 16 + low);
            } else {
                decoded += str[i];
            }
        }
        return decoded;
    }

private:
    static unsigned char ToHex(unsigned char x) {
        return x + (x > 9 ? ('A' - 10) : '0');
    }

    static unsigned char FromHex(unsigned char x) {
        if (x >= 'A' && x <= 'F') return x - 'A' + 10;
        if (x >= 'a' && x <= 'f') return x - 'a' + 10;
        if (x >= '0' && x <= '9') return x - '0';
        return 0;
    }
};

// Test cases
int main() {
    std::string original = "Hello World! This is a test.";
    std::string encoded = UrlUtility::UrlEncode(original);
    std::string decoded = UrlUtility::UrlDecode(encoded);

    std::cout << "Original: " << original << std::endl;
    std::cout << "Encoded: " << encoded << std::endl;
    std::cout << "Decoded: " << decoded << std::endl;

    return 0;
}
