#include "Matrix.hpp"
#include "Vector.hpp"

namespace gnsstk {

class ENUConverter {
public:
    ENUConverter(double refGeodeticLatRad, double refLonRad) {
        updateReferencePoint(refGeodeticLatRad, refLonRad);
    }

    gnsstk::Vector<double> convertToENU(const gnsstk::Vector<double>& ecefCoord) const {
        // Multiply the ECEF coordinates by the rotation matrix to get ENU coordinates
        return rotMat * ecefCoord;
    }

    void updateReferencePoint(double refGeodeticLatRad, double refLonRad) {
        computeRotationMatrix(refGeodeticLatRad, refLonRad);
    }

private:
    Matrix<double> rotMat;

    void computeRotationMatrix(double refLat, double refLon) {
        // Compute the rotation matrix from ECEF to ENU
        double sinLat = std::sin(refLat);
        double cosLat = std::cos(refLat);
        double sinLon = std::sin(refLon);
        double cosLon = std::cos(refLon);

        rotMat.resize(3, 3);
        rotMat(0, 0) = -sinLon;
        rotMat(0, 1) = cosLon;
        rotMat(0, 2) = 0.0;
        rotMat(1, 0) = -sinLat * cosLon;
        rotMat(1, 1) = -sinLat * sinLon;
        rotMat(1, 2) = cosLat;
        rotMat(2, 0) = cosLat * cosLon;
        rotMat(2, 1) = cosLat * sinLon;
        rotMat(2, 2) = sinLat;
    }
};

} // namespace gnsstk

// Test cases to verify the solution correctness
int main() {
    // Reference point in geodetic coordinates (latitude, longitude in radians)
    double refLat = 0.709186; // ~40.65 degrees
    double refLon = -1.396263; // ~80 degrees

    // Create an ENUConverter object with the reference point
    gnsstk::ENUConverter converter(refLat, refLon);

    // ECEF coordinate to be converted
    gnsstk::Vector<double> ecefCoord(3);
    ecefCoord(0) = 1000.0; // X
    ecefCoord(1) = 500.0;  // Y
    ecefCoord(2) = 250.0;  // Z

    // Convert ECEF to ENU
    gnsstk::Vector<double> enuCoord = converter.convertToENU(ecefCoord);

    // Output the result
    std::cout << "ECEF Coordinate: " << ecefCoord << std::endl;
    std::cout << "ENU Coordinate: " << enuCoord << std::endl;

    // Update the reference point and convert again
    refLat = 0.785398; // ~45 degrees
    refLon = -1.570796; // ~90 degrees
    converter.updateReferencePoint(refLat, refLon);
    enuCoord = converter.convertToENU(ecefCoord);

    // Output the result with the updated reference point
    std::cout << "Updated ENU Coordinate: " << enuCoord << std::endl;

    return 0;
}
