// Define the basic structures for color, point3, ray, and hit_record
struct color {
  double r, g, b;

  color(double red, double green, double blue) : r(red), g(green), b(blue) {}
};

struct point3 {
  double x, y, z;

  point3(double x, double y, double z) : x(x), y(y), z(z) {}
};

struct ray {
  point3 origin;
  point3 direction;

  ray(const point3& origin, const point3& direction) : origin(origin), direction(direction) {}

  point3 at(double t) const {
    return point3(origin.x + t * direction.x, origin.y + t * direction.y, origin.z + t * direction.z);
  }
};

struct hit_record {
  point3 p;
  point3 normal;
  double t;

  hit_record(const point3& p, const point3& normal, double t) : p(p), normal(normal), t(t) {}
};

// Define the matte class
class matte {
  color albedo;

public:
  matte(color a) : albedo(a) {}

  ray scatter(const ray& r_in, const hit_record& rec) const {
    point3 target = rec.p + rec.normal + random_in_unit_sphere();
    return ray(rec.p, target - rec.p);
  }
};

// Utility function to generate a random point inside a unit sphere
point3 random_in_unit_sphere() {
  std::random_device rd;
  std::mt19937 gen(rd());
  std::uniform_real_distribution<> dis(-1.0, 1.0);

  point3 p;
  do {
    p = point3(dis(gen), dis(gen), dis(gen));
  } while (p.x * p.x + p.y * p.y + p.z * p.z >= 1.0);
  return p;
}

// Function to trace a ray and determine its color after scattering off a matte surface
color trace_ray(const ray& r, const matte& surface, const hit_record& rec) {
  ray scattered = surface.scatter(r, rec);
  // For simplicity, we'll just return the albedo color of the surface
  // In a more complex scenario, we might calculate lighting, shadows, etc.
  return surface.albedo;
}

// Test cases
int main() {
  // Create a matte surface with a blue color
  matte blue_surface(color(0.1, 0.2, 0.5));

  // Create a hit record for the point of intersection
  hit_record rec(point3(1.0, 2.0, 3.0), point3(0.0, 1.0, 0.0), 4.0);

  // Create an incoming ray
  ray incoming_ray(point3(1.0, 1.0, 1.0), point3(0.0, 1.0, 0.0));

  // Trace the ray and get the color after scattering
  color scattered_color = trace_ray(incoming_ray, blue_surface, rec);

  // Output the color
  std::cout << "Scattered color: " << scattered_color.r << ", " << scattered_color.g << ", " << scattered_color.b << std::endl;

  return 0;
