            size_t spacePos = command.find(" ", 7);
            if (spacePos != string::npos) {
                position = stoi(command.substr(7, spacePos - 7));
                substring = command.substr(spacePos + 1);
                if (position >= 0 && position <= s.size()) {
                    s.insert(position, substring);
                    cout << s << endl;
                } else {
                    cout << "INVALID COMMAND" << endl;
                }
            } else {
                cout << "INVALID COMMAND" << endl;
            }
        } else if (command.substr(0, 7) == "REPLACE") {
            size_t firstSpacePos = command.find(" ", 8);
            if (firstSpacePos != string::npos) {
                size_t secondSpacePos = command.find(" ", firstSpacePos + 1);
                if (secondSpacePos != string::npos) {
                    string old_substring = command.substr(8, firstSpacePos - 8);
                    string new_substring = command.substr(secondSpacePos + 1);
                    size_t pos = s.find(old_substring);
                    while (pos != string::npos) {
                        s.replace(pos, old_substring.size(), new_substring);
                        pos = s.find(old_substring, pos + new_substring.size());
                    }
                    cout << s << endl;
                } else {
                    cout << "INVALID COMMAND" << endl;
                }
            } else {
                cout << "INVALID COMMAND" << endl;
            }
        } else {
            cout << "INVALID COMMAND" << endl;
        }
    }

    return 0;
}
