using namespace std;

/**
 * Removes duplicates from a sorted array of integers and returns the length of the new array without duplicates.
 * The original array is modified such that the first part contains the unique elements in their original order.
 * 
 * @param nums A reference to a vector of integers sorted in non-decreasing order.
 * @return The new length of the array after duplicates have been removed.
 */
int removeDuplicates(vector<int>& nums) {
    if (nums.size() == 0) return 0;
    int l = 0;
    for (int h = 1; h < nums.size(); ++h) {
        if (nums[h] != nums[l]) {
            ++l;
            nums[l] = nums[h];
        }
    }
    return l + 1;
}

int main() {
    vector<int> arr{0,0,1,1,1,2,2,3,3,4};
    int length = removeDuplicates(arr);
    for (int i = 0; i < length; i++) cout << arr[i] << " ";
    return 0;
}
