class StringFormatter {
public:
    // Concatenates two strings and returns the result
    static std::string concatenate(const std::string& str1, const std::string& str2) {
        return str1 + str2;
    }

    // Converts a string to uppercase and returns the result
    static std::string toUpperCase(const std::string& str) {
        std::string upperStr = str;
        std::transform(upperStr.begin(), upperStr.end(), upperStr.begin(), ::toupper);
        return upperStr;
    }

    // Converts a string to lowercase and returns the result
    static std::string toLowerCase(const std::string& str) {
        std::string lowerStr = str;
        std::transform(lowerStr.begin(), lowerStr.end(), lowerStr.begin(), ::tolower);
        return lowerStr;
    }

    // Reverses a string and returns the result
    static std::string reverse(const std::string& str) {
        std::string revStr = str;
        std::reverse(revStr.begin(), revStr.end());
        return revStr;
    }

    // Checks if a string is a palindrome
    static bool isPalindrome(const std::string& str) {
        std::string lowerStr = toLowerCase(str);
        return lowerStr == reverse(lowerStr);
    }
};

