// Function to compute the number of ways to tile a 2xN rectangle
int countTilingWays(int N) {
    int dp[41] = {0, 1, 2};
    for(int i = 3; i <= N; i++) {
        dp[i] = dp[i-1] + dp[i-2];
    }
    return dp[N];
}

