// Recursive function to find the number of subsets that sum up to k.
void dfs(int now, int depth) {
    if (depth == n) {
        if (k == now) {
            result++;
        }
        return;
    }
    dfs(now, depth + 1); // Case when the current element is not included in the subset.
    dfs(now + s[depth], depth + 1); // Case when the current element is included in the subset.
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);

    cin >> n >> k;

    for (int i = 0; i < n; i++) {
        cin >> s[i];
    }

    dfs(0, 0);
    if (k == 0) {
        result--; // Exclude the empty set if k is 0.
    }
    cout << result;

    return 0;
}
