    ios_base::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);

    fill(ans, ans + N, -1);

    cin >> n;
    for (int i = 1; i < n; i++) {
        int a, b;
        cin >> a >> b;
        adl[a].push_back(b);
        adl[b].push_back(a);
        edl[i] = make_pair(a, b);
        max_degree = max(max_degree, (int)adl[a].size());
        max_degree = max(max_degree, (int)adl[b].size());
    }

    vector<bool> used(max_degree, false);
    for (int i = 1; i < n; i++) {
        int a = edl[i].first;
        int b = edl[i].second;
        fill(used.begin(), used.end(), false);

        // Mark colors used by adjacent edges
        for (int adj : adl[a]) {
            if (ans[adj] != -1) {
                used[ans[adj]] = true;
            }
        }
        for (int adj : adl[b]) {
            if (ans[adj] != -1) {
                used[ans[adj]] = true;
            }
        }

        // Assign the first unused color
        for (int color = 0; color < max_degree; color++) {
            if (!used[color]) {
                ans[i] = color;
                break;
            }
        }
    }

    for (int i = 1; i < n; i++) {
        cout << ans[i] << el;
    }

    return 0;
}
