#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>

using namespace std;

/**
 * Finds the pair of elements in an array whose sum is closest to a given target value.
 * Outputs the absolute difference between the closest sum and the target value.
 * 
 * @param n The number of elements in the array.
 * @param target The target sum to get close to.
 * @param a The array of integers.
 * @return The absolute difference between the closest sum and the target value.
 */
int findClosestPairSum(int n, int target, vector<int>& a) {
    if (n < 2) {
        return target;
    }

    int ans = INT_MAX;
    sort(a.begin(), a.end());
    for (int i = 0; i < n - 1; i++) {
        int low = i + 1, hi = n - 1;
        while (low < hi) {
            int cSum = a[i] + a[low];
            int dif = abs(cSum - target);
            ans = min(dif, ans);
            if (cSum > target) {
                hi--;
            } else {
                low++;
            }
        }
    }
    return ans;
}

int main() {
    int n, target;
    cin >> n >> target;
    vector<int> a(n);
    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    cout << findClosestPairSum(n, target, a);
    return 0;
}

// Test cases to verify the solution
int main() {
    // Test case 1
    vector<int> arr1 = {1, 3, 5, 7, 9};
    int target1 = 10;
    cout << "Test case 1 - Expected: 0, Output: " << findClosestPairSum(arr1.size(), target1, arr1) << endl;

    // Test case 2
    vector<int> arr2 = {-1, 2, 1, -4};
    int target2 = 1;
    cout << "Test case 2 - Expected: 0, Output: " << findClosestPairSum(arr2.size(), target2, arr2) << endl;

    // Test case 3
    vector<int> arr3 = {0, 0, 0};
    int target3 = 2;
    cout << "Test case 3 - Expected: 2, Output: " << findClosestPairSum(arr3.size(), target3, arr3) << endl;

    // Test case 4
    vector<int> arr4 = {1};
    int target4 = 3;
    cout << "Test case 4 - Expected: 3, Output: " << findClosestPairSum(arr4.size(), target4, arr4) << endl;

    return 0;
