using namespace std;

class Solution {
public:
    string reverseWords(string s) {
        string new_s;
        int end = s.size() - 1;
        char sep = '\0'; // Corrected from '' to '\0' to represent the null character
        while (end >= 0) {
            int right = -1;
            while (end >= 0) {
                if (s[end] != ' ') {
                    right = end;
                    end--;
                    break;
                }
                end--;
            }

            if (right == -1)
                break;

            int left = right;
            while (end >= 0 && s[end] != ' ') {
                left--;
                end--;
            }

            new_s.append(s.substr(left + 1, right - left));
            if (end >= 0) new_s.push_back(' '); // Only add a space if not at the beginning of the string

            end--;
        }
        return new_s;
    }
};

int main() {
    // Test cases
    Solution solution;
    cout << solution.reverseWords("  hello world  ") << endl; // Output: "world hello"
    cout << solution.reverseWords("a good   example") << endl; // Output: "example good a"
    cout << solution.reverseWords("  Bob    Loves  Alice   ") << endl; // Output: "Alice Loves Bob"
    cout << solution.reverseWords("Alice does not even like bob") << endl; // Output: "bob like even not does Alice"

    return 0;
