// Enums for sync states and sync operation results
enum class SyncState {
    RUNNING,
    AUTHENTICATION_REQUIRED,
    TEMPORARY_UNAVAILABLE,
    DISABLED
};

enum class SyncOperationResult {
    NONE,
    ADDED,
    UPDATED,
    DELETED,
    CONFLICTED
};

// Forward declaration of the observer interface
class SyncEventObserver;

// FileSyncEventSystem class
class FileSyncEventSystem {
public:
    void registerObserver(SyncEventObserver* observer) {
        assert(observer != nullptr);
        observers.push_back(observer);
    }

    void unregisterObserver(SyncEventObserver* observer) {
        observers.erase(std::remove(observers.begin(), observers.end(), observer), observers.end());
    }

    void notifySyncStateUpdated(SyncState state, const std::string& description) {
        for (auto* observer : observers) {
            observer->onSyncStateUpdated(state, description);
        }
    }

    void notifyFileSynced(const std::string& filePath, SyncOperationResult result) {
        for (auto* observer : observers) {
            observer->onFileSynced(filePath, result);
        }
    }

private:
    std::vector<SyncEventObserver*> observers;
};

// SyncEventObserver interface
class SyncEventObserver {
public:
    virtual void onSyncStateUpdated(SyncState state, const std::string& description) = 0;
    virtual void onFileSynced(const std::string& filePath, SyncOperationResult result) = 0;
    virtual ~SyncEventObserver() {}
};

// Example observer implementation
class ExampleObserver : public SyncEventObserver {
public:
    void onSyncStateUpdated(SyncState state, const std::string& description) override {
        std::cout << "Sync state updated: " << static_cast<int>(state) << ", " << description << std::endl;
    }

    void onFileSynced(const std::string& filePath, SyncOperationResult result) override {
        std::cout << "File synced: " << filePath << ", " << static_cast<int>(result) << std::endl;
    }
};

// Test cases
int main() {
    FileSyncEventSystem eventSystem;
    ExampleObserver observer;

    eventSystem.registerObserver(&observer);

    // Test sync state update notification
    eventSystem.notifySyncStateUpdated(SyncState::RUNNING, "Service is running");
    eventSystem.notifySyncStateUpdated(SyncState::AUTHENTICATION_REQUIRED, "Authentication is required");

    // Test file sync notification
    eventSystem.notifyFileSynced("/path/to/file.txt", SyncOperationResult::ADDED);
    eventSystem.notifyFileSynced("/path/to/file.txt", SyncOperationResult::UPDATED);

    eventSystem.unregisterObserver(&observer);

    return 0;
}
