// Define verification macros (placeholders for actual test framework macros)
#define VERIFY_IS_APPROX(a, b) assert((a).isApprox(b))
#define VERIFY_IS_EQUAL(a, b) assert((a) == (b))

// Define a custom absolute square function for complex numbers
template<typename Scalar>
Scalar abs2(const Scalar& x) {
    return x * x;
}

template<typename MatrixType>
void performMatrixOperations(const MatrixType& m) {
    typedef typename MatrixType::Index Index;
    typedef typename MatrixType::Scalar Scalar;

    Index rows = m.rows();
    Index cols = m.cols();

    MatrixType m1 = MatrixType::Random(rows, cols);
    Scalar s1 = static_cast<Scalar>(std::rand()) / RAND_MAX;
    Scalar s2 = static_cast<Scalar>(std::rand()) / RAND_MAX;

    // Scalar addition
    VERIFY_IS_APPROX(m1.array() + s1, MatrixType::Constant(rows, cols, s1) + m1);

    // Scalar subtraction
    VERIFY_IS_APPROX(m1.array() - s2, m1 - MatrixType::Constant(rows, cols, s2));

    // Access patterns
    VERIFY_IS_EQUAL(m1.topLeftCorner(1, 1), m1.block(0, 0, 1, 1));
    VERIFY_IS_EQUAL(m1.col(0).head(1), m1.col(0).segment(0, 1));
    VERIFY_IS_EQUAL(m1.col(0).tail(1), m1.col(0).segment(rows - 1, 1));

    // Verify scalar functions
    VERIFY_IS_EQUAL(std::cos(s1), std::cos(s1));
    VERIFY_IS_EQUAL(std::real(s1), std::real(s1));
    VERIFY_IS_EQUAL(abs2(s1), abs2(s1));
}

int main() {
    // Test cases
    performMatrixOperations(Matrix<double, 1, 1>::Random());
    performMatrixOperations(MatrixXd::Random(1, 1));
    performMatrixOperations(Matrix3f::Random());
    performMatrixOperations(Matrix4d::Random());
    performMatrixOperations(MatrixXf::Random(200, 200));
    performMatrixOperations(MatrixXcd::Random(100, 100));

    std::cout << "All tests passed!" << std::endl;
    return 0;
}
