#include <ctime>

// Forward declarations
class Room;
class Player;
class Dungeon;
class Game;

// Constants for game settings
const int DUNGEON_SIZE = 5;
const int MAX_HEALTH = 100;
const int POTION_HEAL = 20;
const int MONSTER_DAMAGE = 10;

// Room class
class Room {
public:
    enum Type { EMPTY, MONSTER, TREASURE, POTION };

    Room(Type type) : roomType(type) {}

    Type getType() const { return roomType; }

private:
    Type roomType;
};

// Player class
class Player {
public:
    Player() : health(MAX_HEALTH), x(0), y(0) {}

    void move(int dx, int dy) {
        x += dx;
        y += dy;
    }

    void takeDamage(int damage) {
        health -= damage;
    }

    void heal(int amount) {
        health += amount;
        if (health > MAX_HEALTH) health = MAX_HEALTH;
    }

    bool isAlive() const { return health > 0; }
    int getHealth() const { return health; }
    int getX() const { return x; }
    int getY() const { return y; }

private:
    int health;
    int x, y;
};

// Dungeon class
class Dungeon {
public:
    Dungeon() {
        // Initialize the dungeon with random rooms
        srand(time(nullptr));
        for (int i = 0; i < DUNGEON_SIZE; ++i) {
            std::vector<Room> row;
            for (int j = 0; j < DUNGEON_SIZE; ++j) {
                Room::Type type = static_cast<Room::Type>(rand() % 4);
                row.push_back(Room(type));
            }
            rooms.push_back(row);
        }
        // Ensure the entrance and treasure rooms are set
        rooms[0][0] = Room(Room::EMPTY);
        rooms[DUNGEON_SIZE - 1][DUNGEON_SIZE - 1] = Room(Room::TREASURE);
    }

    Room getRoom(int x, int y) const {
        return rooms[x][y];
    }

private:
    std::vector<std::vector<Room>> rooms;
};

// Game class
class Game {
public:
    Game() : dungeon(), player(), treasureFound(false) {}

    void start() {
        std::cout << "Welcome to the Dungeon Adventure!" << std::endl;
        while (player.isAlive() && !treasureFound) {
            printStatus();
            handleInput();
        }
        if (treasureFound) {
            std::cout << "Congratulations! You found the treasure and won the game!" << std::endl;
        } else {
            std::cout << "You have been defeated. Game over." << std::endl;
        }
    }

private:
    Dungeon dungeon;
    Player player;
    bool treasureFound;

    void printStatus() {
        std::cout << "You are in a room. Your health is " << player.getHealth() << "." << std::endl;
        Room currentRoom = dungeon.getRoom(player.getX(), player.getY());
        switch (currentRoom.getType()) {
            case Room::EMPTY:
                std::cout << "The room is empty." << std::endl;
                break;
            case Room::MONSTER:
                std::cout << "There is a monster here!" << std::endl;
                player.takeDamage(MONSTER_DAMAGE);
                std::cout << "You take " << MONSTER_DAMAGE << " damage." << std::endl;
                break;
            case Room::TREASURE:
                std::cout << "You found the treasure!" << std::endl;
                treasureFound = true;
                break;
            case Room::POTION:
                std::cout << "You found a potion and drink it." << std::endl;
                player.heal(POTION_HEAL);
                break;
        }
    }

    void handleInput() {
        std::cout << "Enter your move (N/E/S/W): ";
        char move;
        std::cin >> move;
        switch (move) {
            case 'N':
                if (player.getY() > 0) player.move(0, -1);
                break;
            case 'E':
                if (player.getX() < DUNGEON_SIZE - 1) player.move(1, 0);
                break;
            case 'S':
                if (player.getY() < DUNGEON_SIZE - 1) player.move(0, 1);
                break;
            case 'W':
                if (player.getX() > 0) player.move(-1, 0);
                break;
            default:
                std::cout << "Invalid move. Try again." << std::endl;
                break;
        }
    }
};

// Main function
int main() {
    Game game;
    game.start();
    return 0;
}
