#include <iostream>
#include <vector>
#include <string>
using namespace std;

vector<int> computePrefixFunction(const string& p) {
    int m = p.length();
    vector<int> pi(m);
    pi[0] = 0;
    int k = 0;
    for (int q = 1; q < m; ++q) {
        while (k > 0 && p[k] != p[q])
            k = pi[k - 1];
        if (p[k] == p[q])
            ++k;
        pi[q] = k;
    }
    return pi;
}

vector<int> kmpMatcher(const string& s, const string& p) {
    int n = s.length();
    int m = p.length();
    vector<int> pi = computePrefixFunction(p);
    vector<int> matches;
    int q = 0;
    for (int i = 0; i < n; ++i) {
        while (q > 0 && p[q] != s[i])
            q = pi[q - 1];
        if (p[q] == s[i])
            ++q;
        if (q == m) {
            matches.push_back(i - m + 1);
            q = pi[q - 1];
        }
    }
    return matches;
}

int main() {
    string s, p;
    getline(cin, s);
    getline(cin, p);

    vector<int> matches = kmpMatcher(s, p);
    cout << matches.size() << endl;
    for (int i = 0; i < matches.size(); ++i) {
        if (i > 0) cout << " ";
        cout << matches[i];
    }
    cout << endl;
    return 0;
}
