#include <vector>
#include <limits>

using namespace std;

vector<pair<int, int>> mat;
int cache[502][502];

int MatrixChainOrder(int l, int r) {
    if (l == r)
        return 0;
    if (l + 1 == r)
        return mat[l].first * mat[r].first * mat[r].second;
    int& ret = cache[l][r];
    if (ret != -1) return ret;
    ret = numeric_limits<int>::max();
    for (int i = l; i < r; i++) {
        ret = min(ret, MatrixChainOrder(l, i) + MatrixChainOrder(i + 1, r) + mat[l].first * mat[i].second * mat[r].second);
    }
    return ret;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(0);
    cout.tie(0);
    memset(cache, -1, sizeof(cache));
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        int a, b;
        cin >> a >> b;
        mat.push_back({ a,b });
    }
    cout << MatrixChainOrder(0, n - 1) << endl;
    return 0;
}
