const int MAX = 1001;
int N, M;
int grid[MAX][MAX];
int largest[MAX][MAX];

// Function to recursively find the length of the longest path starting from (y, x)
int findLongestPath(int y, int x) {
    if (largest[y][x])
        return largest[y][x];
    largest[y][x] = 1;

    // Check the cell below
    if (y < N-1 && grid[y+1][x]+1 == grid[y][x])
        largest[y][x] = max(largest[y][x], 1 + findLongestPath(y+1, x));

    // Check the cell above
    if (y > 0 && grid[y-1][x] + 1 == grid[y][x])
        largest[y][x] = max(largest[y][x], 1 + findLongestPath(y-1, x));

    // Check the cell to the right
    if (x < M-1 && grid[y][x+1] + 1 == grid[y][x])
        largest[y][x] = max(largest[y][x], 1 + findLongestPath(y, x+1));

    // Check the cell to the left
    if (x > 0 && grid[y][x-1] + 1 == grid[y][x])
        largest[y][x] = max(largest[y][x], 1 + findLongestPath(y, x-1));

    return largest[y][x];
}

// Function to find the length of the longest path in the entire grid
int largestPath() {
    int res = 1;
    for (int y = 0; y < N; ++y)
        for (int x = 0; x < M; ++x)
            res = max(res, findLongestPath(y, x));
    return res;
}

int main() {
    cin >> N >> M;
    for (int y = 0; y < N; ++y)
        for (int x = 0; x < M; ++x)
            largest[y][x] = 0, cin >> grid[y][x];

    cout << largestPath() << endl;

    return 0;
}
