#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <cmath>

class FibonacciCoder {
private:
    std::vector<uint64_t> fibs;

    void generateFibs(size_t maxBits) {
        fibs.push_back(1);
        fibs.push_back(2);
        while (fibs.back() < (1ULL << (maxBits - 1))) {
            fibs.push_back(fibs[fibs.size() - 1] + fibs[fibs.size() - 2]);
        }
    }

public:
    FibonacciCoder() {
        generateFibs(64); // Assuming we are dealing with 64-bit integers
    }

    std::string encode(int x) {
        if (x <= 0) {
            throw std::invalid_argument("Input must be a positive integer.");
        }

        std::string code;
        auto it = std::lower_bound(fibs.begin(), fibs.end(), x);
        if (*it != x) --it; // Find the largest Fibonacci number <= x

        while (x > 0) {
            int index = std::distance(fibs.begin(), it);
            code = '1' + code;
            x -= *it;
            if (x > 0) {
                it = std::lower_bound(fibs.begin(), it, x);
                code = std::string(index - std::distance(fibs.begin(), it) - 1, '0') + code;
            }
        }
        return code + '1'; // Append the additional '1'
    }

    int decode(const std::string& code) {
        int result = 0;
        int prevBit = 0;
        for (size_t i = 0; i < code.size() - 1; ++i) { // Exclude the last '1'
            if (code[i] == '1') {
                result += fibs[i];
                if (prevBit == 1) { // Two consecutive '1's are not allowed
                    throw std::invalid_argument("Invalid Fibonacci code word.");
                }
                prevBit = 1;
            } else {
                prevBit = 0;
            }
        }
        return result;
    }
};

int main() {
    FibonacciCoder coder;

    // Test cases
    std::vector<int> testNumbers = {1, 2, 3, 4, 5, 10, 21};
    for (int num : testNumbers) {
        std::string encoded = coder.encode(num);
        int decoded = coder.decode(encoded);
        std::cout << "Number: " << num << ", Encoded: " << encoded << ", Decoded: " << decoded << std::endl;
    }

    return 0;
}
