#include <iostream>
#include <set>
#include <algorithm>
using namespace std;

class Graph {
    void APUtil(int u, bool visited[], int disc[], int low[], int parent[], set<int> &ap) {
        static int time = 0;
        int children = 0;
        visited[u] = true;
        disc[u] = low[u] = ++time;
        for (auto v : adj[u]) {
            if (!visited[v]) {
                children++;
                parent[v] = u;
                APUtil(v, visited, disc, low, parent, ap);
                low[u] = min(low[u], low[v]);
                if (parent[u] == -1 && children > 1) ap.insert(u);
                if (parent[u] != -1 && low[v] >= disc[u]) ap.insert(u);
                if (low[v] > disc[u]) bridges.insert(make_pair(min(u, v), max(u, v)));
            } else if (v != parent[u]) {
                low[u] = min(low[u], disc[v]);
            }
        }
    }

public:
    int V;    // No. of vertices
    set<int> *adj; // Adjacency list
    set<pair<int, int>> bridges; // Set to store bridges

    Graph(int V) {
        this->V = V;
        adj = new set<int>[V];
    }

    void addEdge(int v, int w) {
        adj[v].insert(w);
        adj[w].insert(v);  // Note: the graph is undirected
    }

    set<int> AP() {
        bool *visited = new bool[V];
        int *disc = new int[V];
        int *low = new int[V];
        int *parent = new int[V];
        set<int> ap;

        for (int i = 0; i < V; i++) {
            parent[i] = -1;
            visited[i] = false;
        }

        for (int i = 0; i < V; i++)
            if (!visited[i])
                APUtil(i, visited, disc, low, parent, ap);

        delete[] visited;
        delete[] disc;
        delete[] low;
        delete[] parent;

        return ap;
    }

    set<pair<int, int>> findBridges() {
        AP(); // Call AP to fill in the bridges
        return bridges;
    }
};

int main() {
    // Create a graph given in the above diagram
    Graph g(5);
    g.addEdge(1, 0);
    g.addEdge(0, 2);
    g.addEdge(2, 1);
    g.addEdge(0, 3);
    g.addEdge(3, 4);

    set<int> ap = g.AP();
    set<pair<int, int>> bridges = g.findBridges();

    cout << "Articulation points in the graph:\n";
    for (int point : ap)
        cout << point << "\n";

    cout << "\nBridges in the graph:\n";
    for (auto bridge : bridges)
        cout << bridge.first << " -- " << bridge.second << "\n";

    return 0;
}
