  return b;
}

ll lcm(ll a, ll b) { return a / gcd(a, b) * b; }

ll find_smallest_multiple_length(ll N, ll M, const string& S, const string& T) {
  ll L = lcm(N, M);
  map<ll, char> mp;
  for (ll i = 0; i < N; i++) {
    ll idx = i * (L / N) + 1;
    mp[idx] = S[i];
  }
  for (ll i = 0; i < M; i++) {
    ll idx = i * (L / M) + 1;
    if (mp.find(idx) != mp.end() && mp[idx] != T[i]) {
      return -1;
    }
  }
  return L;
}

int main() {
  ios::sync_with_stdio(false);
  cin.tie(0);

  ll N, M;
  string S, T;
  cin >> N >> M;
  cin >> S >> T;

  cout << find_smallest_multiple_length(N, M, S, T) << endl;
  return 0;
}
