class StringToIntegerConverter {
public:
    int convert(const std::string& s) {
        long long num = 0; // Use long long to handle potential overflow
        int i = 0;
        while (s[i] == ' ') i++;
        bool is_negative = false;
        if (s[i] == '+') i++;
        else if (s[i] == '-') {
            is_negative = true;
            i++;
        }
        while (i < s.size() && s[i] >= '0' && s[i] <= '9') {
            num = num * 10 + (s[i] - '0');
            if (num > INT_MAX) break; // Check for overflow
            i++;
        }
        if (is_negative) num *= -1;
        if (num > INT_MAX) num = INT_MAX;
        else if (num < INT_MIN) num = INT_MIN;
        return static_cast<int>(num);
    }
};

int main() {
    StringToIntegerConverter converter;
    // Test cases
    std::cout << converter.convert("42") << std::endl; // Should output 42
    std::cout << converter.convert("   -42") << std::endl; // Should output -42
    std::cout << converter.convert("4193 with words") << std::endl; // Should output 4193
    std::cout << converter.convert("words and 987") << std::endl; // Should output 0
    std::cout << converter.convert("-91283472332") << std::endl; // Should output -2147483648 (INT_MIN)
