class HasPtr {
    friend void swap(HasPtr& lhs, HasPtr& rhs);
public:
    // Constructor
    HasPtr(const std::string &s = std::string(), int n = 0) : ps(new std::string(s)), i(n) {}

    // Copy constructor
    HasPtr(const HasPtr &hp) : ps(new std::string(*hp.ps)), i(hp.i) {}

    // Copy-assignment operator
    HasPtr& operator=(HasPtr hp) {
        swap(*this, hp);
        return *this;
    }

    // Destructor
    ~HasPtr() {
        delete ps;
    }

    // Debug function to print the state of the object
    void show() const {
        std::cout << "String: " << *ps << ", Int: " << i << std::endl;
    }

private:
    std::string *ps;
    int i;
};

// Swap function for HasPtr
void swap(HasPtr& lhs, HasPtr& rhs) {
    using std::swap;
    swap(lhs.ps, rhs.ps);
    swap(lhs.i, rhs.i);
    std::cout << "HasPtr swap called" << std::endl;
}

// Foo class definition
class Foo {
    friend void swap(Foo &lhs, Foo &rhs);
public:
    // Constructor
    Foo(HasPtr p) : h(p) {}

    // Debug function to print the state of the object
    void show() const {
        h.show();
    }

private:
    HasPtr h;
};

// Swap function for Foo
void swap(Foo &lhs, Foo &rhs) {
    using std::swap;
    swap(lhs.h, rhs.h); // this way, friend function swap of HasPtr will be called
    std::cout << "Foo swap called" << std::endl;
}

// Main function to demonstrate swapping
int main() {
    HasPtr hp1("string1", 10);
    HasPtr hp2("string2", 20);
    std::cout << "Before swap:" << std::endl;
    hp1.show();
    hp2.show();

    swap(hp1, hp2);
    std::cout << "After swap:" << std::endl;
    hp1.show();
    hp2.show();

    Foo f1(HasPtr("string3", 30));
    Foo f2(HasPtr("string4", 40));
    std::cout << "Before swap:" << std::endl;
    f1.show();
    f2.show();

    swap(f1, f2);
    std::cout << "After swap:" << std::endl;
    f1.show();
    f2.show();

    return 0;
}
