template<typename Range>
class RangeWrapper {
public:
    using iterator = decltype(std::begin(std::declval<Range&>()));
    using const_iterator = decltype(std::begin(std::declval<const Range&>()));

    explicit RangeWrapper(Range& range) : range_(range) {}

    iterator begin() { return std::begin(range_); }
    const_iterator begin() const { return std::begin(range_); }
    iterator end() { return std::end(range_); }
    const_iterator end() const { return std::end(range_); }

    bool empty() const { return range_.empty(); }
    std::size_t size() const { return range_.size(); }

    // Conversion operator to allow conversion back to a container
    template<typename Container>
    operator Container() const {
        static_assert(std::is_constructible<Container, const_iterator, const_iterator>::value,
                      "Container must be constructible from a range.");
        return Container(begin(), end());
    }

private:
    Range& range_;
};

TEST_CASE("RangeWrapper functionality") {
    SECTION("Wrapping and iterating over a static array") {
        int arr[] = {1, 2, 3, 4, 5};
        RangeWrapper<int[]> wrapper(arr);
        int sum = 0;
        for (int value : wrapper) {
            sum += value;
        }
        CHECK(sum == 15);
    }

    SECTION("Wrapping and iterating over a std::vector") {
        std::vector<int> vec = {1, 2, 3, 4, 5};
        RangeWrapper<std::vector<int>> wrapper(vec);
        int sum = 0;
        for (int value : wrapper) {
            sum += value;
        }
        CHECK(sum == 15);
    }

    SECTION("Checking the size and emptiness of the wrapped range") {
        std::vector<int> vec = {1, 2, 3, 4, 5};
        RangeWrapper<std::vector<int>> wrapper(vec);
        CHECK(wrapper.size() == 5);
        CHECK(!wrapper.empty());
    }

    SECTION("Converting the RangeWrapper back to a std::vector") {
        std::vector<int> vec = {1, 2, 3, 4, 5};
        RangeWrapper<std::vector<int>> wrapper(vec);
        std::vector<int> vec_copy = wrapper;
        CHECK(vec == vec_copy);
    }
}
