#include <bits/stdc++.h>
using namespace std;

int calculateMaxTeamSize(const vector<int>& sequence) {
    unordered_map<int, int> frequency;
    int distinctCount = 0, maxFrequency = 0;

    for (int num : sequence) {
        frequency[num]++;
        maxFrequency = max(maxFrequency, frequency[num]);
    }
    distinctCount = frequency.size();

    // The maximum size of a valid team is either the number of distinct elements
    // or the maximum frequency of any element, whichever is smaller.
    // However, if the maximum frequency is greater than the number of distinct elements,
    // we can include one more of the most frequent element.
    int maxTeamSize = min(maxFrequency, distinctCount);
    if (maxFrequency > distinctCount) {
        maxTeamSize = distinctCount + 1;
    }
    return maxTeamSize;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> sequence(n);
        for (int i = 0; i < n; i++) {
            cin >> sequence[i];
        }
        cout << calculateMaxTeamSize(sequence) << '\n';
    }
    return 0;
}
