        // Wait for a task to be available
        sem_wait(taskSemaphore);

        // Lock the queue mutex to safely access the queue
        pthread_mutex_lock(&queueMutex);
        if (taskQueue.empty()) {
            // This should not happen as the semaphore count should prevent it
            pthread_mutex_unlock(&queueMutex);
            continue;
        }

        // Get the next task
        int taskID = taskQueue.front();
        taskQueue.pop();

        // Unlock the queue mutex
        pthread_mutex_unlock(&queueMutex);

        // Simulate task execution
        std::cout << "Worker " << pthread_self() << " executing task " << taskID << std::endl;
        sleep(1); // Simulate work by sleeping for 1 second
    }
    return NULL;
}

// Function to add a task to the queue
void addTask(int taskID) {
    // Lock the queue mutex to safely access the queue
    pthread_mutex_lock(&queueMutex);

    // Add the task to the queue
    taskQueue.push(taskID);

    // Unlock the queue mutex
    pthread_mutex_unlock(&queueMutex);

    // Post to the semaphore to signal that a new task is available
    sem_post(taskSemaphore);
}

int main() {
    // Initialize the semaphore with a count of 0
    taskSemaphore = sem_open("taskSemaphore", O_CREAT, S_IRUSR | S_IWUSR, 0);

    // Create worker threads
    pthread_t workers[MAX_WORKERS];
    for (int i = 0; i < MAX_WORKERS; ++i) {
        pthread_create(&workers[i], NULL, workerFunction, NULL);
    }

    // Add tasks to the queue
    for (int i = 1; i <= 10; ++i) {
        addTask(i);
        sleep(1); // Simulate time between adding tasks
    }

    // Wait for worker threads to finish (this example will run indefinitely)
    for (int i = 0; i < MAX_WORKERS; ++i) {
        pthread_join(workers[i], NULL);
    }

    // Cleanup
    sem_close(taskSemaphore);
    sem_unlink("taskSemaphore");
    pthread_mutex_destroy(&queueMutex);

    return 0;
}
