std::vector<std::vector<std::vector<int>>> unstack(const std::vector<std::vector<int>>& tensor, int axis, int num) {
    // Check if the axis is valid
    int rank = tensor.size() > 0 ? tensor[0].size() : 0;
    if (axis < -rank || axis >= rank) {
        throw std::invalid_argument("The attribute axis is out of range.");
    }
    if (axis < 0) axis += rank;

    // Check if the number of outputs is valid
    if (num <= 0) {
        throw std::invalid_argument("The number of outputs must be greater than 0.");
    }

    // Check if the tensor can be unstacked along the given axis
    if (tensor.size() == 0 || tensor[0].size() != num) {
        throw std::invalid_argument("The tensor cannot be unstacked along the given axis with the specified number of outputs.");
    }

    // Perform the unstack operation
    std::vector<std::vector<std::vector<int>>> result(num, std::vector<std::vector<int>>(tensor.size()));
    for (size_t i = 0; i < tensor.size(); ++i) {
        for (int j = 0; j < num; ++j) {
            result[j][i].push_back(tensor[i][j]);
        }
    }

    return result;
}

int main() {
    try {
        // Test case 1
        std::vector<std::vector<int>> tensor1 = {{1, 2}, {3, 4}};
