// Mock definitions to represent the API and data structures used in the given code snippet.
// In a real-world scenario, these would be provided by the deep learning framework's API.
enum DataType { FP32, FP16, INT8, UINT8 };
enum Layout { NCHW, NHWC };
struct Tensor {
    std::vector<int> shape;
    DataType data_type;
    std::vector<float> data;
    // ... other members and methods ...
};
struct Node {
    Tensor* input_tensor;
    Tensor* output_tensor;
    Tensor* gamma_tensor;
    Tensor* beta_tensor;
    // ... other members and methods ...
};

class RefInstanceNorm {
private:
    float eps;
    DataType data_type;
    Layout layout;

public:
    RefInstanceNorm(float epsilon, DataType dt, Layout lt) : eps(epsilon), data_type(dt), layout(lt) {}

    bool Prerun(Node* node) {
        // Check if the kernel for the given layout and data type is registered.
        // For simplicity, we assume it is always registered.
        return true;
    }

    bool Run(Node* node) {
        if (!node || !node->input_tensor || !node->output_tensor || !node->gamma_tensor || !node->beta_tensor) {
            throw std::invalid_argument("Node or tensors cannot be null.");
        }

        Tensor* input_tensor = node->input_tensor;
        Tensor* output_tensor = node->output_tensor;
        Tensor* gamma_tensor = node->gamma_tensor;
        Tensor* beta_tensor = node->beta_tensor;

        int N = input_tensor->shape[0];
        int C = input_tensor->shape[1];
        int H = input_tensor->shape[2];
        int W = input_tensor->shape[3];

        // Initialize output tensor with the same shape as input.
        output_tensor->shape = input_tensor->shape;
        output_tensor->data.resize(N * C * H * W);

        for (int n = 0; n < N; ++n) {
            for (int c = 0; c < C; ++c) {
                float sum = 0.0f;
                float sq_sum = 0.0f;
                for (int h = 0; h < H; ++h) {
                    for (int w = 0; w < W; ++w) {
                        float val = input_tensor->data[n * C * H * W + c * H * W + h * W + w];
                        sum += val;
                        sq_sum += val * val;
                    }
                }

                float mean = sum / (H * W);
                float variance = sq_sum / (H * W) - mean * mean;
                float gamma = gamma_tensor->data[c];
                float beta = beta_tensor->data[c];

                for (int h = 0; h < H; ++h) {
                    for (int w = 0; w < W; ++w) {
                        float val = input_tensor->data[n * C * H * W + c * H * W + h * W + w];
                        output_tensor->data[n * C * H * W + c * H * W + h * W + w] =
                            (val - mean) / std::sqrt(variance + eps) * gamma + beta;
                    }
                }
            }
        }

        return true;
    }
};

// Test cases to verify the solution correctness.
int main() {
    // Create a mock node with input, output, gamma, and beta tensors.
    Node node;
    Tensor input_tensor = {{1, 3, 4, 4}, FP32, std::vector<float>(48, 1.0f)}; // Example data.
