using namespace std;

/**
 * Sorts an array of integers using the bubble sort algorithm.
 * 
 * The function takes a vector of integers by reference and sorts it in place.
 * It uses the bubble sort algorithm, which repeatedly steps through the list,
 * compares each pair of adjacent items and swaps them if they are in the wrong order.
 * The pass through the list is repeated until no swaps are needed.
 * 
 * @param arr The vector of integers to be sorted.
 */
void bubbleSort(vector<int>& arr) {
    int n = arr.size();
    bool swapped;
    do {
        swapped = false;
        for (int i = 1; i < n; ++i) {
            if (arr[i - 1] > arr[i]) {
                swap(arr[i - 1], arr[i]);
                swapped = true;
            }
        }
        --n; // Each iteration, the largest element is bubbled to the end, so we can ignore it in the next pass
    } while (swapped);
}

int main() {
    int num;
    cout << "Enter the size of the array: ";
    cin >> num;

    vector<int> a(num);

    cout << "Enter the elements: ";
    for (int i = 0; i < num; i++) {
        cin >> a[i];
    }

    bubbleSort(a);

    cout << "Sorted array is: ";
    for (int i = 0; i < num; i++) {
        cout << a[i] << "\t";
    }
    cout << endl;

    return 0;
}

// Test cases to verify the solution correctness
