#include "heapNode.h"
using namespace std;

class MinHeap {
private:
    vector<heapNode> heap;

    void heapifyUp(int index) {
        while (index > 0 && heap[(index - 1) / 2] < heap[index]) {
            swap(heap[index], heap[(index - 1) / 2]);
            index = (index - 1) / 2;
        }
    }

    void heapifyDown(int index) {
        int smallest = index;
        int leftChildIndex = 2 * index + 1;
        int rightChildIndex = 2 * index + 2;

        if (leftChildIndex < heap.size() && heap[leftChildIndex] < heap[smallest]) {
            smallest = leftChildIndex;
        }

        if (rightChildIndex < heap.size() && heap[rightChildIndex] < heap[smallest]) {
            smallest = rightChildIndex;
        }

        if (smallest != index) {
            swap(heap[index], heap[smallest]);
            heapifyDown(smallest);
        }
    }

public:
    void insert(heapNode node) {
        heap.push_back(node);
        heapifyUp(heap.size() - 1);
    }

    heapNode getMin() {
        if (isEmpty()) {
            throw runtime_error("Heap is empty");
        }
        heapNode minNode = heap[0];
        heap[0] = heap.back();
        heap.pop_back();
        heapifyDown(0);
        return minNode;
    }

    bool isEmpty() const {
        return heap.empty();
    }

    int size() const {
        return heap.size();
    }
};

// Test cases to verify the solution correctness
int main() {
    MinHeap minHeap;
    minHeap.insert(heapNode(5, 'a'));
    minHeap.insert(heapNode(9, 'b'));
    minHeap.insert(heapNode(3, 'c'));
    minHeap.insert(heapNode(4, 'd'));
    minHeap.insert(heapNode(2, 'e'));

    cout << "MinHeap size: " << minHeap.size() << endl;
    while (!minHeap.isEmpty()) {
        heapNode minNode = minHeap.getMin();
