using namespace std;

/**
 * Finds the length of the longest alternating subsequence in a given sequence.
 * 
 * @param A The sequence of integers.
 * @return The length of the longest alternating subsequence.
 */
int longestAlternatingSubsequence(const vector<int>& A) {
    int N = A.size() - 1; // Adjust for 1-based indexing
    vector<int> even(N + 1, 0);
    vector<int> odd(N + 1, 1);
    int ans = 1; // The minimum length of an alternating subsequence is 1

    for (int i = 1; i <= N; i++) {
        for (int j = 1; j < i; j++) {
            if (A[i] > A[j]) {
                even[i] = max(even[i], odd[j] + 1);
            }
            if (A[j] > A[i]) {
                odd[i] = max(odd[i], even[j] + 1);
            }
        }
        ans = max(ans, max(even[i], odd[i])); // Update the answer with the maximum length found so far
    }

    return ans;
}

int main() {
    int test;
    cin >> test;
    while (test--) {
        int N;
        cin >> N;
        vector<int> A(N + 1); // Using 1-based indexing
        for (int i = 1; i <= N; i++) {
            cin >> A[i];
        }

        int ans = longestAlternatingSubsequence(A);
        cout << ans << endl;
    }
    return 0;
}
