#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    /**
     * Calculate the minimum number of steps needed to water all plants.
     * 
     * @param plants A vector of integers where plants[i] is the amount of water the i-th plant needs.
     * @param capacity An integer representing the capacity of the watering can.
     * @return The minimum number of steps needed to water all the plants.
     */
    int wateringPlants(vector<int>& plants, int capacity) {
        int cp = capacity; // Current capacity of the watering can
        int steps = 0; // Steps taken to water the plants
        for (int i = 0; i < plants.size(); i++) {
            // If the current capacity is less than the water needed for the plant
            if (cp < plants[i]) {
                // Walk back to the river to refill (2 * i steps) and then return to the current plant
                steps += 2 * i;
                cp = capacity; // Refill the watering can
            }
            cp -= plants[i]; // Water the plant
            steps++; // Take a step to the next plant
        }
        return steps;
    }
};

int main() {
    // Test cases
    Solution solution;
    vector<int> plants1 = {2, 4, 5, 1, 2};
    int capacity1 = 6;
    cout << "Test Case 1: " << solution.wateringPlants(plants1, capacity1) << endl; // Expected output: 17

    vector<int> plants2 = {1, 1, 1, 4, 2, 3};
    int capacity2 = 4;
    cout << "Test Case 2: " << solution.wateringPlants(plants2, capacity2) << endl; // Expected output: 30

    vector<int> plants3 = {7, 7, 7, 7, 7, 7, 7};
    int capacity3 = 8;
    cout << "Test Case 3: " << solution.wateringPlants(plants3, capacity3) << endl; // Expected output: 49

    return 0;
}
