#include <iostream>
#include <string>

#if defined (ACE_HAS_IP_MULTICAST)

static const ACE_TCHAR *INTERFACE = 0;
static const char *MCAST_ADDR = "239.255.0.1"; // Example multicast address
static const u_short UDP_PORT = 12345; // Example UDP port

class MulticastChatHandler : public ACE_Event_Handler {
public:
  MulticastChatHandler(const ACE_TCHAR *a_interface, ACE_Reactor &reactor)
    : mcast_addr_(UDP_PORT, MCAST_ADDR), reactor_(reactor) {
    if (mcast_.join(mcast_addr_, 1, a_interface) == -1)
      ACE_ERROR((LM_ERROR, "%p\n", "can't join multicast group"));

    if (reactor.register_handler(this, ACE_Event_Handler::READ_MASK) == -1)
      ACE_ERROR((LM_ERROR, "%p\n", "can't register with Reactor"));
  }

  virtual int handle_input(ACE_HANDLE) {
    char buf[BUFSIZ];
    ACE_INET_Addr remote_addr;
    ssize_t recv_cnt = mcast_.recv(buf, sizeof(buf), remote_addr);
    if (recv_cnt > 0) {
      std::cout << "Message from " << remote_addr.get_host_addr() << ":"
                << remote_addr.get_port_number() << " - "
                << std::string(buf, recv_cnt) << std::endl;
    } else {
      ACE_ERROR_RETURN((LM_ERROR, "%p\n", "recv error"), -1);
    }
    return 0;
  }

  virtual ACE_HANDLE get_handle() const {
    return mcast_.get_handle();
  }

  ~MulticastChatHandler() {
    if (mcast_.leave(mcast_addr_) == -1)
      ACE_ERROR((LM_ERROR, "%p\n", "leave fails"));
  }

private:
  ACE_SOCK_Dgram_Mcast mcast_;
  ACE_INET_Addr mcast_addr_;
  ACE_Reactor &reactor_;
};

int ACE_TMAIN(int argc, ACE_TCHAR *argv[]) {
  ACE_Get_Opt get_opt(argc, argv, ACE_TEXT("i:"));
  int c;
  while ((c = get_opt()) != -1) {
    if (c == 'i') {
      INTERFACE = get_opt.opt_arg();
    } else {
      ACE_DEBUG((LM_DEBUG, "Usage: %s -i interface\n", argv[0]));
      return 1;
    }
  }

  ACE_Reactor reactor;
  MulticastChatHandler handler(INTERFACE, reactor);

  // Run the event loop.
  reactor.run_reactor_event_loop();

  return 0;
}

