#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

template<typename T>
class Heap {
private:
    int n;
    vector<T> h;

public:
    Heap() : n(1) {
        h.push_back(0); // Dummy element to make the indexing start from 1
    }

    void push(T v) {
        h.push_back(v);
        int i = n++;
        while (i != 1 && h[i] > h[i / 2]) {
            swap(h[i], h[i / 2]);
            i /= 2;
        }
    }

    T top() {
        return h[1];
    }

    void pop() {
        h[1] = h[--n];
        int i = 1;
        while (i < n / 2) {
            int c1 = 2 * i;
            int c2 = 2 * i + 1;
            int maxIndex = i;
            if (c1 < n && h[c1] > h[maxIndex]) maxIndex = c1;
            if (c2 < n && h[c2] > h[maxIndex]) maxIndex = c2;
            if (maxIndex == i) break;
            swap(h[i], h[maxIndex]);
            i = maxIndex;
        }
    }

    bool empty() {
        return n == 1;
    }

    void print() {
        for (int i = 1; i < n; i++) {
            cout << h[i] << " ";
        }
        cout << endl;
    }
};

void heapify(vector<int>& h, int n) {
    for (int i = n / 2; i >= 1; --i) {
        int j = i;
        while (j <= n / 2) {
            int c1 = 2 * j;
            int c2 = c1 + 1;
            int maxIndex = j;
            if (c1 <= n && h[c1] > h[maxIndex]) maxIndex = c1;
            if (c2 <= n && h[c2] > h[maxIndex]) maxIndex = c2;
            if (maxIndex == j) break;
            swap(h[j], h[maxIndex]);
            j = maxIndex;
        }
    }
}

void heapSort(vector<int>& h, int n) {
    for (int i = n; i > 1; --i) {
        swap(h[1], h[i]);
        heapify(h, i - 1);
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> a(n + 1); // 1-indexed array for heap
    Heap<int> h1;
    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        h1.push(a[i]);
    }

    h1.print();

    while (!h1.empty()) {
        cout << h1.top() << " ";
        h1.pop();
    }
    cout << endl << "The array initially: " << endl;

    for (int i = 1; i <= n; i++) {
        cout << a[i] << " ";
    }

    cout << endl;

    heapify(a, n);

    cout << "After heapify: " << endl;

    for (int i = 1; i <= n; i++) {
        cout << a[i] << " ";
    }

    heapSort(a, n);
    cout << "\nAfter heapSort: " << endl;

    for (int i = 1; i <= n; i++) {
        cout << a[i] << " ";
    }
    return 0;
}
