#include <utility>
#include <algorithm>

using namespace std;

/**
 * Determines the number of animals that have entered the reserve at least once
 * and the number of animals that have stayed within the reserve for at least k
 * consecutive time points.
 *
 * @param n The number of animals.
 * @param k The minimum number of consecutive time points to be considered staying in the reserve.
 * @param t The number of time points.
 * @param xl The x-coordinate of the bottom-left corner of the reserve.
 * @param yd The y-coordinate of the bottom-left corner of the reserve.
 * @param xr The x-coordinate of the top-right corner of the reserve.
 * @param yu The y-coordinate of the top-right corner of the reserve.
 * @param trails The trails of the animals, each trail is a vector of time points (x, y).
 * @return A pair of integers where the first is the number of animals that entered the reserve
 *         and the second is the number of animals that stayed for at least k consecutive time points.
 */
pair<int, int> trackAnimals(int n, int k, int t, int xl, int yd, int xr, int yu, const vector<vector<pair<int, int>>>& trails) {
    int enteredReserve = 0;
    int stayedInReserve = 0;

    for (const auto &trail : trails) {
        bool hasEntered = false;
        int consecutiveCount = 0;
        int maxConsecutiveCount = 0;

        for (int i = 0; i < trail.size(); ++i) {
            int x = trail[i].first, y = trail[i].second;
            if (x >= xl && x <= xr && y >= yd && y <= yu) {
                hasEntered = true;
                consecutiveCount++;
            } else {
                maxConsecutiveCount = max(maxConsecutiveCount, consecutiveCount);
                consecutiveCount = 0;
            }
        }
        maxConsecutiveCount = max(maxConsecutiveCount, consecutiveCount);

        if (hasEntered) enteredReserve++;
        if (maxConsecutiveCount >= k) stayedInReserve++;
    }

    return {enteredReserve, stayedInReserve};
}

int main() {
    int n, k, t, xl, yd, xr, yu;
    cin >> n >> k >> t >> xl >> yd >> xr >> yu;

    vector<vector<pair<int, int>>> trails(n);
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < t; ++j) {
            int x, y;
            cin >> x >> y;
            trails[i].emplace_back(x, y);
        }
    }

    pair<int, int> result = trackAnimals(n, k, t, xl, yd, xr, yu, trails);
    cout << result.first << endl; // Number of animals that entered the reserve
    cout << result.second << endl; // Number of animals that stayed for at least k consecutive time points

    return 0;
}
