#include <iostream>
#include <cstdlib>

using namespace std;

template<typename t>
class tcontainer {
public:
    virtual void push(const t&) = 0;
    virtual void pop() = 0;
    virtual const t& begin() = 0;
    virtual const t& end() = 0;
    virtual size_t size() const = 0;
    virtual ~tcontainer() {}
};

template<typename t>
class tvector : public tcontainer<t> {
public:
    static const size_t _step = 100;

    tvector() : _size(0), _cap(_step), buf(static_cast<t*>(malloc(sizeof(t) * _cap))) {}

    ~tvector() {
        free(buf);
    }

    void recapacity(size_t s) {
        buf = static_cast<t*>(realloc(buf, sizeof(t) * s));
        if (!buf) {
            throw std::bad_alloc();
        }
        _cap = s;
    }

    virtual void push(const t& v) {
        if (_size >= _cap) {
            recapacity(_cap + _step);
        }
        buf[_size++] = v;
    }

    virtual void pop() {
        if (_size) {
            _size--;
        }
    }

    virtual const t& begin() {
        return buf[0];
    }

    virtual const t& end() {
        if (_size) {
            return buf[_size - 1];
        }
        throw std::out_of_range("Vector is empty");
    }

    virtual size_t size() const {
        return _size;
    }

    const t& operator[] (size_t i) const {
        if (i < _size) {
            return buf[i];
        }
        throw std::out_of_range("Index out of range");
    }

private:
    size_t _size; // Number of elements
    size_t _cap;  // Allocated capacity
    t* buf;       // Pointer to the data
};

int main() {
    tvector<int> v;
    for (int i = 0; i < 1000; ++i) {
        v.push(i);
    }

    for (size_t i = 0; i < v.size(); ++i) {
        cout << v[i] << endl;
    }

    while (v.size() > 0) {
        v.pop();
    }

    return 0;
}
