#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
using namespace std;

/**
 * @brief Determines the minimum number of elevator trips required to transport all items.
 * 
 * @param n The number of items.
 * @param x The maximum capacity of the elevator.
 * @param weights A vector containing the weights of the items.
 * @return int The minimum number of trips required.
 */
int minElevatorTrips(int n, int x, const vector<int>& weights) {
    vector<pair<int, int>> states((1 << n), {n + 1, x + 1});
    states[0] = {1, 0};

    for (int mask = 1; mask < (1 << n); mask++) {
        for (int i = 0; i < n; i++) {
            if (mask & (1 << i)) {
                auto &[elevators, weight] = states[mask ^ (1 << i)];
                if (weight + weights[i] > x) {
                    states[mask] = min(states[mask], {elevators + 1, weights[i]});
                } else {
                    states[mask] = min(states[mask], {elevators, weight + weights[i]});
                }
            }
        }
    }

    return states[(1 << n) - 1].first;
}

int main() {
    int n, x;
    cin >> n >> x;
    vector<int> weights(n);
    for (auto& weight : weights) cin >> weight;

    cout << minElevatorTrips(n, x, weights) << "\n";
    return 0;
}

