    while (!q.empty()) {
        int y, x;
        tie(y, x) = q.front();
        q.pop();
        for (int i = 0; i < 4; i++) {
            int ty = y + dy[i];
            int tx = x + dx[i];
            if (ty < start_y || ty >= N || tx < start_x || tx >= M || route[ty][tx] == 0)
                continue;
            if (visited[ty][tx] > 0)
                continue;
            visited[ty][tx] = visited[y][x] + 1;
            q.push({ty, tx});
        }
    }
    return visited[N-1][M-1];
}

int main() {
    scanf("%d %d", &N, &M);
    for (int i = 0; i < N; i++)
        for (int j = 0; j < M; j++)
            scanf("%1d", &route[i][j]);

    int result = shortestPathLength();
    if (result > 0) {
        printf("%d\n", result);
    } else {
        printf("-1\n");
    }

    return 0;
}
