class Solution{
    public:
    /**
     * Finds the kth element in the array formed by merging two sorted arrays.
     * 
     * @param arr1 The first sorted array.
     * @param arr2 The second sorted array.
     * @param n The size of the first array.
     * @param m The size of the second array.
     * @param k The kth position to find the element for (1-indexed).
     * @return The kth element of the merged array.
     */
    int kthElement(int arr1[], int arr2[], int n, int m, int k){
        if(n > m){
            return kthElement(arr2, arr1, m, n, k);
        }
        int low = max(0, k - m);
        int high = min(k, n);
        while(low <= high){
            int cut1 = (low + high) / 2;
            int cut2 = k - cut1;
            int l1 = cut1 == 0 ? INT_MIN : arr1[cut1 - 1];
            int l2 = cut2 == 0 ? INT_MIN : arr2[cut2 - 1];
            int r1 = cut1 == n ? INT_MAX : arr1[cut1];
            int r2 = cut2 == m ? INT_MAX : arr2[cut2];
            if(l1 <= r2 && l2 <= r1){
                return max(l1, l2);
            }
            else if(l1 > r2){
                high = cut1 - 1;
            }
            else{
                low = cut1 + 1;
            }
        }
        return 1; // This line should never be reached if input is valid
    }
};

