using number = double;

number getConditionalityAssessment(const vector<number> &result, const vector<number> &resultDisturbance,
                                   const vector<number> &b, const vector<number> &bDisturbance) {
    auto deltaResult = getResidual(result, resultDisturbance);
    auto deltaB = getResidual(b, bDisturbance);
    return deltaResult / deltaB;
}

int main() {
    // Task 1: Read a square matrix
    vector<vector<number>> matrix;
    getMatrixEx1(matrix);

    // Task 2: Find all the eigenvalues using the QR algorithm
    auto eigenValues = QR<number>::findEigenValues(matrix);
    cout << "Eigenvalues:" << endl;
    printVector(eigenValues);

    // Task 3 and 4: Find and print eigenvectors for each eigenvalue
    for (const auto &eigenValue : eigenValues) {
        cout << "Eigenvector for eigenvalue " << eigenValue << ":" << endl;
        auto iterMatrix = matrix;
        auto eigenvector = QR<number>::reverseIterations(iterMatrix, eigenValue);
        printVector(eigenvector);
        cout << "--------------------------------------------------------" << endl;
    }

    // Task 5: Calculate and print the condition number of the matrix
    cout << "Condition number of the matrix: " << getConditionNumber(matrix, 3) << endl;

    // Task 6 and 7: Perturb the input vector b and assess the sensitivity of the solution
    number coefDisturbance = 0.01;
    auto A = getMatrixA(matrix);
    auto b = getVectorB(matrix);
    auto result = QR<number>::solveSystem(A, b);
    cout << "Original solution vector:" << endl;
    printVector(result);

    for (size_t i = 0; i < b.size(); ++i) {
        auto bDisturbance = b;
        bDisturbance[i] += coefDisturbance;
        auto resultDisturbance = QR<number>::solveSystem(A, bDisturbance);
        cout << "Perturbed solution vector for disturbance in b[" << i << "]:" << endl;
        printVector(resultDisturbance);
        cout << "Conditionality assessment: " << getConditionalityAssessment(result, resultDisturbance, b, bDisturbance) << endl;
        cout << "--------------------------------------------------------" << endl;
    }

    return 0;
}
