using namespace std;

class Solution {
public:
    /**
     * Searches for the target value in a sorted array and returns the index where it is found.
     * If the target is not found, returns the index where it should be inserted to maintain
     * the sorted order.
     * 
     * @param nums A reference to a vector of integers sorted in ascending order.
     * @param target The integer value to search for or insert into the vector.
     * @return The index of the target if found, or the index where it should be inserted.
     */
    int searchInsert(vector<int>& nums, int target) {
        int L = 0;
        int R = nums.size() - 1;
        while (L <= R) {
            int m = (R - L) / 2 + L;
            if (nums[m] == target)
                return m;
            else if (nums[m] > target)
                R = m - 1;
            else
                L = m + 1;
        }
        return L;
    }
};

int main() {
    // Test cases
    Solution solution;
    vector<int> nums1 = {1, 3, 5, 6};
    cout << "Test Case 1: " << solution.searchInsert(nums1, 5) << endl; // Output: 2
    cout << "Test Case 2: " << solution.searchInsert(nums1, 2) << endl; // Output: 1
    cout << "Test Case 3: " << solution.searchInsert(nums1, 7) << endl; // Output: 4
    cout << "Test Case 4: " << solution.searchInsert(nums1, 0) << endl; // Output: 0
    vector<int> nums2 = {};
    cout << "Test Case 5: " << solution.searchInsert(nums2, 1) << endl; // Output: 0
    return 0;
}
