class Server {
public:
    void run(int argc, const char** argv) {
        std::cout << "Server is running..." << std::endl;
        sleep(2); // Simulate server operation
        do_restart(argc, argv);
    }

private:
    static char** duplicate_arguments(int argc, const char** argv) {
        char** arguments = new char*[argc + 1];

        for (int i = 0; i < argc; ++i) {
            size_t length = strlen(argv[i]);
            arguments[i] = new char[length + 1];
            strncpy(arguments[i], argv[i], length);
            arguments[i][length] = '\0';
        }
        arguments[argc] = nullptr;
        return arguments;
    }

    void do_restart(int argc, const char** original_argv) {
        char** argv = duplicate_arguments(argc, original_argv);

        std::cout << "Attempting to restart server..." << std::endl;
        execve(argv[0], argv, nullptr);
        std::cerr << "!! execve failed, the server won't restart" << std::endl;

        for (int i = 0; argv[i]; ++i) {
            delete[] argv[i];
        }
        delete[] argv;
    }
};

int main(int argc, const char** argv) {
    Server server;
    server.run(argc, argv);
    return 0;
}
