  string toHex(int num) {
    if (num == 0) {
      return "0";
    }
    string hexChars = "0123456789abcdef";
    string hex = "";
    int count = 0;
    while (num && count++ < 8) {
      hex = hexChars[num & 0xF] + hex;
      num >>= 4;
    }
    return hex;
  }
};

