/**
 * Extracts the acronym from a hyphen-separated string.
 * 
 * @param fullName The string from which to extract the acronym.
 * @return The acronym as a string.
 */
std::string extractAcronym(const std::string& fullName) {
    string acronym = "";
    bool nextIsFirst = true; // Flag to check if the next character is the first of a word

    for (const char& c : fullName) {
        if (nextIsFirst && isalpha(c)) {
            acronym += toupper(c);
            nextIsFirst = false;
        } else if (c == '-') {
            nextIsFirst = true;
        }
    }

    return acronym;
}

