#include <iostream>
#include <vector>
#include <unordered_map>
using namespace std;

class Solution {
public:
    /**
     * Counts the number of tuples (i, j, k, l) such that A[i] + B[j] + C[k] + D[l] is zero.
     * 
     * @param nums1 First list of integers.
     * @param nums2 Second list of integers.
     * @param nums3 Third list of integers.
     * @param nums4 Fourth list of integers.
     * @return The count of tuples that sum up to zero.
     */
    int fourSumCount(vector<int>& nums1, vector<int>& nums2, vector<int>& nums3, vector<int>& nums4) {
        int n = nums1.size();
        unordered_map<int, int> map;

        // Store the sum of all possible pairs from nums1 and nums2
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int sum = nums1[i] + nums2[j];
                map[sum]++;
            }
        }

        int ans = 0;
        // For each pair from nums3 and nums4, check if the negative sum exists in the map
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                int sum = nums3[i] + nums4[j];
                ans += map[-sum];
            }
        }
        return ans;
    }
};

int main() {
    Solution solution;
    vector<int> A = {1, 2};
    vector<int> B = {-2, -1};
    vector<int> C = {-1, 2};
    vector<int> D = {0, 2};

    // Test case 1
    cout << "Test case 1: " << solution.fourSumCount(A, B, C, D) << endl; // Expected output: 2

    // Test case 2
    vector<int> E = {0, 1, -1};
    vector<int> F = {-1, 1, 0};
    vector<int> G = {0, 0, 1};
    vector<int> H = {1, -1, 1};
    cout << "Test case 2: " << solution.fourSumCount(E, F, G, H) << endl; // Expected output: 17

    return 0;
}
