using namespace std;

/**
 * Calculates the maximum number of unique paths in an n x n grid.
 * The only movements allowed are either down or right at any point in time.
 * The first row and the first column are initialized with 1s.
 * 
 * @param n The size of the grid.
 * @return The maximum number of unique paths from the top-left to the bottom-right corner.
 */
int calculateMaxUniquePaths(int n) {
    vector<vector<int>> grid(n + 1, vector<int>(n + 1));
    for (int k = 1; k <= n; ++k) {
        grid[k][1] = 1;
        grid[1][k] = 1;
    }
    for (int i = 2; i <= n; ++i) {
        for (int j = 2; j <= n; ++j) {
            grid[i][j] = grid[i - 1][j] + grid[i][j - 1];
        }
    }
    return grid[n][n];
}

int main() {
    int n;
    cout << "Enter the size of the grid (n x n): ";
    cin >> n;
    int maxPaths = calculateMaxUniquePaths(n);
    cout << "The maximum number of unique paths is: " << maxPaths << '\n';
    return 0;
}

