#include <cassert>

struct Agent {
    int age, risk;

    static Agent read(int a, int r) {
        return Agent{a, r};
    }
};

int calculateMinimumRisk(std::vector<Agent>& agents) {
    int n = agents.size();
    std::sort(agents.begin(), agents.end(), [](const Agent& a, const Agent& b){
        assert(a.age != b.age);
        return a.age < b.age;
    });
    const int INF = (int)1e9+1;
    std::vector<int> minRisk(n+1, INF);

    minRisk[1] = 0; // No risk for a single agent
    minRisk[2] = agents[1].risk; // Risk of the second agent for a team of two

    if (n >= 3) {
        minRisk[3] = agents[2].risk + agents[1].risk; // Risk of the first three agents for a team of three
    }
    for (int len = 4; len <= n; ++len) {
        minRisk[len] = std::min(minRisk[len-2] + agents[len-1].risk, minRisk[len-3] + agents[len-2].risk + agents[len-1].risk);
    }
    return minRisk[n];
}

int main() {
    // Test cases
    std::vector<Agent> agents = {
        Agent::read(25, 10), // Agent with age 25 and risk 10
        Agent::read(30, 20), // Agent with age 30 and risk 20
        Agent::read(35, 30), // Agent with age 35 and risk 30
        Agent::read(40, 40), // Agent with age 40 and risk 40
        Agent::read(45, 50)  // Agent with age 45 and risk 50
    };

    int minimumRisk = calculateMinimumRisk(agents);
    std::cout << "Minimum possible total risk: " << minimumRisk << std::endl;

    return 0;
}
