#include <iostream>
#include <stack>
using namespace std;

class Solution
{
public:
    /**
     * Checks if the parentheses in the string are balanced.
     * 
     * @param s The string containing the parentheses to be checked.
     * @return true if the parentheses are balanced, false otherwise.
     */
    bool isValid(string s)
    {
        stack<char> st;
        for (char ch : s)
        {
            switch (ch)
            {
                case '(':
                case '{':
                case '[':
                    st.push(ch);
                    break;
                case ')':
                    if (st.empty() || st.top() != '(') return false;
                    st.pop();
                    break;
                case '}':
                    if (st.empty() || st.top() != '{') return false;
                    st.pop();
                    break;
                case ']':
                    if (st.empty() || st.top() != '[') return false;
                    st.pop();
                    break;
                default:
                    // Ignore non-parenthesis characters
                    break;
            }
        }
        return st.empty();
    }
};

int main()
{
    Solution solution;
    // Test cases
    cout << boolalpha; // Print bools as true/false
    cout << "Test Case 1: " << solution.isValid("()") << endl; // true
    cout << "Test Case 2: " << solution.isValid("()[]{}") << endl; // true
    cout << "Test Case 3: " << solution.isValid("(]") << endl; // false
    cout << "Test Case 4: " << solution.isValid("([)]") << endl; // false
    cout << "Test Case 5: " << solution.isValid("{[]}") << endl; // true
    cout << "Test Case 6: " << solution.isValid("{[()]}") << endl; // true
    cout << "Test Case 7: " << solution.isValid("{[(])}") << endl; // false
    cout << "Test Case 8: " << solution.isValid("") << endl; // true
    cout << "Test Case 9: " << solution.isValid("((()))") << endl; // true
    cout << "Test Case 10: " << solution.isValid("((())") << endl; // false
    return 0;
}
