using namespace std;

int main(int argc, char* argv[]) {
    string route = "";
    int lifetime = 2;
    string hint = "";

    try {
        namespace po = boost::program_options;
        po::variables_map vm;

        po::options_description generic("Generic Options");
        generic.add_options()("help,h", "print help message");

        po::options_description config("Configuration");
        config.add_options()
            ("lifetime,t", po::value<int>(&lifetime)->default_value(2),
             "set the lifetime of Interest. default: 2")
            ("hint,H", po::value<string>(&hint),
             "enable the forwarding Hint of Root Zone, which is disable by default");

        po::options_description hidden("Hidden Options");
        hidden.add_options()
            ("prefix,p", po::value<string>(&route)->default_value("/"),
             "routable prefix of the server. default: /");

        po::positional_options_description position;
        position.add("prefix", 1);

        po::options_description cmdline_options;
        cmdline_options.add(generic).add(config).add(hidden);

        po::options_description config_file_options;
        config_file_options.add(config).add(hidden);

        po::options_description visible("Allowed options");
        visible.add(generic).add(config);

        po::parsed_options parsed =
            po::command_line_parser(argc, argv).options(cmdline_options).positional(position).run();

        po::store(parsed, vm);
        po::notify(vm);

        if (vm.count("help")) {
            cout << "Usage: caching-resolver-daemon [options] /routable/prefix/announced" << endl;
            cout << visible << endl;
            return 0;
        }

        cout << "routablePrefix=" << route << " lifetime=" << lifetime << "s" << endl;
    }
    catch (const std::exception& ex) {
        cout << "Parameter Error: " << ex.what() << endl;
        return 0;
    }
    catch (...) {
        cout << "Parameter Unknown error" << endl;
        return 0;
    }

    try {
        Face face;
        KeyChain keyChain;
        NameCachingResolver server(face, keyChain, Name(route));

        time::milliseconds t(1000 * lifetime);
        server.setInterestLifetime(t);

        if (!hint.empty()) {
            server.setEnableForwardingHint(true);
            server.setRootZoneForwardingHint(Name(hint));
        }

        server.run();

        cout << "The server ends with hasError=" << server.hasError() << endl;

        return server.hasError() ? -1 : 1;
    }
    catch (const std::exception& ex) {
        cout << "Runtime Error: " << ex.what() << endl;
        return -1;
    }
    catch (...) {
        cout << "Runtime Unknown error" << endl;
        return -1;
    }
}
