    cout << fixed << setprecision(9) << ((ld)max(arr[0], d - arr[n - 1]) > Max_D / 2.0 ? max(arr[0], d - arr[n - 1]) : Max_D / 2.0) << "\n";
}

int main()
{
    solve();
    return 0;
}

