#include <bits/stdc++.h>
using namespace std;

typedef long long ll;
typedef pair<int, int> pii;

const ll INF = 1e18;

void chmin(ll &a, ll b) { a = min(a, b); }

int grid[1007][2007];
int N, H, M, K;
ll score, ans;
vector<ll> A, goals;
vector<vector<int>> B;
map<int, map<int, int>> keys;
queue<pii> que;
pii cur;

ll check(int start) {
    start++;
    start *= 2;
    start--;
    que.push({1, start});
    while (!que.empty()) {
        cur = que.front(); que.pop();
        int h = cur.first, w = cur.second;
        if (h == H) {
            return A[(w+1)/2-1];
        }
        if (grid[h][w-1] == 1) {
            B[keys[h][w-1]].push_back((start+1)/2-1);
            que.push({h+1, w-2});
        } else if (grid[h][w+1] == 1) {
            B[keys[h][w+1]].push_back((start+1)/2-1);
            que.push({h+1, w+2});
        } else {
            que.push({h+1, w});
        }
    }
    return -1; // This should never be reached if the grid is properly formed
}

int main() {
    cin.tie(0);
    ios::sync_with_stdio(false);

    cin >> N >> M >> H >> K;
    A.resize(N);
    B.resize(M);
    goals.resize(N);
    int W = N * 2;
    memset(grid, -1, sizeof(grid));
    for (int i = 1; i < H; ++i) {
        for (int j = 1; j < W; j += 2) {
            grid[i][j] = 0;
        }
    }
    for (int i = 0; i < N; ++i) cin >> A[i];
    for (int i = 0; i < M; ++i) {
        int a, b;
        cin >> a >> b;
        grid[b][a*2] = 1;
        keys[b][a*2] = i;
    }

    for (int i = 0; i < N; ++i) {
        goals[i] = check(i);
    }
    score = 0;
    for (int i = 0; i < K; ++i) {
        score += goals[i];
    }

    ans = score;
    for (int i = 0; i < M; ++i) {
        int a = B[i][0], b = B[i][1];
        if (a < K && b >= K) {
            chmin(ans, score - goals[a] + goals[b]);
        }
        if (b < K && a >= K) {
            chmin(ans, score - goals[b] + goals[a]);
        }
    }
    cout << ans << '\n';
    return 0;
}
