#include <iostream>
#include <string>

class Solution {
public:
    /**
     * Finds the index of the first occurrence of needle in haystack.
     * 
     * @param haystack The string to be searched within.
     * @param needle The string to be searched for.
     * @return The index of the first occurrence of needle in haystack, or -1 if not found.
     */
    int strStr(std::string haystack, std::string needle) {
        // Edge case: if needle is longer than haystack, it can't be contained
        if (needle.length() > haystack.length()) {
            return -1;
        }

        int N = needle.length();

        // Implement sliding window approach
        for (int i = 0; i <= haystack.length() - N; i++) {
            // Check if the current window matches the needle
            if (haystack.substr(i, N) == needle) {
                return i;
            }
        }

        // Needle not found in haystack
        return -1;
    }
};

// Test cases
int main() {
    Solution solution;
    std::cout << "Test Case 1: " << (solution.strStr("hello", "ll") == 2 ? "Passed" : "Failed") << std::endl;
    std::cout << "Test Case 2: " << (solution.strStr("aaaaa", "bba") == -1 ? "Passed" : "Failed") << std::endl;
    std::cout << "Test Case 3: " << (solution.strStr("a", "a") == 0 ? "Passed" : "Failed") << std::endl;
    std::cout << "Test Case 4: " << (solution.strStr("mississippi", "issip") == 4 ? "Passed" : "Failed") << std::endl;
