        image[i][j] = c2;

        dfs(image, m, n, i + 1, j, c1, c2);
        dfs(image, m, n, i - 1, j, c1, c2);
        dfs(image, m, n, i, j + 1, c1, c2);
        dfs(image, m, n, i, j - 1, c1, c2);
    }

