#include <iostream>
#include <string>
using namespace std;

constexpr int ALPHABET_SIZE = 26;

struct TrieNode {
  TrieNode *child[ALPHABET_SIZE];
  bool isEndOfWord;

  TrieNode() : isEndOfWord(false) {
    for (int i = 0; i < ALPHABET_SIZE; ++i) {
      child[i] = nullptr;
    }
  }
};

class Trie {
public:
  Trie() {
    root = new TrieNode();
  }

  ~Trie() {
    clear(root);
  }

  void insert(string word) {
    TrieNode *pNode = root;
    for (char ch : word) {
      int idx = ch - 'a';
      if (pNode->child[idx] == nullptr) {
        pNode->child[idx] = new TrieNode();
      }
      pNode = pNode->child[idx];
    }
    pNode->isEndOfWord = true;
  }

  bool search(string word) {
    TrieNode *pNode = find(word);
    return pNode != nullptr && pNode->isEndOfWord;
  }

  bool startsWith(string prefix) {
    TrieNode *pNode = find(prefix);
    return pNode != nullptr;
  }

private:
  TrieNode *root;

  TrieNode* find(string s) {
    TrieNode *pNode = root;
    for (char ch : s) {
      int idx = ch - 'a';
      if (pNode->child[idx] == nullptr) {
        return nullptr;
      }
      pNode = pNode->child[idx];
    }
    return pNode;
  }

  void clear(TrieNode *node) {
    for (int i = 0; i < ALPHABET_SIZE; ++i) {
      if (node->child[i]) {
        clear(node->child[i]);
      }
    }
    delete node;
  }
};

int main() {
  Trie trie;
  trie.insert("apple");
  cout << boolalpha << trie.search("apple") << endl;   // returns true
  cout << trie.search("app") << endl;                  // returns false
  trie.insert("app");
  cout << trie.search("app") << endl;                  // returns true
  cout << trie.startsWith("app") << endl;              // returns true
  cout << trie.startsWith("apl") << endl;              // returns false
  return 0;
}
