using namespace std;

/**
 * The Solution class contains a method findDisappearedNumbers which finds all the
 * numbers in the range [1, n] that do not appear in the input vector nums.
 * The algorithm works by iterating over the input vector and marking the presence
 * of numbers by negating the value at the index corresponding to the number.
 * After marking, it iterates again to collect the indexes that point to positive
 * numbers, which indicates the numbers that did not appear in the input vector.
 */
class Solution{
public:
    vector<int> findDisappearedNumbers(vector<int>& nums) {
        int index, length = nums.size();
        for(int i = 0; i < length; i++){
            index = abs(nums[i]) - 1;
            nums[index] = -abs(nums[index]);
        }
        vector<int> result;
        for(int i = 0; i < length; i++)
            if(nums[i] > 0)
                result.push_back(i + 1);
        return result;
    }
};

int main(){
    // Test cases
    vector<vector<int>> testCases = {
        {4,3,2,7,8,2,3,1},
        {1,1},
        {2,2},
        {1,2,2,3,3,4,7,8}
    };

    Solution solution;
    for(auto& test : testCases){
        vector<int> disappearedNumbers = solution.findDisappearedNumbers(test);
        for(int num : disappearedNumbers)
            cout << num << " ";
        cout << endl;
    }
