#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
    static bool compareVectors(vector<int> &a, vector<int> &b) {
        return (a[0] < b[0]);
    }

public:
    vector<vector<int>> merge(vector<vector<int>>& intervals) {
        if (intervals.empty()) return {};

        sort(intervals.begin(), intervals.end(), compareVectors);
        vector<vector<int>> mergedIntervals;

        int start = intervals[0][0], end = intervals[0][1];

        for(int i = 1; i < intervals.size(); i++) {
            if (end < intervals[i][0]) {
                mergedIntervals.push_back(vector<int>{start, end});
                start = intervals[i][0];
                end = intervals[i][1];
            } else {
                end = max(end, intervals[i][1]);
            }
        }

        mergedIntervals.push_back(vector<int>{start, end});
        return mergedIntervals;
    }
};

int main() {
    Solution solution;
    vector<vector<int>> intervals = {{1,3}, {2,6}, {8,10}, {15,18}};
    vector<vector<int>> mergedIntervals = solution.merge(intervals);

    for (const auto& interval : mergedIntervals) {
        cout << "[" << interval[0] << "," << interval[1] << "] ";
    }
    cout << endl;

    return 0;
}
