using namespace std;

class Solution {
public:
  int longestAscendingSubarray(vector<int> &nums) {
    int maxLength = 1;
    int currentLength = 1;
    for (int i = 1; i < nums.size(); ++i) {
      if (nums[i] > nums[i - 1]) {
        ++currentLength;
        maxLength = max(maxLength, currentLength);
      } else {
        currentLength = 1;
      }
    }
    return maxLength;
  }
};

// Test cases
