using namespace std;

int* sieve(int);
int no_of_primes = 0;

const int N = 1000000000; // Maximum value for n

int main() {
    int t;
    int* primes = sieve(ceil(sqrt(N))); // Generate primes up to sqrt(N)
    cin >> t; // Read the number of test cases

    while (t--) {
        int m, n;
        cin >> m >> n; // Read the range [m, n]

        list<int> primes_mn; // List to store primes in the range [m, n]
        if (m == 1) m++;
        if (m == 2 && m <= n) {
            primes_mn.push_back(2);
        }
        if (m % 2 == 0) m++;
        for (int i = m; i <= n; i += 2) {
            primes_mn.push_back(i);
        }

        int max_prime_factor = ceil(sqrt(n));
        for (int i = 0; i < no_of_primes && primes[i] <= max_prime_factor; i++) {
            for (auto it = primes_mn.begin(); it != primes_mn.end();) {
                if (*it != primes[i] && (*it) % primes[i] == 0) {
                    it = primes_mn.erase(it);
                } else {
                    ++it;
                }
            }
        }

        for (auto it = primes_mn.begin(); it != primes_mn.end(); it++) {
            cout << *it << endl;
        }
        cout << endl;
    }
    free(primes);
    return 0;
}

int* sieve(int N) {
    if (N <= 1) {
        return NULL;
    }

    int* primes = (int*)calloc(N + 1, sizeof(int));
    no_of_primes = 1;
    for (int next_prime = 3; next_prime <= N;) {
        if (!primes[next_prime] && next_prime % 2)
            no_of_primes++;

        for (int i = 3; next_prime * i <= N; i += 2) {
            primes[next_prime * i] = 1;
        }

        next_prime += 2;
        while (next_prime <= N && primes[next_prime]) {
            next_prime += 2;
        }
    }

    int* p_primes = (int*)malloc(sizeof(int) * no_of_primes);
    int ind = 0;
    p_primes[ind++] = 2;
    for (int i = 3; i <= N; i += 2) {
        if (primes[i] == 0)
            p_primes[ind++] = i;
    }

    free(primes);
    return p_primes;
}
