#include <unordered_map>
#include <algorithm>
#include <climits>
using namespace std;

class Solution {
public:
    int maximumUniqueSubarray(vector<int> &nums) {
        int sum = 0, sol = INT_MIN, i = 0, j = 0;
        unordered_map<int, int> m;
        while (j < nums.size()) {
            if (m[nums[j]] == 0) {
                sum += nums[j];
                m[nums[j]]++;
                sol = max(sol, sum);
                j++;
            } else {
                sum -= nums[i];
                m[nums[i]]--;
                i++;
            }
        }
        return sol;
    }
};

int main() {
    Solution solution;
    vector<int> test1 = {4, 2, 4, 5, 6};
    vector<int> test2 = {5, 2, 1, 2, 5, 2, 1, 2, 5};
