class Model {
public:
    void setOperands(double operand1, double operand2) {
        this->operand1 = operand1;
        this->operand2 = operand2;
    }

    double add() { return operand1 + operand2; }
    double subtract() { return operand1 - operand2; }
    double multiply() { return operand1 * operand2; }
    double divide() {
        if (operand2 == 0) throw std::runtime_error("Division by zero");
        return operand1 / operand2;
    }

private:
    double operand1, operand2;
};

class Controller {
public:
    Controller(Model *model) : model(model) {}

    void onAddition() {
        model->setOperands(view->getOperand1(), view->getOperand2());
        view->setResult(model->add());
    }

    void onSubtraction() {
        model->setOperands(view->getOperand1(), view->getOperand2());
        view->setResult(model->subtract());
    }

    void onMultiplication() {
        model->setOperands(view->getOperand1(), view->getOperand2());
        view->setResult(model->multiply());
    }

    void onDivision() {
        try {
            model->setOperands(view->getOperand1(), view->getOperand2());
            view->setResult(model->divide());
        } catch (const std::runtime_error& e) {
            view->showError(e.what());
        }
    }

    void setView(MainWindow *view) {
        this->view = view;
    }

private:
    Model *model;
    MainWindow *view;
};

class MainWindow : public QMainWindow {
