    }

    double getOperand2() {
        return operand2Edit->text().toDouble();
    }

    void setResult(double result) {
        resultLabel->setText(QString::number(result));
    }

    void showError(const QString &message) {
        QMessageBox::critical(this, "Error", message);
    }

private:
    QLineEdit *operand1Edit;
    QLineEdit *operand2Edit;
    QLabel *resultLabel;
    Controller *controller;

    void setupUi() {
        auto *centralWidget = new QWidget(this);
        auto *layout = new QGridLayout(centralWidget);

        operand1Edit = new QLineEdit(centralWidget);
        operand2Edit = new QLineEdit(centralWidget);
        resultLabel = new QLabel("Result:", centralWidget);

        auto *addButton = new QPushButton("Add", centralWidget);
        auto *subtractButton = new QPushButton("Subtract", centralWidget);
        auto *multiplyButton = new QPushButton("Multiply", centralWidget);
        auto *divideButton = new QPushButton("Divide", centralWidget);

        layout->addWidget(new QLabel("Operand 1:", centralWidget), 0, 0);
        layout->addWidget(operand1Edit, 0, 1);
        layout->addWidget(new QLabel("Operand 2:", centralWidget), 1, 0);
        layout->addWidget(operand2Edit, 1, 1);
