#include <iostream>

class Solution {
public:
    /**
     * Calculates the power of a given number using fast exponentiation.
     * 
     * @param x The base number as a double.
     * @param n The exponent as an integer.
     * @return The result of x raised to the power n.
     */
    double myPow(double x, int n) {
        if (n == 0) return 1;
        if (n < 0) {
            // Handle negative exponent by converting it to positive
            // and taking the reciprocal of the base.
            return (1 / x) * myPow(1 / x, -(n + 1));
        }
        // Use fast exponentiation by squaring for even exponents
        // and multiply by x for odd exponents.
        return n % 2 == 0 ? myPow(x * x, n / 2) : x * myPow(x, n - 1);
    }
};

// Test cases to verify the solution
int main() {
    Solution sol;

    // Test case 1
    std::cout << "2^10 = " << sol.myPow(2.0, 10) << std::endl; // Expected: 1024

    // Test case 2
    std::cout << "2^-2 = " << sol.myPow(2.0, -2) << std::endl; // Expected: 0.25

    // Test case 3
    std::cout << "3^0 = " << sol.myPow(3.0, 0) << std::endl; // Expected: 1

    // Test case 4
    std::cout << "2^15 = " << sol.myPow(2.0, 15) << std::endl; // Expected: 32768

    // Test case 5
    std::cout << "10^3 = " << sol.myPow(10.0, 3) << std::endl; // Expected: 1000

    return 0;
}
