#include <iostream>
#include <vector>
#include <algorithm>
#include <utility>

// Function to count the frequency of each unique element in a vector
std::vector<std::pair<int, int>> countFrequencies(const std::vector<int>& vec) {
    std::vector<std::pair<int, int>> frequencies;
    std::vector<int> V = vec; // Copy the input vector to avoid modifying the original
    std::sort(V.begin(), V.end()); // Sort the vector
    auto it = V.begin();
    while (it != V.end()) {
        auto upper = std::upper_bound(it, V.end(), *it);
        int count = std::distance(it, upper);
        frequencies.emplace_back(*it, count);
        it = upper;
    }
    return frequencies;
}

int main() {
    // Read a vector of integers from the user
    std::vector<int> inputVector;
    int number;
    std::cout << "Enter integers (type 'end' to finish): ";
    while (std::cin >> number) {
        inputVector.push_back(number);
    }
    std::cin.clear(); // Clear any error flags
    std::cin.ignore(std::numeric_limits<std::streamsize>::max(), '\n'); // Ignore any characters in the input buffer

    // Call the function and print the results
    std::vector<std::pair<int, int>> result = countFrequencies(inputVector);
    for (const auto& elem : result) {
        std::cout << elem.first << " - " << elem.second << std::endl;
    }

    return 0;
}
