```cpp
#include <iostream>
#include <vector>
#include <map>
using namespace std;

// Definition for a Node.
class Node {
public:
    int val;
    vector<Node*> neighbors;
    Node() {
        val = 0;
        neighbors = vector<Node*>();
    }
    Node(int _val) {
        val = _val;
        neighbors = vector<Node*>();
    }
    Node(int _val, vector<Node*> _neighbors) {
        val = _val;
        neighbors = _neighbors;
    }
};

class Solution {
    Node* dfs(Node* node, map<int, Node*>& m) {
        if (!node)
            return nullptr;
        if (m.find(node->val) != m.end())
            return m[node->val];
        Node* newNode = new Node(node->val);
        m[node->val] = newNode;
        for (auto neighbor : node->neighbors) {
            newNode->neighbors.push_back(dfs(neighbor, m));
        }
        return newNode;
    }
public:
    Node* cloneGraph(Node* node) {
        map<int, Node*> m;
        return dfs(node, m);
    }
};

// Helper function to print the graph - for testing purposes
void printGraph(Node* node, map<int, bool>& visited) {
    if (!node || visited[node->val]) return;
    visited[node->val] = true;
    cout << "Node " << node->val << " connects to nodes: ";
    for (auto neighbor : node->neighbors) {
        cout << neighbor->val << " ";
    }
    cout << endl;
    for (auto neighbor : node->neighbors) {
        printGraph(neighbor, visited);
    }
}

int main() {
    // Create a test graph
    Node* node1 = new Node(1);
    Node* node2 = new Node(2);
    Node* node3 = new Node(3);
    Node* node4 = new Node(4);
    node1->neighbors = {node2, node4};
    node2->neighbors = {node1, node3};
    node3->neighbors = {node2, node4};
    node4->neighbors = {node1, node3};

    // Clone the graph
    Solution solution;
    Node* clonedGraph = solution.cloneGraph(node1);

    // Print the original and cloned graph
    map<int, bool> visited;
    cout << "Original graph:" << endl;
    printGraph(node1, visited);

    visited.clear();
    cout << "Cloned graph:" << endl;
    printGraph(clonedGraph, visited);

    // Clean up memory (not shown here, but important in a real-world scenario)
