    cin.ignore(); // To ignore the newline after reading n
    for (int i = 0; i < n; i++) {
        set<string> final;
        getline(cin, str);
        str = clean(str);

        // Generate all possible permutations
        sort(str.begin(), str.end());
        do {
            if (validDay(str)) {
                final.insert(str);
            }
        } while (next_permutation(str.begin(), str.end()));

        if (final.empty()) {
            cout << "0" << endl;
        } else {
            string earliestDate = *final.begin();
            cout << earliestDate.substr(0, 2) << " " << earliestDate.substr(2, 2) << " " << earliestDate.substr(4, 4) << endl;
        }
    }
    return 0;
}

// Remove spaces from the string before generating permutations
string clean(string str) {
    string cleanedStr;
    for (char ch : str) {
        if (ch != ' ') {
            cleanedStr += ch;
        }
    }
    return cleanedStr;
}

// Verify if a date is valid
bool validDay(string str) {
    string day = str.substr(0, 2);
    string month = str.substr(2, 2);
    string year = str.substr(4, 4);

    if (stoi(year) >= 2000) {
        int bix = Bissextile(stoi(year));
        if (stoi(month) <= 0 || stoi(month) > 12) return false;
        int jMax = 31; // Default max days
        switch (stoi(month)) {
            case 2: jMax = 28 + bix; break;
            case 4: case 6: case 9: case 11: jMax = 30; break;
        }

        if (stoi(day) > jMax || stoi(day) == 0) return false;
        return true;
    } else return false;
}

// Determine if the year is a leap year
int Bissextile(int A) {
    if (A % 4 != 0) return 0;
    if (A % 400 == 0) return 1;
    if (A % 100 == 0) return 0;
    return 1;
}
