#include <iostream>
#include <vector>
#include <unordered_map>
using namespace std;

/**
 * Finds and prints the most frequent element in the array.
 * If there are multiple elements with the same maximum frequency,
 * the one that appears first in the array is printed.
 * 
 * @param arr The array of integers.
 * @param n The size of the array.
 */
void printMostFrequentElement(int arr[], int n) {
    unordered_map<int, pair<int, int>> freqMap; // Maps element to its frequency and first occurrence index
    int maxFreq = 0;
    int mostFrequentElement = arr[0];
    int earliestIndex = n;

    for (int i = 0; i < n; ++i) {
        if (freqMap.find(arr[i]) == freqMap.end()) {
            freqMap[arr[i]] = make_pair(1, i); // Initialize frequency and index
        } else {
            freqMap[arr[i]].first++; // Increment frequency
        }

        // Update the most frequent element if necessary
        if (freqMap[arr[i]].first > maxFreq || 
           (freqMap[arr[i]].first == maxFreq && freqMap[arr[i]].second < earliestIndex)) {
            maxFreq = freqMap[arr[i]].first;
            mostFrequentElement = arr[i];
            earliestIndex = freqMap[arr[i]].second;
        }
    }

    cout << mostFrequentElement << endl;
}

int main() {
    int n;
    cout << "Enter the number of elements in the array: ";
    cin >> n;
    int* arr = new int[n];
    cout << "Enter the elements of the array: ";
    for (int i = 0; i < n; i++) {
        cin >> arr[i];
    }
    printMostFrequentElement(arr, n);
    delete[] arr;
    return 0;
}
