    void payResourceBundle(const ResourceBundle& resourceBundle);
    void payResourceId(std::size_t resourceId, int amount);
    void receiveResourceBundle(const ResourceBundle& resourceBundle);
    void receiveResourceMaxBundle(const ResourceBundle& resourceBundle);
    void registerResourceId(const std::string& resourceName);
    bool resourceExists(const std::string& resourceName) const;

private:
    static const int DefaultResourceMaximum = INT_MAX;
    std::unordered_map<std::string, LevelResource> m_ResourceMap;
    std::unordered_map<std::size_t, std::string> m_ResourceIdMap;

    LevelResource& getOrCreateResource(const std::string& resourceName);
    void revalidateResourceAgainstMaximum(LevelResource& resource);
};

void ResourceService::updateResource(const std::string& resourceName, int amount) {
    setResource(resourceName, amount + getResource(resourceName));
}

void ResourceService::updateResourceMax(const std::string& resourceName, int amount) {
    setResourceMaximum(resourceName, getResourceMax(resourceName) + amount);
}

void ResourceService::setResource(const std::string& resourceName, int amount) {
    LevelResource& resource = getOrCreateResource(resourceName);
    resource.amount = amount;
    revalidateResourceAgainstMaximum(resource);
}

void ResourceService::setResourceMaximum(const std::string& resourceName, int maximum) {
    LevelResource& resource = getOrCreateResource(resourceName);
    resource.max = maximum;
    revalidateResourceAgainstMaximum(resource);
}

int ResourceService::getResource(const std::string& resourceName) {
    return getOrCreateResource(resourceName).amount;
}

int ResourceService::getResourceMax(const std::string& resourceName) {
    return getOrCreateResource(resourceName).max;
}

bool ResourceService::canAfford(const ResourceBundle& resourceBundle) {
    for (const auto& res : resourceBundle.resources) {
        if (res.amount == 0) {
            continue;
        }
        if (!resourceExists(res.name) || getResource(res.name) < res.amount) {
            return false;
        }
    }
    return true;
}

bool ResourceService::canAfford(std::size_t resourceId, int amount) {
    if (m_ResourceIdMap.find(resourceId) == m_ResourceIdMap.end()) {
        return false;
    }
    const std::string resourceName = m_ResourceIdMap[resourceId];
    return resourceExists(resourceName) && amount <= getResource(resourceName);
}

void ResourceService::payResourceBundle(const ResourceBundle& resourceBundle) {
    for (const auto& res : resourceBundle.resources) {
        if (res.amount == 0) {
            continue;
        }
        updateResource(res.name, -res.amount);
    }
}

void ResourceService::payResourceId(std::size_t resourceId, int amount) {
    if (m_ResourceIdMap.find(resourceId) == m_ResourceIdMap.end()) {
        return;
    }
    const std::string resourceName = m_ResourceIdMap[resourceId];
    if (!resourceExists(resourceName)) {
        return;
    }
    updateResource(resourceName, -amount);
}

void ResourceService::receiveResourceBundle(const ResourceBundle& resourceBundle) {
    for (const auto& res : resourceBundle.resources) {
        if (res.amount == 0) {
            continue;
        }
        updateResource(res.name, res.amount);
    }
}

void ResourceService::receiveResourceMaxBundle(const ResourceBundle& resourceBundle) {
    for (const auto& res : resourceBundle.resources) {
        if (res.amount == 0) {
            continue;
        }
        updateResourceMax(res.name, res.amount);
    }
}

void ResourceService::registerResourceId(const std::string& resourceName) {
    const std::size_t resourceId = djb_hash(resourceName.c_str());
    if (m_ResourceIdMap.find(resourceId) != m_ResourceIdMap.end()) {
        return;
    }
    m_ResourceIdMap[resourceId] = resourceName;
}

bool ResourceService::resourceExists(const std::string& resourceName) const {
    return m_ResourceMap.find(resourceName) != m_ResourceMap.end();
}

ResourceService::LevelResource& ResourceService::getOrCreateResource(const std::string& resourceName) {
    auto iter = m_ResourceMap.find(resourceName);
    if (iter == m_ResourceMap.end()) {
        LevelResource& resource = m_ResourceMap[resourceName];
        resource.name = resourceName;
        resource.amount = 0;
        resource.max = DefaultResourceMaximum;
        m_ResourceIdMap[djb_hash(resourceName.c_str())] = resourceName;
        return resource;
    }
    return iter->second;
}

void ResourceService::revalidateResourceAgainstMaximum(LevelResource& resource) {
    if (resource.amount > resource.max && resource.max != DefaultResourceMaximum) {
        resource.amount = resource.max;
    }
}

