class QuantConvolution {
public:
    std::vector<std::size_t> padding  = {0, 0};
    std::vector<std::size_t> stride   = {1, 1};
    std::vector<std::size_t> dilation = {1, 1};
    int group                         = 1;

    QuantConvolution() = default;

    void check_attribute_size() const {
        if (!(padding.size() == stride.size() && padding.size() == dilation.size())) {
            throw std::runtime_error("QuantConvolution: inconsistent attribute sizes");
        }
    }

    std::vector<std::size_t> compute_output_dimensions(
        const std::vector<std::size_t>& input_dims,
        const std::vector<std::size_t>& weights_dims) const {
        if (input_dims.size() < 3 || weights_dims.size() < 3) {
            throw std::runtime_error("QuantConvolution: input and weights must have at least 3 dimensions");
        }
        if (input_dims.size() != weights_dims.size()) {
            throw std::runtime_error("QuantConvolution: input and weights must have the same number of dimensions");
        }
        check_attribute_size();

        size_t kdims = input_dims.size() - 2;
        if (kdims != padding.size()) {
            throw std::runtime_error("QuantConvolution: input k-dims does not match attribute size");
        }

        std::vector<size_t> output_dims{input_dims[0], weights_dims[0]};

        for (size_t i = 0; i < kdims; ++i) {
            output_dims.push_back(std::size_t(std::max<std::ptrdiff_t>(
                1,
                (input_dims[i + 2] - (1 + dilation[i] * (weights_dims[i + 2] - 1)) + 2 * padding[i]) / stride[i] + 1)));
        }

        return output_dims;
    }
};

int main() {
    // Test cases to verify the solution correctness
    QuantConvolution qc;
    qc.padding = {1, 1};
    qc.stride = {2, 2};
    qc.dilation = {1, 1};

    std::vector<std::size_t> input_dims = {1, 1, 5, 5}; // Batch size, Channels, Height, Width
    std::vector<std::size_t> weights_dims = {1, 1, 3, 3}; // Output channels, Input channels, Height, Width

    try {
        auto output_dims = qc.compute_output_dimensions(input_dims, weights_dims);
        std::cout << "Output dimensions: ";
        for (auto dim : output_dims) {
            std::cout << dim << " ";
        }
        std::cout << std::endl;
    } catch (const std::runtime_error& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
