// FlatIntegrator class derived from SamplerIntegrator
class FlatIntegrator : public SamplerIntegrator {
public:
    FlatIntegrator(Camera* camera) : SamplerIntegrator(camera) {}

    ColorXYZ Li(const Ray& ray, Scene& scene, ColorXYZ& default_color) override {
