class TimePrinter {
private:
    std::string format;

public:
    // Constructor that initializes the time format
    explicit TimePrinter(const std::string& timeFormat) : format(timeFormat) {}

    // Method to print the current time to the given output stream
    void printCurrentTime(std::ostream& os) const {
        auto now = std::time(nullptr);
        char buf[100];
        std::strftime(buf, sizeof buf, format.c_str(), std::gmtime(&now));
        os << buf;
    }

    // Overload the insertion operator to print the current time
    friend std::ostream& operator<<(std::ostream& os, const TimePrinter& tp) {
        tp.printCurrentTime(os);
        return os;
    }
};

int main() {
