// Function to sort indices based on comparing values in p2
bool myLess(const vector<int>& p2, int i, int j) { return p2[i] < p2[j]; }

int main() {
    int n;
    cin >> n;
    vector<vector<int>> a(n, vector<int>(n));
    vector<int> p(n), p2(n), x(n), ans(n);
    vector<vector<bool>> is(n, vector<bool>(n, false));

    // Reading the preference matrix
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> a[i][j];
            a[i][j]--;
        }
    }

    // Reading the priority array
    for (int i = 0; i < n; i++) {
        cin >> p[i];
        p[i]--;
        p2[p[i]] = i;
    }

    // Initialize x with indices 0 to n-1
    for (int i = 0; i < n; i++) {
        x[i] = i;
    }

    // Assign items to people based on priority and preference
    for (int i = 0; i < n; i++) {
        sort(x.begin(), x.begin() + i + 1, [&](int i, int j) { return myLess(p2, i, j); });
        for (int j = 0; j < n; j++) {
            if (x[0] != j) {
                is[j][x[0]] = true;
            } else if (i > 0) {
                is[j][x[1]] = true;
            }
        }
    }

    // Find the highest preference item for each person that is not taken by higher priority
    for (int i = 0; i < n; i++) {
        int j = 0;
        while (is[i][a[i][j]]) {
            j++;
        }
        ans[i] = a[i][j];
    }

    // Output the result
    for (int i = 0; i < n; i++) {
        cout << ans[i] + 1 << " ";
    }
    cout << endl;

    return 0;
}
