#define endl '\n'

typedef long long ll;

vector<vector<int>> tree;
vector<int> heights;
vector<bool> visited;

int dfs(int current) {
    if (visited[current])
        return heights[current];
    visited[current] = true;

    if (tree[current].size() == 1 && current != 0) { // Leaf node, except for root
        return heights[current] = 0;
    }
    int minHeight = INT_MAX;
    for (int& next : tree[current]) {
        minHeight = min(minHeight, dfs(next));
    }
    return heights[current] = minHeight + 1;
}

void calculateHeights(int n) {
    heights.assign(n, 0);
    visited.assign(n, false);
    dfs(0); // Assuming the root is node 0
}

int main() {
    ios_base::sync_with_stdio(0);
    cin.tie(0);

    int n, q;
    cin >> n >> q;

    tree.assign(n, vector<int>());
    for (int i = 0; i < n - 1; i++) {
        int a, b;
        cin >> a >> b;
        a--; b--; // Adjusting for 0-based indexing
        tree[a].push_back(b);
        tree[b].push_back(a);
    }

    calculateHeights(n);

    for (int i = 0; i < q; i++) {
        int x;
        cin >> x;
        x--; // Adjusting for 0-based indexing
        cout << heights[x] << endl;
    }

    return 0;
}
