#include <vector>
using namespace std;

class Solution {
public:
    int countPairs(vector<int>& nums, int k) {
        int cnt = 0;
        int n = nums.size();
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                if (nums[i] == nums[j] && (i * j) % k == 0) cnt++;
            }
        }
        return cnt;
    }
};

// Test cases
int main() {
    Solution solution;
    vector<int> nums1 = {1, 2, 3, 1, 2, 3, 1};
    int k1 = 2;
    assert(solution.countPairs(nums1, k1) == 4); // Expected output: 4

    vector<int> nums2 = {1, 1, 1, 1};
    int k2 = 1;
    assert(solution.countPairs(nums2, k2) == 6); // Expected output: 6

    vector<int> nums3 = {1, 2, 3, 4};
    int k3 = 3;
    assert(solution.countPairs(nums3, k3) == 0); // Expected output: 0

    // Add more test cases as needed
    return 0;
}
