class ClapTrap {
private:
    std::string name;
    unsigned int hitPoints;
    unsigned int energyPoints;
    unsigned int attackDamage;

public:
    ClapTrap(const std::string& name)
        : name(name), hitPoints(100), energyPoints(50), attackDamage(20) {
        std::cout << "ClapTrap " << this->name << " has been created!" << std::endl;
    }

    void attack(const std::string& target) {
        if (energyPoints == 0) {
            std::cout << "ClapTrap " << name << " has no energy to attack!" << std::endl;
            return;
        }
        std::cout << "ClapTrap " << name << " attacks " << target << ", causing " << attackDamage << " points of damage!" << std::endl;
        energyPoints--;
    }

    void takeDamage(unsigned int amount) {
        if (amount >= hitPoints) {
            hitPoints = 0;
            std::cout << "ClapTrap " << name << " has been destroyed!" << std::endl;
        } else {
            hitPoints -= amount;
            std::cout << "ClapTrap " << name << " took " << amount << " points of damage!" << std::endl;
        }
    }

    void beRepaired(unsigned int amount) {
        hitPoints += amount;
        std::cout << "ClapTrap " << name << " has been repaired by " << amount << " points!" << std::endl;
    }

    // Copy constructor
    ClapTrap(const ClapTrap& other)
        : name(other.name), hitPoints(other.hitPoints), energyPoints(other.energyPoints), attackDamage(other.attackDamage) {
        std::cout << "ClapTrap " << name << " has been copied!" << std::endl;
    }

    // Copy assignment operator
    ClapTrap& operator=(const ClapTrap& other) {
        if (this != &other) {
            name = other.name;
            hitPoints = other.hitPoints;
            energyPoints = other.energyPoints;
            attackDamage = other.attackDamage;
            std::cout << "ClapTrap " << name << " has been assigned!" << std::endl;
        }
        return *this;
    }

    ~ClapTrap() {
        std::cout << "ClapTrap " << name << " has been destroyed!" << std::endl;
    }
};

int main(void) {
    ClapTrap alpha("Alpha");

    alpha.attack("Beta");
    alpha.beRepaired(10);
    alpha.takeDamage(20);

    ClapTrap beta("Beta");
    ClapTrap gamma(beta);
    beta = alpha;

    beta.attack("Alpha");
    return 0;
}
