#ifndef ASCII_TRIE_HPP
#define ASCII_TRIE_HPP

#include <cstddef>
#include <string>
#include <memory>

#define KEY_COUNT 95 // printable ascii character count

template <typename T> class TrieNode {
public:
    std::unique_ptr<TrieNode<T>[]> letters;
    std::unique_ptr<T> data;
    bool isEndOfWord;

    TrieNode() : letters(new TrieNode<T>[KEY_COUNT]()), isEndOfWord(false) {}
};

template <typename T> class AsciiTrie {
public:
    TrieNode<T> root;

    AsciiTrie() {}

    void add(std::string key, T data) {
        TrieNode<T>* current = &root;

        for (char ch : key) {
            if (ch < 32 || ch > 126) {
                throw std::invalid_argument("Key contains non-printable ASCII characters");
            }
            if (!current->letters[ch - 32]) {
                current->letters[ch - 32] = std::make_unique<TrieNode<T>>();
            }
            current = current->letters[ch - 32].get();
        }

        current->isEndOfWord = true;
        current->data = std::make_unique<T>(data);
    }

    T get(std::string key) {
        TrieNode<T>* current = &root;

        for (char ch : key) {
            if (ch < 32 || ch > 126) {
                throw std::invalid_argument("Key contains non-printable ASCII characters");
            }
            if (!current->letters[ch - 32]) {
                return T();
            }
            current = current->letters[ch - 32].get();
        }

        return current->isEndOfWord ? *(current->data) : T();
    }

    void remove(std::string key) {
        removeHelper(&root, key, 0);
    }

private:
    bool removeHelper(TrieNode<T>* node, const std::string& key, size_t depth) {
        if (!node) {
            return false;
        }

        if (depth == key.size()) {
            if (node->isEndOfWord) {
                node->isEndOfWord = false;
                node->data.reset();
                return true;
            }
            return false;
        }

        char ch = key[depth];
        if (ch < 32 || ch > 126) {
            throw std::invalid_argument("Key contains non-printable ASCII characters");
        }

        bool shouldDeleteChild = removeHelper(node->letters[ch - 32].get(), key, depth + 1);

        if (shouldDeleteChild) {
            node->letters[ch - 32].reset();
            return true;
        }

        return false;
    }
};

#endif // ASCII_TRIE_HPP

// Test cases
#include <iostream>
#include <cassert>

int main() {
    AsciiTrie<int> trie;

    trie.add("hello", 1);
    trie.add("world", 2);
    trie.add("hi", 3);
    trie.add("her", 4);

    assert(trie.get("hello") == 1);
    assert(trie.get("world") == 2);
    assert(trie.get("hi") == 3);
    assert(trie.get("her") == 4);
    assert(trie.get("unknown") == 0); // default-constructed int

    trie.remove("hello");
    assert(trie.get("hello") == 0);

    trie.remove("world");
    assert(trie.get("world") == 0);

    std::cout << "All test cases passed!" << std::endl;

    return 0;
}
