#include <iostream>
#include <vector>
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <functional>
#include <memory>
#include <atomic>

class ThreadPool {
public:
    explicit ThreadPool(int num_threads);
    ~ThreadPool();

    void EnqueueTask(std::function<void()> task);
    void WaitForCompletion();
    void Shutdown();

private:
    void TaskLoop();
    bool Done() const;

    std::vector<std::unique_ptr<std::thread>> threads_;
    std::queue<std::function<void()>> tasks_;
    mutable std::mutex mutex_;
    std::condition_variable scheduled_;
    std::condition_variable completed_;
    std::atomic<bool> running_;
    int total_threads_;
    int idle_threads_;
};

ThreadPool::ThreadPool(int num_threads)
    : total_threads_(num_threads), idle_threads_(num_threads), running_(true) {
    threads_.reserve(num_threads);
    for (int i = 0; i < num_threads; ++i) {
        threads_.emplace_back(new std::thread(&ThreadPool::TaskLoop, this));
    }
}

ThreadPool::~ThreadPool() {
    Shutdown();
}

void ThreadPool::EnqueueTask(std::function<void()> task) {
    std::unique_lock<std::mutex> lock(mutex_);
    tasks_.push(std::move(task));
    scheduled_.notify_one();
}

void ThreadPool::WaitForCompletion() {
    std::unique_lock<std::mutex> lock(mutex_);
    completed_.wait(lock, [this] { return Done(); });
}

void ThreadPool::Shutdown() {
    {
        std::unique_lock<std::mutex> lock(mutex_);
        running_ = false;
        scheduled_.notify_all();
    }

    for (auto& thread : threads_) {
        if (thread->joinable()) {
            thread->join();
        }
    }
}

void ThreadPool::TaskLoop() {
    while (running_) {
        std::function<void()> task;
        {
            std::unique_lock<std::mutex> lock(mutex_);
            scheduled_.wait(lock, [this] { return !tasks_.empty() || !running_; });

            if (!running_ && tasks_.empty()) {
                break;
            }

            task = std::move(tasks_.front());
            tasks_.pop();
            --idle_threads_;
        }

        task();

        {
            std::unique_lock<std::mutex> lock(mutex_);
            ++idle_threads_;
            if (Done()) {
                completed_.notify_all();
            }
        }
    }
}

bool ThreadPool::Done() const {
    return tasks_.empty() && (idle_threads_ == total_threads_);
}

// Test cases to verify the solution correctness
int main() {
    ThreadPool pool(4); // Create a thread pool with 4 worker threads

    // Enqueue a few tasks
    pool.EnqueueTask([]() { std::cout << "Task 1 is running\n"; });
    pool.EnqueueTask([]() { std::cout << "Task 2 is running\n"; });
    pool.EnqueueTask([]() { std::cout << "Task 3 is running\n"; });

    // Wait for all tasks to complete
    pool.WaitForCompletion();

    // Shutdown the thread pool
    pool.Shutdown();

    std::cout << "All tasks have been completed and thread pool is shutdown.\n";

    return 0;
}
