// Define the Calculator class
class Calculator : public QWidget {
    Q_OBJECT

public:
    Calculator(QWidget *parent = nullptr);
    ~Calculator();

private slots:
    void numberButtonClicked();
    void operatorButtonClicked();
    void equalButtonClicked();
    void clearButtonClicked();
    void allClearButtonClicked();

private:
    QLineEdit *display;
    double currentValue;
    double lastValue;
    QString currentOperator;
    bool waitingForOperand;

    void calculate();
    void abortOperation();
    void clearAll();
};

Calculator::Calculator(QWidget *parent) : QWidget(parent), currentValue(0), lastValue(0), waitingForOperand(true) {
    display = new QLineEdit("0");
    display->setReadOnly(true);
    display->setAlignment(Qt::AlignRight);

    QGridLayout *gridLayout = new QGridLayout;
    QVBoxLayout *mainLayout = new QVBoxLayout(this);

    // Add display to layout
    mainLayout->addWidget(display);

    // Create buttons
    QStringList numberButtons = {"7", "8", "9", "4", "5", "6", "1", "2", "3", "0"};
    QStringList operatorButtons = {"/", "*", "-", "+", "="};
    QPushButton *clearButton = new QPushButton("C");
    QPushButton *allClearButton = new QPushButton("AC");

    // Add number buttons to grid layout
    int position = 0;
    foreach (const QString &text, numberButtons) {
        QPushButton *button = new QPushButton(text);
        int row = position / 3;
        int col = position % 3;
        gridLayout->addWidget(button, row, col);
        connect(button, &QPushButton::clicked, this, &Calculator::numberButtonClicked);
        position++;
    }

    // Add operator buttons to grid layout
    foreach (const QString &text, operatorButtons) {
        QPushButton *button = new QPushButton(text);
        gridLayout->addWidget(button, position / 3, position % 3);
        connect(button, &QPushButton::clicked, this, &Calculator::operatorButtonClicked);
        position++;
    }

    // Add clear buttons to grid layout
    gridLayout->addWidget(clearButton, 4, 0);
    gridLayout->addWidget(allClearButton, 4, 1);

    // Connect clear buttons
    connect(clearButton, &QPushButton::clicked, this, &Calculator::clearButtonClicked);
    connect(allClearButton, &QPushButton::clicked, this, &Calculator::allClearButtonClicked);

    // Add grid layout to main layout
    mainLayout->addLayout(gridLayout);

    // Set layout to the widget
    setLayout(mainLayout);
}

Calculator::~Calculator() {
    // Destructor code if needed
}

void Calculator::numberButtonClicked() {
    QPushButton *button = qobject_cast<QPushButton *>(sender());
    if (!button)
        return;

    if (display->text() == "0" && button->text() == "0")
        return;

    if (waitingForOperand) {
        display->clear();
        waitingForOperand = false;
    }

    display->setText(display->text() + button->text());
}

void Calculator::operatorButtonClicked() {
    QPushButton *button = qobject_cast<QPushButton *>(sender());
    if (!button)
        return;

    if (!waitingForOperand)
        calculate();

    currentOperator = button->text();
    lastValue = display->text().toDouble();
    waitingForOperand = true;
}

void Calculator::equalButtonClicked() {
    calculate();
    currentOperator.clear();
}

void Calculator::clearButtonClicked() {
    if (waitingForOperand)
        return;

    display->setText("0");
    waitingForOperand = true;
}

void Calculator::allClearButtonClicked() {
    clearAll();
}

void Calculator::calculate() {
    double operand = display->text().toDouble();
    double result = 0;

    if (currentOperator == "+") {
        result = lastValue + operand;
    } else if (currentOperator == "-") {
        result = lastValue - operand;
    } else if (currentOperator == "*") {
        result = lastValue * operand;
    } else if (currentOperator == "/") {
        if (operand == 0) {
            abortOperation();
            return;
        }
        result = lastValue / operand;
    }

    display->setText(QString::number(result));
    currentValue = result;
    waitingForOperand = true;
}

void Calculator::abortOperation() {
    QMessageBox::critical(this, tr("Error"), tr("Cannot divide by zero"));
    clearAll();
}

void Calculator::clearAll() {
    currentValue = 0;
    lastValue = 0;
    currentOperator.clear();
    display->setText("0");
    waitingForOperand = true;
}

// Main function
int main(int argc, char *argv[]) {
    QApplication app(argc, argv);
    Calculator calculator;
    calculator.show();
    return app.exec();
}

