#include "sylar/hook.h"
#include "sylar/log.h"
#include "sylar/iomanager.h"

#include <sys/types.h>
#include <sys/socket.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <fcntl.h>
#include <string.h>
#include <functional>
#include <iostream>

sylar::Logger::ptr g_logger = SYLAR_LOG_ROOT();

void async_sleep(int seconds, std::function<void()> callback) {
    sylar::IOManager iom(1);
    iom.scheduler([seconds, callback](){
        sleep(seconds);
        SYLAR_LOG_INFO(g_logger) << "Completed async sleep for " << seconds << " seconds";
        callback();
    });
}

void non_blocking_http_get(const std::string& url, std::function<void(const std::string&)> callback) {
    sylar::IOManager iom(1);
    iom.scheduler([url, callback](){
        int sock = socket(AF_INET, SOCK_STREAM, 0);
        sockaddr_in addr;
        memset(&addr, 0, sizeof(addr));
        addr.sin_family = AF_INET;
        addr.sin_port = htons(80);
        inet_pton(AF_INET, url.c_str(), &addr.sin_addr.s_addr);

        SYLAR_LOG_INFO(g_logger) << "Begin connect to " << url;
        int rt = connect(sock, (const sockaddr*)&addr, sizeof(addr));
        if(rt) {
            SYLAR_LOG_ERROR(g_logger) << "Connect failed with errno = " << errno;
            return;
        }

        const char data[] = "GET / HTTP/1.0\r\n\r\n";
        rt = send(sock, data, sizeof(data), 0);
        if(rt <= 0) {
            SYLAR_LOG_ERROR(g_logger) << "Send failed with errno = " << errno;
            return;
        }

        std::string buff;
        buff.resize(4096);
        rt = recv(sock, &buff[0], buff.size(), 0);
        if(rt <= 0) {
            SYLAR_LOG_ERROR(g_logger) << "Recv failed with errno = " << errno;
            return;
        }

        buff.resize(rt);
        SYLAR_LOG_INFO(g_logger) << "Received data from " << url;
        callback(buff);

        close(sock);
        SYLAR_LOG_INFO(g_logger) << "End of non-blocking HTTP GET";
    });
}

int main() {
    // Asynchronous sleep for 2 seconds
    async_sleep(2, [](){
        SYLAR_LOG_INFO(g_logger) << "Callback after async sleep";
    });

    // Non-blocking HTTP GET request
    non_blocking_http_get("93.184.216.34", [](const std::string& response){
        SYLAR_LOG_INFO(g_logger) << "HTTP GET Response: " << response;
    });

    // Keep the main thread running until all async operations are complete
    sylar::IOManager main_iom;
    main_iom.scheduler([](){
        SYLAR_LOG_INFO(g_logger) << "Main thread is waiting for async operations to complete";
    });
    main_iom.stop();

    return 0;
}
