using namespace std;

// Function to initialize the vector with the first n lowercase letters of the alphabet
void initializeVector(vector<char>& vec, size_t limit) {
    for(size_t i = 0; i < limit; ++i) {
        vec.at(i) = static_cast<char>(i + 'a');
    }
}

// Function to expand the vector to include the remaining lowercase letters of the alphabet
void expandVector(vector<char>& vec) {
    for(size_t i = vec.size(); i < 26; ++i) {
        vec.push_back(static_cast<char>(i + 'a'));
    }
}

// Function to convert all characters in the vector to uppercase
void convertToUpper(vector<char>& vec) {
    for(auto& letter : vec) {
        letter = static_cast<char>(toupper(letter));
    }
}

// Function to print the contents of the vector
void printVector(const vector<char>& vec, const string& message) {
    cout << message;
    for(const auto& letter : vec) {
        cout << letter << " ";
    }
    cout << endl;
}

int main() {
    constexpr size_t limit = 10; // Initial number of letters to include
    vector<char> alphabet(limit); // Create vector of length limit

    // Initialize the vector with the first n lowercase letters
    initializeVector(alphabet, limit);

    // Print the size and original contents of the vector
    cout << "Size: " << alphabet.size() << endl;
    printVector(alphabet, "Original Contents: ");

    // Expand the vector to include the remaining lowercase letters
    expandVector(alphabet);

    // Print the new size and current contents of the vector
    cout << "Expanding vector & now Size: " << alphabet.size() << endl;
    printVector(alphabet, "Current Contents: ");

    // Convert all characters to uppercase
    convertToUpper(alphabet);

    // Print the modified contents of the vector
    printVector(alphabet, "Modified Contents: ");

    cout << "\t\t\tHappy Ending!!!" << endl;
    return 0;
}

// Test cases to verify the solution correctness
int main() {
    // Test case 1: Initialize with the first 10 letters
    main();

    // Test case 2: Initialize with the first 5 letters
    constexpr size_t limit = 5;
    vector<char> alphabet(limit);
    initializeVector(alphabet, limit);
    expandVector(alphabet);
    convertToUpper(alphabet);
    printVector(alphabet, "Test Case 2 - Contents: ");

    // Test case 3: Initialize with the first 26 letters (entire alphabet)
    constexpr size_t fullLimit = 26;
    vector<char> fullAlphabet(fullLimit);
    initializeVector(fullAlphabet, fullLimit);
    // No need to expand as it already contains the entire alphabet
    convertToUpper(fullAlphabet);
    printVector(fullAlphabet, "Test Case 3 - Contents: ");

    return 0;
}
