node* buildTree() {
    cout << "Enter the data for nodes (enter -1 for no node): " << endl;
    queue<node*> q;
    int data;
    cin >> data;
    if (data == -1) return NULL;
    node* root = new node(data);
    q.push(root);

    while (!q.empty()) {
        node* temp = q.front();
        q.pop();

        cin >> data;
        if (data != -1) {
            temp->left = new node(data);
            q.push(temp->left);
        }

        cin >> data;
        if (data != -1) {
            temp->right = new node(data);
            q.push(temp->right);
        }
    }
    return root;
}

void levelOrderTraversal(node* root) {
    if (root == NULL) return;
    queue<node*> q;
    q.push(root);
    q.push(NULL);

    while (!q.empty()) {
        node* temp = q.front();
        q.pop();

        if (temp == NULL) {
            cout << endl;
            if (!q.empty()) {
                q.push(NULL);
            }
        } else {
            cout << temp->data << " ";
            if (temp->left) {
                q.push(temp->left);
            }
            if (temp->right) {
                q.push(temp->right);
            }
        }
    }
}

int main() {
    node* root = buildTree();
    cout << "Level order traversal of the binary tree:" << endl;
    levelOrderTraversal(root);
