// Function to generate the word pattern
std::string wordPattern(const std::string &word) {
    if (word.empty()) return "";

    std::string pattern;
    std::map<char, int> charMap;
    int counter = 0;

    for (char ch : word) {
        char lowerCh = std::tolower(ch);
        if (charMap.count(lowerCh) == 0) {
            charMap[lowerCh] = counter++;
        }
        pattern += std::to_string(charMap[lowerCh]) + ".";
    }

    // Remove the trailing dot
    pattern.pop_back();
    return pattern;
}

int main() {
