// Define a base class for particles
class Particle {
public:
    Particle(double mass, int charge, double lifetime)
        : mass(mass), charge(charge), lifetime(lifetime), position(0.0), velocity(0.0) {}

    virtual ~Particle() {}

    virtual void updatePosition(double deltaTime) {
        // Simple motion update: position += velocity * deltaTime
        position += velocity * deltaTime;
    }

    virtual bool decay(double deltaTime) {
        // Reduce lifetime and check if the particle should decay
        lifetime -= deltaTime;
        return lifetime <= 0.0;
    }

    virtual std::string getType() const = 0;

    double getPosition() const { return position; }
    double getVelocity() const { return velocity; }
    void setVelocity(double v) { velocity = v; }

protected:
    double mass;
    int charge;
    double lifetime;
    double position;
    double velocity;
};

// Define specific particle types
class Electron : public Particle {
public:
    Electron() : Particle(9.109e-31, -1, std::numeric_limits<double>::infinity()) {}

    std::string getType() const override { return "Electron"; }
};

class Positron : public Particle {
public:
    Positron() : Particle(9.109e-31, 1, std::numeric_limits<double>::infinity()) {}

    std::string getType() const override { return "Positron"; }
};

class Photon : public Particle {
public:
    Photon() : Particle(0.0, 0, std::numeric_limits<double>::infinity()) {
        setVelocity(299792458.0); // Speed of light
    }

    std::string getType() const override { return "Photon"; }
};

// Define the ParticleTracker class
class ParticleTracker {
public:
    ParticleTracker() {
        std::srand(static_cast<unsigned int>(std::time(nullptr))); // Seed random number generator
    }

    ~ParticleTracker() {
        for (Particle* particle : particles) {
            delete particle;
        }
    }

    void addParticle(Particle* particle) {
        particles.push_back(particle);
    }

    void update(double deltaTime) {
        for (size_t i = 0; i < particles.size(); ++i) {
            Particle* particle = particles[i];

            // Update position
            particle->updatePosition(deltaTime);

            // Check for decay
            if (particle->decay(deltaTime)) {
                std::cout << particle->getType() << " decayed." << std::endl;
                delete particle;
                particles.erase(particles.begin() + i);
                --i;
            }
        }
    }

    void report() const {
        for (const Particle* particle : particles) {
            std::cout << particle->getType() << " at position " << particle->getPosition() << std::endl;
        }
    }

private:
    std::vector<Particle*> particles;
};

// Example usage
int main() {
    ParticleTracker tracker;

    // Add particles to the simulation
    tracker.addParticle(new Electron());
    tracker.addParticle(new Positron());
    tracker.addParticle(new Photon());

    // Simulate for 10 time units
    for (int i = 0; i < 10; ++i) {
        tracker.update(1.0); // Update simulation with deltaTime = 1.0
        tracker.report();    // Report the state of the simulation
    }

    return 0;
}
