#include "gtest/gtest.h"

class AudioNegator {
public:
    AudioNegator(size_t block_size, unsigned int sample_rate)
        : block_size_(block_size), sample_rate_(sample_rate) {
        if (block_size == 0) {
            throw std::invalid_argument("Block size must be greater than 0.");
        }
    }

    std::vector<float> process(const std::vector<float>& input) {
        if (input.size() != block_size_) {
            throw std::invalid_argument("Input block size does not match the configured block size.");
        }

        std::vector<float> output(block_size_);
        std::transform(input.begin(), input.end(), output.begin(), [](float sample) {
            return -sample;
        });

        return output;
    }

private:
    size_t block_size_;
    unsigned int sample_rate_;
};

TEST(AudioNegatorTest, NegateBlock) {
    const size_t block_size = 480;
    const unsigned int sample_rate = 48000;
    AudioNegator negator(block_size, sample_rate);

    std::vector<float> input_block(block_size);
    std::vector<float> expected_output(block_size);

    // Fill the input block with sample data and prepare the expected output
    for (size_t i = 0; i < block_size; ++i) {
        input_block[i] = i * 0.001f;
        expected_output[i] = -input_block[i];
    }

    // Process the block and check the output
    std::vector<float> output_block = negator.process(input_block);
    ASSERT_EQ(output_block.size(), block_size);
    for (size_t i = 0; i < block_size; ++i) {
        EXPECT_FLOAT_EQ(output_block[i], expected_output[i]);
    }
}

int main(int argc, char **argv) {
    ::testing::InitGoogleTest(&argc, argv);
    return RUN_ALL_TESTS();
}
