/**
 * Converts a non-negative decimal number to its 8-bit binary representation.
 * The program prompts the user for a decimal number, converts it to binary,
 * and displays the result. It repeats this process until the user chooses to exit.
 */
int main() {
    char repeat;
    do {
        int decimal;
        short binary[8];
        cout << "\tDecimal to Binary Converter" << endl;
        cout << "\t---------------------------" << endl;
        cout << "Enter a non-negative decimal value: ";
        while (!(cin >> decimal) || decimal < 0) {
            cout << "Invalid input. Please enter a valid non-negative integer: ";
            cin.clear(); // Clear error flags
            cin.ignore(numeric_limits<streamsize>::max(), '\n'); // Discard invalid input
        }

        // Convert decimal to binary
        for (int i = 0; i < 8; i++) {
            binary[i] = decimal % 2;
            decimal /= 2;
        }

        // Display the binary number
        cout << "The binary representation is: ";
        for (int i = 7; i >= 0; i--) {
            cout << binary[i];
        }
        cout << endl;

