        cout << "Do you want to perform another conversion? [Y/N] ";
        cin >> repeat;
        cin.ignore(numeric_limits<streamsize>::max(), '\n'); // Discard newline character
        cout << endl;
    } while (toupper(repeat) == 'S');

    return 0;
