class Solution {
public:
    int maximumSplicedArray(vector<int>& nums1, vector<int>& nums2) {
        return max(maxSpliceSum(nums1, nums2), maxSpliceSum(nums2, nums1));
    }

private:
    int maxSpliceSum(vector<int>& nums1, vector<int>& nums2) {
        int n = nums1.size();
        int totalSum1 = 0, totalSum2 = 0;
        int maxDiff = 0, currDiff = 0;

        for (int i = 0; i < n; ++i) {
            totalSum1 += nums1[i];
            totalSum2 += nums2[i];
            currDiff += nums2[i] - nums1[i];
            if (currDiff < 0) {
                currDiff = 0;
            }
            maxDiff = max(maxDiff, currDiff);
        }
        return totalSum1 + maxDiff;
    }
};

