int GCD_Euclidean(int divisor, int dividend) {
    if (divisor == 0) {
        return dividend;
    }
    return GCD_Euclidean(dividend % divisor, divisor);
}

// Function to calculate GCD of multiple numbers
int GCD_MultipleNumbers(const vector<int>& numbers) {
    if (numbers.empty()) {
        return 0;
    }
    int result = numbers[0];
    for (size_t i = 1; i < numbers.size(); ++i) {
        result = GCD_Euclidean(numbers[i], result);
        if (result == 1) {
            return 1; // GCD of any number with 1 is 1
        }
