/**
 * Determines if an array of integers is sorted in non-decreasing order.
 * 
 * @param arr The array to check.
 * @param n The size of the array.
 * @return true if the array is sorted, false otherwise.
 */
bool is_sorted(int arr[], int n) {
    // Base case: An array with one or no elements is sorted.
    if (n <= 1) {
        return true;
    }
    // Check if the first element is less than or equal to the next,
    // and recursively check the rest of the array.
    if (arr[0] <= arr[1] && is_sorted(arr + 1, n - 1)) {
        return true;
    }
    return false;
}

