#include <iostream>
#include <cstring>
#include <vector>
#include <algorithm>
using namespace std;

const int MAXN = 16;
vector<pair<int,int>> edges[MAXN];
int min_distance[MAXN][MAXN];
bool visited[MAXN];
int min_edge[MAXN][MAXN];
int dp[1<<MAXN];

void dfs(int v = 0) {
  visited[v] = true;
  for(auto u : edges[v])
    if(!visited[u.first]) dfs(u.first);
}

int& minimize(int& x, int y) {
  return x = min(x, y);
}

int main() {
  ios::sync_with_stdio(false);
  cin.tie(NULL); cout.tie(NULL);
  int n, m; cin >> n >> m;
  if (n % 2 != 0) { cout << -1 << endl; return 0; } // Check for odd number of vertices

  memset(min_edge, 0x3f, sizeof min_edge);
  memset(min_distance, 0x3f, sizeof min_distance);
  int total_weight = 0;
  for(int i = 0; i < m; i++) {
    int x, y, z; cin >> x >> y >> z;
    x--, y--;
    min_edge[x][y] = minimize(min_edge[y][x], z);
    edges[x].push_back({y, z});
    edges[y].push_back({x, z});
    total_weight += z;
  }
  dfs(0);
  for(int i = 0; i < n; i++) 
    if(!visited[i] && edges[i].size()) { cout << -1 << endl; return 0; } // Check for disconnected graph

  for(int i = 0; i < n; min_distance[i][i] = 0, i++)
    for(int j = 0; j < n; j++)
      min_distance[i][j] = min_edge[i][j];

  for(int k = 0; k < n; k++)
    for(int i = 0; i < n; i++)
      for(int j = 0; j < n; j++)
        minimize(min_distance[i][j], min_distance[i][k] + min_distance[k][j]);

  memset(dp, 0x3f, sizeof dp);
  dp[0] = 0;
  for(int mask = 0; mask < (1 << n); mask++) {
    for(int i = 0; i < n; i++) {
      if((mask >> i) & 1) continue;
      if(edges[i].size() % 2 == 0) { minimize(dp[mask | (1 << i)], dp[mask]); continue; }
      for(int j = 0; j < n; j++) {
        if((mask >> j) & 1) continue;
        if(i == j || edges[j].size() % 2 == 0) continue;
        minimize(dp[mask | (1 << i) | (1 << j)], dp[mask] + min_distance[i][j]);
      }
    }
  }
  cout << dp[(1 << n) - 1] + total_weight << endl;
  return 0;
}
