class SignalHoldBlock {
private:
    bool d_hold;
    float d_value;

public:
    SignalHoldBlock(bool hold) : d_hold(hold), d_value(0) {}

    void set_hold(bool new_hold) {
        d_hold = new_hold;
    }

    void process(const std::vector<float>& input, std::vector<float>& output) {
        output.resize(input.size());

        if (!d_hold) {
            // Pass-through mode
            std::copy(input.begin(), input.end(), output.begin());
            if (!input.empty()) {
                d_value = input.back();
            }
        } else {
            // Hold mode
            std::fill(output.begin(), output.end(), d_value);
        }
    }
};

int main() {
    // Test cases
    SignalHoldBlock block(false); // Initially in pass-through mode
    std::vector<float> input = {1.0, 2.0, 3.0, 4.0};
    std::vector<float> output;

    // Test pass-through mode
    block.process(input, output);
    for (float val : output) {
        std::cout << val << " "; // Should print 1.0 2.0 3.0 4.0
    }
    std::cout << std::endl;

    // Switch to hold mode
    block.set_hold(true);
    input = {5.0, 6.0, 7.0, 8.0}; // New input, but should be ignored
    block.process(input, output);
    for (float val : output) {
        std::cout << val << " "; // Should print 4.0 4.0 4.0 4.0
    }
    std::cout << std::endl;

    // Switch back to pass-through mode
    block.set_hold(false);
    block.process(input, output);
    for (float val : output) {
        std::cout << val << " "; // Should print 5.0 6.0 7.0 8.0
    }
    std::cout << std::endl;

    return 0;
}
