T dot_product(const std::vector<T>& v1, const std::vector<T>& v2) {
  if (v1.size() != v2.size()) {
    throw std::invalid_argument("Vectors must be of the same size.");
  }

  T result = 0;
  for (size_t i = 0; i < v1.size(); ++i) {
    result += eve::detail::dot_(eve::cpu_, v1[i], v2[i]);
  }
  return result;
