/**
 * Finds the unique element in an array where every element appears twice except for one.
 * 
 * @param arr The array of integers.
 * @param n The size of the array.
 * @return The unique element that appears only once.
 */
int findUniqueElement(int arr[], int n) {
    int xorSum = 0;
    for(int i = 0; i < n; i++) {
        xorSum ^= arr[i];
    }
    return xorSum;
}

