class HttpHeaderModifier {
public:
  HttpHeaderModifier(nsHttpChannel* channel) : mChannel(channel) {}

  void AddHeader(const std::string& headerName, const std::string& headerValue) {
    mHeaders[headerName] = headerValue;
    ApplyChanges();
  }

  void RemoveHeader(const std::string& headerName) {
    mHeaders.erase(headerName);
    ApplyChanges();
  }

  void UpdateHeader(const std::string& headerName, const std::string& newHeaderValue) {
    mHeaders[headerName] = newHeaderValue;
    ApplyChanges();
  }

  void ClearHeaders() {
    mHeaders.clear();
    ApplyChanges();
  }

private:
  nsHttpChannel* mChannel;
  std::unordered_map<std::string, std::string> mHeaders;

  void ApplyChanges() {
    // Clear existing headers
    mChannel->SetEmptyRequestHeaders();

    // Apply new headers
    for (const auto& header : mHeaders) {
      mChannel->SetRequestHeader(nsCString(header.first.c_str()), nsCString(header.second.c_str()), false);
    }
  }
};

