    cout << "\n=================== Welcome to the Calculator ===================" << endl;
    cout << "\nEnter your expression below ending with \"=\" and the program will automatically evaluate it." << endl;
    cout << "Note that only integers and the operators + - * / % ^ & are accepted, spaces will be ignored, and other symbols will result in an error." << endl;

    for(;;){
        cout << "\nPlease enter your expression: ";
        char expression = 'a';
        char lastPre = expression;
        bool isNum = false;
        for(;; lastPre = expression){
            cin >> expression;
            if(expression >= '0' && expression <= '9'){
                cin.putback(expression);
                double number;
                cin >> number;
                numStack.push(number);
            }
            else if(expression == '+' || expression == '-' || expression == '*' || expression == '/'
                    || expression == '%' || expression == '^' || expression == '&' || expression == '='
                    || expression == '(' || expression == ')'){
                if((lastPre < '0' || lastPre > '9') && expression != '-' && expression != '(' && lastPre != ')'){
                    unknownExpressionException();
                    break;
                }
                if(expression == '-'){
                    judge_last_isNum(lastPre, isNum);
                    if(isNum == false && lastPre != ')'){
                        numStack.push(0);
                    }
                    if(isNum == false && !(lastPre == 'a' || lastPre == '(') && lastPre != ')'){
