// RollNorth, RollSouth, RollWest, RollEast

// Function to calculate the load of the grid
uint64_t CalculateLoad(const std::vector<std::string>& board) {
    uint64_t result = 0;
    for (size_t i = 0; i < board.size(); ++i) {
        const auto cost = board.size() - i;
        for (char c : board[i]) {
            if (c == 'O') {
                result += cost;
            }
        }
    }
    return result;
}

// Part 1: Roll rocks North and calculate the load
void Part1(std::vector<std::string>& board) {
    RollNorth(board);
    uint64_t result = CalculateLoad(board);
    std::cout << "Part 1 Load: " << result << std::endl;
}

// Part 2: Roll rocks in a cycle and calculate the load after 1,000,000,000 cycles
void Part2(std::vector<std::string>& board) {
    std::vector<std::vector<std::string>> history;
    uint64_t cycleCount = 0;
    do {
        history.push_back(board);
        RollNorth(board);
        RollWest(board);
        RollSouth(board);
        RollEast(board);
        ++cycleCount;
    } while (std::find(history.begin(), history.end(), board) == history.end());

    uint64_t cycleBegin = 0;
    for (size_t i = 0; i < history.size(); ++i) {
        if (history[i] == board) {
            cycleBegin = i;
            break;
        }
    }
    cycleCount -= cycleBegin;

    constexpr uint64_t totalCycles = 1000000000;
    uint64_t remainingCycles = (totalCycles - cycleBegin) % cycleCount;
    for (uint64_t i = 0; i < remainingCycles; ++i) {
        RollNorth(board);
        RollWest(board);
        RollSouth(board);
        RollEast(board);
    }

    uint64_t result = CalculateLoad(board);
    std::cout << "Part 2 Load: " << result << std::endl;
}

int main() {
    std::vector<std::string> board;
    std::string input;
    while (std::getline(std::cin, input)) {
        board.emplace_back(std::move(input));
    }

    // Assuming RunPart1() is a function that determines whether to run Part 1 or Part 2
    if (RunPart1()) {
        Part1(board);
    } else {
        Part2(board);
    }
    return 0;
}
