#include <iostream>
using namespace std;

// Definition for a binary tree node.
template <typename T>
class BinaryTreeNode {
public:
    T data;
    BinaryTreeNode<T> *left;
    BinaryTreeNode<T> *right;

    BinaryTreeNode(T data) {
        this->data = data;
        left = NULL;
        right = NULL;
    }
};

// Helper function to build the tree from preorder and inorder traversals.
BinaryTreeNode<int>* buildTreeHelper(int* preOrder, int* inOrder, int preS, int preE, int inS, int inE) {
    if (inS > inE) {
        return NULL;
    }

    int rootData = preOrder[preS];
    int rootIndex = -1;
    for (int i = inS; i <= inE; i++) {
        if (inOrder[i] == rootData) {
            rootIndex = i;
            break;
        }
    }

    int leftPreS = preS + 1;
    int leftInS = inS;
    int leftInE = rootIndex - 1;
    int leftPreE = leftPreS + leftInE - leftInS;
    int rightPreS = leftPreE + 1;
    int rightInS = rootIndex + 1;
    int rightInE = inE;

    BinaryTreeNode<int>* root = new BinaryTreeNode<int>(rootData);
    root->left = buildTreeHelper(preOrder, inOrder, leftPreS, leftPreE, leftInS, leftInE);
    root->right = buildTreeHelper(preOrder, inOrder, rightPreS, preE, rightInS, rightInE);

    return root;
}

// Function to build the tree given preorder and inorder traversal arrays.
BinaryTreeNode<int>* buildTree(int* preorder, int preLength, int* inorder, int inLength) {
    return buildTreeHelper(preorder, inorder, 0, preLength - 1, 0, inLength - 1);
}

// Function to print the inorder traversal of the binary tree.
void printInorder(BinaryTreeNode<int>* root) {
    if (root == NULL) {
        return;
    }
    printInorder(root->left);
    cout << root->data << " ";
    printInorder(root->right);
}

// Main function with test cases.
int main() {
    int preorder[] = {1, 2, 4, 5, 3, 6, 7};
    int inorder[] = {4, 2, 5, 1, 6, 3, 7};
    int length = sizeof(preorder) / sizeof(preorder[0]);

    BinaryTreeNode<int>* root = buildTree(preorder, length, inorder, length);

    cout << "Inorder traversal of the constructed tree is: ";
    printInorder(root);
    cout << endl;

    // Free the allocated memory
    // Note: This is just a placeholder. In a real scenario, you should implement a function to delete the tree.
    delete root;

    return 0;
}
