using namespace std;

class Mistake {
public:
    virtual string tell() = 0;
    virtual ~Mistake() {}
};

class Mistake_size : public Mistake {
public:
    string tell() override {
        return "Size bigger than int";
    }
};

class Mistake_char : public Mistake {
public:
    string tell() override {
        return "Translate in int error";
    }
};

int convert(const string& s) {
    if (s.length() > 10) {
        throw Mistake_size();
    }
    int result = 0;
    for (char c : s) {
        if (c < '0' || c > '9') {
            throw Mistake_char();
        }
        result = result * 10 + (c - '0');
    }
    return result;
}

int main() {
    string str = "34678";
    try {
        int a = convert(str);
        cout << a << endl;
    } catch (Mistake& e) {
        cout << e.tell() << endl;
    }

    // Test cases
    string test1 = "2147483647"; // Max 32-bit int
    string test2 = "2147483648"; // Overflow
    string test3 = "123abc";     // Invalid characters

    try {
        cout << convert(test1) << endl;
    } catch (Mistake& e) {
        cout << e.tell() << endl;
    }

    try {
        cout << convert(test2) << endl;
    } catch (Mistake& e) {
        cout << e.tell() << endl;
    }

    try {
        cout << convert(test3) << endl;
    } catch (Mistake& e) {
        cout << e.tell() << endl;
    }

    return 0;
}
