#include <iostream>
#include <vector>
#include <climits>
using namespace std;

int helper(vector<int>& A, vector<vector<int>>& dp, int i, int j) {
    if (i == j) {
        return 0;
    }
    if (dp[i][j] != -1) {
        return dp[i][j];
    }
    int ans = INT_MAX;
    int sum = 0;
    for (int k = i; k <= j; k++) {
        sum += A[k];
    }
    for (int k = i; k < j; k++) {
        ans = min(ans, sum + helper(A, dp, i, k) + helper(A, dp, k + 1, j));
    }
    dp[i][j] = ans;
    return ans;
}

int minMergeCost(vector<int> &A) {
    int n = A.size();
    vector<vector<int>> dp(n, vector<int>(n, -1));
    return helper(A, dp, 0, n - 1);
}

// Test cases
int main() {
    vector<int> test1 = {1, 2, 3, 4};
    cout << "Test Case 1: " << minMergeCost(test1) << endl; // Expected output: 19

    vector<int> test2 = {10, 20, 30};
    cout << "Test Case 2: " << minMergeCost(test2) << endl; // Expected output: 90

    vector<int> test3 = {1, 3, 1, 4, 1};
    cout << "Test Case 3: " << minMergeCost(test3) << endl; // Expected output: 35

    return 0;
}
