class LimitByProcessor {
public:
    LimitByProcessor(size_t group_length, size_t group_offset)
        : group_length_(group_length), group_offset_(group_offset) {}

    void process(std::vector<std::tuple<std::string, int>> & data) {
        std::unordered_map<std::string, size_t> key_counts;
        auto it = data.begin();
        while (it != data.end()) {
            const std::string & key = std::get<0>(*it);
            size_t & count = key_counts[key];
            if (count >= group_offset_ && count < group_length_ + group_offset_) {
                ++count;
                ++it;
            } else {
                it = data.erase(it);
                ++count;
            }
        }
    }

private:
    size_t group_length_;
    size_t group_offset_;
};

int main() {
    // Test cases
    std::vector<std::tuple<std::string, int>> data = {
        {"apple", 10}, {"apple", 20}, {"apple", 30}, {"banana", 15},
        {"banana", 25}, {"banana", 35}, {"banana", 45}, {"cherry", 22},
        {"cherry", 32}, {"cherry", 42}
    };

    LimitByProcessor processor(2, 1); // Limit to 2 per group, skip the first 1
    processor.process(data);

    // Expected output:
    // apple 20
    // apple 30
    // banana 25
    // banana 35
    // cherry 32
    // cherry 42
    for (const auto & row : data) {
        std::cout << std::get<0>(row) << " " << std::get<1>(row) << std::endl;
    }

    return 0;
}
