#include<iostream>
#include<vector>
#include<string>
#define endl "\n"
using namespace std;

/**
 * Finds the length of the longest common subsequence (LCS) between two strings.
 * 
 * @param s1 The first string.
 * @param s2 The second string.
 * 
 * This function creates a 2D vector `dp` with dimensions (s1.size() + 1) x (s2.size() + 1)
 * to store the lengths of the LCS at each subproblem. It then iterates through each character
 * of both strings, updating the `dp` table according to the LCS dynamic programming approach.
 * The length of the LCS is printed at the end.
 */
void LCS(string s1, string s2) {
    vector<vector<int>> dp(s1.size() + 1, vector<int>(s2.size() + 1));

    for (int i = 1; i <= s1.size(); i++) {
        for (int j = 1; j <= s2.size(); j++) {
            if (s1[i - 1] == s2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1] + 1;
            } else {
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]);
            }
        }
    }

    cout << dp[s1.size()][s2.size()] << endl;
}

int main() {
    string lcs_first, lcs_last;
    // Example test cases
    lcs_first = "ABCDGH";
    lcs_last = "AEDFHR";
    LCS(lcs_first, lcs_last); // Output: 3

    lcs_first = "AGGTAB";
    lcs_last = "GXTXAYB";
    LCS(lcs_first, lcs_last); // Output: 4

    return 0;
}
