using namespace std;

/**
 * Simulates a simplified version of the Battleship game where ships are sunk
 * with bomb attacks. Ships are placed vertically and do not touch each other.
 * 
 * @param N The size of the grid (N x N).
 * @param M The number of bomb attacks.
 * @param grid The initial grid configuration with ships.
 * @param attacks The list of bomb attacks as pairs of coordinates.
 * @return The total number of sunk ships after all bomb attacks.
 */
int simulateBattleship(int N, int M, vector<vector<int>>& grid, vector<pair<int, int>>& attacks) {
    int shipsSunk = 0;
    for (int i = 0; i < M; ++i) {
        int row = attacks[i].first;
        int col = attacks[i].second;
        if (grid[row][col] == 0 && row < N && col < N) {
            for (int r = row; r >= 0; --r) {
                if (grid[r][col] == 1) {
                    shipsSunk++;
                    grid[r][col] = 0;
                    break;
                }
            }
        }
    }
    return shipsSunk;
}

int main() {
    int N, M;
    cin >> N >> M;
    vector<vector<int>> grid(N, vector<int>(N));
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < N; ++j) {
            cin >> grid[i][j];
        }
    }
    vector<pair<int, int>> attacks(M);
    for (int i = 0; i < M; ++i) {
        cin >> attacks[i].first >> attacks[i].second;
    }
    cout << simulateBattleship(N, M, grid, attacks) << endl;
    return 0;
}

