#include <iostream>
#include <vector>
#include <algorithm>

class MemoryBlock {
public:
    size_t start;
    size_t size;
    int id; // Unique identifier for the allocated block

    MemoryBlock(size_t s, size_t sz, int i) : start(s), size(sz), id(i) {}
};

class MemoryManager {
private:
    size_t totalSize;
    std::vector<MemoryBlock> allocatedBlocks;
    std::vector<MemoryBlock> freeBlocks;
    int nextId;

    void mergeFreeBlocks() {
        // Sort free blocks by starting address
        std::sort(freeBlocks.begin(), freeBlocks.end(), [](const MemoryBlock &a, const MemoryBlock &b) {
            return a.start < b.start;
        });

        // Merge contiguous free blocks
        for (size_t i = 0; i < freeBlocks.size() - 1; ++i) {
            if (freeBlocks[i].start + freeBlocks[i].size == freeBlocks[i + 1].start) {
                freeBlocks[i].size += freeBlocks[i + 1].size;
                freeBlocks.erase(freeBlocks.begin() + i + 1);
                --i; // Stay at the current index to check for further merges
            }
        }
    }

public:
    MemoryManager(size_t size) : totalSize(size), nextId(1) {
        freeBlocks.emplace_back(0, size, -1); // Initialize with one large free block
    }

    int allocate(size_t size) {
        for (auto &block : freeBlocks) {
            if (block.size >= size) {
                // Allocate from this block
                allocatedBlocks.emplace_back(block.start, size, nextId);
                block.start += size;
                block.size -= size;
                return nextId++;
            }
        }
        return -1; // Allocation failed
    }

    bool deallocate(int id) {
        auto it = std::find_if(allocatedBlocks.begin(), allocatedBlocks.end(), [id](const MemoryBlock &block) {
            return block.id == id;
        });

        if (it != allocatedBlocks.end()) {
            // Add the deallocated block to free blocks
            freeBlocks.emplace_back(it->start, it->size, -1);
            allocatedBlocks.erase(it);
            mergeFreeBlocks();
            return true;
        }
        return false; // Deallocate failed
    }

    void defragment() {
        mergeFreeBlocks();
    }

    void displayMemory() {
        std::cout << "Allocated Blocks:\n";
        for (const auto &block : allocatedBlocks) {
            std::cout << "ID: " << block.id << " Start: " << block.start << " Size: " << block.size << "\n";
        }
        std::cout << "Free Blocks:\n";
        for (const auto &block : freeBlocks) {
            std::cout << "Start: " << block.start << " Size: " << block.size << "\n";
        }
    }
};

int main() {
    MemoryManager gpuMemory(1024); // Initialize GPU memory manager with 1024 units of memory

    // Test cases
    int block1 = gpuMemory.allocate(256);
    int block2 = gpuMemory.allocate(128);
    gpuMemory.displayMemory();

    gpuMemory.deallocate(block1);
    gpuMemory.displayMemory();

    gpuMemory.defragment();
    gpuMemory.displayMemory();

    return 0;
}
