#include <iostream>

int recursiveFactorial(int num);
int iterativeFactorial(int num);

int main() {
    // Test cases
    std::cout << "Recursive Factorial of 5: " << recursiveFactorial(5) << std::endl;
    std::cout << "Iterative Factorial of 5: " << iterativeFactorial(5) << std::endl;
    std::cout << "Recursive Factorial of 0: " << recursiveFactorial(0) << std::endl;
    std::cout << "Iterative Factorial of 0: " << iterativeFactorial(0) << std::endl;
    std::cout << "Recursive Factorial of -1: " << recursiveFactorial(-1) << std::endl;
    std::cout << "Iterative Factorial of -1: " << iterativeFactorial(-1) << std::endl;

    return 0;
}

int recursiveFactorial(int num) {
    if (num < 0) {
        return -1; // Error case
    }
    if (num == 0 || num == 1) {
        return 1;
    } else {
        return num * recursiveFactorial(num - 1);
    }
}

int iterativeFactorial(int num) {
    if (num < 0) {
        return -1; // Error case
    }
    int result = 1;
    for (int i = 2; i <= num; ++i) {
        result *= i;
    }
    return result;
}
