// Environment variable management class
class EnvManager {
public:
    // Check if an environment variable exists
    static bool has(const std::string& var) {
        return std::getenv(var.c_str()) != nullptr;
    }

    // Get the value of an environment variable, throw if not found
    static std::string get(const std::string& var) {
        const char* val = std::getenv(var.c_str());
        if (val == nullptr) {
            throw std::runtime_error("Environment variable not found: " + var);
        }
        return std::string(val);
    }

    // Get the value of an environment variable with a default value
    static std::string get(const std::string& var, const std::string& defaultVal) {
        const char* val = std::getenv(var.c_str());
        return val ? std::string(val) : defaultVal;
    }

    // Set a new value for an environment variable
    static void set(const std::string& var, const std::string& value) {
        setenv(var.c_str(), value.c_str(), 1);
    }

    // Unset an environment variable
    static void unset(const std::string& var) {
        unsetenv(var.c_str());
    }
};

// Test cases
