#include <iostream>
using namespace std;

// Define the structure for a tree node
struct TreeNode {
    int value;
    TreeNode *left;
    TreeNode *right;

    TreeNode(int x) : value(x), left(NULL), right(NULL) {}
};

class BinarySearchTree {
public:
    TreeNode *root;

    BinarySearchTree() : root(NULL) {}

    // Insert a new node with the given value into the BST
    void insert(int value) {
        root = insertRecursive(root, value);
    }

    // Find a node with the given value in the BST
    TreeNode* find(int value) {
        return findRecursive(root, value);
    }

    // Print the BST in pre-order traversal
    void printPreOrder() {
        printPreOrderRecursive(root);
        cout << endl;
    }

    // Print all descendants of a node with the given value
    void printDescendants(int value) {
        TreeNode *node = find(value);
        if (node != NULL) {
            printPreOrderRecursive(node->left);
            printPreOrderRecursive(node->right);
            cout << endl;
        }
    }

    // Calculate the sum of all node values in the BST
    int sumNodes() {
        return sumNodesRecursive(root);
    }

    // Count the number of leaf nodes in the BST
    int countLeaves() {
        return countLeavesRecursive(root);
    }

    // Determine the height of the BST
    int height() {
        return heightRecursive(root);
    }

private:
    // Helper function to insert a new node into the BST
    TreeNode* insertRecursive(TreeNode *node, int value) {
        if (node == NULL) {
            return new TreeNode(value);
        }
        if (value > node->value) {
            node->right = insertRecursive(node->right, value);
        } else if (value < node->value) {
            node->left = insertRecursive(node->left, value);
        }
        return node;
    }

    // Helper function to find a node in the BST
    TreeNode* findRecursive(TreeNode *node, int value) {
        if (node == NULL || node->value == value) {
            return node;
        }
        if (value > node->value) {
            return findRecursive(node->right, value);
        }
        return findRecursive(node->left, value);
    }

    // Helper function for pre-order traversal of the BST
    void printPreOrderRecursive(TreeNode *node) {
        if (node != NULL) {
            cout << node->value << " ";
            printPreOrderRecursive(node->left);
            printPreOrderRecursive(node->right);
        }
    }

    // Helper function to calculate the sum of all node values in the BST
    int sumNodesRecursive(TreeNode *node) {
        if (node == NULL) {
            return 0;
        }
        return node->value + sumNodesRecursive(node->left) + sumNodesRecursive(node->right);
    }

    // Helper function to count the number of leaf nodes in the BST
    int countLeavesRecursive(TreeNode *node) {
        if (node == NULL) {
            return 0;
        }
        if (node->left == NULL && node->right == NULL) {
            return 1;
        }
        return countLeavesRecursive(node->left) + countLeavesRecursive(node->right);
    }

    // Helper function to determine the height of the BST
    int heightRecursive(TreeNode *node) {
        if (node == NULL) {
            return -1;
        }
        int leftHeight = heightRecursive(node->left);
        int rightHeight = heightRecursive(node->right);
        return (leftHeight > rightHeight ? leftHeight : rightHeight) + 1;
    }
};

// Test cases to verify the solution correctness
int main() {
    BinarySearchTree bst;

    // Insert nodes
    bst.insert(10);
    bst.insert(5);
    bst.insert(15);
    bst.insert(3);
    bst.insert(7);
    bst.insert(12);
    bst.insert(18);

    // Print pre-order traversal
    cout << "Pre-order traversal: ";
    bst.printPreOrder();

    // Print descendants of node with value 10
    cout << "Descendants of node 10: ";
    bst.printDescendants(10);

    // Sum of all nodes
    cout << "Sum of all nodes: " << bst.sumNodes() << endl;

    // Count of leaf nodes
    cout << "Number of leaf nodes: " << bst.countLeaves() << endl;

    // Height of the tree
    cout << "Height of the tree: " << bst.height() << endl;

    return 0;
}
