#include <iostream>
#include <vector>
#include <string>
using namespace std;

long long int hashString(const string& s, long long int p, long long int m) {
    long long int hashValue = 0;
    for (int i = s.size() - 1; i >= 0; --i) {
        hashValue = (hashValue * 263 + s[i]) % p;
    }
    return hashValue % m;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(0); cout.tie(0);
    long long int m, n, p = 1e9 + 7;
    string command, str;
    cin >> m >> n;
    vector<vector<string>> hashTable(m);

    for (int i = 0; i < n; ++i) {
        cin >> command;
        if (command == "add") {
            cin >> str;
            long long int hashValue = hashString(str, p, m);
            bool found = false;
            for (const auto& s : hashTable[hashValue]) {
                if (s == str) {
                    found = true;
                    break;
                }
            }
            if (!found) hashTable[hashValue].push_back(str);
        } else if (command == "del") {
            cin >> str;
            long long int hashValue = hashString(str, p, m);
            for (auto it = hashTable[hashValue].begin(); it != hashTable[hashValue].end(); ++it) {
                if (*it == str) {
                    hashTable[hashValue].erase(it);
                    break;
                }
            }
        } else if (command == "find") {
            cin >> str;
            long long int hashValue = hashString(str, p, m);
            bool found = false;
            for (const auto& s : hashTable[hashValue]) {
                if (s == str) {
                    found = true;
                    break;
                }
            }
            cout << (found ? "yes" : "no") << "\n";
        } else if (command == "check") {
            int index;
            cin >> index;
            for (auto it = hashTable[index].rbegin(); it != hashTable[index].rend(); ++it) {
                cout << *it << " ";
            }
            cout << "\n";
        }
    }
    return 0;
}
