namespace upm {

class Joystick12 {
public:
    Joystick12(int pinX, int pinY) {
        m_joystickCtxX = mraa_aio_init(pinX);
        m_joystickCtxY = mraa_aio_init(pinY);
    }

    ~Joystick12() {
        mraa_aio_close(m_joystickCtxX);
        mraa_aio_close(m_joystickCtxY);
    }

    float getXInput() {
        int raw = mraa_aio_read(m_joystickCtxX);
        return normalize(raw, X_left, X_center, X_right);
    }

    float getYInput() {
        int raw = mraa_aio_read(m_joystickCtxY);
        return normalize(raw, Y_left, Y_center, Y_right);
    }

private:
    mraa_aio_context m_joystickCtxX;
    mraa_aio_context m_joystickCtxY;

    static const int X_left = 0;
    static const int X_center = 512;
    static const int X_right = 1023;
    static const int Y_left = 0;
    static const int Y_center = 512;
    static const int Y_right = 1023;

    float normalize(int value, int min, int center, int max) {
        if (value < center) {
            return -1.0f + (value - min) * 1.0f / (center - min);
        } else {
            return (value - center) * 1.0f / (max - center);
        }
    }
};

} // namespace upm

int main() {
    // Assuming analog pins 0 and 1 are connected to the joystick
    upm::Joystick12 joystick(0, 1);

    float xValue = joystick.getXInput();
    float yValue = joystick.getYInput();

    std::cout << "Joystick X: " << xValue << ", Y: " << yValue << std::endl;

    return 0;
}
