using namespace std;

/**
 * Scales the y-axis of a histogram by a given factor, adjusts the x-axis by another factor,
 * overlays lines representing previous performance metrics, and saves the modified histogram
 * as a PDF file.
 *
 * @param filename The path to the ROOT file containing the BDT efficiency histogram.
 * @param yfactor The scaling factor for the y-axis of the histogram.
 * @param xfactor The scaling factor for the x-axis of the histogram.
 * @param oldrate The previous rate to be displayed as a horizontal line on the histogram.
 * @param oldeff The previous efficiency to be displayed as a vertical line on the histogram.
 * @param output The name of the output PDF file.
 */
void BDT_BvsS(string filename, double yfactor = 1, double xfactor = 1, double oldrate = 0, double oldeff = 0, string output = "plots/BDT_BvsS.pdf")
{
    // Open the ROOT file and retrieve the histogram
    TFile* file = TFile::Open(Gridify(filename).c_str());
    TH1D* histo = (TH1D*)file->Get("default/Method_BDT/BDT/MVA_BDT_effBvsS");

    // Read project configuration
    Constants const_list(GetValueFor("Project_name", "Dictionaries/Project_variables.txt"));

    // Scale the histogram's y-axis
    for (int i = 0; i < histo->GetNbinsX() + 1; i++)
    {
        histo->SetBinContent(i, histo->GetBinContent(i) * yfactor);
    }

    // Adjust the histogram's x-axis
    int Nbins = histo->GetXaxis()->GetNbins();
    double* xbin = new double[Nbins + 1];
    Double_t* xbin0 = new Double_t[Nbins + 1];
    histo->GetXaxis()->GetLowEdge(xbin0);
    for (int i = 0; i < Nbins; i++)
    {
        xbin[i] = xbin0[i] * xfactor;
    }
    xbin[Nbins] = 1 * xfactor;
    histo->GetXaxis()->Set(Nbins, xbin);

    // Set the histogram title and axis titles
    histo->SetTitle(const_list.plot_title.c_str());
    histo->GetYaxis()->SetTitle("Rate (kHz)");

    // Create a canvas to draw the histogram
    TCanvas* c1 = new TCanvas();
    c1->SetLogy(const_list.logY);
    c1->SetGrid();

    // Draw the histogram
    gStyle->SetOptStat(0);
    histo->Draw();

    // Overlay lines representing previous performance metrics
    TLine* RateLine = new TLine(histo->GetXaxis()->GetXmin(), oldrate, histo->GetXaxis()->GetXmax(), oldrate);
    TLine* EffLine = new TLine(oldeff, histo->GetYaxis()->GetXmin() * yfactor, oldeff, histo->GetBinContent(histo->GetNbinsX()) * 21 / 20);
    RateLine->SetLineColor(kRed);
    EffLine->SetLineColor(kRed);
    RateLine->Draw("same");
    EffLine->Draw("same");

    // Save the canvas as a PDF file
    c1->SaveAs(output.c_str());

    // Clean up
    delete[] xbin;
    delete[] xbin0;
    delete RateLine;
    delete EffLine;
    delete c1;
    file->Close();
    delete file;
}

#if !defined(__CLING__)
int main(int argc, char** argv)
{
    // Parse command-line arguments and call the BDT_BvsS function
    switch (argc - 1)
    {
    case 1:
        BDT_BvsS(argv[1]);
        break;
    case 2:
        BDT_BvsS(argv[1], stod(argv[2]));
        break;
    case 3:
        BDT_BvsS(argv[1], stod(argv[2]), stod(argv[3]));
        break;
    case 4:
        BDT_BvsS(argv[1], stod(argv[2]), stod(argv[3]), stod(argv[4]));
        break;
    case 5:
        BDT_BvsS(argv[1], stod(argv[2]), stod(argv[3]), stod(argv[4]), stod(argv[5]));
        break;
    case 6:
        BDT_BvsS(argv[1], stod(argv[2]), stod(argv[3]), stod(argv[4]), stod(argv[5]), argv[6]);
        break;
    default:
        cout << "Wrong number of arguments (" << argc << ") for " << argv[0] << endl;
        return 1;
    }
