#include <bits/stdc++.h>
using namespace std;

#define N 100001
int anArr[N], st[3*N];

void build(int v, int tl, int tr) {
    if(tl == tr) {
        st[v] = anArr[tl];
    } else {
        int tm = (tl + tr) / 2;
        build(v*2, tl, tm);
        build(v*2+1, tm+1, tr);
        st[v] = min(st[v*2], st[v*2+1]);
    }
}

int getMin(int v, int tl, int tr, int l, int r) {
    if(l > tr || r < tl) return INT_MAX;
    if(tl >= l && tr <= r) {
        return st[v];
    }
    int tm = (tl + tr) / 2;
    return min(getMin(v*2, tl, tm, l, r),
               getMin(v*2+1, tm+1, tr, l, r));
}

void solve() {
    int n, q, l, r;
    scanf("%d%d", &n, &q);
    for(int i = 1; i <= n; i++) scanf("%d", &anArr[i]);
    build(1, 1, n);
    while(q-- > 0) {
        scanf("%d%d", &l, &r);
        printf("%d\n", getMin(1, 1, n, l, r));
    }
}

int main() {
    int t;
    scanf("%d", &t);
    for(int i = 1; i <= t; i++) {
        printf("Case #%d:\n", i);
        solve();
    }
    return 0;
}

