// Include the necessary headers for the theta_sketch
#include <theta_sketch.hpp>

// Assuming the namespace datasketches and theta_sketch_timing_profile class are defined elsewhere
namespace datasketches {

size_t get_num_trials(size_t stream_length, size_t lg_min_stream_len, size_t lg_max_stream_len, size_t lg_min_trials, size_t lg_max_trials) {
  // Implement a function that determines the number of trials based on the stream length
  // For simplicity, let's assume it returns a fixed number for this example
  return std::max(static_cast<size_t>(1), (1 << lg_max_trials) / stream_length);
}

size_t pwr_2_law_next(size_t ppo, size_t cur_point) {
  // Implement a function that returns the next point in a power-of-two law series
  // For simplicity, let's assume it multiplies the current point by 2
  return cur_point * 2;
}

void theta_sketch_timing_profile::run() const {
  const size_t lg_min_stream_len(0);
  const size_t lg_max_stream_len(23);
  const size_t ppo(16);

  const size_t lg_max_trials(16);
  const size_t lg_min_trials(8);

  update_theta_sketch::builder builder;

  uint64_t counter(35538947);
  const uint64_t golden64(0x9e3779b97f4a7c13ULL);

  std::cout << "Stream\tTrials\tBuild\tUpdate\tSer\tDeser\tSize" << std::endl;

  size_t stream_length(1 << lg_min_stream_len);
  while (stream_length <= (1 << lg_max_stream_len)) {
    std::chrono::nanoseconds build_time_ns(0);
    std::chrono::nanoseconds update_time_ns(0);
    std::chrono::nanoseconds serialize_time_ns(0);
    std::chrono::nanoseconds deserialize_time_ns(0);
    size_t size_bytes(0);

    const size_t num_trials = get_num_trials(stream_length, lg_min_stream_len, lg_max_stream_len, lg_min_trials, lg_max_trials);

    for (size_t i = 0; i < num_trials; i++) {
      auto start_build = std::chrono::high_resolution_clock::now();
      update_theta_sketch sketch = builder.build();
      auto finish_build = std::chrono::high_resolution_clock::now();
      build_time_ns += std::chrono::duration_cast<std::chrono::nanoseconds>(finish_build - start_build);

      auto start_update = std::chrono::high_resolution_clock::now();
      for (size_t j = 0; j < stream_length; j++) {
        sketch.update(counter);
        counter += golden64;
      }
      auto finish_update = std::chrono::high_resolution_clock::now();
      update_time_ns += std::chrono::duration_cast<std::chrono::nanoseconds>(finish_update - start_update);

      std::stringstream s(std::ios::in | std::ios::out | std::ios::binary);
      auto start_serialize = std::chrono::high_resolution_clock::now();
      sketch.serialize(s);
      auto finish_serialize = std::chrono::high_resolution_clock::now();
      serialize_time_ns += std::chrono::duration_cast<std::chrono::nanoseconds>(finish_serialize - start_serialize);

      auto start_deserialize = std::chrono::high_resolution_clock::now();
      auto deserialized_sketch = theta_sketch::deserialize(s);
      auto finish_deserialize = std::chrono::high_resolution_clock::now();
      deserialize_time_ns += std::chrono::duration_cast<std::chrono::nanoseconds>(finish_deserialize - start_deserialize);

      size_bytes += s.tellp();
    }

    std::cout << stream_length << "\t"
              << num_trials << "\t"
              << static_cast<double>(build_time_ns.count()) / num_trials << "\t"
              << static_cast<double>(update_time_ns.count()) / num_trials / stream_length << "\t"
              << static_cast<double>(serialize_time_ns.count()) / num_trials << "\t"
              << static_cast<double>(deserialize_time_ns.count()) / num_trials << "\t"
              << static_cast<double>(size_bytes) / num_trials << std::endl;

    stream_length = pwr_2_law_next(ppo, stream_length);
  }
}

} // namespace datasketches

int main() {
  datasketches::theta_sketch_timing_profile profile;
  profile.run();
  return 0;
}
