#include <iostream>
#include <vector>
#include <queue>
#include <memory>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <atomic>
#include <unordered_map>

// Message class definition
class Message {
public:
    Message(int id, bool sync) : id_(id), is_sync_(sync) {}
    bool is_sync() const { return is_sync_; }
    int id() const { return id_; }

private:
    int id_;
    bool is_sync_;
};

// MessageQueue class definition
class MessageQueue {
public:
    MessageQueue() : shutdown_(false) {}

    bool Send(std::unique_ptr<Message> message) {
        std::unique_lock<std::mutex> lock(mutex_);
        if (shutdown_) {
            return false;
        }

        if (message->is_sync()) {
            // Synchronous message handling
            auto id = message->id();
            sync_messages_[id] = std::move(message);
            lock.unlock();
            std::unique_lock<std::mutex> sync_lock(sync_mutex_);
            sync_cond_.wait(sync_lock, [this, id] { return sync_responses_.count(id) > 0 || shutdown_; });
            if (shutdown_) {
                return false;
            }
            sync_responses_.erase(id);
            return true;
        } else {
            // Asynchronous message handling
            messages_.push(std::move(message));
            lock.unlock();
            cond_.notify_one();
            return true;
        }
    }

    void OnMessageReceived(std::unique_ptr<Message> message) {
        std::lock_guard<std::mutex> lock(mutex_);
        if (message->is_sync()) {
            // Handle reply to synchronous message
            int id = message->id();
            if (sync_messages_.count(id) > 0) {
                sync_messages_.erase(id);
                sync_responses_.insert(id);
                sync_cond_.notify_all();
            }
        } else {
            // Handle asynchronous message
            messages_.push(std::move(message));
            cond_.notify_one();
        }
    }

    void Shutdown() {
        std::lock_guard<std::mutex> lock(mutex_);
        shutdown_ = true;
        cond_.notify_all();
        sync_cond_.notify_all();
    }

    ~MessageQueue() {
        Shutdown();
    }

private:
    std::queue<std::unique_ptr<Message>> messages_;
    std::unordered_map<int, std::unique_ptr<Message>> sync_messages_;
    std::unordered_set<int> sync_responses_;
    std::mutex mutex_;
    std::mutex sync_mutex_;
    std::condition_variable cond_;
    std::condition_variable sync_cond_;
    std::atomic<bool> shutdown_;
};

// Test cases
int main() {
    MessageQueue queue;

    // Start a thread to simulate message receiving
    std::thread receiver([&queue]() {
        std::this_thread::sleep_for(std::chrono::seconds(1));
        queue.OnMessageReceived(std::make_unique<Message>(1, true));
        queue.OnMessageReceived(std::make_unique<Message>(2, false));
    });

    // Send a synchronous message
    bool result_sync = queue.Send(std::make_unique<Message>(1, true));
    std::cout << "Synchronous message sent with result: " << result_sync << std::endl;

    // Send an asynchronous message
    bool result_async = queue.Send(std::make_unique<Message>(2, false));
    std::cout << "Asynchronous message sent with result: " << result_async << std::endl;

    // Shutdown the message queue
    queue.Shutdown();

    receiver.join();
    return 0;
}
