    cout << "Operations:" << endl;

    while (pq.top() != 1) {
        int a = pq.top();
        pq.pop();
        int b = pq.top();
        pq.pop();
        cout << "(" << a << ", " << b << ")" << endl;
        int c = (a + b + 1) / 2;
        pq.push(c);
        operations++;
