#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
  bool search(vector<int>& nums, int target) {
    int start = 0, end = nums.size() - 1;
    while (start <= end) {
      int mid = start + (end - start) / 2;
      if (nums[mid] == target) return true;

      // If we know for sure right side is sorted or left side is unsorted
      if (nums[mid] < nums[end] || nums[mid] < nums[start]) {
        if (target > nums[mid] && target <= nums[end]) {
          start = mid + 1;
        } else {
          end = mid - 1;
        }
      // If we know for sure left side is sorted or right side is unsorted
      } else if (nums[mid] > nums[start] || nums[mid] > nums[end]) {
        if (target < nums[mid] && target >= nums[start]) {
          end = mid - 1;
        } else {
          start = mid + 1;
        }
      } else {
        // If we get here, that means nums[start] == nums[mid] == nums[end], then shifting out
        // any of the two sides won't change the result but can help remove duplicate from
        // consideration, here we just use end-- but start++ works too
        end--;
      }
    }
    return false;
  }
};

int main() {
    Solution solution;
    vector<int> nums;
    bool result;

    // Test case 1
    nums = {2, 5, 6, 0, 0, 1, 2};
    result = solution.search(nums, 0);
    cout << "Test case 1: " << (result ? "Found" : "Not found") << endl;

    // Test case 2
    nums = {2, 5, 6, 0, 0, 1, 2};
    result = solution.search(nums, 3);
    cout << "Test case 2: " << (result ? "Found" : "Not found") << endl;

    // Test case 3
    nums = {1, 1, 3, 1};
    result = solution.search(nums, 3);
    cout << "Test case 3: " << (result ? "Found" : "Not found") << endl;

    return 0;
}
