#include <pcl/io/pcd_io.h>
#include <pcl/io/ply_io.h>
#include <pcl/point_types.h>
#include <pcl/point_cloud.h>
#include <pcl/registration/icp.h>
#include <pcl/registration/gicp.h>
#include <pcl/visualization/pcl_visualizer.h>
#include <pcl/common/distances.h>
#include <pcl/registration/transformation_estimation_svd.h>
#include <Eigen/Core>

// Include your custom headers for GROR and preprocessing
#include "ia_gror.h"
#include "gror_pre.h"

// Function prototypes
void visualizePointClouds(const pcl::PointCloud<pcl::PointXYZ>::Ptr& cloud1,
                          const pcl::PointCloud<pcl::PointXYZ>::Ptr& cloud2,
                          const std::string& window_name);

int main(int argc, char** argv) {
    // Check for correct number of arguments
    if (argc < 5) {
        std::cerr << "Usage: " << argv[0] << " source_cloud.pcd target_cloud.pcd resolution optimal_threshold [use_icp]" << std::endl;
        return -1;
    }

    // Parse input arguments
    std::string fnameS = argv[1];
    std::string fnameT = argv[2];
    double resolution = std::stod(argv[3]);
    int n_optimal = std::stoi(argv[4]);
    bool use_icp = (argc > 5) ? std::stoi(argv[5]) != 0 : false;

    // Load point clouds
    pcl::PointCloud<pcl::PointXYZ>::Ptr source_cloud(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr target_cloud(new pcl::PointCloud<pcl::PointXYZ>);
    if (pcl::io::loadPCDFile(fnameS, *source_cloud) == -1 || pcl::io::loadPCDFile(fnameT, *target_cloud) == -1) {
        std::cerr << "Error loading point cloud files." << std::endl;
        return -1;
    }

    // Visualize initial point clouds
    visualizePointClouds(source_cloud, target_cloud, "Initial Point Clouds");

    // Preprocess point clouds using GROR preparation
    pcl::PointCloud<pcl::PointXYZ>::Ptr preprocessed_source(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr preprocessed_target(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr keypoints_source(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::PointCloud<pcl::PointXYZ>::Ptr keypoints_target(new pcl::PointCloud<pcl::PointXYZ>);
    pcl::CorrespondencesPtr correspondences(new pcl::Correspondences);
    GrorPre::grorPreparation(source_cloud, target_cloud, preprocessed_source, preprocessed_target, keypoints_source, keypoints_target, correspondences, resolution);

    // Perform GROR alignment
    auto start_time = std::chrono::high_resolution_clock::now();
    pcl::registration::GRORInitialAlignment<pcl::PointXYZ, pcl::PointXYZ, float> gror;
    pcl::PointCloud<pcl::PointXYZ>::Ptr aligned_source(new pcl::PointCloud<pcl::PointXYZ>);
    gror.setInputSource(keypoints_source);
    gror.setInputTarget(keypoints_target);
    gror.setResolution(resolution);
    gror.setOptimalSelectionNumber(n_optimal);
    gror.setNumberOfThreads(1);
    gror.setInputCorrespondences(correspondences);
    gror.align(*aligned_source);
    auto end_time = std::chrono::high_resolution_clock::now();
    std::chrono::duration<double> gror_time = end_time - start_time;
    std::cout << "GROR alignment completed in " << gror_time.count() << " seconds." << std::endl;
    std::cout << "GROR transformation matrix:\n" << gror.getFinalTransformation() << std::endl;

    // Optional ICP refinement
    if (use_icp) {
        pcl::IterativeClosestPoint<pcl::PointXYZ, pcl::PointXYZ> icp;
        icp.setInputSource(preprocessed_source);
        icp.setInputTarget(preprocessed_target);
        icp.setUseReciprocalCorrespondences(true);
        icp.align(*aligned_source, gror.getFinalTransformation());
        std::cout << "ICP refinement transformation matrix:\n" << icp.getFinalTransformation() << std::endl;
    }

    // Visualize final aligned point clouds
    visualizePointClouds(aligned_source, target_cloud, "Aligned Point Clouds");

    return 0;
}

void visualizePointClouds(const pcl::PointCloud<pcl::PointXYZ>::Ptr& cloud1,
                          const pcl::PointCloud<pcl::PointXYZ>::Ptr& cloud2,
                          const std::string& window_name) {
    pcl::visualization::PCLVisualizer::Ptr viewer(new pcl::visualization::PCLVisualizer(window_name));
    viewer->setBackgroundColor(0, 0, 0);
    pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZ> source_color_handler(cloud1, 255, 0, 0);
    viewer->addPointCloud<pcl::PointXYZ>(cloud1, source_color_handler, "source cloud");
    pcl::visualization::PointCloudColorHandlerCustom<pcl::PointXYZ> target_color_handler(cloud2, 0, 255, 0);
    viewer->addPointCloud<pcl::PointXYZ>(cloud2, target_color_handler, "target cloud");
    viewer->addCoordinateSystem(1.0);
    viewer->initCameraParameters();
    while (!viewer->wasStopped()) {
        viewer->spinOnce(100);
        std::this_thread::sleep_for(std::chrono::milliseconds(100));
    }
