#include <Arduino.h>

// Define constants for the PWM frequency, channel, resolution, and motor control pins
#define PWM_FREQ  5000
#define PWM_CH    0
#define PWM_RES   8
#define MOT_PIN   5
#define MOT_DIR1  2
#define MOT_DIR2  3

// Initialize variables for motor speed and direction control
uint8_t dutyCycle = 0;
uint8_t accAmount = 5;
bool motorDir = true; // true for forward, false for backward

void setup() {
  // Set motor control pins as outputs
  pinMode(MOT_PIN, OUTPUT);
  pinMode(MOT_DIR1, OUTPUT);
  pinMode(MOT_DIR2, OUTPUT);

  // Initialize PWM for motor speed control
  ledcSetup(PWM_CH, PWM_FREQ, PWM_RES);
  ledcAttachPin(MOT_PIN, PWM_CH);

  // Start serial communication
  Serial.begin(115200);
  Serial.println("Motor Control Example");
}

void loop() {
  // Write the PWM signal to control motor speed
  ledcWrite(PWM_CH, dutyCycle);

  // Set motor direction
  digitalWrite(MOT_DIR1, motorDir ? HIGH : LOW);
  digitalWrite(MOT_DIR2, motorDir ? LOW : HIGH);

  // Output the motor state to the serial monitor
  if (dutyCycle == 0 || dutyCycle == 255) {
    Serial.println(motorDir ? "Decelerating..." : "Accelerating...");
    Serial.println(motorDir ? "Changing direction to backward." : "Changing direction to forward.");
    motorDir = !motorDir; // Change direction
  }

  // Update the duty cycle for acceleration/deceleration
  dutyCycle += motorDir ? -accAmount : accAmount;

  // Ensure the duty cycle stays within the 8-bit limit
  if (dutyCycle <= 0 || dutyCycle >= 255) {
    dutyCycle = motorDir ? 255 : 0;
  }

  // Delay to control the rate of acceleration/deceleration
  delay(50);
}
