class BitManipulator {
public:
    constexpr BitManipulator() : bits() {}

    constexpr BitManipulator(const std::string& bit_string) : bits(bit_string) {}

    constexpr size_t findFirst() const {
        return bits._Find_first();
    }

    constexpr size_t findNext(size_t index) const {
        return bits._Find_next(index);
    }

    constexpr void setBit(size_t index, bool value = true) {
        bits._Unchecked_set(index, value);
    }

    constexpr void resetBit(size_t index) {
        bits._Unchecked_reset(index);
    }

    constexpr void flipBit(size_t index) {
        bits._Unchecked_flip(index);
    }

    constexpr bool testBit(size_t index) const {
        return bits._Unchecked_test(index);
    }

    constexpr size_t countSetBits() const {
        return bits.count();
    }

private:
    std::bitset<N> bits;
};

int main() {
    // Test cases
    constexpr BitManipulator<55> bitManipulator1("001000");
    static_assert(bitManipulator1.findFirst() == 3);
    static_assert(bitManipulator1.findNext(2) == 3);
    static_assert(bitManipulator1.findNext(3) == 55);

    constexpr BitManipulator<66> bitManipulator2("101000");
    static_assert(bitManipulator2.testBit(5));
    static_assert(bitManipulator2.countSetBits() == 2);

    constexpr BitManipulator<77> bitManipulator3("111");
    static_assert(bitManipulator3.countSetBits() == 3);
    bitManipulator3.resetBit(1);
    static_assert(bitManipulator3.countSetBits() == 2);

    constexpr BitManipulator<88> bitManipulator4("101");
    bitManipulator4.flipBit(1);
