class RawDigitAdder_HardSaturate {
private:
    bool _throw;
    short _max;
    float _scale1;
    float _scale2;

    void FixOverflow(short& value) {
        if (value < std::numeric_limits<short>::min()) {
            value = std::numeric_limits<short>::min();
        } else if (value > std::numeric_limits<short>::max()) {
            value = std::numeric_limits<short>::max();
        }
    }

public:
    RawDigitAdder_HardSaturate(bool t) :
        _throw(t),
        _max(std::numeric_limits<short>::max()),
        _scale1(1),
        _scale2(1) {}

    void SetSaturationPoint(short x) {
        if (x < 0) {
            if (_throw)
                throw std::runtime_error("Error in SetSaturationPoint: point < 0");
            return;
        }
        _max = x;
    }

    void SetScaleInput1(float f) {
        SetScaleInput(f, _scale1);
    }

    void SetScaleInput2(float f) {
        SetScaleInput(f, _scale2);
    }

    void AddRawDigit(short const& d1, short const& d2, short& d_out) {
        d_out = (short)(std::round(d1 * _scale1)) + (short)(std::round(d2 * _scale2));
        FixOverflow(d_out);
        if (d_out > _max)
            d_out = _max;
    }

private:
    void SetScaleInput(float f, float& _scale) {
        if (f < 0) {
            if (_throw)
                throw std::runtime_error("Error in SetScaleInput: scale < 0");
            return;
        }
        _scale = f;
    }
};

int main() {
    // Test cases
    RawDigitAdder_HardSaturate adder(true);
    short result;

    // Test case 1: Normal addition without saturation
    adder.SetScaleInput1(1.0f);
    adder.SetScaleInput2(1.0f);
    adder.AddRawDigit(1000, 2000, result);
    std::cout << "Test 1 Result: " << result << std::endl;

    // Test case 2: Addition with saturation
    adder.SetSaturationPoint(2500);
    adder.AddRawDigit(1500, 2000, result);
    std::cout << "Test 2 Result: " << result << std::endl;

    // Test case 3: Addition with scaling
    adder.SetScaleInput1(0.5f);
    adder.SetScaleInput2(0.5f);
    adder.AddRawDigit(4000, 4000, result);
    std::cout << "Test 3 Result: " << result << std::endl;

    // Test case 4: Handling negative scale (should throw exception)
    try {
        adder.SetScaleInput1(-1.0f);
    } catch (const std::runtime_error& e) {
        std::cout << "Test 4 Caught Exception: " << e.what() << std::endl;
    }

    // Test case 5: Handling negative saturation point (should throw exception)
    try {
        adder.SetSaturationPoint(-100);
    } catch (const std::runtime_error& e) {
        std::cout << "Test 5 Caught Exception: " << e.what() << std::endl;
    }

    return 0;
}
