using namespace std;

class Node {
public:
    int data;
    Node *left;
    Node *right;

    Node(int d) {
        this->data = d;
        this->left = NULL;
        this->right = NULL;
    }
};

void levelOrderTraversal(Node *root) {
    if (!root) return;
    queue<Node *> q;
    q.push(root);

    while (!q.empty()) {
        Node *temp = q.front();
        q.pop();

        cout << temp->data << " ";
        if (temp->left) {
            q.push(temp->left);
        }
        if (temp->right) {
            q.push(temp->right);
        }
    }
    cout << endl;
}

void inorder(Node *root) {
    if (root == NULL) {
        return;
    }
    inorder(root->left);
    cout << root->data << " ";
    inorder(root->right);
}

void preorder(Node *root) {
    if (root == NULL) {
        return;
    }
    cout << root->data << " ";
    preorder(root->left);
    preorder(root->right);
}

void postorder(Node *root) {
    if (root == NULL) {
        return;
    }
    postorder(root->left);
    postorder(root->right);
    cout << root->data << " ";
}

void buildfromLOT(Node *&root) {
    int data;
    cout << "Enter the data for the root node: ";
    cin >> data;
    if (data == -1) return;

    root = new Node(data);
    queue<Node *> q;
    q.push(root);

    while (!q.empty()) {
        Node *temp = q.front();
        q.pop();

        int leftData, rightData;
        cout << "Enter left child of " << temp->data << ": ";
        cin >> leftData;
        if (leftData != -1) {
            temp->left = new Node(leftData);
            q.push(temp->left);
        }

        cout << "Enter right child of " << temp->data << ": ";
        cin >> rightData;
        if (rightData != -1) {
            temp->right = new Node(rightData);
            q.push(temp->right);
        }
    }
}

int main() {
    Node *root = NULL;
    buildfromLOT(root);

    cout << "Level Order Traversal: " << endl;
    levelOrderTraversal(root);

    cout << "Inorder Traversal: " << endl;
    inorder(root);
    cout << endl;

    cout << "Preorder Traversal: " << endl;
    preorder(root);
    cout << endl;

    cout << "Postorder Traversal: " << endl;
    postorder(root);
    cout << endl;

    return 0;
}
