int solveMaxDistancePairing(int n, int k, vector<int>& nums) {
    sort(nums.begin(), nums.end());
    vector<bool> paired(n, false);
    int pairs = 0;
    for (int i = 0; i < n - 1; i++) {
        if (paired[i]) continue;
        for (int j = i + 1; j < n; j++) {
