// Function to remove duplicates from a sorted array
int removeDuplicates(std::vector<int>& nums) {
    if (nums.empty()) return 0;

    int writeIndex = 1;
    for (int i = 1; i < nums.size(); ++i) {
        if (nums[i] != nums[i - 1]) {
            nums[writeIndex++] = nums[i];
        }
    }
    return writeIndex;
}

// Helper function to create a vector from an initializer list
void createNums(std::vector<int> &nums, std::initializer_list<int> li) {
    nums.assign(li);
}

// Helper function to verify the vector against expected values
void verifyVector(std::initializer_list<int> expected, std::vector<int> actual, int size) {
    ASSERT_EQ(expected.size(), size);
    auto ptr = expected.begin();
    for (int i = 0; i < size; ++i) {
        ASSERT_EQ(*(ptr++), actual[i]);
    }
}

