// Assume the Point2D structure and surfaceDistance function are defined elsewhere
struct Point2D {
    double x, y;
};

double surfaceDistance(const Point2D& p1, const Point2D& p2) {
    // Hypothetical distance calculation on the surface
    return std::hypot(p2.x - p1.x, p2.y - p1.y);
}

// Define the PolygonOnSurface class
class PolygonOnSurface {
private:
    std::vector<Point2D> vertices;

public:
    PolygonOnSurface() {}

    void addVertex(const Point2D& point) {
        vertices.push_back(point);
    }

    bool removeVertex(size_t index) {
        if (index < vertices.size()) {
            vertices.erase(vertices.begin() + index);
            return true;
        }
        return false;
    }

    double calculatePerimeter() const {
        double perimeter = 0.0;
        for (size_t i = 0; i < vertices.size(); ++i) {
            size_t nextIndex = (i + 1) % vertices.size();
            perimeter += surfaceDistance(vertices[i], vertices[nextIndex]);
        }
        return perimeter;
    }

    // Serialization method
    void SWrite(std::ostream& os) const {
        // Write the number of vertices
        os << vertices.size() << '\n';
        // Write the vertices
        for (const auto& vertex : vertices) {
            os << vertex.x << ' ' << vertex.y << '\n';
        }
    }

    // Deserialization method
    void SRead(std::istream& is) {
        size_t numVertices;
        is >> numVertices;
        vertices.clear();
        for (size_t i = 0; i < numVertices; ++i) {
            Point2D vertex;
            is >> vertex.x >> vertex.y;
            vertices.push_back(vertex);
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    PolygonOnSurface polygon;
    polygon.addVertex({0.0, 0.0});
    polygon.addVertex({1.0, 0.0});
    polygon.addVertex({1.0, 1.0});
    polygon.addVertex({0.0, 1.0});

    std::cout << "Perimeter: " << polygon.calculatePerimeter() << std::endl; // Expected: 4.0

    // Serialization
    std::ostringstream out;
    polygon.SWrite(out);
    std::string serializedData = out.str();
    std::cout << "Serialized Data: " << serializedData << std::endl;

    // Deserialization
    std::istringstream in(serializedData);
    PolygonOnSurface deserializedPolygon;
    deserializedPolygon.SRead(in);
    std::cout << "Deserialized Perimeter: " << deserializedPolygon.calculatePerimeter() << std::endl; // Expected: 4.0

    return 0;
}
