    for (int i = 0; i < n; i++) {
        ll a, b; cin >> a >> b;
        happy[i] = Pll(a, b);
        pq.push(Pll(a + b, i));
    }

    ll taka = 0, aoki = 0;
    ll count = 0;
    while (!pq.empty()) {
        Pll p = pq.top(); pq.pop();
        if (count % 2 == 0) taka += happy[p.second].first;
        else aoki += happy[p.second].second;
        count++;
    }

