};

// Forward declarations
class coreModel;
class coreTexture;
class coreShader;
class coreFont;
class coreProgram;

// Base class for all resources
class coreResource {
public:
    virtual ~coreResource() = default;
    virtual void Load(const std::string& name, CoreResourceUpdateType updateType, const std::string& path) = 0;
};

// Derived classes for each resource type
class coreModel : public coreResource {
public:
    void Load(const std::string& name, CoreResourceUpdateType updateType, const std::string& path, CoreModelLoadOption option) override {
        std::cout << "Loading model: " << name << " from " << path << std::endl;
