    }
};

class coreProgram : public coreResource {
private:
    std::vector<std::string> attachedShaders;
public:
    void Load(const std::string& name, CoreResourceUpdateType updateType, const std::string* path) override {
        std::cout << "Creating program: " << name << std::endl;
    }

    coreProgram* AttachShader(const std::string& shaderName) {
        attachedShaders.push_back(shaderName);
        std::cout << "Attaching shader: " << shaderName << " to program" << std::endl;
        return this;
    }

    void Finish() {
        std::cout << "Finishing program setup with " << attachedShaders.size() << " shaders attached." << std::endl;
    }
};

// Resource manager class
class ResourceManager {
private:
    std::unordered_map<std::string, std::unique_ptr<coreResource>> resources;

public:
    template <typename T, typename... Args>
    T* Load(const std::string& name, CoreResourceUpdateType updateType, Args... args) {
        auto resource = std::make_unique<T>();
        resource->Load(name, updateType, args...);
        T* rawPtr = resource.get();
        resources[name] = std::move(resource);
        return rawPtr;
    }

    coreResource* GetResource(const std::string& name) {
        auto it = resources.find(name);
        if (it != resources.end()) {
            return it->second.get();
        }
        return nullptr;
    }
};

// Core application class
