using namespace std;

/**
 * Finds the length of the longest contiguous subsequence in which each element
 * is one greater than its predecessor.
 * 
 * @param arr The vector of integers.
 * @return The length of the longest such subsequence.
 */
int longestConsecutiveSubsequence(const vector<int>& arr) {
    if (arr.empty()) return 0;

    int max_length = 1;
    int current_length = 1;

    for (size_t i = 1; i < arr.size(); ++i) {
        if (arr[i - 1] + 1 == arr[i]) {
            current_length++;
        } else {
            max_length = max(max_length, current_length);
            current_length = 1;
        }
    }

    return max(max_length, current_length);
}

int main() {
    int N;
    cin >> N;
    vector<int> a(N);
    for (int i = 0; i < N; i++) {
        cin >> a[i];
    }

    cout << longestConsecutiveSubsequence(a) << endl;
    return 0;
}
