#include <iostream>
#include <climits> // For INT_MIN

using namespace std;

struct TreeNode
{
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution
{
public:
    int findClosestValueInBST(TreeNode *root, int target)
    {
        int closest = INT_MIN;
        int minDiff = INT_MAX;

        while (root)
        {
            int currentDiff = abs(root->val - target);
            if (minDiff > currentDiff)
            {
                minDiff = currentDiff;
                closest = root->val;
            }

            if (root->val > target)
            {
                root = root->left;
            }
            else if (root->val < target)
            {
                root = root->right;
            }
            else
            {
                break; // The target is found
            }
        }

        return closest;
    }
};

// Test cases
int main()
{
    // Test case 1
    TreeNode *root1 = new TreeNode(4);
    root1->left = new TreeNode(2);
    root1->right = new TreeNode(5);
    root1->left->left = new TreeNode(1);
    root1->left->right = new TreeNode(3);

    Solution sol;
    cout << "Closest value to 3.714286 in BST: " << sol.findClosestValueInBST(root1, 3) << endl; // Output: 3

    // Test case 2
    TreeNode *root2 = new TreeNode(9);
    root2->left = new TreeNode(4);
    root2->right = new TreeNode(17);
    root2->left->left = new TreeNode(3);
    root2->left->right = new TreeNode(6);
    root2->left->right->left = new TreeNode(5);
    root2->left->right->right = new TreeNode(7);
    root2->right->right = new TreeNode(22);
    root2->right->right->left = new TreeNode(20);

    cout << "Closest value to 18 in BST: " << sol.findClosestValueInBST(root2, 18) << endl; // Output: 17

    // Test case 3
    TreeNode *root3 = nullptr;

    cout << "Closest value to 5 in empty BST: " << sol.findClosestValueInBST(root3, 5) << endl; // Output: INT_MIN

    return 0;
}
