// Assuming Sprite class is defined elsewhere
#include "Sprite.h"

namespace MikuMikuWorld
{
    class TextureManager
    {
    private:
        struct Texture
        {
            unsigned int glID;
            int width;
            int height;
            std::unordered_map<std::string, Sprite> sprites;

            Texture() : glID(0), width(0), height(0) {}
        };

        std::unordered_map<std::string, Texture> textures;

        void loadTextureFromFile(const std::string& filepath)
        {
            Texture texture;
            glGenTextures(1, &texture.glID);
            glBindTexture(GL_TEXTURE_2D, texture.glID);

            int nrChannels;
            stbi_set_flip_vertically_on_load(0);
            unsigned char* data = stbi_load(filepath.c_str(), &texture.width, &texture.height, &nrChannels, 4);

            if (data)
            {
                glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, texture.width, texture.height, 0, GL_RGBA, GL_UNSIGNED_BYTE, data);
                glGenerateMipmap(GL_TEXTURE_2D);
                glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_REPEAT);
                glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_REPEAT);
                glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR);
                glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
            }
            else
            {
                std::cerr << "Failed to load texture: " << filepath << std::endl;
            }

            glBindTexture(GL_TEXTURE_2D, 0);
            stbi_image_free(data);

            std::string name = std::filesystem::path(filepath).stem().string();
            texture.sprites[name] = Sprite(name, 0, 0, texture.width, texture.height);

            textures[name] = texture;
        }

        void loadSpriteSheet(const std::string& filepath, Texture& texture)
        {
            std::ifstream file(filepath);
            std::string line;
            while (std::getline(file, line))
            {
                if (line.empty() || line[0] == '#') continue;

                std::istringstream iss(line);
                std::string spriteName;
                int x, y, w, h;

                if (!(iss >> spriteName >> x >> y >> w >> h))
                {
                    std::cerr << "Invalid sprite format in " << filepath << std::endl;
                    continue;
                }

                texture.sprites[spriteName] = Sprite(spriteName, x, y, w, h);
            }
        }

    public:
        void loadTexture(const std::string& filepath)
        {
            loadTextureFromFile(filepath);

            std::string spriteSheetPath = filepath + ".txt";
            if (std::filesystem::exists(spriteSheetPath))
            {
                std::string name = std::filesystem::path(filepath).stem().string();
                loadSpriteSheet(spriteSheetPath, textures[name]);
            }
        }

        void bindTexture(const std::string& name)
        {
            if (textures.find(name) != textures.end())
            {
                glBindTexture(GL_TEXTURE_2D, textures[name].glID);
            }
            else
            {
                std::cerr << "Texture not found: " << name << std::endl;
            }
        }

        void disposeTexture(const std::string& name)
        {
            if (textures.find(name) != textures.end())
            {
                glDeleteTextures(1, &textures[name].glID);
                textures.erase(name);
            }
            else
            {
                std::cerr << "Texture not found: " << name << std::endl;
            }
        }

        Sprite getSprite(const std::string& textureName, const std::string& spriteName)
        {
            if (textures.find(textureName) != textures.end() && textures[textureName].sprites.find(spriteName) != textures[textureName].sprites.end())
            {
                return textures[textureName].sprites[spriteName];
            }
            else
            {
                std::cerr << "Sprite not found: " << spriteName << " in texture " << textureName << std::endl;
                return Sprite();
            }
        }
    };
}

// Test cases
int main()
{
    MikuMikuWorld::TextureManager textureManager;

    // Load a texture and its sprites
    textureManager.loadTexture("assets/texture.png");

    // Bind the texture for rendering
    textureManager.bindTexture("texture");

    // Retrieve a sprite from the texture
    MikuMikuWorld::Sprite sprite = textureManager.getSprite("texture", "hero_idle");

    // Dispose of the texture when it's no longer needed
    textureManager.disposeTexture("texture");

    return 0;
}
