/**
 * @brief Calculate the sum of the k smallest integers in the array.
 * 
 * @param arr The array of integers.
 * @param k The number of smallest integers to sum.
 * @return int The sum of the k smallest integers.
 */
int sumOfKSmallest(const vector<int>& arr, int k) {
  vector<int> sortedArr = arr;
  sort(sortedArr.begin(), sortedArr.end());
  int sum = 0;
  for (int i = 0; i < k; ++i) {
    sum += sortedArr[i];
  }
  return sum;
}

int main() {
  // Test cases
  vector<int> arr1 = {5, 3, 8, 2, 4};
