#include <iostream>
using namespace std;

/**
 * Checks if a number is prime.
 * @param num The number to check.
 * @return True if the number is prime, false otherwise.
 */
bool isPrime(int num) {
    if (num <= 1) return false;
    for (int j = 2; j * j <= num; j++) {
        if (num % j == 0)
            return false;
    }
    return true;
}

/**
 * Finds the sum of all prime numbers in a given range and the minimum prime number.
 * @param M The start of the range.
 * @param N The end of the range.
 * @param sum Reference to the sum of primes in the range.
 * @param minimum Reference to the minimum prime in the range.
 * @return True if at least one prime number is found, false otherwise.
 */
bool findPrimesInRange(int M, int N, int& sum, int& minimum) {
    bool found = false;
    sum = 0;
    minimum = -1;
    for (int i = M; i <= N; i++) {
        if (isPrime(i)) {
            if (!found) {
                minimum = i;
                found = true;
            }
            sum += i;
        }
    }
    return found;
}

int main() {
    int M, N, sum, minimum;
    cin >> M >> N;

    bool hasPrimes = findPrimesInRange(M, N, sum, minimum);
    if (!hasPrimes)
        cout << -1 << "\n";
    else
        cout << sum << "\n" << minimum;

    return 0;
}

