    std::unordered_map<std::string, std::tuple<int, int, int, int, int>> moduleMap;
    int moduleCount;

public:
    PixelMapping(const std::string& filePath) : moduleCount(0) {
        std::ifstream file(filePath);
        if (!file.is_open()) {
            throw std::runtime_error("Could not open file: " + filePath);
        }
        std::string line;
        while (std::getline(file, line)) {
            std::istringstream iss(line);
            std::string moduleName;
            int hashID, bec, layer, phimod, etamod;
            if (!(iss >> moduleName >> hashID >> bec >> layer >> phimod >> etamod)) {
                throw std::runtime_error("Error parsing line: " + line);
            }
            moduleMap[moduleName] = std::make_tuple(hashID, bec, layer, phimod, etamod);
            moduleCount++;
        }
        file.close();
    }

    std::tuple<int, int, int, int, int> mapping(const std::string& moduleName) {
        auto it = moduleMap.find(moduleName);
        if (it == moduleMap.end()) {
            throw std::runtime_error("Module name not found: " + moduleName);
        }
        return it->second;
    }

    int nModules() const {
        return moduleCount;
    }
};

