// Base class for loss functions
class Loss {
public:
    virtual ~Loss() {}
    virtual double ComputeLoss(double predicted, double actual) const = 0;
};

// Squared loss function
class SquaredLoss : public Loss {
public:
    double ComputeLoss(double predicted, double actual) const override {
        double diff = predicted - actual;
        return diff * diff;
    }
};

// Absolute loss function
class AbsoluteLoss : public Loss {
public:
    double ComputeLoss(double predicted, double actual) const override {
        return std::abs(predicted - actual);
    }
};

// Factory for creating loss functions
class LossFactory {
private:
    using LossCreator = std::function<std::unique_ptr<Loss>()>;
    static std::unordered_map<std::string, LossCreator> loss_creators;

public:
    static std::unique_ptr<Loss> CreateLossFunction(const std::string& type) {
        auto it = loss_creators.find(type);
        if (it != loss_creators.end()) {
            return it->second();
        }
        return nullptr;
    }
};

// Static map initialization
std::unordered_map<std::string, LossFactory::LossCreator> LossFactory::loss_creators = {
    {"squared", []() { return std::make_unique<SquaredLoss>(); }},
    {"absolute", []() { return std::make_unique<AbsoluteLoss>(); }}
};

// Main function to demonstrate the usage of the factory
int main() {
    std::unique_ptr<Loss> squared_loss = LossFactory::CreateLossFunction("squared");
    std::unique_ptr<Loss> absolute_loss = LossFactory::CreateLossFunction("absolute");

    double predicted = 3.5;
    double actual = 2.5;

    if (squared_loss) {
        std::cout << "Squared Loss: " << squared_loss->ComputeLoss(predicted, actual) << std::endl;
    }

    if (absolute_loss) {
        std::cout << "Absolute Loss: " << absolute_loss->ComputeLoss(predicted, actual) << std::endl;
    }

    return 0;
}
