#include<bits/stdc++.h>
using namespace std;

const long long mod = 1e9 + 7, mx = 105;

struct Matrix {
    long long mat[mx][mx];

    Matrix operator*(const Matrix &b) const {
        Matrix res;
        for(int i = 0; i < mx; ++i) {
            for(int j = 0; j < mx; ++j) {
                res.mat[i][j] = 0;
                for(int k = 0; k < mx; ++k) {
                    res.mat[i][j] += (mat[i][k] * b.mat[k][j]) % mod;
                    res.mat[i][j] %= mod;
                }
            }
        }
        return res;
    }

    static Matrix binpow(Matrix a, long long k) {
        Matrix res;
        for(int i = 0; i < mx; ++i) {
            for(int j = 0; j < mx; ++j) {
                res.mat[i][j] = (i == j);
            }
        }
        while(k > 0) {
            if(k & 1) res = res * a;
            k >>= 1;
            a = a * a;
        }
        return res;
    }
};

int main() {
    long long n, m;
    cin >> n >> m;

    if(n < m) {
        cout << "1\n";
        return 0;
    }

    Matrix base;
    for(int i = 0; i < m; ++i) {
        for(int j = 0; j < m; ++j) {
            base.mat[i][j] = (i == m - 1) || (j == i + 1);
        }
    }

    Matrix result = Matrix::binpow(base, n - m + 1);
    long long ans = 0;
    for(int i = 0; i < m; ++i) {
        ans = (ans + result.mat[m - 1][i]) % mod;
    }

    cout << ans << endl;
    return 0;
}
