#include <iostream>
#include <string>

// Abstract base class representing any AST node
class AstNode {
public:
    virtual ~AstNode() {}
    virtual std::string toJson(int spaces) const = 0;
};

// Helper function to add indentation
void fillString(std::string& str, int spaces, const std::string& indent) {
    for (int i = 0; i < spaces; ++i) {
        str += indent;
    }
}

// Class representing an identifier in the AST
class IdentifierNode : public AstNode {
private:
    std::string m_name;
public:
    IdentifierNode(const std::string& name) : m_name(name) {}
    virtual std::string toJson(int spaces) const override {
        std::string result;
        fillString(result, spaces, "    ");
        result += "\"" + m_name + "\"";
        return result;
    }
};

// Class representing an expression in the AST
class ExpressionNode : public AstNode {
private:
    std::string m_expression;
public:
    ExpressionNode(const std::string& expression) : m_expression(expression) {}
    virtual std::string toJson(int spaces) const override {
        std::string result;
        fillString(result, spaces, "    ");
        result += "\"" + m_expression + "\"";
        return result;
    }
};

// Class representing structure access in the AST
class StructAccessNode : public AstNode {
private:
    AstNode* m_expr;
    AstNode* m_id;
public:
    StructAccessNode(AstNode* expr, AstNode* id) : m_expr(expr), m_id(id) {}
    virtual ~StructAccessNode() {
        delete m_expr;
        delete m_id;
    }
    virtual std::string toJson(int spaces) const override {
        std::string result;
        fillString(result, spaces, "    ");
        result += "StructAccess {\n";
        spaces++;
        fillString(result, spaces, "    ");
        result += "object:\n";
        result += m_expr->toJson(spaces + 1);
        result += ",\n";
        fillString(result, spaces, "    ");
        result += "field:\n";
        result += m_id->toJson(spaces + 1);
        result += '\n';
        fillString(result, spaces - 1, "    ");
        result += '}';
        return result;
    }
};

int main() {
    // Create an example structure access expression
    AstNode* expr = new ExpressionNode("myStruct");
    AstNode* id = new IdentifierNode("myField");
    StructAccessNode* structAccess = new StructAccessNode(expr, id);

    // Serialize to JSON and print
    std::cout << structAccess->toJson(0) << std::endl;

    // Clean up
    delete structAccess;

    return 0;
}
