template <typename T>
class CustomSet {
private:
    std::set<T> internal_set;
    mutable size_t comparison_count;

public:
    CustomSet() : comparison_count(0) {}

    void insert(const T& value) {
        internal_set.insert(value);
    }

    size_t get_comparison_count() const {
        size_t count = comparison_count;
        comparison_count = 0; // Reset the count after it's retrieved
        return count;
    }

    // Relational operators
    bool operator==(const CustomSet& other) const {
        comparison_count++;
        return internal_set == other.internal_set;
    }

    bool operator!=(const CustomSet& other) const {
        comparison_count++;
        return internal_set != other.internal_set;
    }

    bool operator<(const CustomSet& other) const {
        comparison_count++;
        return internal_set < other.internal_set;
    }

    bool operator>(const CustomSet& other) const {
        comparison_count++;
        return internal_set > other.internal_set;
    }

    bool operator<=(const CustomSet& other) const {
        comparison_count++;
        return internal_set <= other.internal_set;
    }

    bool operator>=(const CustomSet& other) const {
        comparison_count++;
        return internal_set >= other.internal_set;
    }
};

int main() {
    CustomSet<int> foo, bar;
    foo.insert(10);
    bar.insert(20);
    bar.insert(30);
    foo.insert(40);

    // foo ({10,40}) vs bar ({20,30}):
    if (foo == bar) std::cout << "foo and bar are equal\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    if (foo != bar) std::cout << "foo and bar are not equal\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    if (foo < bar) std::cout << "foo is less than bar\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    if (foo > bar) std::cout << "foo is greater than bar\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    if (foo <= bar) std::cout << "foo is less than or equal to bar\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    if (foo >= bar) std::cout << "foo is greater than or equal to bar\n";
    std::cout << "Comparison count: " << foo.get_comparison_count() << std::endl;

    return 0;
}
