typedef long long ll;

// Function to calculate the product of the sums of the digits of a two-part split of a given number, minus two.
ll calculateProductMinusTwo(ll n) {
    ll a = 0, b = 0;
    ll pw = 1;
    while (n) {
        a += pw * (n % 10);
        n /= 10;
        b += pw * (n % 10);
        n /= 10;
        pw *= 10;
    }
    return (a + 1) * (b + 1) - 2;
}

int main() {
