using namespace std;

vector<double> calculateMovingAverages(const vector<double>& numbers, int k) {
    vector<double> movingAverages;
    double windowSum = 0.0;
    for (int i = 0; i < k; ++i) {
        windowSum += numbers[i];
    }
    movingAverages.push_back(windowSum / k);
    for (int i = k; i < numbers.size(); ++i) {
        windowSum += numbers[i] - numbers[i - k];
        movingAverages.push_back(windowSum / k);
    }
    return movingAverages;
}

int main() {
    int n, k;
    cin >> n >> k;
    vector<double> numbers(n);
    for (int i = 0; i < n; ++i) {
        cin >> numbers[i];
    }
