#include <iostream>
#include <vector>
#include <cstring>

class DynamicArray {
public:
    DynamicArray(size_t size) : m_size(size), m_data(new int[size]) {
        std::memset(m_data, 0, size * sizeof(int));
    }

    ~DynamicArray() {
        delete[] m_data;
    }

    void set(size_t index, int value) {
        if (index >= m_size) {
            throw std::out_of_range("Index out of bounds");
        }
        m_data[index] = value;
    }

    int get(size_t index) const {
        if (index >= m_size) {
            throw std::out_of_range("Index out of bounds");
        }
        return m_data[index];
    }

    void serialize(std::vector<char>& buffer) const {
        buffer.clear();
        buffer.resize(sizeof(size_t) + m_size * sizeof(int));
        std::memcpy(buffer.data(), &m_size, sizeof(size_t));
        std::memcpy(buffer.data() + sizeof(size_t), m_data, m_size * sizeof(int));
    }

    void deserialize(const std::vector<char>& buffer) {
        size_t size;
        std::memcpy(&size, buffer.data(), sizeof(size_t));
        if (size != m_size) {
            delete[] m_data;
            m_size = size;
            m_data = new int[m_size];
        }
        std::memcpy(m_data, buffer.data() + sizeof(size_t), m_size * sizeof(int));
    }

private:
    size_t m_size;
    int* m_data;
};

// Test cases to verify the solution correctness
int main() {
    DynamicArray arr(5);
    arr.set(0, 10);
    arr.set(1, 20);
    arr.set(2, 30);
    arr.set(3, 40);
    arr.set(4, 50);

    std::vector<char> buffer;
    arr.serialize(buffer);

    DynamicArray arr2(0);
    arr2.deserialize(buffer);

    for (size_t i = 0; i < 5; ++i) {
        std::cout << "arr2[" << i << "] = " << arr2.get(i) << std::endl;
    }

    return 0;
}
