        std::cout << "ARM memory layout obtained." << std::endl;

        // Test alignment for ARM
        uint32_t size = 7;
        uint32_t alignedSize = armMemoryLayout->align(size);
        std::cout << "Aligned size for ARM: " << alignedSize << std::endl;

        // Test getting a compiler for an unsupported type
