// NetworkChannelManager class implementation
NetworkChannelManager::NetworkChannelManager() {}

NetworkChannelManager::~NetworkChannelManager() {
    std::lock_guard<std::mutex> lock(m_mutex);
    m_channels.clear();
}

uint32_t NetworkChannelManager::AddChannel(Ptr channel) {
    std::lock_guard<std::mutex> lock(m_mutex);
    uint32_t channelId = m_channels.size();
    m_channels.push_back(channel);
    return channelId;
}

Ptr NetworkChannelManager::GetChannel(uint32_t channelId) const {
    std::lock_guard<std::mutex> lock(m_mutex);
    assert(channelId < m_channels.size() && "Channel ID out of range");
    return m_channels[channelId];
}

uint32_t NetworkChannelManager::GetTotalChannels() const {
    std::lock_guard<std::mutex> lock(m_mutex);
    return m_channels.size();
}

