// FunctionDefn class to define functions that can act as getters or setters
class FunctionDefn {
private:
    std::string name;
public:
    FunctionDefn(const std::string& name) : name(name) {}

    const std::string& getName() const {
        return name;
    }
};

// Module class to represent a module in which the properties are defined
class Module {
    // For simplicity, we're not implementing the full module functionality
};

// PropertyDefn class to define properties with optional getter and setter methods
class PropertyDefn {
private:
    std::string name;
    FunctionDefn* getter;
    FunctionDefn* setter;
    Diagnostics diag;

public:
    PropertyDefn(const std::string& name) : name(name), getter(nullptr), setter(nullptr) {}

    void addAccessor(FunctionDefn* accessor) {
        if (accessor->getName() == "get") {
            if (getter != nullptr) {
                diag.error(this, "Multiple getters not supported");
                return;
            }
            getter = accessor;
        } else if (accessor->getName() == "set") {
            if (setter != nullptr) {
                diag.error(this, "Multiple setters not supported");
                return;
            }
            setter = accessor;
        }
    }

    const std::string& getName() const {
        return name;
    }
};

int main() {
    // Create a property
    PropertyDefn myProperty("myProperty");

    // Create getter and setter functions
    FunctionDefn getter("get");
    FunctionDefn setter("set");

    // Add getter and setter to the property
    myProperty.addAccessor(&getter);
    myProperty.addAccessor(&setter);

    // Attempt to add a second getter, which should trigger an error
    FunctionDefn anotherGetter("get");
    myProperty.addAccessor(&anotherGetter);

    return 0;
}
