using std::vector;
using std::unordered_set;

/**
 * @brief Finds the length of the longest contiguous subsequence within an array.
 *
 * @param A The input vector of integers.
 * @return int The length of the longest contiguous subsequence.
 */
int LongestContainedRange(const vector<int> &A) {
    unordered_set<int> unprocessed(A.begin(), A.end());
    int maxInterval = 0;
    while (!unprocessed.empty()) {
        int value = *unprocessed.begin();
        unprocessed.erase(value);
        int lowerBound = value - 1;
        while (unprocessed.count(lowerBound)) {
            unprocessed.erase(lowerBound);
            lowerBound--;
        }
        int upperBound = value + 1;
        while (unprocessed.count(upperBound)) {
            unprocessed.erase(upperBound);
            upperBound++;
        }
        maxInterval = std::max(maxInterval, upperBound - lowerBound - 1);
    }
    return maxInterval;
}

// Test cases to verify the solution
int main() {
    // Test case 1
    vector<int> test1 = {3, -2, 7, 9, 8, 1, 2, 0, -1, 5, 8};
    std::cout << "Test case 1 - Expected: 6, Actual: " << LongestContainedRange(test1) << std::endl;

    // Test case 2
    vector<int> test2 = {10, 5, 3, 11, 6, 100, 4};
    std::cout << "Test case 2 - Expected: 4, Actual: " << LongestContainedRange(test2) << std::endl;

    // Test case 3
    vector<int> test3 = {1, 2, 3, 4, 5};
    std::cout << "Test case 3 - Expected: 5, Actual: " << LongestContainedRange(test3) << std::endl;

    // Test case 4
