#include <iostream>
#include <vector>
using namespace std;

/**
 * Finds the minimum number of jumps to reach the end of the array.
 * @param a The input array where each element represents the maximum number of steps that can be jumped.
 * @param n The size of the input array.
 * @return The minimum number of jumps to reach the end of the array.
 */
int minimumJumpToReachEnd(int a[], int n) {
    vector<int> jumps(n, INT_MAX); // Initialize jumps array with max int value
    vector<int> path(n, -1); // Initialize path array to reconstruct the jump sequence
    jumps[0] = 0; // Starting point requires 0 jumps

    // Calculate minimum jumps and path for each position
    for (int i = 1; i < n; i++) {
        for (int j = 0; j < i; j++) {
            if (i <= j + a[j] && jumps[j] != INT_MAX) {
                if (jumps[j] + 1 < jumps[i]) {
                    jumps[i] = jumps[j] + 1;
                    path[i] = j;
                }
            }
        }
    }

    // Reconstruct the path of jumps
    vector<int> jumpPath;
    int idx = n - 1;
    while (idx != -1) {
        jumpPath.push_back(idx);
        idx = path[idx];
    }
    reverse(jumpPath.begin(), jumpPath.end());

    // Output the results
    cout << "Minimum number of jumps to reach end: " << (jumps[n - 1] == INT_MAX ? -1 : jumps[n - 1]) << endl;
    cout << "Path: ";
    for (size_t i = 0; i < jumpPath.size(); i++) {
        cout << jumpPath[i];
        if (i < jumpPath.size() - 1) cout << " -> ";
    }
    cout << endl;

    return jumps[n - 1] == INT_MAX ? -1 : jumps[n - 1];
}

int main() {
    int a[] = {1, 3, 1, 1, 5, 1, 4, 4, 1, 1, 2, 3, 2, 1, 1};
    int n = sizeof(a) / sizeof(a[0]);

    cout << "Array: ";
    for (int i = 0; i < n; i++) cout << a[i] << " ";
    cout << endl;

    int answer = minimumJumpToReachEnd(a, n);

    cout << "Final answer: " << answer << endl;
    return 0;
}
