// Forward declarations for assumed types
class Image;
using ImageSharedPointer = std::shared_ptr<Image>;
class ImageQueue;
using ImageQueueSharedPointer = std::shared_ptr<ImageQueue>;

// ImageLoader class definition
class ImageLoader : public QObject {
    Q_OBJECT

public:
    explicit ImageLoader(ImageQueueSharedPointer queue, QObject *parent = nullptr)
        : QObject(parent), mQueue(queue), mFreq(1), mRunning(false) {}

    void setFolderPath(const QString &path) {
        mFolder = QDir(path);
    }

    void setFrequency(uint8_t freq) {
        mFreq = freq;
    }

    void startLoading() {
        mRunning = true;
        mLoadThread = std::thread(&ImageLoader::loadImages, this);
    }

    void stopLoading() {
        mRunning = false;
        if (mLoadThread.joinable()) {
            mLoadThread.join();
        }
    }

signals:
    void imageLoaded(ImageSharedPointer image);

private:
    void loadImages() {
        if (!mFolder.exists()) {
            qDebug() << "Directory does not exist.";
            return;
        }

        QStringList filters;
        filters << "*.png" << "*.jpg" << "*.jpeg";
        mFolder.setNameFilters(filters);
        mFolder.setSorting(QDir::Name);

        auto filenamesList = mFolder.entryList();

        for (const auto &filename : filenamesList) {
            if (!mRunning) {
                break;
            }

            QImageReader qimr(mFolder.path() + QDir::separator() + filename);
            ImageSharedPointer pImg = std::make_shared<Image>(qimr.read());

            queMutex.lock();
            mQueue->enqueue(pImg);
            queMutex.unlock();

            emit imageLoaded(pImg);

            QThread::msleep(static_cast<uint32_t>(1000) / mFreq);
        }
    }

    QDir mFolder;
    ImageQueueSharedPointer mQueue;
    std::mutex queMutex;
    uint8_t mFreq;
    std::thread mLoadThread;
    std::atomic<bool> mRunning;
};

// Test cases
int main() {
