using namespace std;

pair<int, int> findOccurrences(int arr[], int size, int target) {
    int start = 0, end = size - 1;
    int firstOccurrence = -1, lastOccurrence = -1;

    // Find the first occurrence
    while (start <= end) {
        int mid = start + (end - start) / 2;
        if (arr[mid] == target) {
            firstOccurrence = mid;
            end = mid - 1; // Continue searching to the left
        } else if (arr[mid] < target) {
            start = mid + 1;
        } else {
            end = mid - 1;
        }
    }

    // Find the last occurrence
    start = 0, end = size - 1;
    while (start <= end) {
        int mid = start + (end - start) / 2;
        if (arr[mid] == target) {
            lastOccurrence = mid;
            start = mid + 1; // Continue searching to the right
        } else if (arr[mid] < target) {
            start = mid + 1;
        } else {
            end = mid - 1;
        }
    }

    return {firstOccurrence, lastOccurrence};
}

int main() {
    int arr[] = {1, 2, 3, 3, 3, 3, 3, 4, 4, 4, 5, 6, 6, 6, 6, 7, 8};
    int size = sizeof(arr) / sizeof(int);
    int target = 3;
    pair<int, int> occurrences = findOccurrences(arr, size, target);

    if (occurrences.first == -1) {
        cout << "Element " << target << " is not found" << endl;
    } else {
        cout << "First occurrence of element " << target << " found at index " << occurrences.first << endl;
        cout << "Last occurrence of element " << target << " found at index " << occurrences.second << endl;
    }

    return 0;
}
