/**
 * Calculates the ceiling of the average of two integers.
 * 
 * @param a The first integer.
 * @param b The second integer.
 * @return The ceiling of the average of a and b.
 */
int ceilingOfAverage(int a, int b) {
    // If the sum of a and b is even, the average is an integer.
    // If the sum is odd, the ceiling of the average is (sum + 1) / 2.
    return (a + b + (a + b) % 2) / 2;
}

int main() {
    int a, b;
    cout << "Enter two integers: ";
    cin >> a >> b;
    cout << "The ceiling of the average is: " << ceilingOfAverage(a, b) << endl;
