class DoublyLinkedList {
private:
    std::shared_ptr<Node> head;
    std::weak_ptr<Node> tail;
    int size;

public:
    DoublyLinkedList() : size(0) {}

    ~DoublyLinkedList() {
        while (head) {
            head = head->getNext();
        }
    }

    void append(int value) {
        auto newNode = std::make_shared<Node>(value);
        if (!head) {
            head = newNode;
            tail = newNode;
        } else {
            newNode->setPrev(tail);
            tail.lock()->setNext(newNode);
            tail = newNode;
        }
        size++;
    }

    bool remove(int value) {
        auto current = head;
        while (current) {
            if (current->getValue() == value) {
                if (current->getPrev().lock()) {
                    current->getPrev().lock()->setNext(current->getNext());
                } else {
                    head = current->getNext();
                }
                if (current->getNext()) {
                    current->getNext()->setPrev(current->getPrev());
                } else {
                    tail = current->getPrev();
                }
                size--;
                return true;
            }
            current = current->getNext();
        }
        return false;
    }

    void printList() {
        auto current = head;
        while (current) {
            std::cout << current->getValue() << " ";
            current = current->getNext();
        }
        std::cout << std::endl;
    }

    void printListReverse() {
        auto current = tail.lock();
        while (current) {
            std::cout << current->getValue() << " ";
            current = current->getPrev().lock();
        }
        std::cout << std::endl;
    }

    int getSize() const {
        return size;
    }
};

int main() {
    DoublyLinkedList list;
    list.append(10);
    list.append(20);
    list.append(30);
    list.printList(); // Expected output: 10 20 30
    list.printListReverse(); // Expected output: 30 20 10
    std::cout << "Size: " << list.getSize() << std::endl; // Expected output: Size: 3

    list.remove(20);
    list.printList(); // Expected output: 10 30
    list.printListReverse(); // Expected output: 30 10
    std::cout << "Size: " << list.getSize() << std::endl; // Expected output: Size: 2

    list.remove(40); // Element not in the list
    std::cout << "Size: " << list.getSize() << std::endl; // Expected output: Size: 2

    return 0;
}
