#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    /**
     * Calculates the number of unique paths from the top-left corner to the
     * bottom-right corner of an m x n grid.
     * 
     * @param m The number of rows in the grid.
     * @param n The number of columns in the grid.
     * @return The number of unique paths.
     */
    int uniquePaths(int m, int n) {
        vector<vector<int>> dp(m, vector<int>(n, 0));

        // Initialize the last row and last column with 1s since there is only
        // one way to reach the finish point from those cells.
        for(int i = 0; i < m; i++)
            dp[i][n-1] = 1;
        for(int j = 0; j < n; j++)
            dp[m-1][j] = 1;

        // Fill the rest of the grid using dynamic programming. Each cell contains
        // the sum of the paths from the cell to the right and the cell below.
        for(int i = m-2; i >= 0; i--){
            for(int j = n-2; j >= 0; j--){
                dp[i][j] = dp[i+1][j] + dp[i][j+1];
            }
        }
        return dp[0][0];
    }
};

// Test cases
int main() {
    Solution sol;

    cout << "Test Case 1: " << sol.uniquePaths(3, 7) << endl; // Output: 28
    cout << "Test Case 2: " << sol.uniquePaths(3, 2) << endl; // Output: 3
    cout << "Test Case 3: " << sol.uniquePaths(7, 3) << endl; // Output: 28
    cout << "Test Case 4: " << sol.uniquePaths(3, 3) << endl; // Output: 6

    return 0;
}
