class ClipRect {
private:
    PhysicalRect rect;
    bool isInfinite;
    bool hasRadius;

public:
    ClipRect() : isInfinite(true), hasRadius(false) {}

    void SetRect(const PhysicalRect& r) {
        rect = r;
        isInfinite = false;
    }

    void SetHasRadius(bool radius) {
        hasRadius = radius;
    }

    bool IsInfinite() const {
        return isInfinite;
    }

    bool HasRadius() const {
        return hasRadius;
    }

    void Intersect(const ClipRect& other) {
        if (isInfinite) {
            *this = other;
        } else if (!other.isInfinite) {
            // Perform intersection logic here (omitted for brevity)
            // Update rect to the intersection of rect and other.rect
            // Update hasRadius if either rect has a radius
            hasRadius = hasRadius || other.hasRadius;
        }
    }

