                res[0] = abs(num);
            } else {
                nums[abs(num) - 1] *= -1;
            }
        }

        for (int i = 0; i < nums.size(); i++) {
            if (nums[i] > 0) {
                res[1] = i + 1;
                break;
            }
        }
        return res;
    }
};

int main() {
    Solution solution;
    vector<int> test1{1, 2, 2, 4};
    vector<int> result1 = solution.findErrorNums(test1);
    cout << "Test Case 1: Expected: [2, 3], Got: [" << result1[0] << ", " << result1[1] << "]" << endl;

    vector<int> test2{1, 1};
    vector<int> result2 = solution.findErrorNums(test2);
    cout << "Test Case 2: Expected: [1, 2], Got: [" << result2[0] << ", " << result2[1] << "]" << endl;

    vector<int> test3{2, 2};
    vector<int> result3 = solution.findErrorNums(test3);
    cout << "Test Case 3: Expected: [2, 1], Got: [" << result3[0] << ", " << result3[1] << "]" << endl;

    return 0;
}
