const int NMAX = 2e6 + 5;

int countMajoritySubarrays(int N, vector<int>& A) {
    int ans = 0;
    vector<int> freq(NMAX, 0);

    for (int i = 0; i < N; i++) {
        fill(freq.begin(), freq.end(), 0);
        for (int j = i; j < N; j++) {
            freq[A[j]]++;
            if (freq[A[j]] > (j - i + 1) / 2) {
                ans++;
            }
        }
    }
    return ans;
}

