class EventCounter {
public:
    EventCounter() {
        fd = ::eventfd(0, EFD_CLOEXEC);
        if (fd == -1) {
            throw std::runtime_error("Failed to create eventfd");
        }
    }

    ~EventCounter() {
        if (fd != -1) {
            ::close(fd);
        }
    }

    void increment() {
        uint64_t value = 1;
        if (::write(fd, &value, sizeof(value)) != sizeof(value)) {
            throw std::runtime_error("Failed to increment counter");
        }
    }

    uint64_t get_value() {
        uint64_t value;
        if (::read(fd, &value, sizeof(value)) != sizeof(value)) {
            throw std::runtime_error("Failed to get counter value");
        }
        return value;
    }

private:
    int fd;
};

int main() {
    try {
        EventCounter counter;
        counter.increment();
        uint64_t value = counter.get_value();
        ::printf("Counter value: %lu\n", value);
    } catch (const std::runtime_error& e) {
        ::fprintf(stderr, "%s\n", e.what());
        return 1;
    }
    return 0;
}
