#include <iostream>
#include <vector>
#include <queue>
#include <stack>
#include <unordered_set>
#include <unordered_map>
using namespace std;

class Graph {
  public:
  vector<vector<int>> adjList;

  void addNode() {
    adjList.push_back(vector<int>{});
  }

  void addEdge(int i, int j) {
    adjList[i].push_back(j);
  }

  void print() {
    for(int i=0; i<adjList.size(); i++) {
      cout << "node " << i << ": ";
      for(int j=0; j<adjList[i].size(); j++) {
        cout << adjList[i][j] << " ";
      }
      cout << endl;
    }
  }

  void findPath(int start, int target) {
    vector<int> visited (adjList.size(), 0);
    vector<int> parent (adjList.size(), -1);
    queue<int> q;
    q.push(start);
    visited[start] = 1;
    while(!q.empty()) {
      int curr = q.front();
      q.pop();
      for(int child : adjList[curr]) {
        if(visited[child] == 0) {
          parent[child] = curr;
          q.push(child);
          visited[child] = 1;
        }
      }
    }
    stack<int> path;
    int curr = target;
    while(curr != start && curr != -1) {
      path.push(curr);
      curr = parent[curr];
    }
    if(curr == start) path.push(start);
    else {
      cout << "no path found!" << endl;
      return;
    }
    while(!path.empty()) {
      cout << path.top();
      path.pop();
      if(!path.empty()) cout << " -> ";
    }
    cout << endl;
  }

  void buildOrder_v2() {
    vector<int> visited(adjList.size(), 0);
    stack<int> buildOrder;
    for(int i=0; i<adjList.size(); i++) {
      if(visited[i] == 0) {
        if(buildDFS(i, visited, buildOrder) == -1) {
          cout << "NO ORDER EXISTS!" << endl;
          return;
        }
      }
    }
    while(!buildOrder.empty()) {
      cout << buildOrder.top() << " ";
      buildOrder.pop();
    }
    cout << endl;
  }

  int buildDFS(int node, vector<int> &visited, stack<int> &buildOrder) {
    visited[node] = 2; // visiting
    for(auto child : adjList[node]) {
      if(visited[child] == 2) return -1; // cycle exists
      if(visited[child] == 0) { // if unvisited
        if(buildDFS(child, visited, buildOrder) == -1) return -1;
      }
    }
    visited[node] = 1; // visited
    buildOrder.push(node);
    return 0;
  }
};

int main() {
  Graph graph;

  for(int i=0; i<6; i++) graph.addNode();

  // dependencies.. (a,b)... b depends on a
  graph.addEdge(0,3);
  graph.addEdge(3,2);
  graph.addEdge(1,3);
  graph.addEdge(5,1);
  graph.addEdge(5,0);
  // Uncomment the following line to create a cycle and test cycle detection.
  // graph.addEdge(0,5);

  cout << "Graph adjacency list:" << endl;
  graph.print();

  cout << "\nFinding path from 5 to 2:" << endl;
  graph.findPath(5, 2);

  cout << "\nBuild order (topological sort):" << endl;
  graph.buildOrder_v2();

  return 0;
}
