#include <iostream>
#include <fstream>
#include <string>

class SimpleIOHandler {
private:
    std::fstream file;

public:
    bool open(const std::string& filename, const std::string& mode) {
        std::ios_base::openmode openMode = std::ios::binary;
        if (mode == "r") {
            openMode |= std::ios::in;
        } else if (mode == "w") {
            openMode |= std::ios::out | std::ios::trunc;
        } else if (mode == "a") {
            openMode |= std::ios::out | std::ios::app;
        } else {
            return false; // Unsupported mode
        }

        file.open(filename, openMode);
        return file.is_open();
    }

    std::size_t read(std::string& buffer, std::size_t length) {
        if (!file.is_open() || !(file.mode() & std::ios::in)) {
            return 0; // File not open for reading
        }

        buffer.resize(length);
        file.read(&buffer[0], length);
        return file.gcount();
    }

    std::size_t write(const std::string& buffer) {
        if (!file.is_open() || !(file.mode() & std::ios::out)) {
            return 0; // File not open for writing
        }

        std::streamsize length = buffer.size();
        file.write(buffer.c_str(), length);
        return file.good() ? static_cast<std::size_t>(length) : 0;
    }

    bool seek(long offset, int origin) {
        if (!file.is_open()) {
            return false; // File not open
        }

        file.seekg(offset, static_cast<std::ios_base::seekdir>(origin));
        file.seekp(offset, static_cast<std::ios_base::seekdir>(origin));
        return file.good();
    }

    long tell() {
        if (!file.is_open()) {
            return -1; // File not open
        }

        return static_cast<long>(file.tellg());
    }

    bool close() {
        if (!file.is_open()) {
            return false; // File not open
        }

        file.close();
        return !file.is_open();
    }
};

// Test cases to verify the solution correctness
int main() {
    SimpleIOHandler ioHandler;

    // Test opening a file for writing
    bool openSuccess = ioHandler.open("test.txt", "w");
    std::cout << "Open for writing: " << openSuccess << std::endl;

    // Test writing to a file
    std::size_t bytesWritten = ioHandler.write("Hello, World!");
    std::cout << "Bytes written: " << bytesWritten << std::endl;

    // Test closing the file
    bool closeSuccess = ioHandler.close();
    std::cout << "Close file: " << closeSuccess << std::endl;

    // Test opening a file for reading
    openSuccess = ioHandler.open("test.txt", "r");
    std::cout << "Open for reading: " << openSuccess << std::endl;

    // Test reading from a file
    std::string buffer;
    std::size_t bytesRead = ioHandler.read(buffer, 5);
    std::cout << "Bytes read: " << bytesRead << " Content: " << buffer << std::endl;

    // Test seeking in a file
    bool seekSuccess = ioHandler.seek(7, SEEK_SET);
    std::cout << "Seek success: " << seekSuccess << std::endl;

    // Test telling the file position
    long position = ioHandler.tell();
    std::cout << "File position: " << position << std::endl;

    // Test closing the file
    closeSuccess = ioHandler.close();
    std::cout << "Close file: " << closeSuccess << std::endl;

    return 0;
}
