#define ll long long int

int main() {
    ios_base::sync_with_stdio(0);
    cin.tie(0); cout.tie(0);

    ll n, k;
    cin >> n >> k;
    vector<ll> arr(n);
    for (ll &val : arr) cin >> val;

    vector<ll> prefixSum(n + 1, 0);
    for (ll i = 1; i <= n; ++i) {
        prefixSum[i] = prefixSum[i - 1] + arr[i - 1];
    }

    ll maxSum = LLONG_MIN;
    for (ll i = 0; i <= k; ++i) {
        ll sumFromStart = prefixSum[i];
        ll sumFromEnd = prefixSum[n] - prefixSum[n - (k - i)];
        maxSum = max(maxSum, sumFromStart + sumFromEnd);
    }

    cout << maxSum << "\n";
    return 0;
}
