/**
 * @brief Manages process scheduling parameters.
 * 
 * @return int Returns 0 on success, non-zero error code on failure.
 */
int ManageProcessScheduling() {
    struct sched_param param = { 0 };
    int ret;

    // Retrieve the current process's priority
    int currProcessPri = getpriority(PRIO_PROCESS, getpid());
    if (currProcessPri < 0 || currProcessPri > 31) {
        return -1; // Invalid priority range
    }

    // Get the current scheduling parameters
    ret = sched_getparam(getpid(), &param);
    if (ret != 0) {
        return ret; // Error occurred
    }

    // Check if the current policy is SCHED_RR
    int currentPolicy = sched_getscheduler(getpid());
    if (currentPolicy != SCHED_RR) {
        // Set the scheduling policy to Round Robin (SCHED_RR)
        param.sched_priority = currProcessPri;
        ret = sched_setscheduler(getpid(), SCHED_RR, &param);
        if (ret != 0) {
            return ret; // Error occurred
        }
    }

    // Validate the changes
    ret = sched_getparam(getpid(), &param);
    if (ret != 0 || param.sched_priority != currProcessPri) {
        return -1; // Validation failed
    }

    // Attempt to change the process group ID
    ret = setpgid(getpid(), 1);
    if (ret != 0 && errno != EPERM) {
        return -1; // Error occurred, but not EPERM
    }

    // Attempt to change the process group ID to a different value
    ret = setpgid(getpid(), 2);
    if (ret != 0 && errno != EPERM) {
        return -1; // Error occurred, but not EPERM
    }

    return 0; // Success
}

int main() {
    int result = ManageProcessScheduling();
    if (result == 0) {
        std::cout << "Process scheduling parameters managed successfully." << std::endl;
    } else {
        std::cerr << "Failed to manage process scheduling parameters. Error code: " << result << std::endl;
    }
    return result;
}
