#include <string>
#include <vector>
#include <unordered_map>
#include <unordered_set>

using namespace std;

class Solution {
 public:
  bool buddyStrings(string s, string goal, vector<vector<int>>& constraints) {
    if (s.size() != goal.size()) return false;

    unordered_map<int, int> constraint_map;
    for (const auto& pair : constraints) {
      constraint_map[pair[0]] = pair[1];
      constraint_map[pair[1]] = pair[0];
    }

    int first = -1, second = -1;
    unordered_set<char> seen;
    bool repeat = false;

    for (int i = 0; i < s.size(); ++i) {
      if (s[i] != goal[i]) {
        if (first == -1) {
          first = i;
        } else if (second == -1) {
          second = i;
        } else {
          return false; // More than two characters differ
        }
      }
      if (seen.find(s[i]) != seen.end()) repeat = true;
      seen.insert(s[i]);
    }

    if (first == -1) {
      return repeat; // No characters differ, check for repeat characters
    }
    if (second == -1) {
      return false; // Only one character differs
    }

    // Check if the swap is valid with constraints
    if (constraint_map.count(first) && constraint_map[first] != second) {
      return false; // Swap does not adhere to constraints
    }
    if (constraint_map.count(second) && constraint_map[second] != first) {
      return false; // Swap does not adhere to constraints
    }

    // Perform the swap and check if it matches the goal
    swap(s[first], s[second]);
    return s == goal;
  }
};

// Test cases
int main() {
  Solution solution;
  vector<vector<int>> constraints1 = {{0, 2}};
  vector<vector<int>> constraints2 = {{0, 1}};
  vector<vector<int>> constraints3 = {};

  // Test case 1
  bool result1 = solution.buddyStrings("abca", "cbad", constraints1);
  // Expected: true

  // Test case 2
  bool result2 = solution.buddyStrings("abca", "cbad", constraints2);
  // Expected: false

  // Test case 3
  bool result3 = solution.buddyStrings("abcd", "badc", constraints3);
  // Expected: true

  return 0;
}
