using namespace std;

typedef long long ll;

class CircularQueue {
private:
    ll *arr;
    ll front, rear, capacity, count;

public:
    CircularQueue(ll size) : capacity(size), front(-1), rear(-1), count(0) {
        arr = new ll[capacity];
    }

    ~CircularQueue() {
        delete[] arr;
    }

    void enqueue(ll value) {
        if (count == capacity) {
            cout << "Queue is full" << endl;
            return;
        }
        if (front == -1) {
            front = 0;
        }
        rear = (rear + 1) % capacity;
        arr[rear] = value;
        count++;
    }

    ll dequeue() {
        if (count == 0) {
            cout << "Queue is empty" << endl;
            return 0;
        }
        ll value = arr[front];
        front = (front + 1) % capacity;
        count--;
        if (count == 0) {
            front = -1;
            rear = -1;
        }
        return value;
    }

    void printQueue() {
        if (count == 0) {
            cout << "Queue is empty" << endl;
            return;
        }
        ll i = front;
        do {
            cout << arr[i] << " ";
            i = (i + 1) % capacity;
        } while (i != (rear + 1) % capacity);
        cout << endl;
    }

    void copyQueue() {
        CircularQueue copy(capacity);
        ll i = front;
        while (i != (rear + 1) % capacity) {
            copy.enqueue(arr[i]);
            i = (i + 1) % capacity;
        }
        cout << "Original Queue: ";
        printQueue();
        cout << "Copied Queue: ";
        copy.printQueue();
    }
};

int main() {
    CircularQueue *queue = nullptr;
    ll choice, size, value;

    do {
        cout << "\n###### MENU ######" << endl;
        cout << "1. Create Queue" << endl;
        cout << "2. Enqueue Value" << endl;
        cout << "3. Dequeue Value" << endl;
        cout << "4. Print Queue" << endl;
        cout << "5. Copy Queue" << endl;
        cout << "6. Exit" << endl;
        cout << "Enter Choice: ";
        cin >> choice;

        switch (choice) {
            case 1:
                if (queue != nullptr) {
                    delete queue;
                }
                cout << "Enter size of queue: ";
                cin >> size;
                queue = new CircularQueue(size);
                break;
            case 2:
                if (queue == nullptr) {
                    cout << "Create a queue first!" << endl;
                    break;
                }
                cout << "Enter value: ";
                cin >> value;
                queue->enqueue(value);
                break;
            case 3:
                if (queue == nullptr) {
                    cout << "Create a queue first!" << endl;
                    break;
                }
                value = queue->dequeue();
                if (value != 0) {
                    cout << "Dequeued: " << value << endl;
                }
                break;
            case 4:
                if (queue == nullptr) {
                    cout << "Create a queue first!" << endl;
                    break;
                }
                queue->printQueue();
                break;
            case 5:
                if (queue == nullptr) {
                    cout << "Create a queue first!" << endl;
                    break;
                }
                queue->copyQueue();
                break;
            case 6:
                cout << "Exiting..." << endl;
                break;
            default:
                cout << "Invalid choice, please try again." << endl;
        }
    } while (choice != 6);

    if (queue != nullptr) {
        delete queue;
    }

    return 0;
}
