#include <vector>
#include <algorithm>

class Solution {
public:
    int bs(int val, int low, std::vector<std::vector<int>>& offers) {
        int high = offers.size() - 1;
        while (low <= high) {
            int mid = low + (high - low) / 2;
            if (offers[mid][0] > val) {
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        return low;
    }

    int solve(int ind, std::vector<std::vector<int>>& offers, std::vector<int>& dp) {
        int m = offers.size();
        if (ind == m) return 0;
        if (dp[ind] != -1) return dp[ind];
        int notTake = solve(ind + 1, offers, dp);
        int nextPos = bs(offers[ind][1], ind, offers);
        int take = offers[ind][2] + solve(nextPos, offers, dp);
        return dp[ind] = std::max(take, notTake);
    }

    int maximizeTheProfit(int n, std::vector<std::vector<int>>& offers) {
        int m = offers.size();
        std::vector<int> dp(m, -1);
        std::sort(offers.begin(), offers.end());
        return solve(0, offers, dp);
    }
};

// Test cases
int main() {
    Solution sol;

    // Test case 1
    std::vector<std::vector<int>> offers1 = {{1, 3, 50}, {6, 9, 70}, {2, 5, 60}};
    int n1 = 3;
    std::cout << "Test case 1 - Expected: 120, Got: " << sol.maximizeTheProfit(n1, offers1) << std::endl;

