// Define the OMPLStateExtractor type as a pointer to a function that takes a const ompl::base::State* and returns an Eigen::VectorXd
typedef Eigen::VectorXd (*OMPLStateExtractor)(const ompl::base::State*);

namespace tesseract_motion_planners
{
    // Function to extract RealVectorStateSpace state into an Eigen::VectorXd
    Eigen::VectorXd RealVectorStateSpaceExtractor(const ompl::base::State* s1)
    {
        assert(dynamic_cast<const ompl::base::RealVectorStateSpace::StateType*>(s1) != nullptr);
        const auto* s = s1->as<ompl::base::RealVectorStateSpace::StateType>();
        return Eigen::Map<Eigen::VectorXd>(s->values, s1->as<ompl::base::RealVectorStateSpace::StateType>()->space_->getDimension());
    }

    // Function to convert an OMPL path into a trajectory array
    Eigen::MatrixXd toTrajArray(const ompl::geometric::PathGeometric& path, OMPLStateExtractor extractor)
    {
        const auto n_points = static_cast<long>(path.getStateCount());
        const auto dof = static_cast<long>(path.getSpaceInformation()->getStateDimension());

        Eigen::MatrixXd result(n_points, dof);
        for (long i = 0; i < n_points; ++i)
            result.row(i) = extractor(path.getState(static_cast<unsigned>(i)));

        return result;
    }
}  // namespace tesseract_motion_planners

int main()
{
    // Create a 2D real vector state space
    auto space(std::make_shared<ompl::base::RealVectorStateSpace>(2));

    // Define bounds for the state space
    ompl::base::RealVectorBounds bounds(2);
    bounds.setLow(0);
    bounds.setHigh(1);

    // Set the bounds for the state space
    space->setBounds(bounds);

    // Create a simple path with two points in the state space
    ompl::geometric::PathGeometric path(space);
    ompl::base::ScopedState<> state(space);
    state->as<ompl::base::RealVectorStateSpace::StateType>()->values[0] = 0.1;
    state->as<ompl::base::RealVectorStateSpace::StateType>()->values[1] = 0.2;
