using namespace std;

/**
 * Merges two sorted arrays and finds the median of the combined array.
 * 
 * @param arr1 The first sorted array.
 * @param n The number of elements in the first array.
 * @param arr2 The second sorted array.
 * @param m The number of elements in the second array.
 * @return The median of the combined sorted array.
 */
double findMedianSortedArrays(const vector<int>& arr1, const vector<int>& arr2) {
    vector<int> mergedArray;
    mergedArray.reserve(arr1.size() + arr2.size());
    merge(arr1.begin(), arr1.end(), arr2.begin(), arr2.end(), back_inserter(mergedArray));

    int totalSize = mergedArray.size();
    if (totalSize % 2 == 0) {
        return (mergedArray[totalSize / 2 - 1] + mergedArray[totalSize / 2]) / 2.0;
    } else {
        return mergedArray[totalSize / 2];
    }
}

int main() {
    int n, m, input;
    vector<int> arr1, arr2;

    // Read the size and elements of the first array
    cin >> n;
    for (int i = 0; i < n; ++i) {
        cin >> input;
        arr1.push_back(input);
    }

    // Read the size and elements of the second array
    cin >> m;
    for (int i = 0; i < m; ++i) {
        cin >> input;
        arr2.push_back(input);
    }

    // Find and print the median
    double median = findMedianSortedArrays(arr1, arr2);
    cout << median << endl;

    return 0;
}

// Test cases to verify the solution correctness
int main() {
    // Test case 1
