class TwoSumFinder {
public:
    /**
     * Finds two numbers in the given vector that add up to the target.
     * @param numbers A vector of integers.
     * @param target The target sum.
     * @return A vector containing the indices of the two numbers adding up to the target.
     */
    vector<int> findTwoSum(vector<int> &numbers, int target) {
        unordered_map<int, int> hash;
        vector<int> result;
        for (int i = 0; i < numbers.size(); i++) {
            int numberToFind = target - numbers[i];
            if (hash.find(numberToFind) != hash.end()) {
                result.push_back(hash[numberToFind]);
                result.push_back(i);
                return result;
            }
            hash[numbers[i]] = i;
        }
        return result;
    }
};

int main() {
    // Test cases
    TwoSumFinder finder;
    vector<int> numbers1 = {2, 7, 11, 15};
    int target1 = 9;
    vector<int> result1 = finder.findTwoSum(numbers1, target1);
