class Simulation {
private:
    std::vector<double> EarthPos;
    std::vector<double> MoonPos;

public:
    Simulation() {
        initialize_positions();
    }

    void initialize_positions() {
        EarthPos = std::vector<double>(3, 0.0);
        MoonPos = std::vector<double>(3, 0.0);
    }

    void update_positions(double time_step) {
        // Earth moves along the x-axis
        EarthPos[0] += 1.0 * time_step;
        // Moon moves along the y-axis
        MoonPos[1] += 2.0 * time_step;
    }

    void reset_positions() {
        for (int i = 0; i < 3; i++) {
            EarthPos[i] = 0.0;
            MoonPos[i] = 0.0;
        }
    }

    void print_earth_position() {
        std::cout << "Earth's position: ";
        for (int i = 0; i < 3; i++) {
            std::cout << EarthPos.at(i) << ",";
        }
        std::cout << std::endl;
    }

    void print_moon_position() {
        std::cout << "Moon's position: ";
        for (int i = 0; i < 3; i++) {
            std::cout << MoonPos.at(i) << ",";
        }
        std::cout << std::endl;
    }
};

int main() {
    try {
        Simulation sim;
        sim.print_earth_position();
        sim.print_moon_position();

        sim.update_positions(1.0);
        std::cout << "After updating positions with a time step of 1.0:" << std::endl;
        sim.print_earth_position();
        sim.print_moon_position();

        sim.reset_positions();
        std::cout << "After resetting positions:" << std::endl;
        sim.print_earth_position();
        sim.print_moon_position();
    } catch (const std::exception& e) {
        std::cerr << "An error occurred: " << e.what() << std::endl;
    }

    return 0;
