/**
 * Finds the smallest length of a number composed only of the digit '1'
 * that is divisible by a given integer k. If k is divisible by 2 or 5,
 * or if such a number does not exist, the function returns -1.
 * 
 * @param k The integer to check divisibility against.
 * @return The length of the smallest number composed of '1's divisible by k, or -1 if not possible.
 */
int lengthOfNumber(int k) {
    if (k % 2 == 0 || k % 5 == 0) {
        return -1;
    }
    long long int n = 0;
    for (int i = 1; i <= k; i++) {
        n = ((n * 10) + 1) % k;
        if (n == 0) {
            return i;
        }
    }
    return -1;
}

