using namespace std;

class ArrayBalancer {
public:
    vector<int> arr;
    int sum = 0;

    void readAndPrepare() {
        int size;
        cin >> size;
        arr.resize(size);
        for (int i = 0; i < size; i++) {
            cin >> arr[i];
            sum += arr[i];
        }
        sort(arr.begin(), arr.end());
    }
};

int minSwapsToBalance(ArrayBalancer& a, ArrayBalancer& b) {
    if ((a.sum + b.sum) % 2 != 0) return -1; // Cannot balance if total sum is odd

    int target = (a.sum + b.sum) / 2;
    int swaps = 0;
    int i = 0, j = b.arr.size() - 1;

    while (a.sum != target && i < a.arr.size() && j >= 0) {
        int diff = min(b.arr[j] - a.arr[i], target - a.sum);
        a.sum += diff;
        b.sum -= diff;
        if (diff == b.arr[j] - a.arr[i]) {
            i++;
            j--;
        }
        swaps++;
    }

    return a.sum == target ? swaps : -1;
}

int main() {
    int t;
    cin >> t;
    vector<int> results(t);

    for (int i = 0; i < t; i++) {
        ArrayBalancer a, b;
        a.readAndPrepare();
        b.readAndPrepare();
        results[i] = minSwapsToBalance(a, b);
    }

    for (int result : results) {
        cout << result << endl;
    }

    return 0;
}
