/**
 * Swaps two integer values without using a third variable.
 * The function takes two integer references as input and swaps their values using arithmetic operations.
 * 
 * @param a Reference to the first integer.
 * @param b Reference to the second integer.
 */
void swapWithoutTemp(int &a, int &b) {
    a = a + b; // a now contains the sum of a and b
    b = a - b; // b becomes the original value of a
    a = a - b; // a becomes the original value of b
}

int main() {
    int a, b;
    cout << "Enter A: ";
    cin >> a;
    cout << "Enter B: ";
    cin >> b;

