class CharStack
{
    char stck[SIZE];
    int tos;

public:
    CharStack();
    void Push(char ch);
    char Pop();
    bool IsEmpty();
    bool IsFull();
    char Top();
};

CharStack::CharStack()
{
    tos = 0;
}

void CharStack::Push(char ch)
{
    if(IsFull()){
        cout << "Stack is full\n";
        return;
    }
    stck[tos] = ch;
    tos++;
}

char CharStack::Pop()
{
    if(IsEmpty()){
        cout << "Stack is empty\n";
        return '\0';
    }
    tos--;
    return stck[tos];
}

bool CharStack::IsEmpty()
{
    return tos == 0;
}

bool CharStack::IsFull()
{
    return tos == SIZE;
}

char CharStack::Top()
{
    if(IsEmpty()){
        return '\0';
    }
    return stck[tos - 1];
}

int main()
{
    CharStack s1;

    // Pushing characters 'a' to 'z' onto the stack
    for(char c = 'a'; c <= 'z'; c++)
        s1.Push(c);

    // Attempting to push another character onto the full stack
    s1.Push('!');

    // Popping all characters from the stack and printing them
    while(!s1.IsEmpty())
        cout << s1.Pop() << "\n";

    // Attempting to pop a character from the empty stack
    s1.Pop();

    // Checking if the stack is empty after all pops
    cout << (s1.IsEmpty() ? "Stack is empty" : "Stack is not empty") << endl;

    return 0;
}
