class Solution {
public:
    bool halvesAreAlike(std::string s) 
    {
        int cnt = 0;

        // Convert the entire string to lowercase
        for(int i = 0 ; i < s.size() ; i++) s[i] = std::tolower(s[i]);

        // Count vowels in the first half
        for(int i = 0 ; i < s.size() / 2 ; i++)
            if(s[i]=='e'||s[i]=='a'||s[i]=='u'||s[i]=='i'||s[i]=='o') cnt++;

        // Subtract the count of vowels in the second half
        for(int i = s.size() / 2 ; i < s.size() ; i++)
            if(s[i]=='e'||s[i]=='a'||s[i]=='u'||s[i]=='i'||s[i]=='o') cnt--;

        // If the count is zero, both halves have the same number of vowels
        return (cnt == 0);
    }
};

// Test cases
