#include <iostream>
using namespace std;
typedef long long ll;

/**
 * Determines if there exists a pair of non-negative integers (x, y) such that
 * x + y = a and x XOR y = s. Outputs "YES" followed by the values of x and y
 * if such a pair exists, otherwise outputs "NO".
 *
 * @param a The sum of the pair of integers.
 * @param s The XOR of the pair of integers.
 */
void solve(ll a, ll s) {
    ll x = 0, y = 0;
    for (ll i = 0; i < 60; ++i) {
        ll bit_a = (a >> i) & 1;
        ll bit_s = (s >> i) & 1;
        if (bit_a == 0 && bit_s == 1) {
            // Impossible to satisfy both conditions
            cout << "NO" << endl;
            return;
        } else if (bit_a == 1 && bit_s == 1) {
            // Set the i-th bit of both x and y to 1
            x |= (1LL << i);
            y |= (1LL << i);
        } else if (bit_a == 1 && bit_s == 0) {
            // Set the i-th bit of x to 1 and y to 0 (or vice versa)
            x |= (1LL << i);
        }
        // If bit_a == 0 and bit_s == 0, do nothing as both bits are already 0
    }
    cout << "YES" << endl << x << " " << y << endl;
}

int main() {
    ll t;
    cin >> t;
    while (t--) {
        ll a, s;
        cin >> a >> s;
        solve(a, s);
    }
    return 0;
}
