#include <iostream>
#include <vector>
#include <algorithm>

using namespace std;

class Solution {
public:
    int func(vector<int> &nums, int i, vector<int> &dp) {
        if (i >= nums.size())
            return 0;

        int currValue = nums[i];
        int currSum = nums[i];
        int index = i + 1;

        if (dp[i] != -1)
            return dp[i];

        while (index < nums.size() && nums[index] == currValue) {
            currSum += nums[index];
            index++;
        }

        while (index < nums.size() && nums[index] == currValue + 1)
            index++;

        return dp[i] = max(currSum + func(nums, index, dp), func(nums, i + 1, dp));
    }

    int deleteAndEarn(vector<int>& nums) {
        int n = nums.size();
        vector<int> dp(n, -1);

        sort(nums.begin(), nums.end());

        return func(nums, 0, dp);
    }
};

int main() {
    // Test cases
    Solution solution;
    vector<int> nums1{3, 4, 2};
    cout << "Test Case 1: " << solution.deleteAndEarn(nums1) << endl; // Expected output: 6

    vector<int> nums2{2, 2, 3, 3, 3, 4};
    cout << "Test Case 2: " << solution.deleteAndEarn(nums2) << endl; // Expected output: 9

    vector<int> nums3{1};
    cout << "Test Case 3: " << solution.deleteAndEarn(nums3) << endl; // Expected output: 1

    return 0;
}
