using namespace std;

#define MAXN 200005

int adj[MAXN]; // Array to store the child of each node
bool visited[MAXN]; // Array to mark visited nodes

bool isValidSingleChildTree(int n) {
    for (int i = 0; i < n; ++i) {
        if (visited[i] && adj[i] != -1) {
            // If a node is visited and has a child, it's not a single-child tree
            return false;
        }
        visited[i] = true; // Mark the node as visited
    }
    return true;
}

int main() {
    int n, a, b;
    cin >> n;

    // Initialize arrays
    fill(adj, adj + n, -1);
    fill(visited, visited + n, false);

    for (int i = 0; i < n - 1; i++) {
        cin >> a >> b;
        if (adj[a] != -1) {
            // If node 'a' already has a child, it's not a single-child tree
            cout << "NO" << endl;
            return 0;
        }
        adj[a] = b; // Set node 'b' as the child of node 'a'
    }

    // Check if the tree is a valid single-child tree
    if (isValidSingleChildTree(n)) {
        cout << "YES" << endl;
    } else {
        cout << "NO" << endl;
    }

    return 0;
}
