    DirectXCommon* dxCommon = new DirectXCommon();
    dxCommon->Initialize(winApp);

    Input* input = new Input();
    input->Initialize(winApp);

    SpriteCommon* spriteCommon = new SpriteCommon;
    spriteCommon->Initialize(dxCommon);
    spriteCommon->LoadTexture(0, "texture.png");

    Object3d::StaticInitialize(dxCommon->GetDevice(), WinApp::window_width, WinApp::window_height);

    // Initialize the first scene
    Sprite* sprite = new Sprite();
    sprite->Initialize(spriteCommon, 0);

    // Game loop
    while (true) {
        // Process messages
        if (winApp->ProcessMessage()) {
            break;
        }

        // Update input
        input->Update();

        // Move sprite with arrow keys
        XMFLOAT2 position = sprite->GetPosition();
        if (input->PushKey(DIK_LEFT)) {
            position.x -= 1.0f;
        }
        if (input->PushKey(DIK_RIGHT)) {
            position.x += 1.0f;
        }
        if (input->PushKey(DIK_UP)) {
            position.y -= 1.0f;
        }
        if (input->PushKey(DIK_DOWN)) {
            position.y += 1.0f;
        }

        // Jump with spacebar
        static bool isJumping = false;
        static float jumpVelocity = 0.0f;
        if (input->TriggerKey(DIK_SPACE) && !isJumping) {
            isJumping = true;
            jumpVelocity = -10.0f;
        }
        if (isJumping) {
            position.y += jumpVelocity;
            jumpVelocity += 0.5f; // Gravity effect
            if (position.y >= WinApp::window_height - sprite->GetSize().y) {
                position.y = WinApp::window_height - sprite->GetSize().y;
                isJumping = false;
            }
        }

        // Toggle invisibility with 'A' key
        bool isInvisible = sprite->GetInvisible();
        if (input->TriggerKey(DIK_A)) {
            isInvisible = !isInvisible;
        }
        sprite->SetIsInvisible(isInvisible);

        // Prevent sprite from moving outside the window boundaries
        position.x = max(0.0f, min(position.x, WinApp::window_width - sprite->GetSize().x));
        position.y = max(0.0f, min(position.y, WinApp::window_height - sprite->GetSize().y));
        sprite->SetPosition(position);

        // Update sprite
        sprite->Update();

        // Pre-draw
        dxCommon->PreDraw();

        // Draw the first scene
        spriteCommon->PreDraw();
        sprite->Draw();

        // Post-draw
        dxCommon->PostDraw();
    }

    // Clean up
    delete sprite;
    delete dxCommon;
    delete spriteCommon;
    winApp->Finalize();
    delete winApp;

    return 0;
}
