#include <iostream>
using namespace std;

/**
 * Calculates the number of different sequences of N bus stops that can be chosen from M bus stops.
 * Each bus line serves a different stop and no bus line serves more than one stop in the sequence.
 * 
 * @param N The number of bus stops to choose.
 * @param M The total number of bus stops available.
 * @return The number of different sequences of N bus stops.
 */
long long calculateBusStopSequences(int N, int M) {
    long long sum = 1, t = 1;
    for (int i = M + N - 1; i > M; i--)
        sum *= i;
    for (int i = N - 1; i >= 1; i--)
        t *= i;
    return sum / t;
}

int main(void) {
