```cpp
#include <climits> // For LONG_MIN and LONG_MAX
#include <iostream> // For std::cout

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
private:
    bool checkBST(TreeNode* root, long a, long b) {
        if (root == NULL) {
            return true;
        }
        if (root->val <= a || root->val >= b) {
            return false;
        }
        bool leftIsValid = checkBST(root->left, a, root->val);
        bool rightIsValid = checkBST(root->right, root->val, b);
        return leftIsValid && rightIsValid;
    }

public:
    bool isValidBST(TreeNode* root) {
        return checkBST(root, LONG_MIN, LONG_MAX);
    }
};

// Helper function to create a new TreeNode
TreeNode* newNode(int value) {
    return new TreeNode(value);
}

// Test cases
int main() {
    Solution solution;

    // Test case 1: The tree is a valid BST
    TreeNode* root1 = newNode(2);
    root1->left = newNode(1);
    root1->right = newNode(3);
    std::cout << "Test case 1 - Expected: true, Actual: " << solution.isValidBST(root1) << std::endl;

    // Test case 2: The tree is not a valid BST because 4 is in the left subtree of 3
    TreeNode* root2 = newNode(3);
    root2->left = newNode(2);
    root2->left->left = newNode(1);
    root2->left->right = newNode(4);
    std::cout << "Test case 2 - Expected: false, Actual: " << solution.isValidBST(root2) << std::endl;

    // Test case 3: The tree is not a valid BST because 0 is in the right subtree of 1
    TreeNode* root3 = newNode(1);
    root3->left = newNode(0);
    root3->right = newNode(2);
    root3->left->right = newNode(3);
    std::cout << "Test case 3 - Expected: false, Actual: " << solution.isValidBST(root3) << std::endl;

    // Clean up allocated memory
    delete root1->left;
    delete root1->right;
    delete root1;
    delete root2->left->left;
    delete root2->left->right;
    delete root2->left;
    delete root2;
    delete root3->left->right;
    delete root3->left;
    delete root3->right;
    delete root3;

    return 0;
}
