#include <vector>
#include <algorithm>
#include <functional>
#include <cmath>

// Assuming SIGNAL_MAX and other constants are defined elsewhere
constexpr unsigned SIGNAL_MAX = 255;

struct Coordinate {
  int16_t x;
  int16_t y;
};

class Layer {
public:
  Layer(uint16_t sizeX, uint16_t sizeY) : pheromones(sizeX, std::vector<uint8_t>(sizeY, 0)) {}

  std::vector<std::vector<uint8_t>> pheromones;
};

class ParameterManager {
public:
  static ParameterManager& getInstance() {
    static ParameterManager instance;
    return instance;
  }

  int16_t gridSize_X;
  int16_t gridSize_Y;

private:
  ParameterManager() {} // Constructor is private for singleton
};

class Signals {
public:
  void initialize(uint16_t numLayers, uint16_t sizeX, uint16_t sizeY);
  void increment(uint16_t layerNum, Coordinate loc);
  void fade(unsigned layerNum);

private:
  std::vector<Layer> data;
  ParameterManager& parameterMngrSingleton = ParameterManager::getInstance();

  void visitNeighborhood(Coordinate loc, float radius, std::function<void(Coordinate)> func);
};

void Signals::initialize(uint16_t numLayers, uint16_t sizeX, uint16_t sizeY) {
  data = std::vector<Layer>(numLayers, Layer(sizeX, sizeY));
}

void Signals::increment(uint16_t layerNum, Coordinate loc) {
  constexpr float radius = 1.5;
  constexpr uint8_t centerIncreaseAmount = 2;
  constexpr uint8_t neighborIncreaseAmount = 1;

  visitNeighborhood(loc, radius, [this, layerNum](Coordinate loc) {
    if (data[layerNum].pheromones[loc.x][loc.y] < SIGNAL_MAX) {
      data[layerNum].pheromones[loc.x][loc.y] =
          std::min<unsigned>(SIGNAL_MAX, data[layerNum].pheromones[loc.x][loc.y] +
                                             neighborIncreaseAmount);
    }
  });

  if (data[layerNum].pheromones[loc.x][loc.y] < SIGNAL_MAX) {
    data[layerNum].pheromones[loc.x][loc.y] =
        std::min<unsigned>(SIGNAL_MAX, data[layerNum].pheromones[loc.x][loc.y] +
                                           centerIncreaseAmount);
  }
}

void Signals::fade(unsigned layerNum) {
  constexpr unsigned fadeAmount = 1;

  for (int16_t x = 0; x < parameterMngrSingleton.gridSize_X; ++x) {
    for (int16_t y = 0; y < parameterMngrSingleton.gridSize_Y; ++y) {
      if (data[layerNum].pheromones[x][y] >= fadeAmount) {
        data[layerNum].pheromones[x][y] -= fadeAmount;
      } else {
        data[layerNum].pheromones[x][y] = 0;
      }
    }
  }
}

void Signals::visitNeighborhood(Coordinate loc, float radius, std::function<void(Coordinate)> func) {
  int16_t startX = std::max(0, static_cast<int16_t>(loc.x - radius));
  int16_t endX = std::min(parameterMngrSingleton.gridSize_X - 1, static_cast<int16_t>(loc.x + radius));
  int16_t startY = std::max(0, static_cast<int16_t>(loc.y - radius));
  int16_t endY = std::min(parameterMngrSingleton.gridSize_Y - 1, static_cast<int16_t>(loc.y + radius));

  for (int16_t x = startX; x <= endX; ++x) {
    for (int16_t y = startY; y <= endY; ++y) {
      if (std::sqrt(std::pow(x - loc.x, 2) + std::pow(y - loc.y, 2)) <= radius) {
        func({x, y});
      }
    }
  }
}

// Test cases
int main() {
  Signals signals;
  signals.initialize(3, 10, 10); // Initialize with 3 layers of 10x10 grid

  // Increment pheromone levels at a specific location
  signals.increment(0, {5, 5});
  signals.increment(1, {3, 3});

  // Fade pheromone levels across the entire layer
  signals.fade(0);
  signals.fade(1);

  // Additional test cases and validation of pheromone levels can be added here

  return 0;
}
