 */
int countRecordBreaks(const vector<int>& performances) {
    if (performances.empty()) return 0;

    int maxP = performances[0], minP = performances[0], cnt = 0;
    for (size_t i = 1; i < performances.size(); ++i) {
        if (performances[i] > maxP) {
            maxP = performances[i];
            cnt++;
