#include <iostream>
#include <vector>
#include <algorithm>
#include <climits>
using namespace std;

class Solution {
public:
    /**
     * Finds three integers in nums such that the sum is closest to the target.
     * @param nums A vector of integers.
     * @param target The target sum.
     * @return The sum of the three integers closest to the target.
     */
    int threeSumClosest(vector<int>& nums, int target) {
        int ret = -1, diff = INT_MAX;
        sort(nums.begin(), nums.end());
        for (int base = 0; base < nums.size() - 2; ++base) {
            int left = base + 1, right = nums.size() - 1;
            while (left < right) {
                int cur = nums[base] + nums[left] + nums[right];
                int cur_diff = cur - target;
                if (cur_diff == 0) return target;
                if (abs(cur_diff) < diff) {
                    diff = abs(cur_diff);
                    ret = cur;
                }
                if (cur_diff < 0) ++left;
                else --right;
            }
        }
        return ret;
    }
};

int main() {
    // Test cases
    Solution test;
    vector<int> in1 = {-1, 2, 1, -4};
    cout << "Test Case 1: " << test.threeSumClosest(in1, 1) << endl; // Expected output: 2

    vector<int> in2 = {0, 0, 0};
    cout << "Test Case 2: " << test.threeSumClosest(in2, 1) << endl; // Expected output: 0

    vector<int> in3 = {1, 1, -1, -1, 3};
    cout << "Test Case 3: " << test.threeSumClosest(in3, -1) << endl; // Expected output: -1

    vector<int> in4 = {1, 1, 1, 0};
    cout << "Test Case 4: " << test.threeSumClosest(in4, 100) << endl; // Expected output: 3

    return 0;
}
