using namespace std;

class Solution {
public:
    /**
     * Merges a list of possibly overlapping intervals.
     * 
     * @param intervals A vector of vector of integers representing the intervals.
     * @return A vector of vector of integers with no overlapping intervals.
     */
    vector<vector<int>> merge(vector<vector<int>>& intervals) {
        vector<vector<int>> mergedIntervals;

        // Sort the intervals based on the start time.
        sort(intervals.begin(), intervals.end());

        for (const auto& interval : intervals) {
            // If the list of merged intervals is empty or if the current interval
            // does not overlap with the previous, simply append it.
            if (mergedIntervals.empty() || mergedIntervals.back()[1] < interval[0]) {
                mergedIntervals.push_back(interval);
            } else {
                // Otherwise, there is overlap, so we merge the current and previous intervals.
                mergedIntervals.back()[1] = max(mergedIntervals.back()[1], interval[1]);
            }
        }

        return mergedIntervals;
    }
};

