using namespace std;
typedef long long ll;

vector<bool> sieve(ll max_limit) {
    vector<bool> is_prime(max_limit + 1, true);
    is_prime[0] = is_prime[1] = false;
    for (ll i = 2; i * i <= max_limit; ++i) {
        if (is_prime[i]) {
            for (ll j = i * i; j <= max_limit; j += i) {
                is_prime[j] = false;
            }
        }
    }
    return is_prime;
}

bool isSquareOfPrime(ll n, const vector<bool>& is_prime) {
    ll root = sqrt(n);
    return root * root == n && is_prime[root];
}

int main() {
    ll t, n;
    cin >> t;
    vector<bool> is_prime = sieve(1000000); // Precompute primes up to 1,000,000.
    while (t--) {
        cin >> n;
        cout << (isSquareOfPrime(n, is_prime) ? "YES" : "NO") << endl;
    }
    return 0;
}
