class Serializer {
public:
    static std::vector<uint8_t> serialize(const ActuatorControls2& message) {
        std::vector<uint8_t> buffer(sizeof(message));
        std::memcpy(buffer.data(), &message, sizeof(message));
        return buffer;
    }

    static ActuatorControls2 deserialize(const std::vector<uint8_t>& buffer) {
        if (buffer.size() != sizeof(ActuatorControls2)) {
            throw std::runtime_error("Invalid buffer size for deserialization");
        }
        ActuatorControls2 message;
        std::memcpy(&message, buffer.data(), sizeof(message));
        return message;
    }

    static size_t get_serialized_size(const ActuatorControls2& /* message */) {
        return sizeof(ActuatorControls2);
    }
};

void test_serialization() {
    ActuatorControls2 original_message;
    original_message.timestamp = 123456789;
    original_message.timestamp_sample = 987654321;
    for (int i = 0; i < 8; ++i) {
        original_message.control[i] = static_cast<float>(i);
    }

    // Serialize
    std::vector<uint8_t> serialized_data = Serializer::serialize(original_message);

    // Deserialize
    ActuatorControls2 deserialized_message = Serializer::deserialize(serialized_data);

    // Verify
    assert(original_message.timestamp == deserialized_message.timestamp);
    assert(original_message.timestamp_sample == deserialized_message.timestamp_sample);
    for (int i = 0; i < 8; ++i) {
