using namespace std;

/**
 * Calculates the value of the piecewise function f(x) based on the input value of x.
 * The function is defined as follows:
 * f(x) = 2x^2 - 3, if x > 7
 * f(x) = 0, if x = 7
 * f(x) = 2 * |x| + 3, if x < 7
 *
 * @param x The input value for which the function f(x) is to be calculated.
 * @return The calculated value of f(x).
 */
float calculateFunction(float x) {
    if (x > 7) {
        return 2 * x * x - 3;
    } else if (x == 7) {
        return 0;
    } else {
        return 2 * abs(x) + 3;
    }
}

int main() {
    float x;
    cout << "Enter a value for x: ";
    if (!(cin >> x)) {
        cout << "Invalid input" << endl;
        return 1;
    }

