#include <bits/stdc++.h>
using namespace std;

// Tree Node
struct Node {
  int data;
  Node *left;
  Node *right;
};

// Utility function to create a new Tree Node
Node *newNode(int val) {
  Node *temp = new Node;
  temp->data = val;
  temp->left = NULL;
  temp->right = NULL;
  return temp;
}

// } Driver Code Ends

class Solution {
public:
  // Function to return list containing elements of bottom view of binary tree.
  vector<int> bottomView(Node *root) {
    vector<int> ans;
    if (!root) return ans;

    map<int, int> distanceMap; // Maps horizontal distance to node value
    queue<pair<Node*, int>> Q; // Queue to store nodes and their horizontal distance
    Q.push({root, 0});

    while (!Q.empty()) {
      auto p = Q.front();
      Q.pop();
      Node *node = p.first;
      int hd = p.second;
      distanceMap[hd] = node->data; // Update the distance map with the most recent node at that horizontal distance

      if (node->left) Q.push({node->left, hd - 1});
      if (node->right) Q.push({node->right, hd + 1});
    }

    for (auto it : distanceMap) {
      ans.push_back(it.second);
    }
    return ans;
  }
};

//{ Driver Code Starts.

// Function to Build Tree
Node *buildTree(string str) {
  // Corner Case
  if (str.length() == 0 || str[0] == 'N')
    return NULL;

  // Creating vector of strings from input
  // string after spliting by space
  vector<string> ip;

  istringstream iss(str);
  for (string str; iss >> str;)
    ip.push_back(str);

  // Create the root of the tree
  Node *root = newNode(stoi(ip[0]));

  // Push the root to the queue
  queue<Node *> queue;
  queue.push(root);

  // Starting from the second element
  int i = 1;
  while (!queue.empty() && i < ip.size()) {
    // Get and remove the front of the queue
    Node *currNode = queue.front();
    queue.pop();

    // Get the current node's value from the string
    string currVal = ip[i];

    // If the left child is not null
    if (currVal != "N") {
      // Create the left child for the current node
      currNode->left = newNode(stoi(currVal));

      // Push it to the queue
      queue.push(currNode->left);
    }

    // For the right child
    i++;
    if (i >= ip.size())
      break;
    currVal = ip[i];

    // If the right child is not null
    if (currVal != "N") {
      // Create the right child for the current node
      currNode->right = newNode(stoi(currVal));

      // Push it to the queue
      queue.push(currNode->right);
    }
    i++;
  }

  return root;
}

int main() {
  int t;
  string tc;
  getline(cin, tc);
  t = stoi(tc);
  while (t--) {
    string s;
    getline(cin, s);
    Node *root = buildTree(s);

    Solution ob;
    vector<int> vec = ob.bottomView(root);
    for (int x : vec) {
      cout << x << " ";
    }
    cout << endl;
  }
  return 0;
}

// } Driver Code Ends
