/**
 * \brief InputEvent class represents a single input event.
 */
class InputEvent {
public:
    int type;
    int code;
    int value;

    InputEvent(int t, int c, int v) : type(t), code(c), value(v) {}
};

/**
 * \brief InputEventProcessor class processes raw input data into structured events.
 */
class InputEventProcessor {
public:
    /**
     * \brief Process a buffer of raw input data and convert it into a series of structured events.
     * \param rawData The buffer of raw input data.
     * \param sendNullEvents Flag to indicate whether null events should be included.
     * \return A vector of shared pointers to InputEvent objects.
     */
    std::vector<std::shared_ptr<InputEvent>> processInputData(const std::vector<int>& rawData, bool sendNullEvents) {
        std::vector<std::shared_ptr<InputEvent>> events;
        for (size_t i = 0; i < rawData.size(); i += 3) {
            int type = rawData[i];
            int code = rawData[i + 1];
            int value = rawData[i + 2];

            if (!sendNullEvents && type == 0 && code == 0 && value == 0) {
                continue;
            }

            events.push_back(std::make_shared<InputEvent>(type, code, value));
        }
        return events;
    }
};

int main() {
    // Example raw input data buffer (type, code, value)
    std::vector<int> rawData = {1, 100, 1, 0, 0, 0, 1, 101, 0};

    // Process the raw input data
    InputEventProcessor processor;
    bool sendNullEvents = false; // Change to true if null events should be included
    std::vector<std::shared_ptr<InputEvent>> events = processor.processInputData(rawData, sendNullEvents);

    // Output the processed events
    for (const auto& event : events) {
        std::cout << "Event - Type: " << event->type << ", Code: " << event->code << ", Value: " << event->value << std::endl;
    }

    return 0;
}
