bool areBuddyStrings(const string& A, const string& B) {
    if (A.size() != B.size() || A.size() < 2) return false;

    vector<int> diff;
    vector<bool> charExists(26, false);
    bool hasRepeat = false;

    for (size_t i = 0; i < A.size(); ++i) {
        if (A[i] != B[i]) {
            diff.push_back(i);
        }
        if (charExists[A[i] - 'a']) {
            hasRepeat = true;
        } else {
            charExists[A[i] - 'a'] = true;
        }
    }

    if (diff.size() == 0) {
        return hasRepeat;
    }

    if (diff.size() == 2) {
        return A[diff[0]] == B[diff[1]] && A[diff[1]] == B[diff[0]];
    }

    return false;
}

