// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    int res = 0;

    /**
     * Helper function to perform DFS on the binary tree and find the longest ZigZag path.
     * 
     * @param root The root node of the current subtree.
     * @return A pair of integers where the first element is the length of the longest ZigZag path
     *         starting with a left child and the second element is the length of the longest ZigZag
     *         path starting with a right child.
     */
    pair<int,int> dfs(TreeNode* root) {
        if (root == NULL) {
            return {0,0};
        }

        pair<int,int> a = dfs(root->left), b = dfs(root->right);
        res = max(1+a.second, res);
        res = max(1+b.first, res);
        return {1+a.second, 1+b.first};
    }

    /**
     * Finds the length of the longest ZigZag path in the binary tree.
     * 
     * @param root The root node of the binary tree.
     * @return The length of the longest ZigZag path.
     */
    int longestZigZag(TreeNode* root) {
        dfs(root);
        return res-1;
    }
};

// Test cases
int main() {
    Solution solution;
    TreeNode *root = new TreeNode(1);
    root->left = new TreeNode(2);
    root->right = new TreeNode(3);
    root->left->right = new TreeNode(4);
    root->left->right->left = new TreeNode(5);
    root->left->right->left->right = new TreeNode(6);

    cout << "The length of the longest ZigZag path is: " << solution.longestZigZag(root) << endl; // Expected output: 3

    // Clean up allocated nodes
    delete root->left->right->left->right;
    delete root->left->right->left;
    delete root->left->right;
