#include <iostream>
#include <string>
#include <vector>
#include <algorithm>

// Function to compute the minimum number of operations required to convert str1 to str2
int editDistance(const std::string& str1, const std::string& str2) {
    int m = str1.size();
    int n = str2.size();
    std::vector<std::vector<int>> dp(m + 1, std::vector<int>(n + 1));

    // Initialize the base cases
    for (int i = 0; i <= m; i++) {
        dp[i][0] = i;
    }
    for (int j = 0; j <= n; j++) {
        dp[0][j] = j;
    }

    // Compute the edit distance matrix
    for (int i = 1; i <= m; i++) {
        for (int j = 1; j <= n; j++) {
            if (str1[i - 1] == str2[j - 1]) {
                dp[i][j] = dp[i - 1][j - 1];
            } else {
                dp[i][j] = 1 + std::min({dp[i - 1][j],      // Deletion
                                          dp[i][j - 1],      // Insertion
                                          dp[i - 1][j - 1]}); // Substitution
            }
        }
    }

    return dp[m][n];
}

// Main function to demonstrate the editDistance function
int main() {
    std::string str1, str2;
    std::cout << "Enter the first string: ";
    std::cin >> str1;
    std::cout << "Enter the second string: ";
    std::cin >> str2;

    int result = editDistance(str1, str2);
    std::cout << "The minimum number of operations required to convert \"" << str1
              << "\" to \"" << str2 << "\" is " << result << "." << std::endl;

    return 0;
}
