#include <unordered_set>
#include <memory>

class HttpsEnforcer {
public:
    HttpsEnforcer() = default;
    ~HttpsEnforcer() = default;

    // Upgrades an HTTP URL to HTTPS if it is not already using HTTPS.
    std::string UpgradeToHttps(const std::string& url) {
        if (IsHttps(url)) {
            return url;
        }
        return "https://" + url.substr(7); // Assuming 'http://' is 7 characters.
    }

    // Checks if the given URL is already using HTTPS.
    bool IsHttps(const std::string& url) {
        return url.find("https://") == 0;
    }

    // Handles fallback to HTTP if HTTPS request fails and records the hostname.
    std::string FallbackToHttp(const std::string& url) {
        std::string hostname = ExtractHostname(url);
        allowed_http_hosts_.insert(hostname);
        return "http://" + url.substr(8); // Assuming 'https://' is 8 characters.
    }

    // Checks if HTTP traffic is allowed for a specific hostname.
    bool IsHttpAllowedForHost(const std::string& hostname) {
        return allowed_http_hosts_.find(hostname) != allowed_http_hosts_.end();
    }

private:
    // Extracts the hostname from a URL.
    std::string ExtractHostname(const std::string& url) {
        size_t start = url.find("://") + 3;
        size_t end = url.find('/', start);
        return url.substr(start, end - start);
    }

    // A set of hostnames for which HTTP traffic has been allowed.
    std::unordered_set<std::string> allowed_http_hosts_;
};

// Test suite for HttpsEnforcer class.
void TestHttpsEnforcer() {
    HttpsEnforcer enforcer;
    std::string http_url = "http://example.com";
    std::string https_url = "https://example.com";

    // Test upgrading HTTP to HTTPS.
    std::string upgraded_url = enforcer.UpgradeToHttps(http_url);
    assert(enforcer.IsHttps(upgraded_url));

    // Test that HTTPS URLs remain unchanged.
    std::string unchanged_url = enforcer.UpgradeToHttps(https_url);
    assert(unchanged_url == https_url);

    // Test fallback to HTTP.
    std::string fallback_url = enforcer.FallbackToHttp(https_url);
    assert(!enforcer.IsHttps(fallback_url));

    // Test that HTTP is allowed for the host after fallback.
    assert(enforcer.IsHttpAllowedForHost("example.com"));

    std::cout << "All tests passed!" << std::endl;
}

int main() {
    TestHttpsEnforcer();
    return 0;
}
