void high_bit_depth_dc_predictor(uint16_t *dst, ptrdiff_t stride, const uint16_t *above, const uint16_t *left, int block_size, int bit_depth) {
    assert(dst != nullptr);
    assert(above != nullptr);
    assert(left != nullptr);
    assert(block_size > 0);
    assert(bit_depth >= 8 && bit_depth <= 12);

    const int max_pixel_value = (1 << bit_depth) - 1;
    int sum = 0;
    for (int i = 0; i < block_size; ++i) {
        sum += above[i];
        sum += left[i];
    }
    uint16_t predictor = static_cast<uint16_t>((sum + block_size) / (2 * block_size));
    predictor = std::min(predictor, static_cast<uint16_t>(max_pixel_value));

    for (int y = 0; y < block_size; ++y) {
        for (int x = 0; x < block_size; ++x) {
            dst[x + y * stride] = predictor;
        }
    }
}

// Test cases
int main() {
    const int block_size = 4;
    const int bit_depth = 10;
    const ptrdiff_t stride = block_size;
    const uint16_t above[block_size] = {512, 512, 512, 512};
    const uint16_t left[block_size] = {512, 512, 512, 512};
    uint16_t dst[block_size * block_size] = {0};

    high_bit_depth_dc_predictor(dst, stride, above, left, block_size, bit_depth);

    // Verify that all pixels in the destination block are equal to the expected predictor value
    uint16_t expected_predictor = 512;
    for (int y = 0; y < block_size; ++y) {
        for (int x = 0; x < block_size; ++x) {
            assert(dst[x + y * stride] == expected_predictor);
        }
    }

    return 0;
}
