node* mergeSortedLists(node* list1, node* list2) {
    if (list1 == NULL) {
        return list2;
    } else if (list2 == NULL) {
        return list1;
    }
    node* mergedHead = NULL;
    if (list1->data < list2->data) {
        mergedHead = list1;
        mergedHead->next = mergeSortedLists(list1->next, list2);
    } else {
        mergedHead = list2;
        mergedHead->next = mergeSortedLists(list1, list2->next);
    }
    return mergedHead;
}

// Helper function to insert a new node at the tail of the linked list
void insertAtTail(node*& head, int data) {
    node* newNode = new node(data);
    if (head == NULL) {
        head = newNode;
        return;
    }
    node* tail = head;
    while (tail->next != NULL) {
        tail = tail->next;
    }
    tail->next = newNode;
}

// Helper function to print the linked list
void printList(node* head) {
    while (head != NULL) {
        cout << head->data << " -> ";
        head = head->next;
    }
    cout << "NULL\n";
}

// Test cases to verify the solution
int main() {
    node* list1 = NULL;
    node* list2 = NULL;

    // List 1: 1 -> 3 -> 5
    insertAtTail(list1, 1);
    insertAtTail(list1, 3);
    insertAtTail(list1, 5);

    // List 2: 2 -> 4 -> 6
    insertAtTail(list2, 2);
    insertAtTail(list2, 4);
    insertAtTail(list2, 6);

    // Merge the lists
    node* mergedList = mergeSortedLists(list1, list2);

    // Expected Output: 1 -> 2 -> 3 -> 4 -> 5 -> 6 -> NULL
    printList(mergedList);

    return 0;
}
