Design a binary tree class and write a function to determine if the tree has a root-to-leaf path such that adding up all the values along the path equals the given target sum.

A binary tree is defined using the following structure:

```cpp
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
```

Implement the `Solution` class with the following methods:

- `bool hasPathSum(TreeNode* root, int targetSum)`: This method should return `true` if the tree has a root-to-leaf path such that adding up all the values along the path equals `targetSum`. Otherwise, return `false`.

A leaf is a node with no children.

output:
```cpp
#include <iostream>

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
public:
    bool hasPathSum(TreeNode* root, int targetSum) {
        if (root == NULL)
            return false;
        return hasPathSumHelper(root, targetSum);
    }

private:
    bool hasPathSumHelper(TreeNode* node, int remainingSum) {
        if (node == NULL)
            return false;

        remainingSum -= node->val;

        // Check if the current node is a leaf and its value equals the remaining sum
        if (node->left == NULL && node->right == NULL)
            return remainingSum == 0;

        // Recursively check the left and right subtrees
        return hasPathSumHelper(node->left, remainingSum) || hasPathSumHelper(node->right, remainingSum);
    }
};

// Helper function to create a new TreeNode
TreeNode* newNode(int value) {
    return new TreeNode(value);
}

// Test cases
int main() {
    // Construct binary tree
    TreeNode *root = newNode(5);
    root->left = newNode(4);
    root->right = newNode(8);
    root->left->left = newNode(11);
    root->right->left = newNode(13);
    root->right->right = newNode(4);
    root->left->left->left = newNode(7);
    root->left->left->right = newNode(2);
    root->right->right->right = newNode(1);

    Solution solution;
    bool result = solution.hasPathSum(root, 22); // Expected: true
    std::cout << "Has path sum 22: " << (result ? "true" : "false") << std::endl;

    result = solution.hasPathSum(root, 26); // Expected: true
    std::cout << "Has path sum 26: " << (result ? "true" : "false") << std::endl;

    result = solution.hasPathSum(root, 18); // Expected: false
    std::cout << "Has path sum 18: " << (result ? "true" : "false") << std::endl;

    // Clean up allocated nodes
    delete root->left->left->left;
    delete root->left->left->right;
    delete root->left->left;
    delete root->right->right->right;
    delete root->left;
    delete root->right->left;
    delete root->right->right;
    delete root->right;
    delete root;

    return 0;
}
