#include <iostream>
#include <vector>
#include <cstring>
using namespace std;

const int MAXN = 50;
int dp[MAXN][1 << MAXN];
long long count[MAXN][1 << MAXN];
int heights[MAXN];
int N, target;

int solve(int idx, int bitmask) {
    if (bitmask == target) {
        return dp[idx][bitmask] = heights[idx];
    }
    if (dp[idx][bitmask] != -1) return dp[idx][bitmask];
    int add = (__builtin_popcount(bitmask) == 1) ? heights[idx] : 0;
    int best = 0;
    for (int next = 0; next < N; next++) {
        if (bitmask & (1 << next)) continue;
        best = max(best, solve(next, bitmask | (1 << next)) + abs(heights[idx] - heights[next]));
    }
    return dp[idx][bitmask] = best + add;
}

long long countConfigs(int idx, int bitmask) {
    if (bitmask == target) {
        return 1LL;
    }
    if (count[idx][bitmask] != -1) return count[idx][bitmask];
    int add = (__builtin_popcount(bitmask) == 1) ? heights[idx] : 0;
    int best = solve(idx, bitmask);
    long long total = 0;
    for (int next = 0; next < N; next++) {
        if (bitmask & (1 << next)) continue;
        if (solve(next, bitmask | (1 << next)) + abs(heights[idx] - heights[next]) + add == best) {
            total += countConfigs(next, bitmask | (1 << next));
        }
    }
    return count[idx][bitmask] = total;
}

int main() {
    while (cin >> N && N) {
        memset(dp, -1, sizeof(dp));
        memset(count, -1, sizeof(count));
        target = (1 << N) - 1;
        for (int i = 0; i < N; i++) cin >> heights[i];
        int bestPerimeter = 0;
        long long configurations = 0;
        for (int i = 0; i < N; i++) bestPerimeter = max(bestPerimeter, solve(i, (1 << i)));
        for (int i = 0; i < N; i++) {
            if (bestPerimeter == solve(i, 1 << i)) configurations += countConfigs(i, (1 << i));
        }
        cout << bestPerimeter + 2 * N << " " << configurations << endl;
    }
    return 0;
}
