        if (grade > gradeToSign) {
            throw std::runtime_error("Grade too low to sign the form.");
        }
        isSigned = true;
    }

    bool getSignedForm() const {
        return isSigned;
    }

    int getGradeToSign() const {
        return gradeToSign;
    }

    int getGradeToExec() const {
        return gradeToExec;
    }

