class Bureaucrat {
private:
    std::string name;
    int grade;

public:
    Bureaucrat(std::string name, int grade) : name(name), grade(grade) {
        if (grade < 1 || grade > 150) {
            throw std::runtime_error("Invalid grade for bureaucrat.");
        }
    }

    void signForm(AForm& form) {
        try {
            form.beSigned(grade);
            std::cout << name << " signs " << form.getName() << std::endl;
        } catch (std::exception& e) {
            std::cout << name << " cannot sign " << form.getName() << " because " << e.what() << std::endl;
        }
    }

