#include <iostream>
#include <vector>
#include <climits>
using namespace std;

class Solution {
public:
    int minPathSum(vector<vector<int>>& grid) {
        int m = grid.size();
        int n = grid[0].size();
        vector<vector<int>> dp(m, vector<int>(n, 0));

        // Initialize the top-left cell with the value from the grid.
        dp[0][0] = grid[0][0];

        // Fill the first column.
        for (int i = 1; i < m; i++) {
            dp[i][0] = dp[i - 1][0] + grid[i][0];
        }

        // Fill the first row.
        for (int j = 1; j < n; j++) {
            dp[0][j] = dp[0][j - 1] + grid[0][j];
        }

        // Fill the rest of the cells.
        for (int i = 1; i < m; i++) {
            for (int j = 1; j < n; j++) {
                dp[i][j] = grid[i][j] + min(dp[i - 1][j], dp[i][j - 1]);
            }
        }

        // The bottom-right cell contains the minimum path sum.
        return dp[m - 1][n - 1];
    }
};

int main() {
    Solution sol;

    // Test case 1
    vector<vector<int>> grid1 = {
        {1, 3, 1},
        {1, 5, 1},
        {4, 2, 1}
    };
    cout << "Test case 1 - Expected: 7, Output: " << sol.minPathSum(grid1) << endl;

    // Test case 2
    vector<vector<int>> grid2 = {
        {1, 2, 5},
        {3, 2, 1}
    };
    cout << "Test case 2 - Expected: 6, Output: " << sol.minPathSum(grid2) << endl;

    return 0;
}
