// SafeArray class definition
class SafeArray {
private:
    int* array;
    size_t size;

public:
    // Constructor
    SafeArray(size_t size) : size(size), array(new int[size]) {}

    // Destructor
    ~SafeArray() {
        delete[] array;
    }

    // Copy constructor
    SafeArray(const SafeArray& other) : size(other.size), array(new int[other.size]) {
        std::copy(other.array, other.array + other.size, array);
    }

    // Copy assignment operator
    SafeArray& operator=(const SafeArray& other) {
        if (this != &other) {
            delete[] array;
            size = other.size;
            array = new int[size];
            std::copy(other.array, other.array + other.size, array);
        }
        return *this;
    }

    // Set value at index
    void set(size_t index, int value) {
        Aspect_BadAccess_Raise_if(index >= size, "Index out of bounds");
