class Solution {
public:
    /**
     * Removes characters from the string according to the following rule:
     * For each asterisk encountered, remove the most recent non-asterisk character.
     * If no such character exists, ignore the asterisk.
     *
     * @param s The input string containing alphabetic characters and asterisks.
     * @return The resulting string after the removal operation.
     */
    std::string removeStars(std::string s) {
        std::string ans;
        for (char c : s) {
            if (c == '*' && !ans.empty())
                ans.pop_back();
            else if (c != '*')
                ans.push_back(c);
        }
        return ans;
    }
};

int main() {
    Solution solution;

    // Test case 1
    std::string input1 = "ab*c";
