// Define the float2 structure for 2D vectors
struct float2 {
    float x, y;

    float2 operator/(float value) const {
        return {x / value, y / value};
    }

    float2 operator*(float value) const {
        return {x * value, y * value};
    }
};

// Define the float3 structure for 3D vectors
struct float3 {
    float x, y, z;

    float3 operator-(const float3& other) const {
        return {x - other.x, y - other.y, z - other.z};
    }

    float3 operator+(const float3& other) const {
        return {x + other.x, y + other.y, z + other.z};
    }
};

// Normalize a float3 vector
float3 normalize(const float3& v) {
    float length = std::sqrt(v.x * v.x + v.y * v.y + v.z * v.z);
    return {v.x / length, v.y / length, v.z / length};
}

// Compute the cross product of two float3 vectors
float3 cross(const float3& a, const float3& b) {
    return {
        a.y * b.z - a.z * b.y,
        a.z * b.x - a.x * b.z,
        a.x * b.y - a.y * b.x
    };
}

// Ray class
class Ray {
public:
    float3 Origin;
    float3 Direction;

    Ray(const float3& origin, const float3& direction)
        : Origin(origin), Direction(direction) {}
};

// OrthographicCamera class
class OrthographicCamera {
private:
    float OrthoWidth;
    float AspectRatio;
    float3 Location;
    float3 Direction;

public:
    OrthographicCamera()
        : OrthoWidth(25), AspectRatio(1.0f), Location({0, 0, 0}), Direction({0, 0, -1}) {}

    Ray MakeRay(const float2& UV) const {
        const float2 Full = {OrthoWidth, OrthoWidth / AspectRatio};
        const float2 Half = Full / 2.0f;
        const float3 CameraU = normalize(cross({0, 0, 1}, Direction));
        const float3 CameraV = normalize(cross(CameraU, Direction));
        const float3 LeftTop = Location - (Half.x * CameraU) - (Half.y * CameraV);
        const float2 Position = Full * UV;
        const float3 Origin = LeftTop + (Position.x * CameraU) + (Position.y * CameraV);

        return Ray(Origin, Direction);
    }

    OrthographicCamera& SetOrthoWidth(const float& InWidth) {
        OrthoWidth = InWidth;
        return *this;
    }

    OrthographicCamera& SetAspectRatio(const float& InAspectRatio) {
        AspectRatio = InAspectRatio;
        return *this;
    }

    OrthographicCamera& SetLocation(const float3& InLocation) {
        Location = InLocation;
        return *this;
    }

    OrthographicCamera& SetDirection(const float3& InDirection) {
        Direction = normalize(InDirection);
        return *this;
    }
};

// Test cases to verify the solution correctness
int main() {
    OrthographicCamera camera;
    camera.SetOrthoWidth(50)
          .SetAspectRatio(16.0f / 9.0f)
          .SetLocation({0, 0, 10})
          .SetDirection({0, 0, -1});

    // Generate a ray for the center of the image plane
    Ray centerRay = camera.MakeRay({0.5f, 0.5f});
    std::cout << "Center Ray Origin: (" << centerRay.Origin.x << ", " << centerRay.Origin.y << ", " << centerRay.Origin.z << ")" << std::endl;
    std::cout << "Center Ray Direction: (" << centerRay.Direction.x << ", " << centerRay.Direction.y << ", " << centerRay.Direction.z << ")" << std::endl;

    // Generate a ray for the bottom-left corner of the image plane
    Ray cornerRay = camera.MakeRay({0.0f, 0.0f});
    std::cout << "Corner Ray Origin: (" << cornerRay.Origin.x << ", " << cornerRay.Origin.y << ", " << cornerRay.Origin.z << ")" << std::endl;
    std::cout << "Corner Ray Direction: (" << cornerRay.Direction.x << ", " << cornerRay.Direction.y << ", " << cornerRay.Direction.z << ")" << std::endl;

    return 0;
}
