// Assuming the StructMechHeat2DDiffusiveVarSet class is defined as in the given code snippet
// and the necessary headers are included.

class HeatDiffusionSimulator {
public:
    HeatDiffusionSimulator(int width, int height, double initialTemp, double boundaryTemp)
        : width(width), height(height), currentTime(0.0), thermalConductivity(1.0),
          density(1.0), specificHeatCapacity(1.0), deltaT(0.1), deltaX(1.0) {
        // Initialize the temperature grid with the initial temperature
        temperatureGrid = std::vector<std::vector<double>>(height, std::vector<double>(width, initialTemp));
        // Set the boundary temperature
        setBoundaryTemperature(boundaryTemp);
    }

    void setMaterialProperties(double thermalConductivity, double density, double specificHeatCapacity) {
        this->thermalConductivity = thermalConductivity;
        this->density = density;
        this->specificHeatCapacity = specificHeatCapacity;
    }

    void setBoundaryTemperature(double boundaryTemp) {
        for (int i = 0; i < width; ++i) {
            temperatureGrid[0][i] = boundaryTemp;
            temperatureGrid[height - 1][i] = boundaryTemp;
        }
        for (int i = 0; i < height; ++i) {
            temperatureGrid[i][0] = boundaryTemp;
            temperatureGrid[i][width - 1] = boundaryTemp;
        }
    }

    void performTimeStep() {
        std::vector<std::vector<double>> newTemperatureGrid = temperatureGrid;
        double alpha = thermalConductivity / (density * specificHeatCapacity);

        for (int i = 1; i < height - 1; ++i) {
            for (int j = 1; j < width - 1; ++j) {
                double temp_ij = temperatureGrid[i][j];
                double temp_ip1j = temperatureGrid[i + 1][j];
                double temp_im1j = temperatureGrid[i - 1][j];
                double temp_ijp1 = temperatureGrid[i][j + 1];
                double temp_ijm1 = temperatureGrid[i][j - 1];

                newTemperatureGrid[i][j] = temp_ij + (alpha * deltaT / (deltaX * deltaX)) *
                    (temp_ip1j + temp_im1j + temp_ijp1 + temp_ijm1 - 4 * temp_ij);
            }
        }

        temperatureGrid = newTemperatureGrid;
        currentTime += deltaT;
    }

    const std::vector<std::vector<double>>& getTemperatureDistribution() const {
        return temperatureGrid;
    }

private:
    int width;
    int height;
    double currentTime;
    double thermalConductivity;
    double density;
    double specificHeatCapacity;
    double deltaT;
    double deltaX;
    std::vector<std::vector<double>> temperatureGrid;
};

int main() {
    // Example usage:
    HeatDiffusionSimulator simulator(10, 10, 20.0, 100.0);
    simulator.setMaterialProperties(0.5, 1.0, 1.0);

    // Perform 100 time steps
    for (int step = 0; step < 100; ++step) {
        simulator.performTimeStep();
    }

    // Retrieve and print the temperature distribution
    const auto& temperatureDistribution = simulator.getTemperatureDistribution();
    for (const auto& row : temperatureDistribution) {
        for (double temp : row) {
            std::cout << temp << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
