using namespace std;

/**
 * Finds the position of the highest set bit in the integer n.
 * @param n The integer to find the highest set bit in.
 * @return The position of the highest set bit, or -1 if no bits are set.
 */
int highest_bit(int n) {
    if (n == 0) return -1;
    int pos = 0;
    for (int i = 0; i < (sizeof(int) * CHAR_BIT) - 1; i++) {
        if (n & (1 << i))
            pos = i;
    }
    return pos;
}

/**
 * Finds the position of the lowest set bit in the integer n.
 * @param n The integer to find the lowest set bit in.
 * @return The position of the lowest set bit, or -1 if no bits are set.
 */
int lowest_bit(int n) {
    if (n == 0) return -1;
    for (int i = 0; i < (sizeof(int) * CHAR_BIT) - 1; i++) {
        if (n & (1 << i)) {
            return i;
        }
    }
    return -1;
}

int main() {
    int n;
    cout << "Enter a non-negative integer: ";
    cin >> n;

    int hi = highest_bit(n);
    if (hi >= 0)
        cout << "Highest bit position: " << hi << endl;
    else
        cout << "No highest bit set" << endl;

    int lw = lowest_bit(n);
    if (lw >= 0)
        cout << "Lowest bit position: " << lw << endl;
    else
        cout << "No bit set" << endl;

    return 0;
}

// Test cases to verify the solution correctness
int main() {
    // Test case 1: No bits set
    assert(highest_bit(0) == -1);
    assert(lowest_bit(0) == -1);

    // Test case 2: Only the least significant bit set
    assert(highest_bit(1) == 0);
    assert(lowest_bit(1) == 0);

    // Test case 3: Only the most significant bit set
    assert(highest_bit(1 << ((sizeof(int) * CHAR_BIT) - 2)) == (sizeof(int) * CHAR_BIT) - 2);
    assert(lowest_bit(1 << ((sizeof(int) * CHAR_BIT) - 2)) == (sizeof(int) * CHAR_BIT) - 2);

    // Test case 4: Both least and most significant bits set
    assert(highest_bit((1 << ((sizeof(int) * CHAR_BIT) - 2)) + 1) == (sizeof(int) * CHAR_BIT) - 2);
    assert(lowest_bit((1 << ((sizeof(int) * CHAR_BIT) - 2)) + 1) == 0);

    // Test case 5: Random number
    assert(highest_bit(18) == 4);
    assert(lowest_bit(18) == 1);

    cout << "All test cases passed!" << endl;

    return 0;
}
