class Fixed {
private:
    int _fixedValue;
    static int const _fractBits;

public:
    Fixed(void) : _fixedValue(0) {}
    Fixed(const Fixed& obj) : _fixedValue(obj.getRawBits()) {}
    Fixed(const int nb) : _fixedValue(nb << _fractBits) {}
    Fixed(const float nb) : _fixedValue(roundf(nb * (1 << _fractBits))) {}
    ~Fixed(void) {}

    Fixed &operator=(const Fixed &obj) {
        if (this != &obj) {
            this->_fixedValue = obj.getRawBits();
        }
        return *this;
    }

    float operator+(const Fixed &fix) const { return this->toFloat() + fix.toFloat(); }
    float operator-(const Fixed &fix) const { return this->toFloat() - fix.toFloat(); }
    float operator*(const Fixed &fix) const { return this->toFloat() * fix.toFloat(); }
    float operator/(const Fixed &fix) const { return this->toFloat() / fix.toFloat(); }

    bool operator<(const Fixed &fix) const { return this->toFloat() < fix.toFloat(); }
    bool operator>(const Fixed &fix) const { return this->toFloat() > fix.toFloat(); }
    bool operator<=(const Fixed &fix) const { return this->toFloat() <= fix.toFloat(); }
    bool operator>=(const Fixed &fix) const { return this->toFloat() >= fix.toFloat(); }
    bool operator!=(const Fixed &fix) const { return this->toFloat() != fix.toFloat(); }
    bool operator==(const Fixed &fix) const { return this->toFloat() == fix.toFloat(); }

    Fixed &operator++() {
        this->_fixedValue++;
        return *this;
    }

    Fixed &operator--() {
        this->_fixedValue--;
        return *this;
    }

    Fixed operator++(int) {
        Fixed temp = *this;
        ++*this;
        return temp;
    }

    Fixed operator--(int) {
        Fixed temp = *this;
        --*this;
        return temp;
    }

    static const Fixed &min(const Fixed &f1, const Fixed &f2) {
        return f1 < f2 ? f1 : f2;
    }

    static const Fixed &max(const Fixed &f1, const Fixed &f2) {
        return f1 > f2 ? f1 : f2;
    }

    static Fixed &min(Fixed &f1, Fixed &f2) {
        return f1 < f2 ? f1 : f2;
    }

    static Fixed &max(Fixed &f1, Fixed &f2) {
        return f1 > f2 ? f1 : f2;
    }

    int getRawBits(void) const { return _fixedValue; }
    void setRawBits(int const raw) { _fixedValue = raw; }

    float toFloat(void) const { return static_cast<float>(_fixedValue) / (1 << _fractBits); }
    int toInt(void) const { return _fixedValue >> _fractBits; }
};

int const Fixed::_fractBits = 8;

std::ostream &operator<<(std::ostream &os, const Fixed &fixed) {
    os << fixed.toFloat();
    return os;
}

int main() {
    Fixed a;
    Fixed const b(10);
    Fixed const c(42.42f);
    Fixed const d(b);

    a = Fixed(1234.4321f);

    std::cout << "a is " << a << std::endl;
    std::cout << "b is " << b << std::endl;
    std::cout << "c is " << c << std::endl;
    std::cout << "d is " << d << std::endl;

    std::cout << "a is " << a.toInt() << " as integer" << std::endl;
    std::cout << "b is " << b.toInt() << " as integer" << std::endl;
    std::cout << "c is " << c.toInt() << " as integer" << std::endl;
    std::cout << "d is " << d.toInt() << " as integer" << std::endl;

    std::cout << "a + b = " << a + b << std::endl;
    std::cout << "c - b = " << c - b << std::endl;
    std::cout << "b * c = " << b * c << std::endl;
    std::cout << "c / b = " << c / b << std::endl;

    std::cout << "b < c is " << (b < c) << std::endl;
    std::cout << "b > c is " << (b > c) << std::endl;
    std::cout << "b <= c is " << (b <= c) << std::endl;
    std::cout << "b >= c is " << (b >= c) << std::endl;
    std::cout << "b != c is " << (b != c) << std::endl;
    std::cout << "b == d is " << (b == d) << std::endl;

    std::cout << "max(a, b) = " << Fixed::max(a, b) << std::endl;
    std::cout << "min(a, b) = " << Fixed::min(a, b) << std::endl;

    std::cout << "++a = " << ++a << std::endl;
    std::cout << "a++ = " << a++ << std::endl;
    std::cout << "a = " << a << std::endl;
    std::cout << "--a = " << --a << std::endl;
    std::cout << "a-- = " << a-- << std::endl;
    std::cout << "a = " << a << std::endl;

    return 0;
}
