#include <iostream>
#include <vector>
using namespace std;

class Solution {
public:
    vector<vector<int>> ans;

    void backtrack(vector<int>& combination, int start, int n, int k) {
        if (combination.size() == k) {
            ans.push_back(combination);
            return;
        }
        for (int i = start; i <= n; ++i) {
            combination.push_back(i);
            backtrack(combination, i + 1, n, k);
            combination.pop_back();
        }
    }

    vector<vector<int>> combine(int n, int k) {
        vector<int> combination;
        backtrack(combination, 1, n, k);
        return ans;
    }
};

int main() {
    Solution solution;
    int n = 4, k = 2;
    vector<vector<int>> combinations = solution.combine(n, k);

    // Output the combinations
    for (const auto& combination : combinations) {
        cout << "[";
        for (int i = 0; i < combination.size(); ++i) {
            cout << combination[i] << (i < combination.size() - 1 ? ", " : "");
        }
        cout << "]" << endl;
    }

    return 0;
}
