using namespace proxygen;
using namespace folly;

// Assume that the following structs are defined in the proxygen library.
struct Header {
  std::string name;
  std::string value;
};

class StreamingCallback {
public:
  virtual ~StreamingCallback() = default;
  // Callback methods for handling decoded headers and errors.
};

struct EncodeResult {
  std::unique_ptr<IOBuf> control;
  std::unique_ptr<IOBuf> stream;
};

struct CompressionStats {
  uint64_t uncompressed;
  uint64_t compressed;
  uint64_t compressedBlock;
};

class HTTPCompressionCodec {
public:
  HTTPCompressionCodec() : qpackCodec_(), stats_() {}

  EncodeResult encodeHeaders(std::vector<Header>& headers, uint64_t streamId) {
    // Encode headers using QPACKCodec
    auto encodeRes = qpackCodec_.encode(headers, streamId, maxEncoderStreamBytes_);
    // Update stats
    stats_.uncompressed += encodeRes.uncompressed;
    stats_.compressed += encodeRes.compressed;
    stats_.compressedBlock = encodeRes.compressedBlock;
    return encodeRes;
  }

  void decodeHeaders(uint64_t streamId, std::unique_ptr<IOBuf> block, uint32_t length, StreamingCallback* streamingCb) {
    // Decode headers using QPACKCodec
    qpackCodec_.decodeStreaming(streamId, std::move(block), length, streamingCb);
  }

  CompressionStats getCompressionStats() const {
    return stats_;
  }

private:
  QPACKCodec qpackCodec_;
  CompressionStats stats_;
  uint32_t maxEncoderStreamBytes_ = 4096; // Example default value
};

// Example usage
int main() {
  HTTPCompressionCodec codec;
  std::vector<Header> headers = {{"Content-Type", "text/html"}, {"Content-Length", "123"}};
  uint64_t streamId = 1;

  // Encode headers
  auto encodedResult = codec.encodeHeaders(headers, streamId);

  // Assume we have a StreamingCallback implementation
  StreamingCallback* callback = nullptr;

  // Decode headers
  codec.decodeHeaders(streamId, std::move(encodedResult.stream), encodedResult.stream->computeChainDataLength(), callback);

  // Get compression stats
  CompressionStats stats = codec.getCompressionStats();
  std::cout << "Uncompressed size: " << stats.uncompressed << std::endl;
  std::cout << "Compressed size: " << stats.compressed << std::endl;
  std::cout << "Last compressed block size: " << stats.compressedBlock << std::endl;

  return 0;
}
