#include<iostream>
#include<queue>
#include<vector>

using namespace std;

/**
 * Connects all ropes into one rope with minimum cost.
 * The cost to connect two ropes is equal to the sum of their lengths.
 * 
 * @param ropes A vector of integers representing the lengths of the ropes.
 * @return The minimum cost to connect all the ropes.
 */
int minCostToConnectRopes(const vector<int>& ropes) {
    priority_queue<int, vector<int>, greater<int>> pq(ropes.begin(), ropes.end());
    int cost = 0;

    while (pq.size() > 1) {
        int x = pq.top();
        pq.pop();
        int y = pq.top();
        pq.pop();
        int sum = x + y;
        cost += sum;
        pq.push(sum);
    }

    return cost;
}

int main() {
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        vector<int> ropes(n);
        for (int i = 0; i < n; i++) {
            cin >> ropes[i];
        }

        cout << minCostToConnectRopes(ropes) << endl;
    }
    return 0;
}
