    for (int i = b+1; i <= b + 3*g; i++){
        dp[i] = dp[i-1]+1;
        for (int j = 2; j <= k; j++)
            if (i - (i%j) >= b)
                dp[i] = min(dp[i], dp[i-(i%j)] + 1);
    }

    ll tmp = ((a-b)/g);
    if (tmp) tmp--;
    ll ans = tmp * (dp[b+2*g] - dp[b+g]);
    a -= tmp * g;
    ans += dp[a];

