#include <vector>
#include <algorithm>
#include <iostream>
#include <cassert>

template <typename T>
class VectorMath {
public:
    using VectorType = std::vector<T>;

    static VectorType min(const VectorType& lhs, const VectorType& rhs) {
        assert(lhs.size() == rhs.size());
        VectorType result(lhs.size());
        std::transform(lhs.begin(), lhs.end(), rhs.begin(), result.begin(), [](T a, T b) { return std::min(a, b); });
        return result;
    }

    static VectorType max(const VectorType& lhs, const VectorType& rhs) {
        assert(lhs.size() == rhs.size());
        VectorType result(lhs.size());
        std::transform(lhs.begin(), lhs.end(), rhs.begin(), result.begin(), [](T a, T b) { return std::max(a, b); });
        return result;
    }

    static VectorType abs(const VectorType& vec) {
        VectorType result(vec.size());
        std::transform(vec.begin(), vec.end(), result.begin(), [](T a) { return std::abs(a); });
        return result;
    }

    static VectorType fma(const VectorType& x, const VectorType& y, const VectorType& z) {
        assert(x.size() == y.size() && y.size() == z.size());
        VectorType result(x.size());
        for (size_t i = 0; i < x.size(); ++i) {
            result[i] = x[i] * y[i] + z[i];
        }
        return result;
    }

    static VectorType fms(const VectorType& x, const VectorType& y, const VectorType& z) {
        assert(x.size() == y.size() && y.size() == z.size());
        VectorType result(x.size());
        for (size_t i = 0; i < x.size(); ++i) {
            result[i] = x[i] * y[i] - z[i];
        }
        return result;
    }

    static VectorType fnma(const VectorType& x, const VectorType& y, const VectorType& z) {
        assert(x.size() == y.size() && y.size() == z.size());
        VectorType result(x.size());
        for (size_t i = 0; i < x.size(); ++i) {
            result[i] = -x[i] * y[i] + z[i];
        }
        return result;
    }

    static VectorType fnms(const VectorType& x, const VectorType& y, const VectorType& z) {
        assert(x.size() == y.size() && y.size() == z.size());
        VectorType result(x.size());
        for (size_t i = 0; i < x.size(); ++i) {
            result[i] = -x[i] * y[i] - z[i];
        }
        return result;
    }
};

int main() {
    using VM = VectorMath<int>;
    VM::VectorType a = {1, -2, 3};
    VM::VectorType b = {-1, 2, -3};
    VM::VectorType c = {4, 5, 6};

    // Test min
    VM::VectorType min_result = VM::min(a, b);
    assert((min_result == VM::VectorType{-1, -2, -3}));

    // Test max
    VM::VectorType max_result = VM::max(a, b);
    assert((max_result == VM::VectorType{1, 2, 3}));

    // Test abs
    VM::VectorType abs_result = VM::abs(b);
    assert((abs_result == VM::VectorType{1, 2, 3}));

    // Test fma
    VM::VectorType fma_result = VM::fma(a, b, c);
    assert((fma_result == VM::VectorType{3, -1, 3}));

    // Test fms
    VM::VectorType fms_result = VM::fms(a, b, c);
    assert((fms_result == VM::VectorType{-5, -9, -15}));

    // Test fnma
    VM::VectorType fnma_result = VM::fnma(a, b, c);
    assert((fnma_result == VM::VectorType{5, 9, 15}));

    // Test fnms
    VM::VectorType fnms_result = VM::fnms(a, b, c);
    assert((fnms_result == VM::VectorType{-3, 1, -3}));

    std::cout << "All tests passed!" << std::endl;
    return 0;
}
