 * and then replacing all remaining single spaces with plus signs.
 * 
 * @param input The string to be transformed.
 * @return The transformed string.
 */
string transformString(string input) {
    size_t doubleSpacePos = input.find("  ");
    if (doubleSpacePos != string::npos) {
        input.replace(doubleSpacePos, 2, " ");
    }

    for (size_t i = 0; i < input.length(); ++i) {
        if (input[i] == ' ') {
            input[i] = '+';
        }
    }

