#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <cctype>
#include <stack>
#include <iterator>
#include <sstream>
#include <iomanip>
using namespace std;

// Function to extract a number from the expression string
string get_num(const string& expr, string::iterator& iter) {
    string tmp = "";
    auto num_dot = 0;
    do {
        tmp += *iter++;
        if (*iter == '.') {
            tmp += *iter++;
            ++num_dot;
        }
        if (num_dot > 1)
            break;
    } while (isdigit(*iter) || *iter == '.' && iter != expr.end());
    return tmp;
}

// Function to determine the priority of operators
int get_priority(const string& s) {
    if (s == "(" || s == ")")
        return 0;
    else if (s == "+" || s == "-")
        return 1;
    else if (s == "*" || s == "/")
        return 2;
    return 0;
}

// Function to evaluate the postfix expression
double evaluate_postfix(const vector<string>& postfix) {
    stack<double> eval_stack;
    for (const auto& token : postfix) {
        if (isdigit(token[0]) || (token[0] == '-' && token.size() > 1)) {
            eval_stack.push(stod(token));
        } else {
            double right = eval_stack.top();
            eval_stack.pop();
            double left = eval_stack.top();
            eval_stack.pop();
            if (token == "+") eval_stack.push(left + right);
            else if (token == "-") eval_stack.push(left - right);
            else if (token == "*") eval_stack.push(left * right);
            else if (token == "/") {
                if (right == 0) throw runtime_error("Division by zero.");
                eval_stack.push(left / right);
            }
        }
    }
    return eval_stack.top();
}

int main() {
    string expr;
    cout << "Enter an arithmetic expression: ";
    getline(cin, expr);

    // Step 1: Erase redundant space
    expr.erase(remove_if(expr.begin(), expr.end(), ::isspace), expr.end());

    // Step 2: Split string into tokens
    vector<string> tokens;
    auto iter = expr.begin();
    while (iter != expr.end()) {
        if (isdigit(*iter) || (*iter == '-' && (iter == expr.begin() || !isdigit(*(iter - 1))) && isdigit(*(iter + 1)))) {
            tokens.push_back(get_num(expr, iter));
        } else {
            tokens.push_back(string(1, *iter));
            ++iter;
        }
    }

    // Step 3: Convert to postfix expression
    vector<string> postfix;
    stack<string> ops;
    for (const auto& token : tokens) {
        if (isdigit(token[0]) || (token[0] == '-' && token.size() > 1)) {
            postfix.push_back(token);
        } else if (token == "(") {
            ops.push(token);
        } else if (token == ")") {
            while (!ops.empty() && ops.top() != "(") {
                postfix.push_back(ops.top());
                ops.pop();
            }
            ops.pop(); // Remove the '(' from the stack
        } else {
            while (!ops.empty() && get_priority(ops.top()) >= get_priority(token)) {
                postfix.push_back(ops.top());
                ops.pop();
            }
            ops.push(token);
        }
    }
    while (!ops.empty()) {
        postfix.push_back(ops.top());
        ops.pop();
    }

    // Step 4: Evaluate the postfix expression
    try {
        double result = evaluate_postfix(postfix);
        cout << fixed << setprecision(2) << "The result is: " << result << endl;
    } catch (const runtime_error& e) {
        cerr << "Error: " << e.what() << endl;
        return 1;
    }

    return 0;
}
