using namespace std;

void processInflection(vector<int>& output, int start, int end) {
    for (int i = start + 1; i < end; i++) {
        output[i]++;
    }
}

int main() {
    int N;
    cin >> N;
    vector<int> heights(N);
    vector<int> output(N + 1, 0);

    for (int i = 0; i < N; i++) {
        cin >> heights[i];
    }

    bool mode = true; // true for finding next maxima, false for next minima
    int inflectionStart = 0;
    int inflectionEnd = 0;
    int lastHeight = heights[0];

    for (int i = 1; i < N; i++) {
        if (mode) {
            if (heights[i] < lastHeight) { // starting to decrease
                inflectionEnd = i - 1;
                processInflection(output, inflectionStart, inflectionEnd);
                mode = false;
            }
        } else {
            if (heights[i] > lastHeight) { // starting to increase
                inflectionStart = i - 1;
                processInflection(output, inflectionEnd, inflectionStart);
                mode = true;
            }
        }
        lastHeight = heights[i];
    }

    // Process the last inflection point
    if (!mode) {
        inflectionEnd = N - 1;
        processInflection(output, inflectionStart, inflectionEnd);
    }

    for (int i = 0; i <= N; i++) {
        cout << output[i] << endl;
    }

    return 0;
}
