using namespace std;

/**
 * Counts the number of words in the string and finds the most frequently occurring non-space character.
 * @param input The input string to process.
 * @return A pair consisting of the word count and the most frequent character.
 */
pair<int, char> processText(const string& input) {
    int wordCount = 0;
    unordered_map<char, int> charFrequency;
    char mostFrequentChar = '\0';
    int maxFrequency = 0;

    // Remove extra spaces and count words
    string trimmedInput;
    bool inWord = false;
    for (char ch : input) {
        if (ch != ' ') {
            if (!inWord) {
                wordCount++;
                inWord = true;
            }
            trimmedInput += ch;
            charFrequency[ch]++;
            if (charFrequency[ch] > maxFrequency) {
                maxFrequency = charFrequency[ch];
                mostFrequentChar = ch;
            } else if (charFrequency[ch] == maxFrequency && ch < mostFrequentChar) {
                mostFrequentChar = ch;
            }
        } else if (inWord) {
            inWord = false;
            trimmedInput += ch;
        }
    }

    return {wordCount, mostFrequentChar};
}

int main() {
    ifstream inputFile("ONTAP20.INP");
    ofstream outputFile("ONTAP20.OUT");

    if (!inputFile.is_open() || !outputFile.is_open()) {
        cerr << "Error opening files!" << endl;
        return 1;
    }

    string text;
    getline(inputFile, text);
    inputFile.close();

    auto result = processText(text);
    outputFile << result.first << ' ' << result.second;
    outputFile.close();

    return 0;
}

// Test cases
