class UnboundedKnapsack {
public:
    int maxProfit(int N, int W, vector<int>& val, vector<int>& wt) {
        vector<int> dp(W + 1, 0);
        for (int i = 0; i < N; i++) {
            for (int j = wt[i]; j <= W; j++) {
                dp[j] = max(dp[j], dp[j - wt[i]] + val[i]);
            }
        }
        return dp[W];
    }
};

