using namespace std;

struct Team {
    int member[3] = {0, 0, 0};
    bool add(int p) {
        for (int &m : member) {
            if (m == 0) {
                m = p;
                return true;
            }
        }
        return false;
    }
    void print() const {
        for (int m : member) {
            cout << m << ' ';
        }
        cout << '\n';
    }
};

int main() {
    int n, m;
    cin >> n >> m;
    assert(n % 3 == 0);
    int num_teams = n / 3;

    vector<Team> team(num_teams + 1);
    vector<int> player(n + 1, 0);

    int t = 1;
    bool failed = false;
    for (int i = 0; i < m; i++) {
        int p1, p2;
        cin >> p1 >> p2;

        if (player[p1] != 0 && player[p2] != 0) {
            if (player[p1] != player[p2]) {
                failed = true;
                break;
            }
            continue;
        } else if (player[p1] != 0) {
            if (!team[player[p1]].add(p2)) {
                failed = true;
                break;
            }
            player[p2] = player[p1];
        } else if (player[p2] != 0) {
            if (!team[player[p2]].add(p1)) {
                failed = true;
                break;
            }
            player[p1] = player[p2];
        } else if (t <= num_teams) {
            player[p1] = t;
            player[p2] = t;
            assert(team[t].add(p1));
            assert(team[t].add(p2));
            t++;
        } else {
            failed = true;
            break;
        }
    }

    if (failed) {
        cout << "-1\n";
    } else {
        for (int i = 1; i <= n; i++) {
            if (player[i] == 0) {
                while (!team[t].add(i)) {
                    t++;
                    if (t > num_teams) {
                        failed = true;
                        break;
                    }
                }
                player[i] = t;
            }
        }
        if (failed) {
            cout << "-1\n";
        } else {
            for (int i = 1; i <= num_teams; i++) {
                team[i].print();
            }
        }
    }

    return 0;
}
