// Mock definitions for the purpose of this example
namespace share {
    class SCN {
    public:
        static const SCN min_scn() { return SCN(); }
        void set_min() {}
        int fixed_serialize(char *buf, const int64_t buf_len, int64_t &pos) const { return 0; }
        int fixed_deserialize(const char *buf, const int64_t data_len, int64_t &pos) { return 0; }
        int64_t get_fixed_serialize_size() const { return sizeof(SCN); }
    };
