namespace oceanbase {
    using namespace share;

    enum ObTabletBarrierLogStateEnum {
        TABLET_BARRIER_LOG_INIT,
        TABLET_BARRIER_LOG_WRITING,
        TABLET_BARRIER_SOURCE_LOG_WRITTEN,
        TABLET_BARRIER_DEST_LOG_WRITTEN
    };

    class ObTabletBarrierLogState {
    private:
        ObTabletBarrierLogStateEnum state_;
        SCN scn_;
        int64_t schema_version_;

    public:
        ObTabletBarrierLogState()
            : state_(TABLET_BARRIER_LOG_INIT), scn_(SCN::min_scn()), schema_version_(0) {}

        ObTabletBarrierLogStateEnum to_persistent_state() const {
            if (state_ == TABLET_BARRIER_LOG_INIT || state_ == TABLET_BARRIER_LOG_WRITING) {
                return TABLET_BARRIER_LOG_INIT;
            }
            return state_;
        }

        void reset() {
            state_ = TABLET_BARRIER_LOG_INIT;
            scn_.set_min();
            schema_version_ = 0;
        }

        void set_log_info(const ObTabletBarrierLogStateEnum state, const SCN &scn, const int64_t schema_version) {
            state_ = state;
            scn_ = scn;
            schema_version_ = schema_version;
        }

        int serialize(char *buf, const int64_t buf_len, int64_t &pos) const {
            int ret = 0;
            const ObTabletBarrierLogStateEnum persistent_state = to_persistent_state();
            if ((ret = serialization::encode_i64(buf, buf_len, pos, persistent_state)) != 0) {
                std::cerr << "Failed to encode state" << std::endl;
            } else if ((ret = scn_.fixed_serialize(buf, buf_len, pos)) != 0) {
                std::cerr << "Failed to serialize SCN" << std::endl;
            }
            return ret;
        }

        int deserialize(const char *buf, const int64_t data_len, int64_t &pos) {
            int ret = 0;
            int64_t tmp_state = 0;
            if ((ret = serialization::decode_i64(buf, data_len, pos, &tmp_state)) != 0) {
                std::cerr << "Failed to decode state" << std::endl;
            } else if ((ret = scn_.fixed_deserialize(buf, data_len, pos)) != 0) {
                std::cerr << "Failed to deserialize SCN" << std::endl;
            } else {
                state_ = static_cast<ObTabletBarrierLogStateEnum>(tmp_state);
            }
            return ret;
        }

        int64_t get_serialize_size() const {
            int64_t len = 0;
            len += serialization::encoded_length_i64(to_persistent_state());
            len += scn_.get_fixed_serialize_size();
            return len;
        }
    };
}

// Test cases
int main() {
    using namespace oceanbase;
    using namespace share;

    char buffer[1024];
    int64_t pos = 0;

    // Create an instance of ObTabletBarrierLogState and set its state
