#include <iostream>
using namespace std;

// Define the Node structure for the AA Tree
struct Node {
    double value;
    int level;
    Node *left, *right;

    Node(double val) : value(val), level(1), left(nullptr), right(nullptr) {}
};

// Define the AA Tree class
class AA_tree {
private:
    Node *root;

    // Skew operation for balancing the tree
    Node* skew(Node *node) {
        if (node == nullptr || node->left == nullptr) {
            return node;
        }
        if (node->left->level == node->level) {
            Node *L = node->left;
            node->left = L->right;
            L->right = node;
            return L;
        }
        return node;
    }

    // Split operation for balancing the tree
    Node* split(Node *node) {
        if (node == nullptr || node->right == nullptr || node->right->right == nullptr) {
            return node;
        }
        if (node->level == node->right->right->level) {
            Node *R = node->right;
            node->right = R->left;
            R->left = node;
            R->level++;
            return R;
        }
        return node;
    }

    // Recursive insert helper function
    Node* insert(Node *node, double value) {
        if (node == nullptr) {
            return new Node(value);
        }
        if (value < node->value) {
            node->left = insert(node->left, value);
        } else if (value > node->value) {
            node->right = insert(node->right, value);
        }
        node = skew(node);
        node = split(node);
        return node;
    }

    // Recursive search helper function
    bool search(Node *node, double value) const {
        if (node == nullptr) {
            return false;
        }
        if (value < node->value) {
            return search(node->left, value);
        } else if (value > node->value) {
            return search(node->right, value);
        } else {
            return true;
        }
    }

public:
    // Constructor
    AA_tree() : root(nullptr) {}

    // Insert a value into the AA Tree
    void insert(double value) {
        root = insert(root, value);
    }

    // Search for a value in the AA Tree
    bool search(double value) const {
        return search(root, value);
    }
};

int main() {
    AA_tree tree;
    // Insert values into the AA Tree
    for (double i = 0; i <= 1000; i += 1) {
        tree.insert(i);
    }

    // Search for values and print the results
    for (double i = 100; i <= 1500; i += 1) {
        cout << (tree.search(i) ? "Found" : "Not Found") << '\t';
    }

    // Pause the system for viewing the results
    system("Pause");
    return 0;
}
