/**
 * Calculates the sum of all integers from a to b inclusive.
 * If a is greater than b, it calculates the sum from b to a.
 * 
 * @param a The starting integer.
 * @param b The ending integer.
 * @return The sum of integers from a to b inclusive.
 */
long long sumFromAToB(long long a, long long b) {
    // Ensure a is less than or equal to b
    if (a > b) swap(a, b);
    // Use the arithmetic series sum formula: n/2 * (first number + last number)
    return (b - a + 1) * (a + b) / 2;
}

int main() {
    cin.tie(NULL);
    ios::sync_with_stdio(false);

    int n;
    long long a, b;
    cin >> n;

    for (int i = 0; i < n; i++) {
        cin >> a >> b;
        cout << sumFromAToB(a, b) << '\n';
    }

    return 0;
}
