class Variable {
 private:
  std::map<std::string, std::string> envVars;
  std::vector<std::string> pathDirs;

  void parsePath() {
    std::string path = envVars["PATH"];
    std::istringstream stream(path);
    std::string dir;
    while (std::getline(stream, dir, ':')) {
      pathDirs.push_back(dir);
    }
  }

 public:
  Variable() {
    // Initialize with a dummy PATH variable for demonstration purposes
    envVars["PATH"] = "/usr/bin:/bin:/usr/sbin:/sbin";
    parsePath();
  }

  void setEnvVar(const std::string& key, const std::string& value) {
    envVars[key] = value;
    if (key == "PATH") {
      pathDirs.clear();
      parsePath();
    }
  }

  std::string getEnvVar(const std::string& key) {
    return envVars.count(key) ? envVars[key] : "";
  }

  void addToPath(const std::string& dir) {
    if (std::find(pathDirs.begin(), pathDirs.end(), dir) == pathDirs.end()) {
      pathDirs.push_back(dir);
      envVars["PATH"] += ":" + dir;
    }
  }

  void removeFromPath(const std::string& dir) {
    auto it = std::find(pathDirs.begin(), pathDirs.end(), dir);
    if (it != pathDirs.end()) {
      pathDirs.erase(it);
      std::string newPath;
      for (const auto& d : pathDirs) {
        if (!newPath.empty()) newPath += ":";
        newPath += d;
      }
      envVars["PATH"] = newPath;
    }
  }

  void listEnvVars() {
    for (const auto& pair : envVars) {
      std::cout << pair.first << "=" << pair.second << std::endl;
    }
  }
};

