#include <algorithm>
#include <climits>
using namespace std;

class Solution {
public:
    int findMinHeaterRadius(vector<int>& houses, vector<int>& heaters) {
        sort(heaters.begin(), heaters.end());
        int minRadius = INT_MIN;

        for (int house : houses) {
            int closestHeaterDist = findClosestHeaterDistance(house, heaters);
            minRadius = max(minRadius, closestHeaterDist);
        }

        return minRadius;
    }

private:
    int findClosestHeaterDistance(int house, vector<int>& heaters) {
        int left = 0, right = heaters.size() - 1;
        int closestDist = INT_MAX;

        while (left <= right) {
            int mid = left + (right - left) / 2;
            closestDist = min(closestDist, abs(heaters[mid] - house));

            if (heaters[mid] < house) {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }

        return closestDist;
    }
};

int main() {
