/**
 * Evaluates a polynomial of degree n at a given value x.
 * The polynomial is in the form a_n * x^n + a_(n-1) * x^(n-1) + ... + a_1 * x + a_0.
 * 
 * @param n The degree of the polynomial.
 * @param x The value at which the polynomial is to be evaluated.
 * @param coefficients The coefficients of the polynomial.
 * @return The value of the polynomial at x.
 */
double evaluatePolynomial(int n, double x, const double coefficients[]) {
    double sum = 0.0;
    double temp = pow(x, n);
    for (int i = n; i >= 0; --i) {
        sum += temp * coefficients[n - i];
        temp /= x;
    }
    return sum;
}

int main() {
    int n;
    double x;
    cout << "To find the value of a polynomial at x,\n";
    cout << "Enter the degree of the polynomial: ";
    cin >> n;

    double* coefficients = new double[n + 1];

    cout << "Enter the value of x: ";
    cin >> x;

    for (int i = n; i >= 0; --i) {
        cout << "Enter the coefficient of x^" << i << ": ";
        cin >> coefficients[n - i];
    }

    double result = evaluatePolynomial(n, x, coefficients);
    cout << "The value of the polynomial at x = " << x << " is " << result << '\n';

    delete[] coefficients;
    return 0;
}

// Test cases to verify the solution correctness
int main() {
    // Test case 1
    int n1 = 2;
    double x1 = 3.0;
    double coefficients1[] = {2, -4, 3}; // 2x^2 - 4x + 3
