/**
 * Removes all whitespace characters from the input string and returns the modified string.
 * It also counts the number of whitespace characters removed.
 * 
 * @param input The string from which whitespace characters will be removed.
 * @param whitespaceCount Reference to an integer that will store the count of whitespace characters removed.
 * @return The modified string with all whitespace characters removed.
 */
string removeWhitespace(const string& input, int& whitespaceCount) {
    string result;
    whitespaceCount = 0;

    for (char ch : input) {
        if (isspace(ch)) {
            whitespaceCount++;
        } else {
            result += ch;
        }
    }

    return result;
}

int main() {
    cout << "## Program to remove whitespace characters ##" << endl;
    cout << "Enter a sentence:" << endl;

    string sentence;
    getline(cin, sentence);

    int whitespaceCount;
    string modifiedString = removeWhitespace(sentence, whitespaceCount);

    cout << "Modified string: " << modifiedString << endl;
    cout << "Whitespace characters removed: " << whitespaceCount << endl;

    return 0;
}
