namespace mtst_common
{
    namespace optimizer
    {
        template< class R = std::vector<double> >
        class GradientDescentOptimizer : public TraitOptimizer<R>
        {
        private:
            double alpha; // Learning rate
            std::size_t max_iters; // Maximum number of iterations
            R current_params; // Current parameters

        public:
            GradientDescentOptimizer(double learning_rate, std::size_t maximum_iterations)
                : alpha(learning_rate), max_iters(maximum_iterations) {}

            virtual ~GradientDescentOptimizer() {}

            R optimize(std::size_t num_params, std::function<double(R&)> func) override
            {
                initialize();
                for (std::size_t iter = 0; iter < max_iters; ++iter)
                {
                    pre_act();
                    R gradient = compute_gradient(func, current_params);
                    for (std::size_t i = 0; i < num_params; ++i)
                    {
                        current_params[i] -= alpha * gradient[i];
                    }
                    post_act();
                }
                finalize();
                return current_params;
            }

            void initialize() override
            {
                current_params = R(); // Initialize with default values
            }

            void pre_act() override
            {
                // Any pre-iteration actions can be implemented here
            }

            void post_act() override
            {
                // Any post-iteration actions can be implemented here
            }

            void finalize() override
            {
                // Any cleanup can be implemented here
            }

        private:
            R compute_gradient(std::function<double(R&)> func, R& params)
            {
                double h = 1e-5; // Step size for numerical differentiation
                R gradient(params.size());
                for (std::size_t i = 0; i < params.size(); ++i)
                {
                    R params_plus = params;
                    params_plus[i] += h;
                    double rise = func(params_plus) - func(params);
                    gradient[i] = rise / h;
                }
                return gradient;
            }
        };
    } // namespace optimizer
} // namespace mtst_common

// Example usage and test case
int main()
{
    // Define a simple quadratic function to minimize
    auto func = [](std::vector<double>& params) -> double {
        double sum = 0.0;
        for (double x : params)
        {
            sum += x * x;
        }
        return sum;
    };

    // Instantiate the optimizer with a learning rate of 0.1 and a maximum of 100 iterations
    mtst_common::optimizer::GradientDescentOptimizer<> optimizer(0.1, 100);

    // Initial guess for the parameters
    std::vector<double> initial_params = {10.0, 10.0};

    // Perform optimization
    std::vector<double> optimized_params = optimizer.optimize(initial_params.size(), func);

    // Output the optimized parameters
    std::cout << "Optimized parameters:" << std::endl;
    for (double param : optimized_params)
    {
        std::cout << param << std::endl;
    }

    return 0;
}
