// ActionNotifier class template
template <typename MessageT>
class ActionNotifier {
private:
    int m_iActionStackCounter;
    std::vector<MessageT*> m_CollectedMessages;

public:
    ActionNotifier() : m_iActionStackCounter(0) {}

    ~ActionNotifier() {
        for (auto* msg : m_CollectedMessages) {
            delete msg;
        }
    }

    void beginAction() {
        m_iActionStackCounter++;
    }

    void endAction() {
        m_iActionStackCounter--;
        assert(m_iActionStackCounter >= 0);

        if (m_iActionStackCounter == 0) {
            NotifyObservers();
        }
    }

    void addMessage(MessageT* message) {
        // Check for duplicates before adding
        auto it = std::find_if(m_CollectedMessages.begin(), m_CollectedMessages.end(),
                                [message](const MessageT* m) { return typeid(*m) == typeid(*message); });
        if (it == m_CollectedMessages.end()) {
            m_CollectedMessages.push_back(message);
        } else {
            delete message; // Delete the duplicate message
        }
    }

    void NotifyObservers() {
        for (auto* msg : m_CollectedMessages) {
            assert(msg != nullptr);
            msg->send();
            delete msg;
        }
        m_CollectedMessages.clear();
    }
};

// Test cases
