    ActionNotifier<Message> notifier;

    notifier.beginAction();
    notifier.addMessage(new ChangeMessage());
    notifier.addMessage(new ChangeMessage()); // This should not be added as it's a duplicate
    notifier.endAction(); // This should trigger the notification

