using std::vector;
using std::cout;
using std::endl;
using std::sort;

class Solution {
public:
    int minGroups(vector<vector<int>>& intervals) {
        if (intervals.empty()) return 0;

        // Sort the intervals based on the start time
        sort(intervals.begin(), intervals.end(), [](const vector<int>& a, const vector<int>& b) {
            return a[0] < b[0];
        });

        // Initialize a multiset to keep track of end times of intervals in current groups
        std::multiset<int> endTimes;

        for (const auto& interval : intervals) {
            // If there is a group that can accommodate the interval, use it
            auto it = endTimes.upper_bound(interval[0]);
            if (it != endTimes.begin()) {
                --it;
                endTimes.erase(it);
            }
            // Add the end time of the current interval to the set
            endTimes.insert(interval[1]);
        }

        // The number of groups is the number of unique end times
        return endTimes.size();
    }
};

int main(void) {
    vector<vector<int>> input = {{5, 10}, {6, 8}, {1, 5}, {2, 3}, {1, 10}};
    Solution* test = new Solution();
    cout << test->minGroups(input) << endl; // Expected output: 3
    delete test;

    // Additional test cases
    vector<vector<int>> input2 = {{1, 2}, {2, 3}, {3, 4}, {1, 4}};
    test = new Solution();
    cout << test->minGroups(input2) << endl; // Expected output: 2
    delete test;

    vector<vector<int>> input3 = {{1, 10}, {2, 3}, {4, 5}, {6, 7}, {8, 9}};
    test = new Solution();
    cout << test->minGroups(input3) << endl; // Expected output: 1
    delete test;

    return 0;
}
