/**
 * Selects the maximum number of non-overlapping activities.
 *
 * @param n The number of activities.
 * @param startTimes The array of start times of the activities.
 * @param finishTimes The array of finish times of the activities.
 * @param selectedActivities The array to store whether an activity is selected.
 */
void selectMaxActivities(int n, const std::vector<int>& startTimes, const std::vector<int>& finishTimes, std::vector<bool>& selectedActivities) {
    selectedActivities[0] = true;
    int lastSelectedIndex = 0;

    for (int i = 1; i < n; i++) {
        if (startTimes[i] >= finishTimes[lastSelectedIndex]) {
            selectedActivities[i] = true;
            lastSelectedIndex = i;
        }
        else {
            selectedActivities[i] = false;
        }
    }
}

