/**
 * Checks if the given matrix follows the pattern where each row represents a sequence
 * of consecutive numbers that increase by 1 and each column represents a sequence of
 * numbers that increase by 7.
 * 
 * @param N Number of rows in the matrix.
 * @param M Number of columns in the matrix.
 * @param B The matrix of integers.
 * @return "Yes" if the matrix follows the pattern, "No" otherwise.
 */
string checkMatrixPattern(int N, int M, const vector<vector<int>>& B) {
    for (int i = 0; i < N; ++i) {
        for (int j = 0; j < M; ++j) {
            if (i > 0 && B[i][j] != B[i - 1][j] + 7) return "No";
