// Define a simple in-memory matrix representation
template <typename T>
class SimpleMatrix {
public:
    std::vector<std::vector<T>> data;

    SimpleMatrix(int m, int n) : data(m, std::vector<T>(n, T())) {}

    int numRows() const { return data.size(); }
    int numCols() const { return data.empty() ? 0 : data[0].size(); }

    T& operator()(int i, int j) { return data[i][j]; }
    const T& operator()(int i, int j) const { return data[i][j]; }
};

// Concrete implementation of the MatrixAdaptor_t interface for SimpleMatrix
template <typename T>
struct MatrixAdaptor_t<SimpleMatrix<T>> {
    using value_type = T;
    using matrix_type = SimpleMatrix<T>;

    static std::shared_ptr<matrix_type> defaultConstructMatrix(int m, int n, std::string name = "") {
        return std::make_shared<matrix_type>(m, n);
    }

    static std::shared_ptr<matrix_type> copyConstructMatrix(const matrix_type& original) {
        auto mat = std::make_shared<matrix_type>(original.numRows(), original.numCols());
        for (int i = 0; i < original.numRows(); ++i) {
            for (int j = 0; j < original.numCols(); ++j) {
                (*mat)(i, j) = original(i, j);
            }
        }
        return mat;
    }

    static int getNumRows(const matrix_type& A) {
        return A.numRows();
    }

    static int getNumCols(const matrix_type& A) {
        return A.numCols();
    }

    static void add(const matrix_type& A, const matrix_type& B, matrix_type& C) {
        if (A.numRows() != B.numRows() || A.numCols() != B.numCols()) {
            throw std::invalid_argument("Matrix dimensions must match for addition.");
        }
        C = matrix_type(A.numRows(), A.numCols());
        for (int i = 0; i < A.numRows(); ++i) {
            for (int j = 0; j < A.numCols(); ++j) {
                C(i, j) = A(i, j) + B(i, j);
            }
        }
    }

    // ... Implement other operations similarly ...

    static void print(const matrix_type& A, std::ostream& os = std::cout) {
        for (int i = 0; i < A.numRows(); ++i) {
            for (int j = 0; j < A.numCols(); ++j) {
                os << A(i, j) << " ";
            }
            os << std::endl;
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    using Matrix = SimpleMatrix<double>;
    using Adaptor = MatrixAdaptor_t<Matrix>;

    // Create two 3x3 matrices
    auto A = Adaptor::defaultConstructMatrix(3, 3);
    auto B = Adaptor::defaultConstructMatrix(3, 3);

    // Fill matrices with values
    for (int i = 0; i < 3; ++i) {
        for (int j = 0; j < 3; ++j) {
            (*A)(i, j) = i + j;
            (*B)(i, j) = (i + 1) * (j + 1);
        }
    }

    // Perform addition
    Matrix C(3, 3);
    Adaptor::add(*A, *B, C);

    // Print result
    std::cout << "Matrix A:" << std::endl;
    Adaptor::print(*A);
    std::cout << "Matrix B:" << std::endl;
    Adaptor::print(*B);
    std::cout << "Matrix C (A + B):" << std::endl;
    Adaptor::print(C);

    // ... Add more test cases for other operations ...

    return 0;
}
