#include <iostream>
#include <vector>
#include <algorithm>
using namespace std;

class Solution {
public:
    int solver(int n, vector<int>& dp) {
        if (n == 2) return 1;
        if (n == 3) return 2;
        if (dp[n] != -1) return dp[n];
        int maxi = 0;
        for (int i = 1; i < n; i++) {
            maxi = max({maxi, i * solver(n - i, dp), (n - i) * i});
        }
        return dp[n] = maxi;
    }

    int integerBreak(int n) {
        if (n == 2) {
            return 1;
        }
        if (n == 3) {
            return 2;
        }
        vector<int> dp(n + 1, -1);
        dp[2] = 1; dp[3] = 2;
        return solver(n, dp);
    }
};

// Test cases
int main() {
    Solution solution;
    cout << "integerBreak(2) = " << solution.integerBreak(2) << endl; // Output: 1
    cout << "integerBreak(10) = " << solution.integerBreak(10) << endl; // Output: 36
    cout << "integerBreak(5) = " << solution.integerBreak(5) << endl; // Output: 6
    return 0;
}
