struct Node {
    enum class Type : quint8 {
        Invalid,
        Environment,
        Fragment,
        Tag,
        Text,
    };

    Node() = default;
    Node(Type type, QString &&value) : type{type}, value{std::move(value)} {}
    Node(Node &&) = default;
    Node & operator = (Node &&) = default;

    static Type typeFromName(const QString &name) {
        if (Environment.contains(name)) {
            return Type::Environment;
        } else if (Fragment.contains(name)) {
            return Type::Fragment;
        } else if (Tag.contains(name)) {
            return Type::Tag;
        } else {
            return Type::Text;
        }
    }

    QString toString() const {
        QString result;
        switch (type) {
            case Type::Environment:
                result = "\\begin{" + value + "}";
                for (const auto &child : children) {
                    result += child.toString();
                }
                result += "\\end{" + value + "}";
                break;
            case Type::Fragment:
                result = value;
                break;
            case Type::Tag:
                result = "<" + value + ">";
                for (const auto &child : children) {
                    result += child.toString();
                }
                result += "</" + value + ">";
                break;
            case Type::Text:
                result = value;
                break;
            default:
                result = "Invalid";
        }
        if (endParagraph) {
            result += "\n\n";
        }
        return result;
    }

    Node & appendNode(Node::Type type, const QString &value) {
        children.push_back(Node(type, QString(value)));
        return children.last();
    }

    Node & appendNode(Node::Type type, QString &&value) {
        children.push_back(Node(type, std::move(value)));
        return children.last();
    }

