int main() {
    const char* originalText = "Origen";
    int key = 3; // The encryption/decryption key

    // Encrypt the original text
    char* encryptedText = encrypt(originalText, key);
    std::cout << "Encrypted text: " << encryptedText << std::endl;

    // Decrypt the text back to the original
    char* decryptedText = decrypt(encryptedText, key);
    std::cout << "Decrypted text: " << decryptedText << std::endl;

    // Free the dynamically allocated memory
    free(encryptedText);
    free(decryptedText);

    system("Pause");
    return 0;
}

char* encrypt(const char* input, int key) {
    int len = strlen(input);
    char* encrypted = (char*)malloc(len + 1); // Allocate memory for the encrypted string

    for (int i = 0; i < len; ++i) {
        char c = input[i];
        // Shift character within the printable ASCII range
        c = (c - 32 + key) % 95 + 32;
        encrypted[i] = c;
    }
    encrypted[len] = '\0'; // Null-terminate the string
    return encrypted;
}

char* decrypt(const char* input, int key) {
    int len = strlen(input);
    char* decrypted = (char*)malloc(len + 1); // Allocate memory for the decrypted string

    for (int i = 0; i < len; ++i) {
        char c = input[i];
        // Reverse the shift within the printable ASCII range
        c = (c - 32 - key + 95) % 95 + 32;
        decrypted[i] = c;
    }
    decrypted[len] = '\0'; // Null-terminate the string
    return decrypted;
}
