using namespace std;
using ll = long long;

/**
 * Finds the maximum product of two distinct elements in a list of integers.
 * 
 * @param numbers A vector of integers.
 * @return The maximum product of two distinct elements, or 0 if the list has fewer than two elements.
 */
ll maxProductOfTwo(const vector<ll>& numbers) {
    if (numbers.size() < 2) {
        return 0; // Not enough elements to form a product.
    }

    ll max1 = numeric_limits<ll>::min(); // Initialize to the smallest possible value.
    ll max2 = max1;

    // Find the two largest numbers in the list.
    for (ll num : numbers) {
        if (num > max1) {
            max2 = max1;
            max1 = num;
        } else if (num > max2) {
            max2 = num;
        }
    }

    return max1 * max2;
}

int main() {
    string input_line;
    getline(cin, input_line);
    vector<ll> numbers;
    ll number;
    stringstream ss(input_line);

    // Read integers from the input line into the numbers vector.
    while (ss >> number) {
        numbers.push_back(number);
    }

    // Calculate the maximum product.
    ll result = maxProductOfTwo(numbers);

    // Output the result or an error message if the input is invalid.
    if (result == 0 && numbers.size() < 2) {
        cout << "Invalid input" << endl;
    } else {
        cout << result << endl;
    }

    return 0;
}
