// Utility to enable recursive lambda functions
template<typename Func>
struct y_combinator_result {
    Func f;
    template<typename... Args>
    decltype(auto) operator()(Args&&... args) {
        return f(ref(*this), std::forward<Args>(args)...);
    }
};

template<typename Func>
decltype(auto) y_combinator(Func&& f) {
    return y_combinator_result<std::decay_t<Func>>{std::forward<Func>(f)};
}

// Namespace for tree-related functions
namespace tree {
    std::vector<int> depth(const std::vector<std::vector<int>>& tree, int s = 0) {
        int n = tree.size();
        std::vector<int> dep(n);

        auto dfs = y_combinator([&](auto dfs, int u, int p = -1) -> void {
            for (int v : tree[u]) {
                if (v == p)
                    continue;
                dep[v] = dep[u] + 1;
                dfs(v, u);
            }
        });

        dep[s] = 0;
        dfs(s);
        return dep;
    }
}

// Main function to demonstrate the solution
int main() {
    // Example tree represented as an adjacency list
    std::vector<std::vector<int>> tree = {
        {1, 2},    // Node 0 is connected to nodes 1 and 2
        {0, 3, 4}, // Node 1 is connected to nodes 0, 3, and 4
        {0},       // Node 2 is connected to node 0
        {1},       // Node 3 is connected to node 1
        {1}        // Node 4 is connected to node 1
    };

    // Calculate the depth of each node starting from node 0
    std::vector<int> depths = tree::depth(tree, 0);

    // Output the depths
    for (int i = 0; i < depths.size(); ++i) {
        std::cout << "Depth of node " << i << " is " << depths[i] << std::endl;
    }

    return 0;
}
