#include <cmath>
#include <vector>

using Real = double;

class ThermalExpansionDensityCalculator {
public:
    ThermalExpansionDensityCalculator(Real fluid_density, Real solid_density,
                                      Real beta_fluid, Real beta_solid,
                                      Real porosity, Real reference_temperature)
        : fluid_density_(fluid_density), solid_density_(solid_density),
          beta_fluid_(beta_fluid), beta_solid_(beta_solid),
          porosity_(porosity), reference_temperature_(reference_temperature) {}

    void computeProperties(Real current_temperature) {
        Real temp_diff = current_temperature - reference_temperature_;
        rho_f_ = fluid_density_ * (1.0 - beta_fluid_ * temp_diff);
        rho_s_ = solid_density_ * (1.0 - beta_solid_ * temp_diff);
        rho_b_ = porosity_ * rho_f_ + (1.0 - porosity_) * rho_s_;
        drho_f_dtemp_ = -beta_fluid_ * fluid_density_;
        drho_s_dtemp_ = -beta_solid_ * solid_density_;
        drho_dtemp_ = porosity_ * drho_f_dtemp_ + (1.0 - porosity_) * drho_s_dtemp_;
        dinvrho_dtemp_ = (rho_b_ > 0.0) ? -1.0 / (rho_b_ * rho_b_) * drho_dtemp_ : 0.0;
    }

    Real getFluidDensity() const { return rho_f_; }
    Real getSolidDensity() const { return rho_s_; }
    Real getBulkDensity() const { return rho_b_; }
    Real getDerivativeFluidDensity() const { return drho_f_dtemp_; }
    Real getDerivativeSolidDensity() const { return drho_s_dtemp_; }
    Real getDerivativeBulkDensity() const { return drho_dtemp_; }
    Real getDerivativeInverseBulkDensity() const { return dinvrho_dtemp_; }

private:
    Real fluid_density_;
    Real solid_density_;
    Real beta_fluid_;
    Real beta_solid_;
    Real porosity_;
    Real reference_temperature_;
    Real rho_f_;
    Real rho_s_;
    Real rho_b_;
    Real drho_f_dtemp_;
    Real drho_s_dtemp_;
    Real drho_dtemp_;
    Real dinvrho_dtemp_;
};

// Test cases
int main() {
    ThermalExpansionDensityCalculator calculator(1000.0, 2500.0, 0.0001, 0.00001, 0.3, 293.15);
    calculator.computeProperties(303.15); // Current temperature is 303.15 K

    std::cout << "Fluid Density: " << calculator.getFluidDensity() << std::endl;
    std::cout << "Solid Density: " << calculator.getSolidDensity() << std::endl;
    std::cout << "Bulk Density: " << calculator.getBulkDensity() << std::endl;
    std::cout << "Derivative Fluid Density: " << calculator.getDerivativeFluidDensity() << std::endl;
    std::cout << "Derivative Solid Density: " << calculator.getDerivativeSolidDensity() << std::endl;
    std::cout << "Derivative Bulk Density: " << calculator.getDerivativeBulkDensity() << std::endl;
    std::cout << "Derivative Inverse Bulk Density: " << calculator.getDerivativeInverseBulkDensity() << std::endl;

    return 0;
}
