/**
 * Finds the maximum value among the edge elements of all possible subarrays of size k.
 * 
 * @param n The size of the array.
 * @param k The size of the subarrays to consider.
 * @param arr The array of integers.
 * @return The maximum edge value among all subarrays of size k.
 */
int findMaxEdgeValue(int n, int k, const vector<int>& arr) {
    int maxEdgeValue = INT_MIN;
    for (int i = 0; i <= n - k; ++i) {
        maxEdgeValue = max(maxEdgeValue, max(arr[i], arr[i + k - 1]));
    }
    return maxEdgeValue;
}

int main() {
