// Helper function to write the response data
static size_t WriteCallback(void *contents, size_t size, size_t nmemb, std::string *s) {
    size_t newLength = size * nmemb;
    try {
        s->append((char*)contents, newLength);
    } catch(std::bad_alloc &e) {
        // Handle memory allocation errors
        return 0;
    }
    return newLength;
}

// Function to perform the login action
std::string Login(const std::string& clientId, const std::string& clientSecret, const std::string& region) {
    CURL *curl;
    CURLcode res;
    std::string readBuffer;
    std::string projectToken;
    std::string url = "https://identifier." + region + ".gameserver.com/projectToken/login";

    curl_global_init(CURL_GLOBAL_DEFAULT);
    curl = curl_easy_init();

    if(curl) {
        struct curl_slist *headers = NULL;
        headers = curl_slist_append(headers, "Content-Type: application/json");

        Json::Value jsonData;
        jsonData["client_id"] = clientId;
        jsonData["client_secret"] = clientSecret;
        Json::StreamWriterBuilder writerBuilder;
        std::string requestBody = Json::writeString(writerBuilder, jsonData);

        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_HTTPHEADER, headers);
        curl_easy_setopt(curl, CURLOPT_POSTFIELDS, requestBody.c_str());
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, WriteCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &readBuffer);

        res = curl_easy_perform(curl);

        if(res != CURLE_OK) {
            std::cerr << "curl_easy_perform() failed: " << curl_easy_strerror(res) << std::endl;
        } else {
            long http_code = 0;
            curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_code);

            if(http_code == 200) {
                Json::CharReaderBuilder readerBuilder;
                Json::Value root;
                std::string errs;
                std::unique_ptr<Json::CharReader> const reader(readerBuilder.newCharReader());
                if (reader->parse(readBuffer.c_str(), readBuffer.c_str() + readBuffer.size(), &root, &errs)) {
                    projectToken = root.get("project_token", "").asString();
                }
            } else {
                std::cerr << "Server responded with code: " << http_code << std::endl;
                std::cerr << "Response body: " << readBuffer << std::endl;
            }
        }

        curl_easy_cleanup(curl);
        curl_slist_free_all(headers);
    }

    curl_global_cleanup();

    return projectToken;
}

