template <typename T, size_t X_DIM, size_t Y_DIM, size_t Z_DIM>
std::shared_ptr<std::vector<T>> read_and_scale_permeability_values(const std::string& filename, T min_value, T max_value) {
  // Check that max_value is greater than min_value
  if (!(max_value > min_value)) {
    throw std::range_error("max_value must be greater than min_value");
  }

  // Calculate scale and shift for the values
  const T scale = (max_value - min_value) / (998.915 - 0.001);
  const T shift = min_value - scale * 0.001;

  // Open the file
  std::ifstream datafile(filename);
  if (!datafile.is_open()) {
    throw std::runtime_error("Could not open file: " + filename);
  }

  // Read the values from the file and scale them
  size_t total_entries = X_DIM * Y_DIM * Z_DIM;
  auto scaled_values = std::make_shared<std::vector<T>>(total_entries, T());
  T value;
  size_t counter = 0;
  while (datafile >> value && counter < total_entries) {
    (*scaled_values)[counter++] = (value * scale) + shift;
  }

  // Check if the number of entries is correct
  if (counter != total_entries) {
    throw std::ios_base::failure("Incorrect number of entries in file: " + filename);
  }

  return scaled_values;
}

// Example usage with test cases
int main() {
  try {
    // Define the filename and the range for scaling
    std::string filename = "permeability_values.dat";
    double min_value = 0.001;
    double max_value = 998.915;

    // Read and scale the permeability values
    auto permeability_values = read_and_scale_permeability_values<double, 100, 1, 20>(filename, min_value, max_value);

    // Test cases (assuming the file contains the correct number of entries)
    assert(permeability_values->size() == 2000); // 100 * 1 * 20
    std::cout << "Test passed: Correct number of entries read from file." << std::endl;

    // Additional test cases could include checking the scaled values against expected results
    // This would require knowing the expected values after scaling
  } catch (const std::exception& e) {
    std::cerr << "An error occurred: " << e.what() << std::endl;
    return 1;
  }

  return 0;
}
