#include <boost/math/distributions/beta.hpp> // for beta_distribution

// Define the return_type metafunction to deduce the return type
template <typename T_y, typename T_scale_succ, typename T_scale_fail>
struct return_type {
  using type = decltype(std::declval<T_y>() + std::declval<T_scale_succ>() + std::declval<T_scale_fail>());
};

// Define the beta_lccdf function
template <typename T_y, typename T_scale_succ, typename T_scale_fail>
typename return_type<T_y, T_scale_succ, T_scale_fail>::type
beta_lccdf(const T_y& y, const T_scale_succ& alpha, const T_scale_fail& beta) {
  boost::math::beta_distribution<> dist(alpha, beta);
  return log(boost::math::ccdf(dist, y));
}

// Define the deprecated beta_ccdf_log function
template <typename T_y, typename T_scale_succ, typename T_scale_fail>
typename return_type<T_y, T_scale_succ, T_scale_fail>::type
beta_ccdf_log(const T_y& y, const T_scale_succ& alpha, const T_scale_fail& beta) {
  return beta_lccdf(y, alpha, beta);
}

int main() {
  // Test cases
  double y = 0.5; // Example value
  double alpha = 2.0; // Shape parameter alpha
  double beta = 5.0; // Shape parameter beta

  // Calculate the log CCDF
  double log_ccdf = beta_ccdf_log(y, alpha, beta);

  // Output the result
  std::cout << "The log CCDF of Beta(" << alpha << ", " << beta << ") at y = " << y << " is: " << log_ccdf << std::endl;

  return 0;
}
