using namespace std;

void Sort(int* a, int n) {
    int negCount = 0;
    for (int i = 0; i < n; i++) {
        if (a[i] < 0) {
            swap(a[negCount], a[i]);
            negCount++;
        }
    }
}

vector<vector<int>> findTriplets(int* a, int n) {
    vector<vector<int>> triplets;
    Sort(a, n);
    for (int i = 0; i < n - 2; i++) {
        if (i > 0 && a[i] == a[i - 1]) continue; // Skip duplicates
        int left = i + 1, right = n - 1;
        while (left < right) {
            int sum = a[i] + a[left] + a[right];
            if (sum == 0) {
                triplets.push_back({a[i], a[left], a[right]});
                while (left < right && a[left] == a[left + 1]) left++; // Skip duplicates
                while (left < right && a[right] == a[right - 1]) right--; // Skip duplicates
                left++;
                right--;
            } else if (sum < 0) {
                left++;
            } else {
                right--;
            }
        }
    }
    return triplets;
}

int main() {
    int n;
    cin >> n;

    int* a = new int[n];

    for (int i = 0; i < n; i++) {
        cin >> a[i];
    }

    vector<vector<int>> triplets = findTriplets(a, n);

    for (const auto& triplet : triplets) {
        for (int num : triplet) {
            cout << num << " ";
        }
        cout << endl;
    }

    delete[] a;
    return 0;
}
