#include <iostream>
#include <algorithm>
#include <queue>
#include <vector>
using namespace std;

#define MAXS 2000

struct EMO {
    int dis; // Display count
    int clip; // Clipboard count
    int time; // Time spent
};

bool chk[MAXS + 1][MAXS + 1];

/**
 * Finds the minimum time required to get S emoticons on the screen.
 * 
 * @param S The target number of emoticons on the screen.
 * @return The minimum time in seconds to get S emoticons on the screen.
 */
int minTimeForEmoticons(int S) {
    queue<EMO> q;
    fill(&chk[0][0], &chk[MAXS][MAXS], false);

    q.push({1, 0, 0});
    chk[1][0] = true;

    while (!q.empty()) {
        EMO data = q.front(); q.pop();

        // Operations: Copy, Paste, Delete
        int dis[3] = {data.dis, data.dis + data.clip, data.dis - 1};
        int clip[3] = {data.dis, data.clip, data.clip};

        for (int i = 0; i < 3; i++) {
            if (dis[i] < 0 || dis[i] > S || clip[i] < 0 || clip[i] > S) continue;
            if (chk[dis[i]][clip[i]]) continue;

            q.push({dis[i], clip[i], data.time + 1});
            chk[dis[i]][clip[i]] = true;
            if (dis[i] == S) return data.time + 1;
        }
    }
    return -1; // Should never reach here if S is a positive integer
}

int main() {
    int S;
    cin >> S;
    int ans = minTimeForEmoticons(S);
    cout << ans << endl;
    return 0;
}

// Test cases to verify the solution correctness
void test() {
    cout << "Test case 1: " << (minTimeForEmoticons(2) == 2 ? "Passed" : "Failed") << endl;
    cout << "Test case 2: " << (minTimeForEmoticons(3) == 3 ? "Passed" : "Failed") << endl;
    cout << "Test case 3: " << (minTimeForEmoticons(4) == 4 ? "Passed" : "Failed") << endl;
    cout << "Test case 4: " << (minTimeForEmoticons(5) == 5 ? "Passed" : "Failed") << endl;
    cout << "Test case 5: " << (minTimeForEmoticons(6) == 5 ? "Passed" : "Failed") << endl;
}

int main() {
    test(); // Run test cases
    return 0;
}
