#include <iostream>
using namespace std;
#define n 10

class CircularQueue {
    int front, rear;
    int *arr;

public:
    CircularQueue() {
        arr = new int[n];
        front = -1;
        rear = -1;
    }

    ~CircularQueue() {
        delete[] arr;
    }

    void enqueue(int x) {
        if (isFull()) {
            cout << "Queue is full now!\n";
            return;
        }
        if (isEmpty()) {
            front = rear = 0;
        } else {
            rear = (rear + 1) % n;
        }
        arr[rear] = x;
    }

    void dequeue() {
        if (isEmpty()) {
            cout << "Queue is empty, cannot dequeue!\n";
            return;
        }
        if (front == rear) {
            front = rear = -1;
        } else {
            front = (front + 1) % n;
        }
    }

    int frontElement() {
        if (isEmpty()) {
            cout << "Queue is empty, cannot show front!\n";
            return -1;
        }
        return arr[front];
    }

    int rearElement() {
        if (isEmpty()) {
            cout << "Queue is empty, cannot show rear!\n";
            return -1;
        }
        return arr[rear];
    }

    bool isEmpty() {
        return front == -1;
    }

    bool isFull() {
        return (rear + 1) % n == front;
    }
};

int main() {
    CircularQueue q;
    q.enqueue(1);
    q.enqueue(2);
    q.enqueue(3);
    q.enqueue(4);

    cout << "Front element: " << q.frontElement() << endl;
    cout << "Rear element: " << q.rearElement() << endl;

    q.dequeue();
    q.dequeue();

    cout << "After two dequeues, front element: " << q.frontElement() << endl;
    cout << "After two dequeues, rear element: " << q.rearElement() << endl;

    q.dequeue();
    q.dequeue();
    q.dequeue(); // This should print "Queue is empty, cannot dequeue!\n"

    cout << "Is queue empty? " << (q.isEmpty() ? "Yes" : "No") << endl;
    cout << "Is queue full? " << (q.isFull() ? "Yes" : "No") << endl;

    return 0;
}
