#include <openssl/sha.h>

using namespace std;

string hashPIN(const vector<int>& pin);
bool validatePIN(const string& enteredHash, const string& correctHash);

int main()
{
    vector<int> pin_1 {2, 4, 1, 8, 7, 9, 0};
    vector<int> pin_2 {2, 4, 6, 8, 7, 9, 0};
    vector<int> pin_3 {1, 2, 3, 4, 5, 6, 7};

    string hashed_pin_1 = hashPIN(pin_1);
    string hashed_pin_2 = hashPIN(pin_2);
    string hashed_pin_3 = hashPIN(pin_3);

    // Test case 1: pin_1 should not match pin_2
    if (validatePIN(hashed_pin_1, hashed_pin_2))
        cout << "Error: pin_1 and pin_2 report to be the same.\n";
    else
        cout << "Success: pin_1 and pin_2 are different.\n";

    // Test case 2: pin_1 should not match pin_3
    if (validatePIN(hashed_pin_1, hashed_pin_3))
        cout << "ERROR: pin_1 and pin_3 report to be the same.\n";
    else
        cout << "SUCCESS: pin_1 and pin_3 are different.\n";

    // Test case 3: pin_1 should match itself
    if (validatePIN(hashed_pin_1, hashed_pin_1))
        cout << "SUCCESS: pin_1 and pin_1 report to be the same.\n";
    else
        cout << "ERROR: pin_1 and pin_1 report to be different.\n";

    return 0;
}

string hashPIN(const vector<int>& pin)
{
    stringstream ss;
    for (int digit : pin)
    {
        ss << digit;
    }
    string pin_str = ss.str();

    unsigned char hash[SHA256_DIGEST_LENGTH];
    SHA256_CTX sha256;
    SHA256_Init(&sha256);
    SHA256_Update(&sha256, pin_str.c_str(), pin_str.size());
    SHA256_Final(hash, &sha256);

    stringstream hash_ss;
    for (unsigned char i : hash)
    {
        hash_ss << hex << setw(2) << setfill('0') << (int)i;
    }
    return hash_ss.str();
}

bool validatePIN(const string& enteredHash, const string& correctHash)
{
    return enteredHash == correctHash;
}
