using namespace std;

// Function to initialize OpenGL state
void init(GLFWwindow *window) {
    // Set the clear color to black
    glClearColor(0.0, 0.0, 0.0, 1.0);
}

// Function to update and render the scene
void display(GLFWwindow *window, double currentTime) {
    // Calculate the position of the rectangle based on the current time
    float xPos = static_cast<float>(cos(currentTime) * 0.5 + 0.5); // Range from 0 to 1

    // Set the color and draw the rectangle with a gradient
    glBegin(GL_QUADS);
        glColor3f(xPos, 0.0f, 1.0f - xPos); // Color for the first vertex
        glVertex2f(xPos - 0.2f, -0.2f);     // Bottom left
        glColor3f(1.0f - xPos, xPos, 0.0f); // Color for the second vertex
        glVertex2f(xPos + 0.2f, -0.2f);     // Bottom right
        glColor3f(0.0f, 1.0f - xPos, xPos); // Color for the third vertex
        glVertex2f(xPos + 0.2f, 0.2f);      // Top right
        glColor3f(xPos, xPos, 1.0f - xPos); // Color for the fourth vertex
        glVertex2f(xPos - 0.2f, 0.2f);      // Top left
    glEnd();
}

// Function to handle window resize events
void window_size_callback(GLFWwindow* window, int width, int height) {
    // Set the viewport to cover the new window size
    glViewport(0, 0, width, height);

    // Adjust the projection matrix
    glMatrixMode(GL_PROJECTION);
    glLoadIdentity();
    float aspectRatio = static_cast<float>(width) / static_cast<float>(height);
    if (width >= height) {
        // Aspect ratio is wider than it is tall
        glOrtho(-aspectRatio, aspectRatio, -1.0, 1.0, 1.0, -1.0);
    } else {
        // Aspect ratio is taller than it is wide
        glOrtho(-1.0, 1.0, -1.0 / aspectRatio, 1.0 / aspectRatio, 1.0, -1.0);
    }
    glMatrixMode(GL_MODELVIEW);
    glLoadIdentity();
}

int main() {
    if (!glfwInit()) exit(EXIT_FAILURE);
    glfwWindowHint(GLFW_CONTEXT_VERSION_MAJOR, 2); // Use OpenGL 2.1 for immediate mode
    glfwWindowHint(GLFW_CONTEXT_VERSION_MINOR, 1);
    GLFWwindow *window = glfwCreateWindow(800, 600, "Moving Gradient Rectangle", NULL, NULL);
    if (!window) {
        glfwTerminate();
        exit(EXIT_FAILURE);
    }
    glfwMakeContextCurrent(window);
    glfwSetWindowSizeCallback(window, window_size_callback);

    if (glewInit() != GLEW_OK) {
        glfwTerminate();
        exit(EXIT_FAILURE);
    }
    glfwSwapInterval(1);

    init(window);

    while (!glfwWindowShouldClose(window)) {
        glClear(GL_COLOR_BUFFER_BIT);
        display(window, glfwGetTime());
        glfwSwapBuffers(window);
        glfwPollEvents();
    }

    glfwDestroyWindow(window);
    glfwTerminate();
    exit(EXIT_SUCCESS);
}
