   auto cs   = hwlib::target::pin_out{ 1, 1 };

   // SPI bus setup
   auto spi_bus = hwlib::spi_bus_bit_banged_sclk_mosi_miso{ 
      sclk, mosi, hwlib::pin_in_dummy };

   // HC595 shift register setup
   auto chip = hwlib::hc595{ spi_bus, cs };

   // Knight Rider animation loop
   for(;;){
      // Move the light from the first LED to the last
      for( uint_fast8_t i = 0; i < 8; ++i ){
          chip.write( 1 << i );
          chip.flush();
          hwlib::wait_ms( 100 );
      }
      // Move the light back from the last LED to the first
      for( uint_fast8_t i = 7; i > 0; --i ){
          chip.write( 1 << i );
          chip.flush();
          hwlib::wait_ms( 100 );
      }
   }
}

