class CommandHandler {
private:
    LONG m_cRef;

public:
    CommandHandler() : m_cRef(1) {}

    ~CommandHandler() {}

    ULONG AddRef() {
        return InterlockedIncrement(&m_cRef);
    }

    ULONG Release() {
