// Define the maximum number of services that can be managed
const unsigned int SERVICE_MAX_QUANTITY = 10;

// Forward declaration of the Service class
class Service;

// ServiceManager class declaration
class ServiceManager {
private:
    std::array<Service*, SERVICE_MAX_QUANTITY> services;
    ServiceManager();

public:
    static ServiceManager* getInstance();
    int getFreeIndex();
    void add(Service* service);
    void remove(Service* service);
    Service* get(const char* name);
    void process();
};

// Service class declaration
class Service {
public:
    std::string name;

    Service(const std::string& name) : name(name) {}
    virtual void execute() = 0;
};

// ServiceManager class definition
ServiceManager::ServiceManager() {
    services.fill(nullptr);
}

ServiceManager* ServiceManager::getInstance() {
    static ServiceManager instance;
    return &instance;
}

int ServiceManager::getFreeIndex() {
    for (unsigned int i = 0; i < SERVICE_MAX_QUANTITY; i++) {
        if (services[i] == nullptr) {
            return i;
        }
    }
    return -1;
}

void ServiceManager::add(Service* service) {
    int index = getFreeIndex();
    if (index >= 0) {
        services[index] = service;
    }
}

void ServiceManager::remove(Service* service) {
    for (unsigned int i = 0; i < SERVICE_MAX_QUANTITY; i++) {
        if (services[i] == service) {
            services[i] = nullptr;
            break;
        }
    }
}

Service* ServiceManager::get(const char* name) {
    for (unsigned int i = 0; i < SERVICE_MAX_QUANTITY; i++) {
        if (services[i] != nullptr && services[i]->name == name) {
            return services[i];
        }
    }
    return nullptr;
}

void ServiceManager::process() {
    for (unsigned int i = 0; i < SERVICE_MAX_QUANTITY; i++) {
        if (services[i] != nullptr) {
            services[i]->execute();
        }
    }
}

