using namespace std;

/**
 * @brief Finds the most frequent customer ID from a list of IDs.
 * 
 * The function takes a vector of customer IDs and returns the ID that occurs
 * most frequently. If there are multiple IDs with the same highest frequency,
 * it returns the smallest one. It also returns the count of how many times
 * the most frequent ID appears.
 * 
 * @param customerIDs A vector of integers representing customer IDs.
 * @return pair<int, int> A pair where the first element is the most frequent
 *         customer ID and the second element is the count of its occurrences.
 */
pair<int, int> findMostFrequentCustomerID(const vector<int>& customerIDs) {
    map<int, int> frequencyMap;
    for (int id : customerIDs) {
        frequencyMap[id]++;
    }

    int mostFrequentID = customerIDs[0];
    int maxFrequency = 0;
    for (const auto& idFreqPair : frequencyMap) {
        if (idFreqPair.second > maxFrequency ||
            (idFreqPair.second == maxFrequency && idFreqPair.first < mostFrequentID)) {
            mostFrequentID = idFreqPair.first;
            maxFrequency = idFreqPair.second;
        }
    }

    return {mostFrequentID, maxFrequency};
}

int main() {
    int n;
    vector<int> customerIDs(10);
    cout << "Enter the number of customers: ";
    cin >> n;
    cout << "Enter the customer IDs (exactly 10): ";
    for (int i = 0; i < 10; i++) {
        cin >> customerIDs[i];
    }

    auto result = findMostFrequentCustomerID(customerIDs);
    cout << "Most frequent customer ID: " << result.first << " (occurs " << result.second << " times)" << endl;

    return 0;
}

// Test cases to verify the solution
int main() {
    // Test case 1
    vector<int> customerIDs1 = {1, 2, 3, 2, 4, 2, 5, 6, 2, 7};
    auto result1 = findMostFrequentCustomerID(customerIDs1);
