#include <cmath>
#include <algorithm>

class AudioTriodeEmulator {
public:
    AudioTriodeEmulator() : intensity(1.0), wet(1.0), dry(0.0), softCrossover(0.0), hardCrossover(0.0) {}

    void setIntensity(double value) {
        intensity = pow(value, 2) * 8.0;
    }

    void setWetDryMix(double value) {
        wet = value;
        dry = 1.0 - value;
    }

    void setSoftCrossover(double value) {
        softCrossover = pow(value, 3) / 8.0;
    }

    void setHardCrossover(double value) {
        hardCrossover = pow(value, 7) / 8.0;
    }

    void process(float** inputs, float** outputs, int sampleFrames) {
        float* in1 = inputs[0];
        float* in2 = inputs[1];
        float* out1 = outputs[0];
        float* out2 = outputs[1];
        double triodeIntensity = intensity + 0.001;

        while (sampleFrames-- > 0) {
            double inputSampleL = *in1;
            double inputSampleR = *in2;
            double drySampleL = inputSampleL;
            double drySampleR = inputSampleR;

            applyTriodeEffect(inputSampleL, triodeIntensity);
            applyTriodeEffect(inputSampleR, triodeIntensity);

            applyCrossoverDistortion(inputSampleL, softCrossover, hardCrossover);
            applyCrossoverDistortion(inputSampleR, softCrossover, hardCrossover);

            mixWetDrySignal(inputSampleL, drySampleL);
            mixWetDrySignal(inputSampleR, drySampleR);

            *out1++ = static_cast<float>(inputSampleL);
            *out2++ = static_cast<float>(inputSampleR);

            in1++;
            in2++;
        }
    }

private:
    double intensity;
    double wet;
    double dry;
    double softCrossover;
    double hardCrossover;

    void applyTriodeEffect(double& sample, double triodeIntensity) {
        if (intensity > 0.0) {
            sample *= triodeIntensity;
            sample -= 0.5;

            double bridgerectifier = fabs(sample);
            if (bridgerectifier > 1.57079633) bridgerectifier = 1.57079633;
            bridgerectifier = sin(bridgerectifier);
            sample = (sample > 0) ? bridgerectifier : -bridgerectifier;

            sample += 0.5;
            sample /= triodeIntensity;
        }
    }

    void applyCrossoverDistortion(double& sample, double soft, double hard) {
        double bridgerectifier = fabs(sample);
        if (soft > 0.0) {
            if (bridgerectifier > 0.0) bridgerectifier -= (soft * (bridgerectifier + sqrt(bridgerectifier)));
            if (bridgerectifier < 0.0) bridgerectifier = 0.0;
            sample = (sample > 0.0) ? bridgerectifier : -bridgerectifier;
        }

        if (hard > 0.0) {
            bridgerectifier -= hard;
            if (bridgerectifier < 0.0) bridgerectifier = 0.0;
            sample = (sample > 0.0) ? bridgerectifier : -bridgerectifier;
        }
    }

    void mixWetDrySignal(double& wetSample, double drySample) {
        if (wet != 1.0) {
            wetSample = (wetSample * wet) + (drySample * dry);
        }
    }
};

// Test cases
int main() {
    const int sampleFrames = 10;
    float inputSignal[2][sampleFrames] = {
        {0.1f, 0.2f, 0.3f, 0.4f, 0.5f, 0.6f, 0.7f, 0.8f, 0.9f, 1.0f},
        {0.1f, 0.2f, 0.3f, 0.4f, 0.5f, 0.6f, 0.7f, 0.8f, 0.9f, 1.0f}
    };
    float outputSignal[2][sampleFrames] = {0};

    float* inputPointers[2] = {inputSignal[0], inputSignal[1]};
    float* outputPointers[2] = {outputSignal[0], outputSignal[1]};

    AudioTriodeEmulator emulator;
    emulator.setIntensity(0.5);
    emulator.setWetDryMix(0.7);
    emulator.setSoftCrossover(0.3);
    emulator.setHardCrossover(0.1);
    emulator.process(inputPointers, outputPointers, sampleFrames);

    // Output processed signal for verification
    for (int i = 0; i < sampleFrames; ++i) {
        std::cout << "Frame " << i << ": L=" << outputSignal[0][i] << ", R=" << outputSignal[1][i] << std::endl;
    }

    return 0;
}
