#include "CloudPolicyCache.h"
#include "CloudPolicyClient.h"
#include "PolicyNotifier.h"

class PolicyManager {
public:
    PolicyManager(std::unique_ptr<CloudPolicyCache> cache,
                  std::unique_ptr<CloudPolicyClient> client,
                  std::unique_ptr<PolicyNotifier> notifier)
        : cache_(std::move(cache)),
          client_(std::move(client)),
          notifier_(std::move(notifier)) {}

    void FetchAndApplyPolicy() {
        if (client_->HasValidToken()) {
            client_->FetchPolicy([this](const PolicyFetchResponse& response) {
                if (cache_->StorePolicy(response)) {
                    notifier_->NotifyPolicyApplied();
                } else {
                    notifier_->NotifyPolicyError(PolicyError::INVALID_POLICY);
                }
            }, [this](PolicyError error) {
                HandlePolicyFetchError(error);
            });
        } else {
            client_->FetchToken([this]() {
                FetchAndApplyPolicy();  // Retry fetching policy after obtaining token.
            }, [this](PolicyError error) {
                notifier_->NotifyPolicyError(error);
            });
        }
    }

    void RefreshPolicy() {
        // Similar to FetchAndApplyPolicy, but may include logic for refresh intervals.
        FetchAndApplyPolicy();
    }

private:
    void HandlePolicyFetchError(PolicyError error) {
        switch (error) {
            case PolicyError::INVALID_TOKEN:
                client_->InvalidateToken();
                FetchAndApplyPolicy();  // Retry with a new token.
                break;
            case PolicyError::DEVICE_CONFLICT:
                // Handle device ID conflict, possibly by generating a new device ID.
                break;
            // Additional error handling as needed.
            default:
                notifier_->NotifyPolicyError(error);
                break;
        }
    }

    std::unique_ptr<CloudPolicyCache> cache_;
    std::unique_ptr<CloudPolicyClient> client_;
    std::unique_ptr<PolicyNotifier> notifier_;
};

