instruction:
Given two integer arrays `preorder` and `inorder` where `preorder` is the preorder traversal of a binary tree and `inorder` is the inorder traversal of the same tree, construct and return the binary tree.

The function `buildTree` will take two vectors of integers `preorder` and `inorder` and return the root of the constructed binary tree.

The structure of the binary tree node `TreeNode` is defined as follows:

```cpp
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};
```

**Constraints**:
- `1 <= preorder.length <= 3000`
- `inorder.length == preorder.length`
- `-3000 <= preorder[i], inorder[i] <= 3000`
- `preorder` and `inorder` consist of unique values.
- Each value of `inorder` also appears in `preorder`.
- `preorder` is guaranteed to be the preorder traversal of the tree.
- `inorder` is guaranteed to be the inorder traversal of the tree.

output:
```cpp
#include <vector>
#include <unordered_map>
using namespace std;

// Definition for a binary tree node.
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

class Solution {
private:
    unordered_map<int, int> memo;
    TreeNode* rebuild(vector<int>& preorder, vector<int>& inorder,
                        int pre_left, int pre_right,
                        int in_left, int in_right) {
        if(pre_left > pre_right)
            return NULL;
        int pre_root = pre_left;
        int in_root = memo[preorder[pre_root]];

        TreeNode* root = new TreeNode(preorder[pre_root]);
        int left_subtree_num = in_root - in_left;

        root->left = rebuild(preorder, inorder,
                            pre_left + 1, pre_left + left_subtree_num,
                            in_left, in_root - 1);

        root->right = rebuild(preorder, inorder,
                            pre_left + left_subtree_num + 1, pre_right,
                            in_root + 1, in_right);

        return root;
    }
public:
    TreeNode* buildTree(vector<int>& preorder, vector<int>& inorder) {
        int n = inorder.size();
        for (int i = 0; i < n; ++i) {
            memo[inorder[i]] = i;
        }
        return rebuild(preorder, inorder, 0, n - 1, 0, n - 1);
    }
};

// Helper function to print the tree in inorder fashion
void printInorder(TreeNode* node) {
    if (node == NULL)
        return;
    printInorder(node->left);
    cout << node->val << " ";
    printInorder(node->right);
}

// Test cases
int main() {
    Solution solution;
    vector<int> preorder = {3, 9, 20, 15, 7};
    vector<int> inorder = {9, 3, 15, 20, 7};
    TreeNode* root = solution.buildTree(preorder, inorder);
    printInorder(root); // Output should be the inorder sequence: 9 3 15 20 7
    return 0;
}
