// Description of |Merge Two Sorted Arrays|:
//
// Given two sorted arrays |array1| and |array2|, merge them into a single
// sorted array. The merged array should be returned. The function should not
// use any extra space for another array and should merge the arrays in place.
//

vector<int> mergeSortedArrays(vector<int>& array1, vector<int>& array2) {
    int i = array1.size() - 1;
    int j = array2.size() - 1;
    int k = array1.size() + array2.size() - 1;
    array1.resize(array1.size() + array2.size());

    while (j >= 0) {
        if (i >= 0 && array1[i] > array2[j]) {
            array1[k--] = array1[i--];
        } else {
            array1[k--] = array2[j--];
        }
    }

    return array1;
}

int main() {
    // Test cases
    vector<int> array1 = {1, 2, 4};
    vector<int> array2 = {1, 3, 4};
    vector<int> expected = {1, 1, 2, 3, 4, 4};
    assert(mergeSortedArrays(array1, array2) == expected);

    array1 = {};
    array2 = {};
    expected = {};
    assert(mergeSortedArrays(array1, array2) == expected);

    array1 = {};
    array2 = {0};
    expected = {0};
    assert(mergeSortedArrays(array1, array2) == expected);

    cout << "All test cases passed!" << endl;

    return 0;
}
