using namespace std;

const int MAX_SIZE = 19;
int maze[MAX_SIZE][MAX_SIZE];
int n;

void printMaze() {
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cout << maze[i][j] << " ";
        }
        cout << endl;
    }
}

void findPaths(int** arr, int n, int row, int col) {
    if (row == n - 1 && col == n - 1) {
        maze[row][col] = 1;
        printMaze();
        cout << endl;
        return;
    }

    if (row >= n || row < 0 || col >= n || col < 0 || arr[row][col] == 0 || maze[row][col] == 1) {
        return;
    }

    maze[row][col] = 1;
    findPaths(arr, n, row - 1, col); // Move up
    findPaths(arr, n, row + 1, col); // Move down
    findPaths(arr, n, row, col - 1); // Move left
    findPaths(arr, n, row, col + 1); // Move right
    maze[row][col] = 0; // Backtrack
}

void ratInMaze(int** arr, int n) {
    memset(maze, 0, sizeof(maze));
    findPaths(arr, n, 0, 0);
}

int main() {
    cin >> n;
    int** arr = new int*[n];
    for (int i = 0; i < n; i++) {
        arr[i] = new int[n];
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            cin >> arr[i][j];
        }
    }
    ratInMaze(arr, n);

    // Clean up dynamically allocated memory
    for (int i = 0; i < n; i++) {
        delete[] arr[i];
    }
    delete[] arr;

    return 0;
}
