using namespace std;

/**
 * @brief Ranks students based on their physical dimensions.
 * 
 * Each student has a height and weight, and their rank increases by one for each student who is both taller and heavier.
 * 
 * @param students A vector of pairs, where each pair contains the height and weight of a student.
 * @return A vector of integers representing the rank of each student.
 */
vector<int> rankStudents(const vector<pair<int, int>>& students) {
    int N = students.size();
    vector<int> ranks(N, 0);

    for(int i = 0; i < N; i++) {
        for(int j = 0; j < N; j++) {
            if(i == j) continue;
            if(students[i].first < students[j].first && students[i].second < students[j].second)
                ranks[i]++;
        }
    }

    // Adjusting rank to start from 1 instead of 0
    for(int& rank : ranks) {
        rank += 1;
    }

    return ranks;
}

int main() {
    int N;
    cin >> N;
    vector<pair<int, int>> students(N);

    for(int i = 0; i < N; i++) {
        cin >> students[i].first >> students[i].second;
    }

    vector<int> ranks = rankStudents(students);

    for(int rank : ranks) {
        cout << rank << " ";
    }

    return 0;
}

