using namespace std;

optional<pair<double, double>> CalculateRoots(double a, double b, double c) {
    double discriminant = b * b - 4 * a * c;
    if (discriminant > 0) {
        double root1 = (-b + sqrt(discriminant)) / (2 * a);
        double root2 = (-b - sqrt(discriminant)) / (2 * a);
        return make_pair(root1, root2);
    } else if (discriminant == 0) {
        double root = -b / (2 * a);
        return make_pair(root, root);
    }
    return nullopt;
}

int main() {
    cout << "\nQuadratic Equation Solver\n";
    for (int i = 1; i <= 5; i++) {
        double a, b, c;
        cout << "Enter coefficients a, b, and c for equation #" << i << ": ";
        cin >> a >> b >> c;
        auto roots = CalculateRoots(a, b, c);
        if (roots) {
            cout << "Roots: " << roots->first << ", " << roots->second << "\n" << endl;
        } else {
            cout << "No real roots.\n" << endl;
        }
    }
    return 0;
}
