// Function to escape special XML characters in a string
std::string escapeXML(const std::string& str) {
    std::string escaped;
    for (char c : str) {
        switch (c) {
            case '<': escaped.append("&lt;"); break;
            case '>': escaped.append("&gt;"); break;
            case '&': escaped.append("&amp;"); break;
            case '\"': escaped.append("&quot;"); break;
            case '\'': escaped.append("&apos;"); break;
            default: escaped.push_back(c);
        }
    }
    return escaped;
}

// Function to convert CSV to XML
void convertCSVtoXML(const std::string& inputCSV, const std::string& outputXML) {
    std::ifstream csvFile(inputCSV);
    std::ofstream xmlFile(outputXML);
    std::string line;
    std::vector<std::string> headers;
    bool firstLine = true;

    xmlFile << "<records>\n";

    while (getline(csvFile, line)) {
        std::istringstream ss(line);
        std::string field;
        std::vector<std::string> fields;
        while (getline(ss, field, ',')) {
            fields.push_back(field);
        }

        if (firstLine) {
            headers = fields;
            firstLine = false;
            continue;
        }

        xmlFile << "  <record>\n";
        for (size_t i = 0; i < fields.size(); ++i) {
            xmlFile << "    <" << headers[i] << ">"
                    << escapeXML(fields[i])
                    << "</" << headers[i] << ">\n";
        }
        xmlFile << "  </record>\n";
    }

    xmlFile << "</records>\n";

    csvFile.close();
    xmlFile.close();
}

// Main function
int main() {
    const std::string inputCSV = "input.csv";
    const std::string outputXML = "output.xml";

    convertCSVtoXML(inputCSV, outputXML);

    std::cout << "Conversion completed. Check " << outputXML << " for the XML output." << std::endl;

    return 0;
}

