#include <bits/stdc++.h>
using namespace std;

// Tree Node
struct Node
{
    int data;
    Node* left;
    Node* right;
};

// Utility function to create a new Tree Node
Node* newNode(int val)
{
    Node* temp = new Node;
    temp->data = val;
    temp->left = NULL;
    temp->right = NULL;
    return temp;
}

// Function to return a list containing the level order traversal in spiral form.
vector<int> findSpiral(Node *root)
{
    if (!root) return {};

    vector<int> result;
    stack<Node*> s1; // Stack to store nodes of current level
    stack<Node*> s2; // Stack to store nodes of next level

    s1.push(root);

    bool leftToRight = false;
    while (!s1.empty())
    {
        Node* temp = s1.top();
        s1.pop();
        result.push_back(temp->data);

        // Store data according to current order.
        if (leftToRight)
        {
            if (temp->left) s2.push(temp->left);
            if (temp->right) s2.push(temp->right);
        }
        else
        {
            if (temp->right) s2.push(temp->right);
            if (temp->left) s2.push(temp->left);
        }

        if (s1.empty())
        {
            leftToRight = !leftToRight;
            swap(s1, s2);
        }
    }

    return result;
}

