#include <vector>
#include <stdexcept>

class SeparableFilter {
public:
    std::vector<std::vector<uint8_t>> apply_filter(
        const std::vector<std::vector<uint8_t>>& src,
        const std::vector<float>& filter_x,
        const std::vector<float>& filter_y) {

        if (filter_x.size() % 2 == 0 || filter_y.size() % 2 == 0) {
            throw std::invalid_argument("Filters must be of odd length.");
        }

        // Apply horizontal filter
        std::vector<std::vector<float>> temp(src.size(), std::vector<float>(src[0].size(), 0));
        for (size_t i = 0; i < src.size(); ++i) {
            for (size_t j = 0; j < src[i].size(); ++j) {
                for (size_t k = 0; k < filter_x.size(); ++k) {
                    int idx = j + k - filter_x.size() / 2;
                    if (idx >= 0 && idx < static_cast<int>(src[i].size())) {
                        temp[i][j] += src[i][idx] * filter_x[k];
                    }
                }
            }
        }

        // Apply vertical filter
        std::vector<std::vector<uint8_t>> result(src.size(), std::vector<uint8_t>(src[0].size(), 0));
        for (size_t i = 0; i < temp.size(); ++i) {
            for (size_t j = 0; j < temp[i].size(); ++j) {
                float sum = 0;
                for (size_t k = 0; k < filter_y.size(); ++k) {
                    int idx = i + k - filter_y.size() / 2;
                    if (idx >= 0 && idx < static_cast<int>(temp.size())) {
                        sum += temp[idx][j] * filter_y[k];
                    }
                }
                result[i][j] = static_cast<uint8_t>(std::max(0.0f, std::min(255.0f, sum)));
            }
        }

        return result;
    }
};

// Test cases
int main() {
    SeparableFilter filter;
    std::vector<std::vector<uint8_t>> image = {
        {255, 255, 255},
        {255, 255, 255},
        {255, 255, 255}
    };
    std::vector<float> filter_x = {1.0f, 0.0f, -1.0f};
    std::vector<float> filter_y = {1.0f, 2.0f, 1.0f};

    auto filtered_image = filter.apply_filter(image, filter_x, filter_y);

    // Output the filtered image
    for (const auto& row : filtered_image) {
        for (uint8_t val : row) {
            std::cout << static_cast<int>(val) << " ";
        }
        std::cout << std::endl;
    }

    return 0;
}
