class Solution {
public:
    void replaceSpace(char *str, int trueLength) {
        if (str == NULL || trueLength <= 0)
            return;
        int spaceCount = 0, index, i = 0;
        for (i = 0; i < trueLength; i++) {
            if (str[i] == ' ') {
                spaceCount++;
            }
        }
        index = trueLength + spaceCount * 2;
        str[index] = '\0';
        for (i = trueLength - 1; i >= 0; i--) {
            if (str[i] == ' ') {
                str[index - 1] = '0';
                str[index - 2] = '2';
                str[index - 3] = '%';
                index = index - 3;
            } else {
                str[index - 1] = str[i];
                index--;
            }
        }
    }
};

int main() {
    char str[] = "Mr John Smith    ";
    int trueLength = 13;
    Solution().replaceSpace(str, trueLength);
    cout << str << endl;
    return 0;
}
