    FileStatistics(const std::filesystem::path& path) : CInputStream(path) {
        if (!is_open()) {
            throw std::runtime_error("File cannot be opened.");
        }
    }

    std::size_t countLines() {
        std::size_t lines = 0;
        std::string line;
        while (std::getline(*this, line)) {
            ++lines;
        }
        clear(); // Clear EOF flag to allow further operations on the stream
        seekg(0); // Reset stream position to the beginning
        return lines;
    }

    std::size_t countWords() {
        std::size_t words = 0;
        std::string word;
        while (*this >> word) {
            ++words;
        }
        clear(); // Clear EOF flag to allow further operations on the stream
        seekg(0); // Reset stream position to the beginning
        return words;
    }

    std::size_t countCharacters() {
        return std::distance(std::istreambuf_iterator<char>(*this), std::istreambuf_iterator<char>());
    }
};

int main() {
    try {
        FileStatistics stats("example.txt");
        std::cout << "Lines: " << stats.countLines() << std::endl;
        std::cout << "Words: " << stats.countWords() << std::endl;
        std::cout << "Characters: " << stats.countCharacters() << std::endl;
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }
    return 0;
}
