#include <forward_list>
#include <vector>
#include <queue>
#include <stdexcept>

using StateType = size_t;
using StateList = std::forward_list<StateType>;

namespace RegEx {

    class AutomataEpsTransitions {
    private:
        const size_t StatesCount;
        std::vector<StateList> deltaStar;

    public:
        AutomataEpsTransitions(size_t n)
            : StatesCount(n), deltaStar(n) {}

        void addTransition(StateType p, StateType q) {
            if (isValidState(p) && isValidState(q))
                deltaStar[p].push_front(q);
            else
                throw std::invalid_argument("Invalid state index in addTransition(p, q).");
        }

        const StateList& delta(StateType p) const {
            if (isValidState(p))
                return deltaStar[p];
            else
                throw std::invalid_argument("Invalid state index in delta(p).");
        }

        size_t stateCount() const {
            return StatesCount;
        }

        StateList reachableFrom(const StateList& from) const {
            std::vector<bool> visited(StatesCount, false);
            std::queue<StateType> toVisit;

            for (const StateType& s : from) {
                toVisit.push(s);
                visited[s] = true;
            }

            StateType currentState;
            while (!toVisit.empty()) {
                currentState = toVisit.front();
                toVisit.pop();
                for (const StateType& state : deltaStar[currentState]) {
                    if (!visited[state]) {
                        toVisit.push(state);
                        visited[state] = true;
                    }
                }
            }

            StateList reachable;
            for (StateType s = 0; s < StatesCount; ++s) {
                if (visited[s]) reachable.push_front(s);
            }

            return reachable;
        }

    private:
        bool isValidState(StateType p) const {
            return p < StatesCount;
        }
    };

} // namespace RegEx

// Test cases
int main() {
    using namespace RegEx;

    AutomataEpsTransitions epsTransitions(5);

    // Add some transitions
    epsTransitions.addTransition(0, 1);
    epsTransitions.addTransition(1, 2);
    epsTransitions.addTransition(2, 3);
    epsTransitions.addTransition(3, 4);
    epsTransitions.addTransition(4, 0); // Adding a cycle for complexity

    // Test delta function
    const StateList& transitionsFrom1 = epsTransitions.delta(1);
    for (StateType state : transitionsFrom1) {
        std::cout << "State 1 has an epsilon transition to state " << state << std::endl;
    }

    // Test reachableFrom function
    StateList startStates = {0};
    StateList reachableStates = epsTransitions.reachableFrom(startStates);
    std::cout << "States reachable from state 0 via epsilon transitions: ";
    for (StateType state : reachableStates) {
        std::cout << state << " ";
    }
    std::cout << std::endl;

    return 0;
}
