using namespace std;

typedef long long ll;

bool isprime(int x) {
    if (x < 2) {
        return false;
    }
    for (int i = 2; i <= sqrt(x); i++) {
        if (x % i == 0) {
            return false;
        }
    }
    return true;
}

int findLeader(int n) {
    vector<int> primes;
    for (int i = 1; i <= 35000; i++) {
        if (isprime(i)) {
            primes.push_back(i);
        }
    }
    int x = 0;
    for (int i = 1; i <= n; i++) {
        x = (x + primes[n - i]) % i;
    }
    return x + 1;
}

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n;
    cout << "Enter the number of candidates: ";
    cin >> n;
    while (n != 0) {
        cout << "The position of the last remaining person is: " << findLeader(n) << endl;
        cout << "Enter the number of candidates (or 0 to exit): ";
        cin >> n;
    }
    return 0;
}
