#include <vector>
#include <chrono>
#include <thread>
#include <iostream>

// Forward declarations for the Subscription and GuardCondition classes
class Subscription {
public:
    bool hasNewData() const;
};

class GuardCondition {
public:
    bool hasTriggered() const;
    void resetTrigger();
};

// The WaitSet class
class WaitSet {
private:
    std::vector<Subscription*> subscriptions;
    std::vector<GuardCondition*> guardConditions;

public:
    void attachSubscription(Subscription* sub) {
        subscriptions.push_back(sub);
    }

    void attachGuardCondition(GuardCondition* gc) {
        guardConditions.push_back(gc);
    }

    bool wait(const std::chrono::milliseconds& timeout) {
        auto start = std::chrono::steady_clock::now();
        while (std::chrono::steady_clock::now() - start < timeout) {
            for (auto& sub : subscriptions) {
                if (sub->hasNewData()) {
                    return true;
                }
            }
            for (auto& gc : guardConditions) {
                if (gc->hasTriggered()) {
                    return true;
                }
            }
            std::this_thread::sleep_for(std::chrono::milliseconds(10));
        }
        return false;
    }

    std::vector<Subscription*> getReadySubscriptions() {
        std::vector<Subscription*> readySubs;
        for (auto& sub : subscriptions) {
            if (sub->hasNewData()) {
                readySubs.push_back(sub);
            }
        }
        return readySubs;
    }

    std::vector<GuardCondition*> getTriggeredGuardConditions() {
        std::vector<GuardCondition*> triggeredGcs;
        for (auto& gc : guardConditions) {
            if (gc->hasTriggered()) {
                triggeredGcs.push_back(gc);
                gc->resetTrigger();
            }
        }
        return triggeredGcs;
    }

    void detachSubscription(Subscription* sub) {
        subscriptions.erase(std::remove(subscriptions.begin(), subscriptions.end(), sub), subscriptions.end());
    }

    void detachGuardCondition(GuardCondition* gc) {
        guardConditions.erase(std::remove(guardConditions.begin(), guardConditions.end(), gc), guardConditions.end());
    }
};

// Test cases
int main() {
    WaitSet waitSet;
    Subscription sub1, sub2;
    GuardCondition gc1, gc2;

    waitSet.attachSubscription(&sub1);
    waitSet.attachSubscription(&sub2);
    waitSet.attachGuardCondition(&gc1);
    waitSet.attachGuardCondition(&gc2);

    if (waitSet.wait(std::chrono::milliseconds(100))) {
        auto readySubs = waitSet.getReadySubscriptions();
        auto triggeredGcs = waitSet.getTriggeredGuardConditions();

        std::cout << "Ready Subscriptions: " << readySubs.size() << std::endl;
        std::cout << "Triggered Guard Conditions: " << triggeredGcs.size() << std::endl;
    } else {
        std::cout << "Timeout occurred, no events detected." << std::endl;
    }

    waitSet.detachSubscription(&sub1);
    waitSet.detachGuardCondition(&gc1);

    return 0;
}
