#include <iostream>
#include <iterator>
#include <numeric>
#include <algorithm>

// Custom Double-ended Queue (Deque) Class Template
template <typename T>
class Doublelist {
private:
    struct Node {
        T data;
        Node* prev;
        Node* next;
        Node(const T& d) : data(d), prev(nullptr), next(nullptr) {}
    };
    Node* head;
    Node* tail;
    size_t count;

public:
    // Constructor
    Doublelist() : head(nullptr), tail(nullptr), count(0) {}

    // Destructor
    ~Doublelist() {
        while (head) {
            Node* temp = head;
            head = head->next;
            delete temp;
        }
    }

    // Copy constructor and assignment operator omitted for brevity

    // Insert an element at the front of the deque
    void push_front(const T& value) {
        Node* node = new Node(value);
        if (!head) {
            head = tail = node;
        } else {
            node->next = head;
            head->prev = node;
            head = node;
        }
        ++count;
    }

    // Insert an element at the back of the deque
    void push_back(const T& value) {
        Node* node = new Node(value);
        if (!tail) {
            head = tail = node;
        } else {
            tail->next = node;
            node->prev = tail;
            tail = node;
        }
        ++count;
    }

    // Access the first element
    T& front() {
        if (!head) throw std::runtime_error("Deque is empty");
        return head->data;
    }

    // Access the last element
    T& back() {
        if (!tail) throw std::runtime_error("Deque is empty");
        return tail->data;
    }

    // Return the number of elements in the deque
    size_t size() const {
        return count;
    }

    // Iterator class
    class iterator : public std::iterator<std::bidirectional_iterator_tag, T> {
        Node* ptr;
    public:
        iterator(Node* p) : ptr(p) {}
        iterator& operator++() { ptr = ptr->next; return *this; }
        iterator operator++(int) { iterator temp = *this; ++(*this); return temp; }
        bool operator==(const iterator& other) const { return ptr == other.ptr; }
        bool operator!=(const iterator& other) const { return ptr != other.ptr; }
        T& operator*() { return ptr->data; }
    };

    // Return an iterator pointing to the first element
    iterator begin() {
        return iterator(head);
    }

    // Return an iterator pointing to the past-the-end element
    iterator end() {
        return iterator(nullptr);
    }
};

int main() {
    Doublelist<std::string> slist;
    slist.push_front("Tachibana Arisu");
    slist.push_back("Satou Shin");
    slist.push_front("Katagiri Sanae");
    slist.push_back("Sasaki Chie");
    slist.push_front("Tsukioka Kogane");
    slist.push_back("Komiya Kaho");

    std::cout << "Size of string Doublelist: " << slist.size() << std::endl;

    for (const auto& s : slist) {
        std::cout << s << std::endl;
    }

    std::cout << "\nFirst name: " << slist.front() << std::endl;
    std::cout << "Last name: " << slist.back() << std::endl;

    Doublelist<int> ilist;
    ilist.push_back(17);
    ilist.push_back(23);
    ilist.push_back(78);
    ilist.push_back(4);
    ilist.push_back(34);
    ilist.push_back(19);
    ilist.push_back(3);
    ilist.push_back(5);
    ilist.push_back(23);
    ilist.push_back(37);
    ilist.push_back(43);

    int sum = std::accumulate(ilist.begin(), ilist.end(), 0);
    std::cout << "Sum of integers in Doublelist: " << sum << std::endl;

    return 0;
}
