class Taxi;

// Abstract State class
class State {
public:
    virtual shared_ptr<State> hailed(Taxi *taxi) = 0;
    virtual shared_ptr<State> drive(Taxi *taxi) = 0;
    virtual shared_ptr<State> checkout(Taxi *taxi) = 0;
