    taxi.checkout(); // Should indicate no passenger

    // Test case 3: Taxi is off-duty, gets hailed, and hailed again
    taxi.hailed(); // Should pick up the passenger and drive to the destination
    taxi.hailed(); // Should indicate already hailed

    return 0;
}
