#include <iostream>
#include <algorithm>
#include <vector>
using namespace std;
typedef long long ll;

const int MAXR = 100001;
ll Ra[MAXR], Ca[MAXR], countc[MAXR], countr[MAXR];

int main() {
    int R, C, K, N;
    cin >> R >> C >> K >> N;
    fill(Ra, Ra + R, 0);
    fill(Ca, Ca + C, 0);
    for (int i = 0; i < N; i++) {
        int r, c;
        cin >> r >> c;
        r--; c--; // Adjusting for 0-based indexing
        Ra[r]++;
        Ca[c]++;
    }
    fill(countc, countc + C, 0);
    fill(countr, countr + R, 0);
    for (int i = 0; i < R; i++) countr[Ra[i]]++;
    for (int i = 0; i < C; i++) countc[Ca[i]]++;

    ll ways = 0;
    for (int i = 0; i <= K; i++) {
        if (K - i >= 0 && K - i < MAXR) {
            ways += countr[i] * countc[K - i];
        }
    }

    // Subtract the cases where we double-counted the books that are already placed
    for (int i = 0; i < N; i++) {
        int r, c;
        cin >> r >> c;
        r--; c--; // Adjusting for 0-based indexing
        if (Ra[r] + Ca[c] == K) ways--;
        if (Ra[r] + Ca[c] == K + 1) ways++;
    }

    cout << ways << endl;
    return 0;
}
