// graph_addon.cpp
#include <node.h>
#include <node_object_wrap.h>

using namespace v8;

class Graph : public node::ObjectWrap {
 public:
  static void Init(Local<Object> exports);

 private:
  explicit Graph(double value = 0) : value_(value) {}
  ~Graph() {}

  static void New(const FunctionCallbackInfo<Value>& args);
  static void PlusOne(const FunctionCallbackInfo<Value>& args);
  static Persistent<Function> constructor;
  double value_;
};

Persistent<Function> Graph::constructor;

void Graph::Init(Local<Object> exports) {
  Isolate* isolate = exports->GetIsolate();

  // Prepare constructor template
  Local<FunctionTemplate> tpl = FunctionTemplate::New(isolate, New);
  tpl->SetClassName(String::NewFromUtf8(isolate, "Graph").ToLocalChecked());
  tpl->InstanceTemplate()->SetInternalFieldCount(1);

  // Prototype
  NODE_SET_PROTOTYPE_METHOD(tpl, "plusOne", PlusOne);

  constructor.Reset(isolate, tpl->GetFunction(isolate->GetCurrentContext()).ToLocalChecked());
  exports->Set(isolate->GetCurrentContext(), String::NewFromUtf8(isolate, "Graph").ToLocalChecked(), tpl->GetFunction(isolate->GetCurrentContext()).ToLocalChecked()).Check();
}

void Graph::New(const FunctionCallbackInfo<Value>& args) {
  Isolate* isolate = args.GetIsolate();

  if (args.IsConstructCall()) {
    // Invoked as constructor: `new Graph(...)`
    double value = args[0]->IsUndefined() ? 0 : args[0]->NumberValue(isolate->GetCurrentContext()).FromMaybe(0);
    Graph* obj = new Graph(value);
    obj->Wrap(args.This());
    args.GetReturnValue().Set(args.This());
  } else {
    // Invoked as plain function `Graph(...)`, turn into construct call.
    const int argc = 1;
    Local<Value> argv[argc] = { args[0] };
    Local<Function> cons = Local<Function>::New(isolate, constructor);
    Local<Context> context = isolate->GetCurrentContext();
    Local<Object> instance = cons->NewInstance(context, argc, argv).ToLocalChecked();
    args.GetReturnValue().Set(instance);
  }
}

void Graph::PlusOne(const FunctionCallbackInfo<Value>& args) {
  Isolate* isolate = args.GetIsolate();
  Graph* obj = ObjectWrap::Unwrap<Graph>(args.Holder());
  obj->value_ += 1;
  args.GetReturnValue().Set(Number::New(isolate, obj->value_));
}

NODE_MODULE(NODE_GYP_MODULE_NAME, Graph::Init)
