#include <iostream>
using namespace std;

bool canEatHalfCandies(long long n, long long k) {
    long long eaten = 0, remaining = n;
    while (remaining > 0) {
        long long eatToday = min(k, remaining);
        remaining -= eatToday;
        eaten += eatToday;
        remaining -= remaining / 10;
    }
    return eaten * 2 >= n;
}

int main() {
    long long n;
    cin >> n;
    long long left = 1, right = n, minK = n;
    while (left <= right) {
        long long mid = (left + right) / 2;
        if (canEatHalfCandies(n, mid)) {
            minK = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }
    cout << minK << endl;
    return 0;
}
