  void begin() {
    pinMode(_cs, OUTPUT);
    digitalWrite(_cs, HIGH);
    if (_sck == SCK && _miso == MISO && _mosi == MOSI) {
      // Use hardware SPI
      SPI.begin();
    } else {
      // Use software SPI
      pinMode(_sck, OUTPUT);
      pinMode(_miso, INPUT);
      pinMode(_mosi, OUTPUT);
      // Software SPI initialization if needed
    }
    SPI.beginTransaction(spiSettings);
    delayMicroseconds(500);
  }

  uint16_t read(uint8_t channel) {
    uint16_t retVal;
    uint8_t pByte1 = 0x04 | (channel >> 2);
    uint8_t pByte2 = channel << 6;
    digitalWrite(_cs, LOW);
    spiWriteByte(pByte1);
    uint8_t rByte1 = spiByteTransfer(pByte2);
    uint8_t rByte2 = spiByteTransfer(0xFF);
    digitalWrite(_cs, HIGH);
    delayMicroseconds(1);
    retVal = ((uint16_t)(rByte1 & 0x0F) << 8) | (uint16_t)rByte2;
    return retVal;
  }

  void spiWriteByte(uint8_t oneByte) {
    SPI.transfer(oneByte);
  }

  void spiWriteBytes(const uint8_t* bytes, uint8_t size) {
    for (uint8_t i = 0; i < size; ++i) {
      SPI.transfer(bytes[i]);
    }
  }

  uint8_t spiReadByte() {
    digitalWrite(_cs, LOW);
    uint8_t retByte = SPI.transfer(0xFF);
    digitalWrite(_cs, HIGH);
    return retByte;
  }

  uint8_t spiByteTransfer(uint8_t oneByte) {
    return SPI.transfer(oneByte);
  }
};

// Test cases
void setup() {
