  iMCP3208 adc(10, 1000000); // CS pin 10, SPI frequency 1MHz
  adc.begin();
}

void loop() {
  uint16_t value = adc.read(CH0); // Read from channel 0
  Serial.print("Channel 0: ");
  Serial.println(value);
  delay(1000); // Wait for 1 second
}
