        return V2(x * scalar, y * scalar);
    }
    struct {
        float x;
        float y;
    };
};

// Define the V3 union for 3D vectors
union V3 {
    V3() : x(0), y(0), z(0) {}
    V3(float x, float y, float z) : x(x), y(y), z(z) {}
    V3 operator/(float scalar) {
        assert(scalar != 0);
        return V3(x / scalar, y / scalar, z / scalar);
    }
    V3 operator*(float scalar) {
        return V3(x * scalar, y * scalar, z * scalar);
    }
    struct {
        float r;
        float g;
        float b;
    };
    struct {
        float x;
        float y;
        float z;
    };
};

// Define the V4 union for 4D vectors
union V4 {
    V4() : x(0), y(0), z(0), w(0) {}
    V4(float x, float y, float z, float w) : x(x), y(y), z(z), w(w) {}
    V4 operator/(float scalar) {
        assert(scalar != 0);
        return V4(x / scalar, y / scalar, z / scalar, w / scalar);
    }
    V4 operator*(float scalar) {
        return V4(x * scalar, y * scalar, z * scalar, w * scalar);
    }
    struct {
