/**
 * Calculates the sum of the series 2^(n-2) + 2^(n-1) + ... + 2^(2n-2)
 * where n is a non-negative integer provided by the user.
 *
 * @return The sum of the series as a float.
 */
float calculate_series_sum() {
    float sum = 0;
    int n;
    do {
        cout << "Enter a non-negative integer n: ";
        cin >> n;
    } while (n < 0);

    for (int i = n; i <= 2 * n; i++) {
        sum += pow(2, i - 2);
    }

    return sum;
}

int main() {
    float sum = calculate_series_sum();
    cout << "The sum of the series is: " << sum << endl;
    return 0;
}
