    void findTopStudents() const {
        int highestGrade = 0;
        for (const Student& student : this->studentList) {
            highestGrade = max(highestGrade, student.getGrade());
        }

        list<string> topStudents;
        for (const Student& student : this->studentList) {
            if (student.getGrade() == highestGrade) {
                topStudents.push_back(student.getName());
            }
        }

        for (const string& name : topStudents) {
            cout << name << " ";
        }
        cout << endl;
    }
};

