class LoopOutputHandler {
public:
    class Watchdog;

    LoopOutputHandler(const std::chrono::milliseconds& timeout)
        : watchdog_(this, timeout), run_(true) {
        // Initialize the output loop and watchdog in separate threads
        output_thread_ = std::thread(&LoopOutputHandler::operator(), this);
        watchdog_thread_ = std::thread(std::ref(watchdog_));
    }

    ~LoopOutputHandler() {
        // Ensure the threads are joined before destruction
        run_ = false;
        watchdog_.Quit();
        if (output_thread_.joinable()) {
            output_thread_.join();
        }
        if (watchdog_thread_.joinable()) {
            watchdog_thread_.join();
        }
    }

    void operator()() {
        while (run_) {
            Read();
            if (joystick_state_.fake) {
                // Log fake joystick state and continue
                std::cout << "Fake joystick state detected." << std::endl;
                continue;
            }
            watchdog_.Reset();
            Write();
        }
    }

    void Stop() {
        run_ = false;
    }

private:
    struct JoystickState {
        bool fake = false; // Simulate a fake joystick state
    };

    void Read() {
        // Simulate reading joystick input
        // In a real scenario, this would interface with hardware
    }

    void Write() {
        // Simulate writing outputs to actuators
        // In a real scenario, this would interface with hardware
    }

    JoystickState joystick_state_;
    Watchdog watchdog_;
    std::thread output_thread_;
    std::thread watchdog_thread_;
    bool run_;

public:
    class Watchdog {
    public:
        Watchdog(LoopOutputHandler* handler, const std::chrono::milliseconds& timeout)
            : handler_(handler), timeout_(timeout), run_(true) {
            timerfd_ = timerfd_create(CLOCK_MONOTONIC, 0);
            if (timerfd_ == -1) {
                perror("timerfd_create");
                exit(EXIT_FAILURE);
            }
        }

        void operator()() {
            uint64_t expirations;
            while (run_) {
                read(timerfd_, &expirations, sizeof(expirations));
                if (expirations > 0) {
                    handler_->Stop();
                }
            }
        }

        void Reset() {
            itimerspec new_value{};
            new_value.it_value.tv_sec = timeout_.count() / 1000;
            new_value.it_value.tv_nsec = (timeout_.count() % 1000) * 1000000;
            timerfd_settime(timerfd_, 0, &new_value, nullptr);
        }

        void Quit() {
            run_ = false;
        }

    private:
        LoopOutputHandler* handler_;
        std::chrono::milliseconds timeout_;
        int timerfd_;
        bool run_;
    };
};

int main() {
    // Example usage:
    LoopOutputHandler handler(std::chrono::milliseconds(1000)); // 1 second timeout
    // The handler will run until the program is terminated
    // In a real scenario, you would have logic to terminate the handler
    return 0;
}
