    double totalReward = 0.0;
    while (!done)
    {
        // Choose an action (for demonstration, we alternate between forward and backward).
        static bool moveForward = true;
        mlpack::rl::CartPole::Action action = moveForward ? mlpack::rl::CartPole::forward : mlpack::rl::CartPole::backward;
