        // Apply the action to the environment and get the next state and reward.
        double reward = cartPole.Sample(state, action, state);
        totalReward += reward;

        // Check if the state is terminal.
        done = cartPole.IsTerminal(state);

        // Output the current state and reward.
        std::cout << "State: " << state.Encode().t() << "Action: " << (action == mlpack::rl::CartPole::forward ? "Forward" : "Backward") << " Reward: " << reward << std::endl;
    }

    // Output the total reward.
    std::cout << "Total Reward: " << totalReward << std::endl;

