            const vector<MappedValueEntry<T>>& otherEntries = pair.second;

            if (mEntries.find(refSeqId) == mEntries.end()) {
                mEntries[refSeqId] = otherEntries;
            } else {
                vector<MappedValueEntry<T>>& currentEntries = mEntries[refSeqId];
                currentEntries.insert(currentEntries.end(), otherEntries.begin(), otherEntries.end());
                sortAddAndCompress(currentEntries);
            }
        }
    }

    void subtract(const MappedValues<T>& other, bool removeZero = false) {
        for (const auto& pair : other.mEntries) {
            const string& refSeqId = pair.first;
            const vector<MappedValueEntry<T>>& otherEntries = pair.second;

            if (mEntries.find(refSeqId) == mEntries.end()) {
                throw runtime_error("Reference sequence ID not found in current MappedValues object.");
            } else {
                vector<MappedValueEntry<T>>& currentEntries = mEntries[refSeqId];
                for (const auto& entry : otherEntries) {
                    auto it = std::find_if(currentEntries.begin(), currentEntries.end(),
                                           [&entry](const MappedValueEntry<T>& e) { return e.pos == entry.pos; });
                    if (it != currentEntries.end()) {
                        it->entry -= entry.entry;
                        if (removeZero && it->entry == T{}) {
