using namespace std;

class Node {
public:
    string txtChars;
    Node *next;
};

class Queue {
    Node *front;
    Node *back;

    bool isEmpty() {
        return front == NULL;
    }

public:
    Queue() : front(NULL), back(NULL) {}

    ~Queue() {
        while (!isEmpty()) {
            dequeue();
        }
    }

    void dequeue() {
        if (isEmpty()) return;
        Node *temp = front;
        front = front->next;
        delete temp;
    }

    void enqueue(string x) {
        Node *temp = new Node;
        temp->txtChars = x;
        temp->next = NULL;
        if (isEmpty()) {
            front = temp;
            back = temp;
        } else {
            back->next = temp;
            back = temp;
        }
    }

    string displayFirst() {
        if (!isEmpty()) {
            return front->txtChars;
        }
        return "";
    }

