public:
    void LoadNewLevel() {}
};

// Base Transition class
class Transition {
public:
    virtual void Start() {}
    virtual void Change() {}
    virtual void Exit() {}
    virtual float Interpolate(float start, float end, float percentage) {
        return start + percentage * (end - start);
    }
};

// LinesTransition class
class LinesTransition : public Transition {
private:
    j1Color color;
    float duration;
    SDL_Rect lines[11];
    int w, h;
    SDL_Rect screen;
    float percentage;
    int initial_x_left, initial_x_right;

public:
    LinesTransition(j1Color color, float time) : color(color), duration(time) {
        j1App* App = j1App::GetInstance();
        App->win->GetWindowSize(w, h);
        screen = { -(int)w, 0, (int)w, (int)h };
        SDL_SetRenderDrawBlendMode(App->render->renderer, SDL_BLENDMODE_BLEND);

        initial_x_left = App->render->camera.x - (int)w;
        initial_x_right = App->render->camera.x + (int)w;

        int height = 0;
        for (int i = 0; i < 11; i++) {
            lines[i].h = ((int)h / 10);
            lines[i].w = (int)w + 20;

            if (i % 2 == 0)
                lines[i].x = initial_x_left - 10;
            else
                lines[i].x = initial_x_right + 10;

            lines[i].y = height;
            height += h / 10;
        }
    }

    ~LinesTransition() {}

    void Start() override {
        j1App* App = j1App::GetInstance();
        percentage = 0.0f; // Start with 0% of the transition

        for (int i = 0; i < 11; i++) {
            if (i % 2 == 0)
                lines[i].x = Interpolate(-(int)w - 10, -15, percentage);
            else
                lines[i].x = Interpolate((int)w, 0, percentage);
        }

        SDL_SetRenderDrawColor(App->render->renderer, color.r, color.g, color.b, 255);
        for (int i = 0; i < 11; i++)
            SDL_RenderFillRect(App->render->renderer, &lines[i]);
    }

    void Change() override {
        j1App* App = j1App::GetInstance();
        App->audio->PlayFx(App->audio->transitionFx);
        App->scene1->LoadNewLevel();

        SDL_SetRenderDrawColor(App->render->renderer, color.r, color.g, color.b, 255);
        SDL_RenderFillRect(App->render->renderer, &screen);
    }

    void Exit() override {
        j1App* App = j1App::GetInstance();
        percentage = 1.0f; // End with 100% of the transition

        SDL_SetRenderDrawColor(App->render->renderer, color.r, color.g, color.b, 255);
        for (int i = 0; i < 11; i++)
            SDL_RenderFillRect(App->render->renderer, &lines[i]);

        for (int i = 0; i < 11; i++) {
            if (i % 2 == 0)
                lines[i].x = Interpolate(-10, (int)w, percentage);
            else
                lines[i].x = Interpolate(-10, -(int)w, percentage);
        }
    }
};

// Test cases to verify the solution correctness
int main() {
    // Initialize SDL and create a window and renderer
    SDL_Init(SDL_INIT_VIDEO);
    SDL_Window* window = SDL_CreateWindow("Transition Test", SDL_WINDOWPOS_CENTERED, SDL_WINDOWPOS_CENTERED, 800, 600, 0);
    SDL_Renderer* renderer = SDL_CreateRenderer(window, -1, SDL_RENDERER_ACCELERATED);

    // Mock the application environment
    j1App* App = j1App::GetInstance();
    App->render = new j1Render();
    App->render->renderer = renderer;
    App->audio = new j1Audio();
    App->win = new j1Window();
    App->scene1 = new j1Scene1();

    // Create a LinesTransition instance
    j1Color transitionColor(255, 0, 0); // Red color
    LinesTransition transition(transitionColor, 2.0f); // Duration of 2 seconds

    // Start the transition
    transition.Start();

    // Simulate the middle of the transition
    transition.Change();

    // Complete the transition
    transition.Exit();

    // Clean up
    delete App->render;
    SDL_DestroyRenderer(renderer);
    SDL_DestroyWindow(window);
    SDL_Quit();

    return 0;
}
