// Assume the following headers provide the necessary implementations
#include "basic_IO.hpp"
#include "basic_linear_systems.hpp"

typedef std::vector<double> V_d;
typedef std::vector<std::vector<double>> VV_d;

// Function to compute the eigenvalues of a matrix using the QR algorithm
V_d computeEigenvalues(VV_d A, int maxIter, double tol) {
    VV_d Ak = A;
    V_d eigenvalues(A.size(), 0.0);
    VV_d I = A;
    IdentityMatrix(I);

    for (int i = 0; i < maxIter; ++i) {
        QR qr(Ak);
        Ak = Dot(qr.R, qr.Q);

        double total = 0;
        for (size_t j = 0; j < Ak.size(); ++j) {
            eigenvalues[j] = Ak[j][j];
            total += std::abs(Det(A - eigenvalues[j] * I));
        }

        if (std::abs(total) < tol) {
            break;
        }
    }

    return eigenvalues;
}

int main() {
    VV_d A = {{6., 5., 0.},
              {5., 1., 4.},
              {0., 4., 3.}};

    V_d trueEigenvalues = {9.84316, 4.02176, -3.86492}; // True eigenvalues for comparison

    int maxIter = 1000;
    double tol = 1e-9;

    V_d computedEigenvalues = computeEigenvalues(A, maxIter, tol);

    std::cout << "Computed eigenvalues: ";
    for (const auto& val : computedEigenvalues) {
        std::cout << std::fixed << std::setprecision(5) << val << " ";
    }
    std::cout << std::endl;

    std::cout << "True eigenvalues: ";
    for (const auto& val : trueEigenvalues) {
        std::cout << std::fixed << std::setprecision(5) << val << " ";
    }
    std::cout << std::endl;

    return 0;
}
