/*=========================================================================
 *
 *  Example usage of ITK to convert a Philips REC medical image to another
 *  image format such as PNG or JPEG.
 *
 *  This program demonstrates the use of ITK's image IO factory mechanism
 *  to read a proprietary medical image format and convert it to a common
 *  image format for further use or visualization.
 *
 *=========================================================================*/

#include <iostream>
#include <string>

#include "itkImage.h"
#include "itkImageFileReader.h"
#include "itkImageFileWriter.h"
#include "itkPhilipsRECImageIOFactory.h"
#include "itkPNGImageIOFactory.h"
#include "itkJPEGImageIOFactory.h"

int main(int argc, char *argv[])
{
  if (argc < 3)
  {
    std::cerr << "Usage: " << argv[0] << " <InputPhilipsRECImage> <OutputImage>" << std::endl;
    return EXIT_FAILURE;
  }

  const char *inputFileName = argv[1];
  const char *outputFileName = argv[2];

  // Register the Philips REC Image IO factory.
  itk::PhilipsRECImageIOFactory::RegisterOneFactory();

  // Define the pixel type and dimension of the image.
  using PixelType = unsigned short;
  constexpr unsigned int Dimension = 2;
  using ImageType = itk::Image<PixelType, Dimension>;

  // Create the reader and writer using the ImageType.
  using ReaderType = itk::ImageFileReader<ImageType>;
  using WriterType = itk::ImageFileWriter<ImageType>;

  auto reader = ReaderType::New();
  auto writer = WriterType::New();

  // Set the file names for the reader and writer.
  reader->SetFileName(inputFileName);
  writer->SetFileName(outputFileName);

  // Connect the output of the reader to the input of the writer.
  writer->SetInput(reader->GetOutput());

  // Try to read the input image and write the output image.
  try
  {
    writer->Update();
  }
  catch (const itk::ExceptionObject &ex)
  {
    std::cerr << "Error: " << ex << std::endl;
    return EXIT_FAILURE;
  }

  std::cout << "Image conversion successful." << std::endl;
  return EXIT_SUCCESS;
}
