#ifndef SQUARE_ROOT_H
#define SQUARE_ROOT_H

double squareRoot(double number);

#endif // SQUARE_ROOT_H

// square_root.cpp
#include "square_root.h"

double squareRoot(double number) {
    if (number < 0.0) {
        return -1.0;
    }
    if (number == 0.0) {
        return 0.0;
    }

    double guess = number / 2.0;
    double epsilon = 0.0001;
    while (abs(guess * guess - number) > epsilon) {
        guess = (guess + number / guess) / 2.0;
    }
    return guess;
}

// tests.cpp
#include "square_root.h"
#include <gtest/gtest.h>

TEST(SquareRootTest, PositiveNos) { 
    ASSERT_NEAR(6, squareRoot(36.0), 0.0001);
    ASSERT_NEAR(18.0, squareRoot(324.0), 0.0001);
    ASSERT_NEAR(25.4, squareRoot(645.16), 0.0001);
    ASSERT_NEAR(1, squareRoot(1.0), 0.0001);
}

TEST(SquareRootTest, Zero) {
    ASSERT_NEAR(0, squareRoot(0.0), 0.0001);
}

TEST(SquareRootTest, NegativeNos) {
    ASSERT_EQ(-1.0, squareRoot(-15.0));
    ASSERT_EQ(-1.0, squareRoot(-0.2));
}

int main(int argc, char **argv) {
    testing::InitGoogleTest(&argc, argv);
    return RUN_ALL_TESTS();
}
